function installDnsFallback() {
  const originalLookup = dns.lookup.bind(dns);
  const fallbackHosts = new Map([
    ['web.whatsapp.com', WA_WEB_FALLBACK_IP],
    ['mmx-ds.cdn.whatsapp.net', WA_WEB_FALLBACK_IP]
  ]);

  dns.lookup = function lookupWithFallback(hostname, options, callback) {
    let cb = callback;
    let opts = options;
    if (typeof options === 'function') {
      cb = options;
      opts = {};
    }

    originalLookup(hostname, opts, (err, address, family) => {
      const fallbackIp = fallbackHosts.get(String(hostname || '').toLowerCase());
      if (!err || !fallbackIp || !['EAI_AGAIN', 'ENOTFOUND'].includes(err.code)) {
        return cb(err, address, family);
      }
      console.warn(`[DNS] ${hostname} lookup failed (${err.code}); using fallback ${fallbackIp}`);
      if (opts && typeof opts === 'object' && opts.all) {
        return cb(null, [{ address: fallbackIp, family: 4 }]);
      }
      return cb(null, fallbackIp, 4);
    });
  };
}
installDnsFallback();

