function getOutboundProxyUrl() {
  const value = process.env.WA_PROXY
    || process.env.HTTPS_PROXY
    || process.env.https_proxy
    || process.env.HTTP_PROXY
    || process.env.http_proxy
    || '';
  const trimmed = String(value || '').trim();
  if (!trimmed) return '';
  return /^https?:\/\//i.test(trimmed) ? trimmed : `http://${trimmed}`;
}

function getWhatsAppProxyUrl() {
  if (/^(1|true|yes)$/i.test(String(process.env.WA_DISABLE_PROXY || ''))) return '';
  const explicit = String(process.env.WA_PROXY || '').trim();
  if (explicit) return /^https?:\/\//i.test(explicit) ? explicit : `http://${explicit}`;
  const useSystemProxy = /^(1|true|yes)$/i.test(String(process.env.WA_USE_SYSTEM_PROXY || ''));
  if (!useSystemProxy) return '';
  const value = process.env.HTTPS_PROXY
    || process.env.https_proxy
    || process.env.HTTP_PROXY
    || process.env.http_proxy
    || '';
  const trimmed = String(value || '').trim();
  if (!trimmed) return '';
  return /^https?:\/\//i.test(trimmed) ? trimmed : `http://${trimmed}`;
}

function createOutboundProxyAgent(label = 'network') {
  const proxyUrl = getOutboundProxyUrl();
  if (!proxyUrl || !HttpsProxyAgent) return null;
  try {
    console.log(`[Proxy] ${label} using ${proxyUrl.replace(/\/\/.*@/, '//***@')}`);
    return new HttpsProxyAgent(proxyUrl);
  } catch (error) {
    console.warn(`[Proxy] Could not create ${label} proxy agent: ${error.message}`);
    return null;
  }
}

function createWhatsAppProxyAgent(label = 'WhatsApp') {
  const proxyUrl = getWhatsAppProxyUrl();
  if (!proxyUrl || !HttpsProxyAgent) return null;
  try {
    console.log(`[Proxy] ${label} using ${proxyUrl.replace(/\/\/.*@/, '//***@')}`);
    return new HttpsProxyAgent(proxyUrl);
  } catch (error) {
    console.warn(`[Proxy] Could not create ${label} proxy agent: ${error.message}`);
    return null;
  }
}

let outboundFetchProxy = { url: '', dispatcher: null };
function createOutboundFetchOptions(options = {}) {
  const proxyUrl = getOutboundProxyUrl();
  if (!proxyUrl || !UndiciProxyAgent) return options;
  try {
    if (outboundFetchProxy.url !== proxyUrl || !outboundFetchProxy.dispatcher) {
      outboundFetchProxy = { url: proxyUrl, dispatcher: new UndiciProxyAgent(proxyUrl) };
    }
    return { ...options, dispatcher: outboundFetchProxy.dispatcher };
  } catch (error) {
    console.warn(`[Proxy] Could not create fetch proxy dispatcher: ${error.message}`);
    return options;
  }
}

function fetchOutbound(url, options = {}) {
  return fetch(url, createOutboundFetchOptions(options));
}

function withTimeout(promise, timeoutMs, fallback) {
  let timer = null;
  const timeout = new Promise(resolve => {
    timer = setTimeout(() => resolve(typeof fallback === 'function' ? fallback() : fallback), timeoutMs);
  });
  return Promise.race([promise, timeout]).finally(() => clearTimeout(timer));
}

function parseBaileysVersion(value) {
  const parts = String(value || '')
    .split(/[,\s.]+/)
    .map(part => Number(part.trim()))
    .filter(part => Number.isFinite(part));
  return parts.length >= 3 ? parts.slice(0, 3) : null;
}

function fetchTextWithCurl(url) {
  const proxyUrl = getOutboundProxyUrl();
  const args = ['-fsSL', '--connect-timeout', '20'];
  if (proxyUrl) args.push('-x', proxyUrl);
  args.push(url);
  try {
    return execFileSync('curl.exe', args, {
      encoding: 'utf8',
      windowsHide: true,
      maxBuffer: 4 * 1024 * 1024
    });
  } catch (error) {
    return '';
  }
}

function fetchWhatsAppVersionViaProxy() {
  try {
    const sw = fetchTextWithCurl('https://web.whatsapp.com/sw.js');
    const clientRevision = sw.match(/\\"client_revision\\"\s*:\s*(\d+)/)?.[1]
      || sw.match(/"client_revision"\s*:\s*(\d+)/)?.[1]
      || sw.match(/\\"server_revision\\"\s*:\s*(\d+)/)?.[1]
      || sw.match(/"server_revision"\s*:\s*(\d+)/)?.[1]
      || sw.match(/client_revision\\?":\s*(\d+)/)?.[1]
      || sw.match(/"client_revision"\s*:\s*(\d+)/)?.[1]
      || sw.match(/client_revision[^\d]+(\d{8,})/)?.[1];
    if (clientRevision) return [2, 3000, Number(clientRevision)];
  } catch {}

  try {
    const source = fetchTextWithCurl('https://raw.githubusercontent.com/WhiskeySockets/Baileys/master/src/Defaults/index.ts');
    const match = source.match(/const\s+version\s*=\s*\[(\d+),\s*(\d+),\s*(\d+)\]/);
    if (match) return [Number(match[1]), Number(match[2]), Number(match[3])];
  } catch {}

  return null;
}

async function resolveBaileysVersion(fetchLatestBaileysVersion) {
  const envVersion = parseBaileysVersion(process.env.WA_BAILEYS_VERSION);
  if (envVersion) {
    console.log(`[Baileys] Using WA_BAILEYS_VERSION=${envVersion.join('.')}`);
    return envVersion;
  }

  const proxyVersion = fetchWhatsAppVersionViaProxy();
  if (proxyVersion) {
    console.log(`[Baileys] Using WhatsApp Web version via proxy=${proxyVersion.join('.')}`);
    return proxyVersion;
  }

  try {
    const result = await fetchLatestBaileysVersion();
    if (result?.version) {
      console.log(`[Baileys] Using bundled/latest version=${result.version.join('.')}`);
      return result.version;
    }
  } catch (e) {
    console.warn('[Baileys] Could not fetch latest WhatsApp version:', e.message);
  }

  return null;
}

