function mcpText(text) {
  return { content: [{ type: 'text', text: typeof text === 'string' ? text : JSON.stringify(text, null, 2) }] };
}

function mcpJson(value) {
  return mcpText(JSON.stringify(value, null, 2));
}

function mcpLimitRows(rows, limit = 50) {
  return Array.isArray(rows) ? rows.slice(0, Math.max(1, Math.min(Number(limit) || 50, 200))) : rows;
}

function mcpSearchText(value) {
  return JSON.stringify(value || '').toLowerCase();
}

function mcpReadJsonFile(file) {
  const safe = path.basename(file || '');
  if (!safe.endsWith('.json')) throw new Error('Only JSON data files are supported.');
  const full = path.join(dataDir, safe);
  if (!full.startsWith(dataDir)) throw new Error('Invalid data file.');
  if (!fs.existsSync(full)) return [];
  return JSON.parse(fs.readFileSync(full, 'utf8') || '[]');
}

function remoteMcpWaStatus() {
  const inst = waClients.get('default');
  return {
    ...(waLastState || {}),
    connected: !!inst?.isReady,
    status: inst?.isReady ? 'ready' : (waLastState?.status || inst?.status || 'idle'),
    message: inst?.isReady ? 'WhatsApp linked' : (waLastState?.message || inst?.statusMsg || 'Idle'),
    hasSession: hasWASession('default'),
    info: inst?.info || null
  };
}

async function callRemoteMcpTool(name, args = {}) {
  const actionsAllowed = process.env.MCP_ALLOW_ACTIONS === '1';
  switch (name) {
    case 'supersender_health':
      return mcpJson({ ok: true, app: 'SuperSender Pro', uptime: Math.round(process.uptime()), whatsapp: remoteMcpWaStatus(), db: { type: 'json', ok: true, path: dataDir } });
    case 'whatsapp_status':
      return mcpJson(remoteMcpWaStatus());
    case 'dashboard_summary':
      return mcpJson(dashboardFastSummary());
    case 'list_customers': {
      let rows = customers || [];
      if (args.search) {
        const q = String(args.search).toLowerCase();
        rows = rows.filter(row => mcpSearchText(row).includes(q));
      }
      return mcpJson(mcpLimitRows(rows, args.limit));
    }
    case 'list_orders': {
      let rows = orders || [];
      if (args.status) rows = rows.filter(row => String(row.status || '').toLowerCase() === String(args.status).toLowerCase());
      return mcpJson(mcpLimitRows(rows, args.limit));
    }
    case 'list_plans':
      return mcpJson(plans || []);
    case 'list_inbox': {
      let rows = inbox || [];
      if (args.source) rows = rows.filter(row => String(row.source || '').toLowerCase() === String(args.source).toLowerCase());
      return mcpJson(mcpLimitRows(rows, args.limit));
    }
    case 'list_social_accounts':
      return mcpJson(socialAccounts || []);
    case 'search_business_data': {
      const files = Array.isArray(args.files) && args.files.length
        ? args.files
        : ['customers.json', 'orders.json', 'inbox.json', 'alerts.json', 'social_posts.json'];
      const q = String(args.query || '').toLowerCase();
      const matches = [];
      for (const file of files) {
        const rows = mcpReadJsonFile(file);
        for (const row of (Array.isArray(rows) ? rows : [rows])) {
          if (mcpSearchText(row).includes(q)) matches.push({ file: path.basename(file), row });
          if (matches.length >= (Number(args.limit) || 50)) break;
        }
        if (matches.length >= (Number(args.limit) || 50)) break;
      }
      return mcpJson(matches);
    }
    case 'create_action_draft':
      return mcpJson(createMcpActionDraft(args, 'remote-mcp'));
    case 'list_action_drafts':
      return mcpJson(listMcpActionDrafts(args));
    case 'reject_action_draft':
      return mcpJson(rejectMcpActionDraft(args.id, args.reason || 'Rejected from MCP'));
    case 'approve_action_draft':
      if (!actionsAllowed) throw new Error('Approval execution is disabled. Set MCP_ALLOW_ACTIONS=1 or approve from the local dashboard/API.');
      return mcpJson(await executeMcpActionDraft(args.id, 'remote-mcp'));
    case 'send_whatsapp_message':
      if (!actionsAllowed) throw new Error('Action tools are disabled. Set MCP_ALLOW_ACTIONS=1 to enable sending.');
      await sendDirect(args.number, args.message);
      return mcpJson({ success: true });
    case 'publish_social_post':
      if (!actionsAllowed) throw new Error('Action tools are disabled. Set MCP_ALLOW_ACTIONS=1 to enable publishing.');
      return mcpJson(await publishSocialPayloadToPlatform(args.platform, args));
    default:
      throw new Error(`Unknown MCP tool: ${name}`);
  }
}

function sendMcpResponse(res, payload) {
  res.setHeader('Cache-Control', 'no-store');
  res.setHeader('Content-Type', 'application/json');
  res.json(payload);
}

