// Setup Uploads
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    if (!fs.existsSync('uploads')) fs.mkdirSync('uploads');
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    const safeBase = path.basename(file.originalname || 'upload').replace(/[^\w.\- ]+/g, '').slice(0, 80) || 'upload';
    cb(null, `${Date.now()}_${safeBase}`);
  }
});
const blockedUploadExts = new Set(['.exe', '.msi', '.bat', '.cmd', '.ps1', '.vbs', '.js', '.jse', '.wsf', '.scr', '.com', '.dll', '.sh', '.php', '.jar']);
const allowedUploadExts = new Set([
  '.jpg', '.jpeg', '.png', '.webp', '.gif',
  '.mp4', '.mov', '.mkv', '.webm',
  '.mp3', '.m4a', '.ogg', '.wav',
  '.pdf', '.csv', '.txt', '.md', '.json', '.vcf', '.html', '.htm',
  '.xlsx', '.xls', '.doc', '.docx', '.ppt', '.pptx'
]);
function safeUploadFileFilter(req, file, cb) {
  try {
    const ext = path.extname(file.originalname || '').toLowerCase();
    const mime = String(file.mimetype || '').toLowerCase();
    if (blockedUploadExts.has(ext)) return cb(new Error('This file type is blocked for security.'));
    if (!allowedUploadExts.has(ext)) return cb(new Error('Unsupported file type.'));
    const categoryOk =
      mime.startsWith('image/') ||
      mime.startsWith('video/') ||
      mime.startsWith('audio/') ||
      [
        'application/pdf',
        'text/csv',
        'text/plain',
        'text/markdown',
        'application/json',
        'text/html',
        'application/xhtml+xml',
        'text/vcard',
        'text/x-vcard',
        'application/vnd.ms-excel',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'application/msword',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-powerpoint',
        'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        'application/octet-stream'
      ].includes(mime);
    if (!categoryOk) return cb(new Error('Unsupported file MIME type.'));
    cb(null, true);
  } catch (error) {
    cb(error);
  }
}
const upload = multer({
  storage,
  limits: { fileSize: Number(process.env.MAX_UPLOAD_BYTES || 25 * 1024 * 1024) },
  fileFilter: safeUploadFileFilter
});
app.use('/uploads', express.static('uploads', {
  etag: true,
  lastModified: true,
  maxAge: '1d'
}));

