function boolQuery(value) {
  return ['1', 'true', 'yes', 'all'].includes(String(value || '').toLowerCase());
}

function boundedLimit(value, defaultLimit = 250, maxLimit = 1000) {
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return defaultLimit;
  return Math.min(maxLimit, Math.max(1, Math.floor(n)));
}

function sliceForApi(req, rows = [], { defaultLimit = 250, maxLimit = 1000 } = {}) {
  const list = Array.isArray(rows) ? rows : [];
  if (boolQuery(req.query?.all)) return list;
  const offset = Math.max(0, Number(req.query?.offset || 0) || 0);
  const limit = boundedLimit(req.query?.limit, defaultLimit, maxLimit);
  return list.slice(offset, offset + limit);
}

function validateEnv() {
  if (!Number.isFinite(PORT) || PORT <= 0) {
    throw new Error('Invalid PORT. Set PORT=3001 or another valid port.');
  }
  if (!['baileys', 'wwebjs'].includes(WA_ENGINE)) {
    throw new Error('Invalid WA_ENGINE. Use WA_ENGINE=baileys or WA_ENGINE=wwebjs.');
  }
  if (process.env.NODE_ENV === 'production' && (!process.env.SESSION_SECRET || process.env.SESSION_SECRET.includes('change'))) {
    console.warn('[ENV] SESSION_SECRET should be set to a strong value in production.');
  }
}
validateEnv();

function guessMimeType(filePath = '') {
  const ext = path.extname(filePath).toLowerCase();
  const types = {
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.png': 'image/png',
    '.gif': 'image/gif',
    '.webp': 'image/webp',
    '.svg': 'image/svg+xml',
    '.mp4': 'video/mp4',
    '.mov': 'video/quicktime',
    '.mp3': 'audio/mpeg',
    '.m4a': 'audio/mp4',
    '.ogg': 'audio/ogg',
    '.wav': 'audio/wav',
    '.pdf': 'application/pdf',
    '.csv': 'text/csv',
    '.txt': 'text/plain',
    '.json': 'application/json',
    '.vcf': 'text/vcard',
    '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    '.xls': 'application/vnd.ms-excel',
    '.doc': 'application/msword',
    '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    '.ppt': 'application/vnd.ms-powerpoint',
    '.pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation'
  };
  return types[ext] || 'application/octet-stream';
}

function createMediaFromFilePath(filePath, mimetype, filename) {
  if (WA_ENGINE === 'wwebjs') {
    return getWWebJS().MessageMedia.fromFilePath(filePath);
  }
  return {
    data: fs.readFileSync(filePath).toString('base64'),
    mimetype: mimetype || guessMimeType(filePath),
    filename: filename || path.basename(filePath)
  };
}

function safeMediaFilename(value = '', fallback = 'product-image.jpg') {
  try {
    const parsed = new URL(value, 'http://local.test');
    const base = path.basename(parsed.pathname || '') || fallback;
    return base.includes('.') ? base : fallback;
  } catch {
    const base = path.basename(String(value || '')) || fallback;
    return base.includes('.') ? base : fallback;
  }
}

async function createMediaFromRemoteUrl(url, timeoutMs = 12000) {
  let lastError = null;
  for (let attempt = 1; attempt <= 3; attempt += 1) {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);
    if (timer.unref) timer.unref();
    try {
      const response = await fetch(url, {
        signal: controller.signal,
        headers: { 'User-Agent': 'SuperSender-Pro/1.0' }
      });
      if (!response.ok) throw new Error(`Image download failed (${response.status})`);
      const mimetype = (response.headers.get('content-type') || guessMimeType(url)).split(';')[0].trim() || 'image/jpeg';
      if (!mimetype.startsWith('image/')) throw new Error('Product media URL is not an image');
      const buffer = Buffer.from(await response.arrayBuffer());
      if (!buffer.length) throw new Error('Product image is empty');
      const data = buffer.toString('base64');
      const filename = safeMediaFilename(url, 'product-image.jpg');
      if (WA_ENGINE === 'wwebjs') {
        const { MessageMedia } = getWWebJS();
        return new MessageMedia(mimetype, data, filename);
      }
      return { data, mimetype, filename };
    } catch (e) {
      lastError = e;
      if (attempt < 3) await sleep(350 * attempt);
    } finally {
      clearTimeout(timer);
    }
  }
  throw lastError || new Error('Image download failed');
}

async function createMediaFromSource(source = '') {
  const value = String(source || '').trim();
  if (!value) throw new Error('Product image is missing');
  if (/^https?:\/\//i.test(value)) return createMediaFromRemoteUrl(value);
  if (value.startsWith('/uploads/')) {
    const filePath = path.join(__dirname, value.replace(/^\/+/, ''));
    if (!fs.existsSync(filePath)) throw new Error('Product image file was not found');
    return createMediaFromFilePath(filePath);
  }
  if (value.startsWith('/assets/')) {
    const filePath = path.join(__dirname, 'public', value.replace(/^\/+/, ''));
    if (!fs.existsSync(filePath)) throw new Error('Media asset file was not found');
    return createMediaFromFilePath(filePath);
  }
  if (!value.startsWith('/') && !value.includes('://')) {
    const filePath = path.join(__dirname, value);
    if (fs.existsSync(filePath)) return createMediaFromFilePath(filePath);
  }
  if (path.isAbsolute(value) && fs.existsSync(value)) return createMediaFromFilePath(value);
  throw new Error('Product image URL is invalid');
}

function sanitizeVCardField(value = '') {
  return String(value || '').replace(/[\r\n]+/g, ' ').trim();
}

function buildVCardText(payload = {}) {
  const firstName = sanitizeVCardField(payload.firstName || payload.name || 'Contact');
  const lastName = sanitizeVCardField(payload.lastName || '');
  const fullName = sanitizeVCardField(payload.fullName || [firstName, lastName].filter(Boolean).join(' ') || 'Contact');
  const org = sanitizeVCardField(payload.org || payload.company || settings.business_name || '');
  const title = sanitizeVCardField(payload.title || payload.role || '');
  const email = sanitizeVCardField(payload.email || '');
  const url = sanitizeVCardField(payload.url || '');
  const note = sanitizeVCardField(payload.note || '');
  const number = normalizeSafetyNumber(payload.contactNumber || payload.phone || payload.number || '');
  const lines = [
    'BEGIN:VCARD',
    'VERSION:3.0',
    `N:${lastName};${firstName};;;`,
    `FN:${fullName}`
  ];
  if (org) lines.push(`ORG:${org}`);
  if (title) lines.push(`TITLE:${title}`);
  if (number) lines.push(`TEL;TYPE=CELL:+${number}`);
  if (email) lines.push(`EMAIL;TYPE=INTERNET:${email}`);
  if (url) lines.push(`URL:${url}`);
  if (note) lines.push(`NOTE:${note}`);
  lines.push('END:VCARD');
  return lines.join('\n');
}

function normalizeOptInStatus(contact = {}) {
  return contact?.optIn === true
    || contact?.marketingOptIn === true
    || contact?.consent === true
    || contact?.whatsappOptIn === true;
}

function buildOptInSummary() {
  const customerRows = Array.isArray(customers) ? customers : [];
  const contactRows = Array.isArray(waContacts) ? waContacts : [];
  const all = [...customerRows, ...contactRows];
  const unique = new Map();
  for (const row of all) {
    const number = normalizeSafetyNumber(row?.number || row?.phone || row?.whatsapp || row?.id || '');
    if (!number) continue;
    const existing = unique.get(number) || {};
    unique.set(number, {
      number,
      name: row?.name || row?.customerName || existing.name || '',
      optIn: normalizeOptInStatus(row) || normalizeOptInStatus(existing),
      source: row?.source || existing.source || ''
    });
  }
  const rows = [...unique.values()];
  const optedIn = rows.filter(item => item.optIn);
  const withoutOptIn = rows.filter(item => !item.optIn);
  return {
    explicitOptInRequired: settings.explicit_opt_in_required === true || safetySettings.requireOptIn === true,
    totalContacts: rows.length,
    optedIn: optedIn.length,
    missingOptIn: withoutOptIn.length,
    coveragePct: rows.length ? Math.round((optedIn.length / rows.length) * 100) : 0,
    examplesMissing: withoutOptIn.slice(0, 10)
  };
}

function extractProductListingMeta(input = '', rawHtml = '') {
  const text = String(input || '').replace(/\s+/g, ' ').trim();
  const lower = text.toLowerCase();
  const titleMatch =
    text.match(/\b(chatgpt|claude|midjourney|cursor|gemini|meta ai|woocommerce|kimi)\b[^|,\n]*/i)
    || text.match(/\b(title|product|item)\s*[:=-]\s*([^\n|,]+)/i);
  const priceMatch =
    text.match(/\b(?:rs\.?|pkr|price)\s*[:=-]?\s*(\d{2,6}(?:[.,]\d{1,2})?)/i)
    || text.match(/\b(\d{3,6})\b/);
  const moqMatch =
    text.match(/\b(?:moq|min(?:imum)?\s+order)\s*[:=-]?\s*(\d+)/i)
    || text.match(/\b(\d+)\s*(?:pcs|pieces|accounts|slots)\s+min\b/i);
  const imageMatch =
    rawHtml.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i)
    || rawHtml.match(/<img[^>]+src=["']([^"']+)["']/i)
    || text.match(/https?:\/\/\S+\.(?:png|jpe?g|webp|gif)/i);
  const title = titleMatch
    ? sanitizeVCardField(titleMatch[2] || titleMatch[0])
    : sanitizeVCardField(text.split(/[|\n]/)[0] || '');
  const price = priceMatch ? Number(String(priceMatch[1]).replace(/,/g, '')) : 0;
  const moq = moqMatch ? Number(moqMatch[1]) : 0;
  const category = /\b(chatgpt|claude|midjourney|cursor|gemini|meta ai|kimi)\b/i.test(lower) ? 'ai_tools' : 'general';
  return {
    title,
    price,
    moq,
    image: imageMatch ? String(imageMatch[1] || imageMatch[0]).trim() : '',
    category,
    sourceText: text.slice(0, 2000)
  };
}

function normalizeIdentityEmail(value = '') {
  return String(value || '').trim().toLowerCase();
}

function findCustomerByAnyIdentifier(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const cleanNumber = normalizeNumber(raw);
  const email = normalizeIdentityEmail(raw);
  return (Array.isArray(customers) ? customers : []).find(customer => {
    if (String(customer.id || '') === raw) return true;
    if (String(customer.unifiedUserId || '') === raw) return true;
    if (cleanNumber && normalizeNumber(customer.number || customer.phone || customer.whatsapp || '') === cleanNumber) return true;
    if (email && email.includes('@') && normalizeIdentityEmail(customer.email || '') === email) return true;
    if (raw && customer.pushToken && String(customer.pushToken) === raw) return true;
    return false;
  }) || null;
}

function latestInboundTimestamp(number = '') {
  const normalized = normalizeNumber(number);
  if (!normalized || !waConversations || typeof waConversations !== 'object') return 0;
  const candidates = [
    waConversations[normalized],
    waConversations[`${normalized}@c.us`]
  ].filter(Boolean);
  for (const [key, conv] of Object.entries(waConversations)) {
    if (key === normalized || key === `${normalized}@c.us`) continue;
    const keyDigits = String(key || '').replace(/\D/g, '');
    if (keyDigits && keyDigits === normalized.replace(/\D/g, '')) candidates.push(conv);
  }
  let latest = 0;
  for (const conv of candidates) {
    for (const item of (conv?.history || [])) {
      if (item?.role !== 'user') continue;
      const ts = Date.parse(item?.time || item?.createdAt || 0);
      if (ts > latest) latest = ts;
    }
  }
  return latest;
}

function isWithinOpenServiceWindow(number = '', hours = Number(settings.utility_window_hours || 24)) {
  const latest = latestInboundTimestamp(number);
  if (!latest) return false;
  return latest >= (Date.now() - (Math.max(1, Number(hours || 24)) * 60 * 60 * 1000));
}

function countJourneyEvents(type = '', number = '', days = 7) {
  const normalized = normalizeNumber(number);
  const cutoff = Date.now() - (Math.max(1, Number(days || 7)) * 24 * 60 * 60 * 1000);
  return (journeyEvents || []).filter(item => {
    const time = Date.parse(item.createdAt || 0);
    return (!type || item.type === type) &&
      (!normalized || normalizeNumber(item.number || '') === normalized) &&
      time >= cutoff;
  }).length;
}

function upsertUnifiedIdentity(input = {}) {
  const number = normalizeNumber(input.number || input.phone || input.whatsapp || '');
  const email = normalizeIdentityEmail(input.email || '');
  const pushToken = String(input.pushToken || '').trim();
  let customer =
    findCustomerByAnyIdentifier(number || email || pushToken || input.unifiedUserId || '') ||
    (number ? ensureGuestCustomer(number, input.name || input.fullName || '', input.source || 'marketing') : null);

  if (!customer) {
    customer = {
      id: uuid(),
      created: new Date().toISOString(),
      status: 'lead',
      tags: []
    };
    customers.unshift(customer);
  }

  if (number) {
    customer.number = number;
    customer.phone = number;
  }
  if (input.name || input.fullName) customer.name = String(input.name || input.fullName).trim();
  if (email) customer.email = email;
  if (pushToken) customer.pushToken = pushToken;
  customer.unifiedUserId = String(customer.unifiedUserId || input.unifiedUserId || `uid_${String(customer.id || uuid()).replace(/-/g, '').slice(0, 12)}`);
  if (input.source) customer.source = String(input.source).trim();
  if (input.sourceTag) customer.sourceTag = String(input.sourceTag).trim();
  if (input.utmSource) customer.utmSource = String(input.utmSource).trim();
  if (input.utmMedium) customer.utmMedium = String(input.utmMedium).trim();
  if (input.utmCampaign) customer.utmCampaign = String(input.utmCampaign).trim();
  if (input.referral) customer.referral = String(input.referral).trim();
  if (input.channel) {
    customer.channels = Array.from(new Set([...(Array.isArray(customer.channels) ? customer.channels : []), String(input.channel).trim()]));
  }
  if (input.marketingOptIn === true || input.optIn === true || input.consent === true) {
    customer.optIn = true;
    customer.consent = true;
    customer.marketingOptIn = input.marketingOptIn !== false;
    customer.consentAt = input.consentAt || new Date().toISOString();
    customer.consentSource = String(input.consentSource || input.source || customer.consentSource || 'manual').trim();
    customer.consentChannel = String(input.channel || customer.consentChannel || 'whatsapp').trim();
  }
  customer.lastSeen = new Date().toISOString();
  if (!customer.created) customer.created = customer.lastSeen;
  saveJSON('customers.json', customers);
  return customer;
}

function logJourneyEvent(type, payload = {}, stage = '') {
  const event = {
    id: uuid(),
    type,
    stage: stage || '',
    number: normalizeNumber(payload.number || payload.phone || ''),
    customerId: payload.customerId || null,
    customerName: payload.customerName || payload.name || '',
    channel: payload.channel || 'whatsapp',
    meta: payload.meta || {},
    createdAt: payload.createdAt || new Date().toISOString()
  };
  journeyEvents.unshift(event);
  if (journeyEvents.length > 10000) journeyEvents = journeyEvents.slice(0, 10000);
  saveJourneyEvents();
  return event;
}

function getJourneyStageForCustomer(customer = {}) {
  const number = normalizeNumber(customer.number || customer.phone || '');
  const orderCount = (orders || []).filter(item => normalizeNumber(item.number || item.customerNumber || '') === number).length;
  const appointmentCount = (appointments || []).filter(item => normalizeNumber(item.phone || item.number || '') === number).length;
  const leadScore = Number(customer.leadScore || 0);
  const tags = (customer.tags || []).map(item => String(item).toLowerCase());
  if (orderCount > 1 || tags.includes('vip') || String(customer.status || '').toLowerCase() === 'active') return 'retention';
  if (orderCount >= 1) return 'purchase';
  if (leadScore >= 60 || tags.includes('hot lead') || appointmentCount > 0) return 'consideration';
  return 'awareness';
}

function buildUnifiedIdentityProfile(value = '') {
  const customer = findCustomerByAnyIdentifier(value);
  if (!customer) return null;
  const number = normalizeNumber(customer.number || customer.phone || '');
  const timeline = [];
  (journeyEvents || []).filter(item => item.customerId === customer.id || (number && normalizeNumber(item.number || '') === number)).forEach(item => {
    timeline.push({ type: item.type, time: item.createdAt, label: item.stage || item.type, data: item });
  });
  (orders || []).filter(item => normalizeNumber(item.number || item.customerNumber || '') === number).forEach(item => {
    timeline.push({ type: 'order', time: item.created || item.date || item.createdAt, label: `Order ${item.id || item.orderId || ''}`, data: item });
  });
  (appointments || []).filter(item => normalizeNumber(item.phone || item.number || '') === number).forEach(item => {
    timeline.push({ type: 'appointment', time: item.createdAt || item.scheduleAt, label: `Appointment ${item.service || ''}`.trim(), data: item });
  });
  (hotClickLeads || []).filter(item => normalizeNumber(item.customerNumber || '') === number).forEach(item => {
    timeline.push({ type: 'hot_click', time: item.lastClickedAt || item.createdAt, label: `Hot click ${item.linkLabel || ''}`.trim(), data: item });
  });
  timeline.sort((a, b) => Date.parse(b.time || 0) - Date.parse(a.time || 0));
  return {
    customer,
    identity: {
      unifiedUserId: customer.unifiedUserId || '',
      whatsapp: number || '',
      email: customer.email || '',
      pushToken: customer.pushToken || '',
      channels: customer.channels || ['whatsapp']
    },
    consent: {
      optIn: normalizeOptInStatus(customer),
      marketingOptIn: customer.marketingOptIn === true,
      consentAt: customer.consentAt || null,
      consentSource: customer.consentSource || '',
      consentChannel: customer.consentChannel || ''
    },
    acquisition: {
      source: customer.source || '',
      sourceTag: customer.sourceTag || '',
      utmSource: customer.utmSource || '',
      utmMedium: customer.utmMedium || '',
      utmCampaign: customer.utmCampaign || '',
      referral: customer.referral || ''
    },
    stage: getJourneyStageForCustomer(customer),
    timeline: timeline.slice(0, 120)
  };
}

function computeMarketingReachReport(days = 30) {
  const safeDays = Math.max(1, Number(days || 30));
  const cutoff = Date.now() - (safeDays * 24 * 60 * 60 * 1000);
  const rows = (campaigns || [])
    .filter(item => Date.parse(item.created || 0) >= cutoff)
    .map(item => {
      const sent = Number(item.sent || 0);
      const failed = Number(item.failed || 0);
      const total = Math.max(sent + failed, Number(item.total || 0), 1);
      const deliveryRate = Math.max(0, Math.min(100, Math.round((sent / total) * 100)));
      const linksForCampaign = (trackedLinks || []).filter(link => String(link.campaign || '').trim() && [item.id, item.name].includes(String(link.campaign || '').trim()));
      const linkIds = new Set(linksForCampaign.map(link => link.id));
      const clicks = (linkClicks || []).filter(click => linkIds.has(click.linkId)).length;
      const hot = (hotClickLeads || []).filter(lead => String(lead.campaign || '').trim() === String(item.id || item.name || '').trim()).length;
      const clickRate = sent ? Math.round((clicks / sent) * 100) : 0;
      const qualityScore = Math.max(0, Math.min(100, Math.round((deliveryRate * 0.55) + (Math.min(clickRate, 100) * 0.25) + (Math.min(hot * 10, 100) * 0.20))));
      const tier = qualityScore >= 80 ? 'strong' : qualityScore >= 60 ? 'good' : qualityScore >= 40 ? 'watch' : 'throttle';
      return {
        id: item.id,
        name: item.name || 'Campaign',
        created: item.created || '',
        sent,
        failed,
        total,
        clicks,
        hotLeads: hot,
        deliveryRate,
        clickRate,
        qualityScore,
        tier,
        recommendation: tier === 'strong'
          ? 'Performance strong hai. Scale gradually.'
          : tier === 'good'
            ? 'Healthy reach. CTA aur segmentation ko optimize rakhein.'
            : tier === 'watch'
              ? 'Engagement signals improve karein warna reach slow ho sakti hai.'
              : 'Frequency kam karein aur audience ko tighten karein.'
      };
    })
    .sort((a, b) => (b.qualityScore || 0) - (a.qualityScore || 0));
  const sentTotal = rows.reduce((sum, item) => sum + Number(item.sent || 0), 0);
  const clickTotal = rows.reduce((sum, item) => sum + Number(item.clicks || 0), 0);
  return {
    summary: {
      days: safeDays,
      campaigns: rows.length,
      sentTotal,
      clickTotal,
      avgQualityScore: rows.length ? Math.round(rows.reduce((sum, item) => sum + Number(item.qualityScore || 0), 0) / rows.length) : 0,
      topTierCount: rows.filter(item => item.tier === 'strong').length,
      mode: settings.performance_reach_mode || 'engagement'
    },
    campaigns: rows.slice(0, 25)
  };
}

function computeJourneyMap(days = 30) {
  const safeDays = Math.max(1, Number(days || 30));
  const cutoff = Date.now() - (safeDays * 24 * 60 * 60 * 1000);
  const recentCustomers = (customers || []).filter(item => Date.parse(item.created || item.lastSeen || 0) >= cutoff || Date.parse(item.lastSeen || 0) >= cutoff);
  const summary = { awareness: 0, consideration: 0, purchase: 0, retention: 0 };
  recentCustomers.forEach(customer => {
    summary[getJourneyStageForCustomer(customer)] += 1;
  });
  return {
    summary: {
      days: safeDays,
      ...summary,
      total: recentCustomers.length,
      openServiceWindow: recentCustomers.filter(customer => isWithinOpenServiceWindow(customer.number || customer.phone || '', settings.utility_window_hours || 24)).length
    },
    recommendations: [
      'Awareness leads ke liye welcome + value drip sequence use karein.',
      'Consideration stage par CTA ko booking ya demo ki taraf move karein.',
      'Purchase stage ko 24-hour utility window follow-ups ke saath convert karein.',
      'Retention stage ke liye renewal aur loyalty nudges schedule karein.'
    ],
    recentEvents: (journeyEvents || []).filter(item => Date.parse(item.createdAt || 0) >= cutoff).slice(0, 30)
  };
}

const loadJSON = (file, defaultData) => {
  try { return JSON.parse(fs.readFileSync(path.join(dataDir, file), 'utf8')); }
  catch (e) { return defaultData; }
};
const pendingJSONSaves = new Map();

const JSON_FILE_LIMITS = {
  'logs.json': { limit: Number(process.env.LOGS_MAX_ROWS || 5000), keep: 'tail' },
  'inbox.json': { limit: Number(process.env.INBOX_MAX_ROWS || 2000), keep: 'head' },
  'webhook_logs.json': { limit: Number(process.env.WEBHOOK_LOGS_MAX_ROWS || 1500), keep: 'tail' },
  'alerts.json': { limit: Number(process.env.ALERTS_MAX_ROWS || 1500), keep: 'head' },
  'channel_relay_inbox.json': { limit: Number(process.env.CHANNEL_RELAY_MAX_ROWS || 500), keep: 'head' },
  'whatsapp_channel_posts.json': { limit: Number(process.env.CHANNEL_POSTS_MAX_ROWS || 500), keep: 'tail' },
  'whatsapp_cloud_api_log.json': { limit: Number(process.env.WHATSAPP_CLOUD_API_LOG_MAX_ROWS || 1000), keep: 'tail' },
  'group_reply_log.json': { limit: Number(process.env.GROUP_REPLY_LOG_MAX_ROWS || 1000), keep: 'tail' },
  'send_safety_log.json': { limit: Number(process.env.SEND_SAFETY_LOG_MAX_ROWS || 5000), keep: 'tail' }
};

function trimArrayInPlace(rows, limit, keep = 'tail') {
  if (!Array.isArray(rows) || rows.length <= limit) return rows;
  if (keep === 'head') rows.splice(limit);
  else rows.splice(0, rows.length - limit);
  return rows;
}

function compactJsonPayload(file, data) {
  const rule = JSON_FILE_LIMITS[file];
  if (rule && Array.isArray(data)) return trimArrayInPlace(data, rule.limit, rule.keep);
  if (file === 'automation_autopilot.json' && data && typeof data === 'object') {
    if (Array.isArray(data.runs)) {
      trimArrayInPlace(data.runs, Number(process.env.AUTOPILOT_MAX_RUNS || 80), 'tail');
      data.runs = data.runs.map(run => ({
        ...run,
        summary: run.summary ? {
          enabled: run.summary.enabled,
          channelEnabled: run.summary.channelEnabled,
          adminAlerts: run.summary.adminAlerts,
          whatsappReady: run.summary.whatsappReady,
          channelsConfigured: run.summary.channelsConfigured,
          sellerRates: run.summary.sellerRates,
          availablePlans: run.summary.availablePlans,
          unavailablePlans: run.summary.unavailablePlans
        } : undefined
      }));
    }
  }
  return data;
}

function stringifyJsonPayload(data) {
  const spaces = process.env.JSON_PRETTY === '1' ? 2 : 0;
  return JSON.stringify(data, null, spaces);
}

let saveJSON = (file, data) => {
  const delay = Math.max(25, Number(process.env.JSON_SAVE_DEBOUNCE_MS || 150));
  const existing = pendingJSONSaves.get(file);
  if (existing?.timer) clearTimeout(existing.timer);
  const timer = setTimeout(() => flushJSONSave(file), delay);
  if (timer.unref) timer.unref();
  pendingJSONSaves.set(file, { data: compactJsonPayload(file, data), timer });
};

function flushJSONSave(file) {
  const entry = pendingJSONSaves.get(file);
  if (!entry) return;
  pendingJSONSaves.delete(file);
  try {
    fs.writeFile(path.join(dataDir, file), stringifyJsonPayload(compactJsonPayload(file, entry.data)), 'utf8', (err) => {
      if (err) console.error('SaveJSON Error:', file, err);
    });
  } catch (err) {
    console.error('SaveJSON Error:', file, err);
  }
}

function flushAllJSONSavesSync() {
  for (const [file, entry] of pendingJSONSaves.entries()) {
    try {
      if (entry.timer) clearTimeout(entry.timer);
      fs.writeFileSync(path.join(dataDir, file), stringifyJsonPayload(compactJsonPayload(file, entry.data)), 'utf8');
    } catch (err) {
      console.error('SaveJSON Flush Error:', file, err);
    }
  }
  pendingJSONSaves.clear();
}

process.on('beforeExit', flushAllJSONSavesSync);
process.on('SIGINT', () => { flushAllJSONSavesSync(); process.exit(0); });
process.on('SIGTERM', () => { flushAllJSONSavesSync(); process.exit(0); });

