let fileLibrary = loadJSON('file_library.json', []);
if (!Array.isArray(fileLibrary)) fileLibrary = [];
const saveFileLibrary = () => saveJSON('file_library.json', fileLibrary);

function fileLibrarySlug(value = '') {
  return String(value || 'file')
    .toLowerCase()
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'file';
}

function fileLibraryContent(section = {}, title = '', index = 1) {
  const label = section.label || section.id || 'Files';
  return [
    `# ${label} - ${title}`,
    '',
    `Section: ${label}`,
    `File No: ${index}`,
    `Created for: SuperSender Pro automation library`,
    '',
    '## Use',
    '- WhatsApp quick reply',
    '- Broadcast caption',
    '- Social media post draft',
    '- Admin reference',
    '',
    '## Draft',
    `${label} ke liye ready-to-edit content. Is file ko customize karke WhatsApp, channel, social post, ya customer reply mein use karein.`,
    '',
    '## CTA',
    'Reply karein for details / DM for order / Admin se confirm karein.'
  ].join('\n');
}

function ensureFileLibrarySeed() {
  const root = path.join(__dirname, 'public', 'file-library');
  try { fs.mkdirSync(root, { recursive: true }); } catch {}
  let changed = false;
  const now = new Date().toISOString();
  for (const section of FILE_LIBRARY_SECTIONS) {
    const sectionDir = path.join(root, section.id);
    try { fs.mkdirSync(sectionDir, { recursive: true }); } catch {}
    const existingCount = fileLibrary.filter(row => row.sectionId === section.id).length;
    for (let i = existingCount; i < 10; i += 1) {
      const title = FILE_LIBRARY_SAMPLE_TITLES[i] || `File ${i + 1}`;
      const filename = `${String(i + 1).padStart(2, '0')}-${fileLibrarySlug(title)}.md`;
      const absolutePath = path.join(sectionDir, filename);
      const url = `/file-library/${section.id}/${filename}`;
      if (!fs.existsSync(absolutePath)) {
        try { fs.writeFileSync(absolutePath, fileLibraryContent(section, title, i + 1), 'utf8'); } catch {}
      }
      fileLibrary.push({
        id: uuid(),
        sectionId: section.id,
        sectionLabel: section.label,
        title,
        filename,
        url,
        mimeType: 'text/markdown',
        type: 'starter',
        tags: [section.id, 'starter', 'automation'],
        size: fs.existsSync(absolutePath) ? fs.statSync(absolutePath).size : 0,
        createdAt: now,
        updatedAt: now
      });
      changed = true;
    }
  }
  if (changed) saveFileLibrary();
  return { sections: FILE_LIBRARY_SECTIONS.length, files: fileLibrary.length };
}

function fileLibrarySummary() {
  const bySection = FILE_LIBRARY_SECTIONS.map(section => {
    const files = fileLibrary.filter(row => row.sectionId === section.id);
    return { ...section, files: files.length, latest: files.slice(-3) };
  });
  return { total: fileLibrary.length, sections: bySection };
}

ensureFileLibrarySeed();

