function ensureDefaultAccessoryProducts() {
  let changed = false;
  for (const product of [...DEFAULT_ACCESSORY_PRODUCTS, ...DEFAULT_RETAIL_PRODUCTS]) {
    const existing = laptopProducts.find(p => String(p.id) === product.id || normalizeBotSearchText(p.name) === normalizeBotSearchText(product.name));
    if (existing) {
      if (String(existing.image || '').endsWith('.svg')) {
        existing.image = product.image;
        existing.updated = new Date().toISOString();
        changed = true;
      }
    } else {
      laptopProducts.push({ ...product, created: new Date().toISOString(), source: 'starter-accessory-stock' });
      changed = true;
    }
  }
  if (changed) saveJSON('laptop_products.json', laptopProducts);
}
ensureDefaultAccessoryProducts();
// API keys for external automation (MCP-style simple REST). Stored as plaintext for simplicity.
let apiKeys = loadJSON('api_keys.json', []);
const saveApiKeys = () => saveJSON('api_keys.json', apiKeys);
function makeApiKey() {
  return 'ssk_' + cryptoRandomHex(24);
}
function cryptoRandomHex(bytes) {
  try {
    const crypto = require('crypto');
    return crypto.randomBytes(bytes).toString('hex');
  } catch {
    // fallback
    return (Date.now().toString(16) + Math.random().toString(16).slice(2)).padEnd(bytes * 2, '0').slice(0, bytes * 2);
  }
}

function normalizeMcpActionType(type = '') {
  const normalized = String(type || '').trim().toLowerCase().replace(/[-\s]+/g, '_');
  const aliases = {
    whatsapp: 'whatsapp_message',
    whatsapp_send: 'whatsapp_message',
    wa: 'whatsapp_message',
    wa_message: 'whatsapp_message',
    social: 'social_post',
    post: 'social_post',
    campaign: 'broadcast'
  };
  return aliases[normalized] || normalized;
}

function validateMcpActionPayload(type, payload = {}) {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) throw new Error('payload must be an object');
  if (type === 'whatsapp_message') {
    if (!String(payload.number || '').trim()) throw new Error('payload.number is required for WhatsApp drafts');
    if (!String(payload.message || '').trim()) throw new Error('payload.message is required for WhatsApp drafts');
  } else if (type === 'broadcast') {
    if (!String(payload.message || '').trim()) throw new Error('payload.message is required for broadcast drafts');
    if (payload.targets !== undefined && !Array.isArray(payload.targets)) throw new Error('payload.targets must be an array when provided');
  } else if (type === 'social_post') {
    if (!String(payload.platform || '').trim()) throw new Error('payload.platform is required for social post drafts');
    if (!String(payload.message || '').trim() && !String(payload.imageUrl || '').trim() && !String(payload.videoUrl || '').trim()) {
      throw new Error('social post drafts need message, imageUrl, or videoUrl');
    }
  } else {
    throw new Error('Unsupported action type. Use whatsapp_message, broadcast, or social_post.');
  }
}

function publicMcpActionDraft(draft) {
  if (!draft) return null;
  return {
    id: draft.id,
    type: draft.type,
    title: draft.title,
    status: draft.status,
    payload: draft.payload,
    source: draft.source,
    createdAt: draft.createdAt,
    updatedAt: draft.updatedAt,
    approvedAt: draft.approvedAt || null,
    executedAt: draft.executedAt || null,
    rejectedAt: draft.rejectedAt || null,
    result: draft.result || null,
    error: draft.error || null,
    reviewNote: draft.reviewNote || ''
  };
}

function createMcpActionDraft(input = {}, source = 'api') {
  const type = normalizeMcpActionType(input.type);
  const payload = input.payload || {};
  validateMcpActionPayload(type, payload);
  const draft = {
    id: uuid(),
    type,
    title: String(input.title || `${type.replace(/_/g, ' ')} draft`).trim().slice(0, 140),
    payload,
    status: 'pending',
    source,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    reviewNote: ''
  };
  mcpActionDrafts.unshift(draft);
  saveMcpActionDrafts();
  try { io.emit('mcp-action-draft', publicMcpActionDraft(draft)); } catch {}
  return publicMcpActionDraft(draft);
}

function listMcpActionDrafts(filters = {}) {
  let rows = [...mcpActionDrafts];
  const status = String(filters.status || 'pending').toLowerCase();
  if (status && status !== 'all') rows = rows.filter(item => String(item.status || '').toLowerCase() === status);
  if (filters.type) {
    const type = normalizeMcpActionType(filters.type);
    rows = rows.filter(item => item.type === type);
  }
  const limit = Math.max(1, Math.min(Number(filters.limit) || 50, 200));
  return rows.slice(0, limit).map(publicMcpActionDraft);
}

function findMcpActionDraft(id) {
  return mcpActionDrafts.find(item => item.id === id);
}

function rejectMcpActionDraft(id, reason = '') {
  const draft = findMcpActionDraft(id);
  if (!draft) throw new Error('Action draft not found');
  if (!['pending', 'approved'].includes(draft.status)) throw new Error(`Cannot reject a ${draft.status} draft`);
  draft.status = 'rejected';
  draft.rejectedAt = new Date().toISOString();
  draft.updatedAt = draft.rejectedAt;
  draft.reviewNote = String(reason || 'Rejected').slice(0, 500);
  saveMcpActionDrafts();
  try { io.emit('mcp-action-draft', publicMcpActionDraft(draft)); } catch {}
  return publicMcpActionDraft(draft);
}

async function executeMcpActionDraft(id, actor = 'api') {
  const draft = findMcpActionDraft(id);
  if (!draft) throw new Error('Action draft not found');
  if (!['pending', 'approved'].includes(draft.status)) throw new Error(`Cannot execute a ${draft.status} draft`);
  draft.status = 'approved';
  draft.approvedAt = draft.approvedAt || new Date().toISOString();
  draft.updatedAt = new Date().toISOString();
  draft.approvedBy = actor;
  saveMcpActionDrafts();

  try {
    let result;
    const payload = draft.payload || {};
    if (draft.type === 'whatsapp_message') {
      result = await sendDirect(payload.number, payload.message, payload.options || {});
    } else if (draft.type === 'broadcast') {
      const targets = Array.isArray(payload.targets) ? payload.targets.filter(Boolean) : [];
      if (!targets.length) throw new Error('Broadcast draft needs payload.targets to execute safely');
      const sent = [];
      const failed = [];
      for (const target of targets) {
        try {
          await sendDirect(target, payload.message, payload.options || {});
          sent.push(target);
        } catch (error) {
          failed.push({ target, error: error.message });
        }
        await sleep(Number(payload.delayMs || 2000));
      }
      result = { sent: sent.length, failed: failed.length, sentTargets: sent, failures: failed };
    } else if (draft.type === 'social_post') {
      result = await publishSocialPayloadToPlatform(payload.platform, payload);
    } else {
      throw new Error('Unsupported action type');
    }
    draft.status = 'executed';
    draft.executedAt = new Date().toISOString();
    draft.updatedAt = draft.executedAt;
    draft.result = result || { success: true };
    draft.error = null;
    saveMcpActionDrafts();
    try { io.emit('mcp-action-draft', publicMcpActionDraft(draft)); } catch {}
    return publicMcpActionDraft(draft);
  } catch (error) {
    draft.status = 'failed';
    draft.error = error.message || 'Execution failed';
    draft.updatedAt = new Date().toISOString();
    saveMcpActionDrafts();
    try { io.emit('mcp-action-draft', publicMcpActionDraft(draft)); } catch {}
    throw error;
  }
}

