app.post('/api/mcp/action-drafts/:id/approve', async (req, res) => {
  try {
    if (process.env.MCP_ALLOW_ACTIONS !== '1') {
      return res.status(403).json({ success: false, error: 'Action execution disabled. Set MCP_ALLOW_ACTIONS=1 and restart to approve/send drafts.' });
    }
    res.json({ success: true, draft: await executeMcpActionDraft(req.params.id, 'api') });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

let codeIntelligenceReports = loadJSON('code_intelligence_reports.json', []);
if (!Array.isArray(codeIntelligenceReports)) codeIntelligenceReports = [];
const saveCodeIntelligenceReports = () => saveJSON('code_intelligence_reports.json', codeIntelligenceReports.slice(0, 50));

const CODE_INTEL_ALLOWED_EXTENSIONS = new Set(['.js', '.ts', '.tsx', '.jsx', '.py', '.json', '.md', '.html', '.css', '.ps1']);
const CODE_INTEL_SKIP_DIRS = new Set([
  '.git', 'node_modules', '.venv', 'venv', 'env', 'dist', 'build', '.next', '__pycache__',
  '.wa-auth', '.baileys-auth', '.wwebjs_cache', 'uploads', 'logs', 'backups', '_backups',
  '_zip_stage_full_with_git_20260518_074334', '_zip_stage_myai', '_release'
]);
const CODE_INTEL_SECRET_FILE_RE = /(^|[\\/])(\.env|.*token.*|.*secret.*|.*credential.*|.*auth.*|.*key.*)(\.[^\\/]*)?$/i;

const CODE_INTEL_FEATURES = [
  { id: 'remote-control', label: 'Remote Control API', keywords: ['remote', 'command server', 'flask', 'token-protected', '/command', 'remote_token'], score: 10, why: 'WhatsApp/admin se system ko remote control karne ke liye useful.' },
  { id: 'browser-automation', label: 'Browser Automation Agent', keywords: ['browser_extension', 'content.js', 'popup.js', 'click', 'type', 'aria', 'chrome'], score: 9, why: 'Social/OAuth/dashboard automation ko browser se control karne mein help karta hai.' },
  { id: 'voice-ocr', label: 'Voice + OCR Assistant', keywords: ['ocr', 'tesseract', 'voice', 'speech', 'screen capture', 'screenshot'], score: 8, why: 'Admin ko screen aur voice based automation assistant de sakta hai.' },
  { id: 'social-harvest', label: 'Social Harvest Pipeline', keywords: ['facebook', 'instagram', 'linkedin', 'tiktok', 'social', 'post', 'oauth'], score: 9, why: 'Social hub ko stronger posting/harvesting workflow de sakta hai.' },
  { id: 'web-scraper', label: 'Website/Data Scraper', keywords: ['scrape', 'cheerio', 'fetchWebsite', 'crawler', 'rss', 'selector'], score: 8, why: 'Scholarship, rates, products aur competitor data auto-collect karne ke liye useful.' },
  { id: 'mcp-connector', label: 'MCP / Connector Layer', keywords: ['mcp', 'connector', 'tool', 'jsonrpc', 'server-sent', 'model context'], score: 7, why: 'Claude/Codex/custom tools se project ko control karne ke liye useful.' },
  { id: 'queue-automation', label: 'Queue / Scheduler Automation', keywords: ['queue', 'cron', 'bull', 'scheduler', 'job', 'retry'], score: 7, why: 'Channel forwarding, follow-ups aur payment scans ko reliable banata hai.' },
  { id: 'media-pipeline', label: 'Media Pipeline', keywords: ['image', 'video', 'caption', 'compress', 'watermark', 'ffmpeg'], score: 8, why: 'Channels/social posts ke media automation ke liye useful.' }
];

function codeIntelWorkspaceRoot(inputRoot = '') {
  const fallback = path.resolve(__dirname, '..');
  const raw = String(inputRoot || fallback).trim();
  const resolved = path.resolve(raw);
  const allowedRoot = path.resolve(__dirname, '..');
  if (!resolved.toLowerCase().startsWith(allowedRoot.toLowerCase())) return allowedRoot;
  return resolved;
}

function codeIntelShouldSkip(filePath = '') {
  const base = path.basename(filePath);
  if (CODE_INTEL_SECRET_FILE_RE.test(filePath)) return true;
  if (/package-lock\.json|yarn\.lock|pnpm-lock\.yaml/i.test(base)) return true;
  return false;
}

function codeIntelWalk(root, options = {}) {
  const maxFiles = Math.max(25, Math.min(Number(options.maxFiles || 450), 1200));
  const rows = [];
  const stack = [root];
  while (stack.length && rows.length < maxFiles) {
    const dir = stack.pop();
    let entries = [];
    try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch { continue; }
    for (const entry of entries) {
      const full = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        if (CODE_INTEL_SKIP_DIRS.has(entry.name) || entry.name.startsWith('codex-archive')) continue;
        stack.push(full);
      } else if (entry.isFile()) {
        if (codeIntelShouldSkip(full)) continue;
        const ext = path.extname(entry.name).toLowerCase();
        if (!CODE_INTEL_ALLOWED_EXTENSIONS.has(ext)) continue;
        let stat = null;
        try { stat = fs.statSync(full); } catch { continue; }
        if (stat.size > Number(options.maxFileBytes || 350000)) continue;
        rows.push({ path: full, ext, size: stat.size, modifiedAt: stat.mtime.toISOString() });
        if (rows.length >= maxFiles) break;
      }
    }
  }
  return rows;
}

function codeIntelReadSample(filePath = '') {
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    return raw.slice(0, 120000);
  } catch {
    return '';
  }
}

function codeIntelScoreFile(file = {}) {
  const text = `${file.path}\n${codeIntelReadSample(file.path)}`.toLowerCase();
  const matches = [];
  let totalScore = 0;
  for (const feature of CODE_INTEL_FEATURES) {
    const hits = (feature.keywords || []).filter(keyword => text.includes(String(keyword).toLowerCase()));
    if (!hits.length) continue;
    const score = feature.score + hits.length;
    matches.push({ id: feature.id, label: feature.label, score, hits, why: feature.why });
    totalScore += score;
  }
  return { totalScore, matches };
}

function buildCodeIntelSuggestion(feature = {}, examples = []) {
  const paths = examples.slice(0, 5).map(row => row.relativePath);
  const prompt = [
    `Feature: ${feature.label}`,
    '',
    `Why useful: ${feature.why}`,
    '',
    'Best source files:',
    ...paths.map(item => `- ${item}`),
    '',
    'Implementation direction for SuperSender Pro:',
    `- Study these source files only for patterns, not secret data.`,
    `- Build a scoped ${feature.label} module with dashboard controls, API endpoint, and admin command if useful.`,
    '- Keep all sending/automation behind preview + approval where risk exists.',
    '- Verify with /api/health and focused endpoint tests.'
  ].join('\n');
  return { ...feature, sourceFiles: paths, prompt };
}

function runCodeIntelligenceScan(input = {}) {
  const root = codeIntelWorkspaceRoot(input.root || input.workspaceRoot || '');
  const files = codeIntelWalk(root, input);
  const scored = files.map(file => {
    const score = codeIntelScoreFile(file);
    return {
      ...file,
      relativePath: path.relative(root, file.path),
      score: score.totalScore,
      matches: score.matches
    };
  }).filter(row => row.score > 0).sort((a, b) => b.score - a.score);
  const byFeature = new Map();
  for (const row of scored) {
    for (const match of row.matches) {
      const list = byFeature.get(match.id) || { ...match, examples: [], score: 0 };
      list.score += match.score;
      list.examples.push(row);
      byFeature.set(match.id, list);
    }
  }
  const suggestions = [...byFeature.values()]
    .sort((a, b) => b.score - a.score)
    .slice(0, 8)
    .map(feature => buildCodeIntelSuggestion(feature, feature.examples));
  const report = {
    id: uuid(),
    root,
    generatedAt: new Date().toISOString(),
    scannedFiles: files.length,
    matchedFiles: scored.length,
    topFiles: scored.slice(0, 25).map(row => ({
      relativePath: row.relativePath,
      score: row.score,
      size: row.size,
      modifiedAt: row.modifiedAt,
      matches: row.matches.map(match => match.label)
    })),
    suggestions
  };
  codeIntelligenceReports.unshift(report);
  saveCodeIntelligenceReports();
  return report;
}

function buildCodeIntelligencePage(req) {
  const last = codeIntelligenceReports[0] || null;
  const suggestionRows = last?.suggestions?.length ? last.suggestions.map(item => `
    <section class="card">
      <div class="head"><h2>${htmlEscape(item.label)}</h2><span>Score ${Number(item.score || 0)}</span></div>
      <p>${htmlEscape(item.why || '')}</p>
      <pre>${htmlEscape(item.prompt || '')}</pre>
    </section>`).join('') : '<section class="card"><p class="muted">No scan report yet. Click Run Scan.</p></section>';
  const fileRows = last?.topFiles?.length ? last.topFiles.map(row => `
    <tr><td>${htmlEscape(row.relativePath)}</td><td>${Number(row.score || 0)}</td><td>${htmlEscape((row.matches || []).join(', '))}</td></tr>
  `).join('') : '<tr><td colspan="3" class="muted">No files scanned yet.</td></tr>';
  return `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Code Intelligence - SuperSender Pro</title>
  <style>
    :root{color-scheme:dark;--bg:#071014;--panel:#122029;--line:#263946;--text:#eaf7f3;--muted:#90a6b1;--accent:#18c29c}
    *{box-sizing:border-box}body{margin:0;background:linear-gradient(135deg,#071014,#101d24);color:var(--text);font-family:Inter,Segoe UI,Arial,sans-serif}.wrap{max-width:1220px;margin:0 auto;padding:28px}.top{display:flex;justify-content:space-between;gap:12px;align-items:center}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.card{background:rgba(18,32,41,.94);border:1px solid var(--line);border-radius:16px;padding:18px;margin-top:16px}.head{display:flex;justify-content:space-between;gap:10px;align-items:center}button,a.btn{border:0;border-radius:10px;padding:10px 13px;background:var(--accent);color:#06231c;font-weight:800;cursor:pointer;text-decoration:none}.secondary{background:#263946!important;color:var(--text)!important;border:1px solid #3b5361!important}pre{white-space:pre-wrap;background:#09141b;border:1px solid #263946;border-radius:12px;padding:12px;line-height:1.45}table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid var(--line);text-align:left;padding:9px}th{color:#9bb0ba;text-transform:uppercase;font-size:12px;letter-spacing:.08em}@media(max-width:900px){.top,.grid{display:block}}
  </style></head><body><div class="wrap">
    <div class="top"><div><h1>Code Intelligence Scanner</h1><p class="muted">Local projects se useful automation ideas scan karta hai. Secrets/auth folders skip hotay hain.</p></div><div><a class="btn secondary" href="/">Dashboard</a></div></div>
    <section class="card"><button onclick="runScan()">Run Workspace Scan</button><span id="status" class="muted" style="margin-left:10px">${last ? `Last scan: ${htmlEscape(last.generatedAt)} | Matched ${last.matchedFiles}/${last.scannedFiles}` : 'No scan yet'}</span></section>
    <div class="grid">${suggestionRows}</div>
    <section class="card"><h2>Top Matched Files</h2><table><thead><tr><th>File</th><th>Score</th><th>Matched Ideas</th></tr></thead><tbody>${fileRows}</tbody></table></section>
  </div><script>
    async function runScan(){
      const status = document.getElementById('status');
      status.textContent = 'Scanning workspace...';
      const res = await fetch('/api/code-intelligence/scan', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({maxFiles:550})});
      const data = await res.json().catch(()=>({error:'Invalid JSON'}));
      status.textContent = data.success ? 'Scan complete. Reloading...' : (data.error || 'Scan failed');
      if(data.success) setTimeout(()=>location.reload(), 900);
    }
  </script></body></html>`;
}

