let searchIndexRebuildTimer = null;
function scheduleSearchIndexRebuild(reason = 'data-change', delayMs = Number(process.env.SEARCH_REBUILD_DEBOUNCE_MS || 30000)) {
  if (searchIndexRebuildTimer) clearTimeout(searchIndexRebuildTimer);
  searchIndexRebuildTimer = setTimeout(() => {
    searchIndexRebuildTimer = null;
    try {
      const analyticsRows = messageAnalytics ? messageAnalytics.loadMessages() : [];
      searchEngine.rebuild(customers, waConversations, analyticsRows);
      console.log(`[Search] index rebuilt (${reason})`);
    } catch (e) {
      console.error('Search index rebuild error:', e.message);
    }
  }, Math.max(1000, Number(delayMs || 30000)));
  if (searchIndexRebuildTimer.unref) searchIndexRebuildTimer.unref();
}

// Hook to rebuild search index when customers change without blocking hot chat paths.
