// ------------------------------------------------------------------
// PRICE INTELLIGENCE EXTRACTOR (from group messages)
// ------------------------------------------------------------------
function extractPriceMentions(text) {
  const raw = (text || '').toString();
  if (!raw.trim()) return [];

  // Quick heuristic: ignore very short messages and messages without any digits.
  if (raw.length < 12 || !/\d/.test(raw)) return [];

  // Split into segments (supports: newline lists, "- item: price", "â€¢ item: price")
  const segments = raw
    .replace(/\r/g, '')
    .split(/\n|â€¢|\u2022|\u25CF|;|\|/g)
    .flatMap(s => s.split(/\s-\s/g))
    .map(s => s.trim())
    .filter(Boolean);

  const out = [];

  for (const seg0 of segments) {
    const seg = seg0.replace(/^[\-\*\u2022]+/g, '').trim();
    if (!seg) continue;

    // Price patterns
    let currency = null;
    let priceStr = null;

    const m1 = seg.match(/\b(\d+(?:\.\d+)?)\s*(\$|usd)\b/i);
    const m2 = seg.match(/\b(\d+(?:\.\d+)?)\s*(rs\.?|pkr)\b/i);
    const m3 = seg.match(/\b(rs\.?|pkr)\s*\.?\s*(\d+(?:\.\d+)?)/i);
    if (m1) { priceStr = m1[1]; currency = 'USD'; }
    else if (m2) { priceStr = m2[1]; currency = 'PKR'; }
    else if (m3) { priceStr = m3[2]; currency = 'PKR'; }

    if (!priceStr) continue;

    // Product name = segment with the price removed (best effort)
    let product = seg
      .replace(m1?.[0] || '', '')
      .replace(m2?.[0] || '', '')
      .replace(m3?.[0] || '', '')
      .replace(/[:=]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    // If product is empty, skip.
    if (!/[a-zA-Z]/.test(product) || product.length < 3) continue;

    const priceNum = Number(priceStr.toString().replace(/,/g, ''));
    if (!Number.isFinite(priceNum) || priceNum <= 0) continue;

    out.push({ product, price: priceNum, currency });
  }

  // Deduplicate similar entries inside one message
  const seen = new Set();
  return out.filter(x => {
    const k = (x.product || '').toLowerCase() + '|' + x.currency + '|' + x.price;
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
}

function parsePriceNumber(value = '', suffix = '') {
  const n = Number(value.toString().replace(/,/g, ''));
  if (!Number.isFinite(n) || n <= 0) return 0;
  return /k/i.test(suffix || '') ? Math.round(n * 1000) : n;
}

const AI_TOOL_RATE_ALIASES = [
  { slug: 'chatgpt', name: 'ChatGPT', re: /\b(chat\s*gpt|chatgpt|gpt|gpt-4|gpt4|openai)\b/i },
  { slug: 'claude', name: 'Claude', re: /\b(claude|cloude|anthropic)\b/i },
  { slug: 'midjourney', name: 'Midjourney', re: /\b(mid\s*journey|midjourney|mj|mid)\b/i },
  { slug: 'cursor', name: 'Cursor', re: /\b(cursor|cursor\s*pro)\b/i },
  { slug: 'gemini', name: 'Gemini', re: /\b(gemini|google\s*ai|google\s*one|bard)\b/i },
  { slug: 'canva', name: 'Canva', re: /\b(canva|canva\s*pro)\b/i },
  { slug: 'perplexity', name: 'Perplexity', re: /\b(perplexity|perplex|pplx)\b/i },
  { slug: 'kimi', name: 'Kimi', re: /\b(kimi|kimi\s*k2)\b/i },
  { slug: 'turnitin', name: 'Turnitin', re: /\b(turnitin|turnitin\s*ai)\b/i },
  { slug: 'deepseek', name: 'DeepSeek', re: /\b(deep\s*seek|deepseek)\b/i },
  { slug: 'capcut', name: 'CapCut', re: /\b(cap\s*cut|capcut)\b/i },
  { slug: 'grammarly', name: 'Grammarly', re: /\b(grammarly|gramerly|grammar)\b/i },
  { slug: 'quillbot', name: 'QuillBot', re: /\b(quill\s*bot|quillbot)\b/i },
  { slug: 'copilot', name: 'GitHub Copilot', re: /\b(github\s*copilot|copilot)\b/i },
  { slug: 'windsurf', name: 'Windsurf', re: /\b(windsurf)\b/i },
  { slug: 'notion', name: 'Notion', re: /\b(notion|notion\s*ai)\b/i },
  { slug: 'adobe', name: 'Adobe', re: /\b(adobe|photoshop|illustrator|premiere)\b/i },
  { slug: 'runway', name: 'Runway', re: /\b(runway|runwayml)\b/i },
  { slug: 'elevenlabs', name: 'ElevenLabs', re: /\b(eleven\s*labs|elevenlabs)\b/i }
];

function inferAITool(segment = '') {
  return AI_TOOL_RATE_ALIASES.find(tool => tool.re.test(segment)) || null;
}

function inferAIPlan(segment = '') {
  const lower = String(segment || '').toLowerCase();
  const plans = [
    ['team', 'Team'],
    ['plus', 'Plus'],
    ['pro', 'Pro'],
    ['max', 'Max'],
    ['basic', 'Basic'],
    ['standard', 'Standard'],
    ['advanced', 'Advanced'],
    ['go', 'Go'],
    ['monthly', 'Monthly'],
    ['month', 'Monthly'],
    ['yearly', 'Yearly'],
    ['year', 'Yearly'],
    ['warranty', 'Warranty'],
    ['private', 'Private'],
    ['shared', 'Shared'],
    ['non warranty', 'Non-Warranty'],
    ['non-warranty', 'Non-Warranty']
  ];
  const found = plans.find(([key]) => lower.includes(key));
  return found ? found[1] : '';
}

function normalizeGroupRateText(text = '') {
  return String(text || '')
    .replace(/\r/g, '\n')
    .replace(/[•●◦▪️]+/g, '\n')
    .replace(/[،؛]+/g, ',')
    .replace(/[–—]/g, '-')
    .replace(/\b(hy|hai|ha|hey|available|avail|aaj|today)\b/gi, ' $1 ')
    .replace(/\t/g, ' ')
    .replace(/[ ]{2,}/g, ' ');
}

function extractAIToolRateMentions(text = '') {
  const raw = normalizeGroupRateText(text);
  if (!raw.trim() || !/\d/.test(raw)) return [];
  const toolPattern = '(chat\\s*gpt|chatgpt|gpt-4|gpt4|gpt|openai|claude|cloude|anthropic|mid\\s*journey|midjourney|mj|mid|cursor|gemini|google\\s*ai|google\\s*one|bard|canva|perplexity|perplex|pplx|kimi|turnitin|deep\\s*seek|deepseek|cap\\s*cut|capcut|grammarly|gramerly|quill\\s*bot|quillbot|github\\s*copilot|copilot|windsurf|notion|adobe|photoshop|illustrator|premiere|runway|runwayml|eleven\\s*labs|elevenlabs)';
  const toolBlockRe = new RegExp(`\\b${toolPattern}\\b[\\s\\S]*?(?=\\b${toolPattern}\\b|$)`, 'gi');
  const normalized = raw;

  const chunks = [];
  const pushChunk = (value = '') => {
    const cleaned = String(value || '').replace(/\s{2,}/g, ' ').trim();
    if (!cleaned) return;
    chunks.push(cleaned);
  };

  for (const line of normalized.split(/\n+/)) {
    const cleanedLine = line.trim();
    if (!cleanedLine || /^tool\s*\|?\s*price$/i.test(cleanedLine)) continue;
    pushChunk(cleanedLine.replace(/\|/g, ' '));
    for (const part of cleanedLine.split(/[,;]+/)) pushChunk(part.replace(/\|/g, ' '));
  }

  const whole = normalized.replace(/\|/g, ' ');
  const toolBlocks = [...whole.matchAll(toolBlockRe)].map(match => match[0]);
  for (const block of toolBlocks) pushChunk(block);

  const offers = [];
  for (const chunk of chunks) {
    const tool = inferAITool(chunk);
    if (!tool) continue;
    const priceMatches = [...chunk.matchAll(/(?:rs\.?|pkr|price|rate)?\s*(?:[:=\-]|hy|hai|only|@)?\s*([0-9][0-9,]{2,5})(?![\d.])/ig)];
    for (const match of priceMatches) {
      const price = Number(String(match[1] || '').replace(/,/g, ''));
      if (!Number.isFinite(price) || price < 100 || price > 99999) continue;
      const plan = inferAIPlan(chunk) || ({
        chatgpt: 'Plus',
        claude: 'Pro',
        cursor: 'Pro',
        gemini: 'Advanced',
        perplexity: 'Pro',
        canva: 'Pro',
        deepseek: 'Pro',
        capcut: 'Pro',
        grammarly: 'Premium',
        quillbot: 'Premium',
        copilot: 'Pro',
        windsurf: 'Pro',
        notion: 'AI',
        adobe: 'Pro',
        runway: 'Pro',
        elevenlabs: 'Pro'
      }[tool.slug] || '');
      offers.push({
        title: `${tool.name}${plan ? ` ${plan}` : ''}`,
        product: tool.name,
        toolSlug: tool.slug,
        plan,
        brand: tool.name,
        category: 'ai-tools',
        price,
        currency: 'PKR',
        condition: '',
        duration: /3\s*month/i.test(chunk) ? '3 months' : /1\s*month|monthly/i.test(chunk) ? '1 month' : '',
        notes: chunk.slice(0, 220),
        confidence: /\|/.test(chunk) ? 0.78 : 0.88,
        source: 'ai_tool_regex'
      });
    }
  }
  const seen = new Set();
  return offers.filter(item => {
    const key = `${item.toolSlug}|${item.plan}|${item.price}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function extractPriceMentionsHeuristic(text) {
  const raw = normalizeGroupRateText(text);
  if (!raw.trim() || raw.length < 4 || !/\d/.test(raw)) return [];

  const segments = raw
    .replace(/\r/g, '')
    .split(/\n|Ã¢â‚¬Â¢|\u2022|\u25CF|;|\|/g)
    .flatMap(s => s.split(/\.\s+/g))
    .flatMap(s => s.split(/\s-\s/g))
    .map(s => s.trim())
    .filter(Boolean);

  const out = [];
  for (const seg0 of segments) {
    const seg = seg0.replace(/^[\-\*\u2022]+/g, '').trim();
    if (!seg) continue;

    const patterns = [
      { re: /\b(rs\.?|pkr|â‚¨)\s*([\d,]+(?:\.\d+)?)(\s*k)?\b/i, currency: 'PKR', val: 2, suffix: 3 },
      { re: /\b([\d,]+(?:\.\d+)?)(\s*k)?\s*(rs\.?|pkr|â‚¨)\b/i, currency: 'PKR', val: 1, suffix: 2 },
      { re: /\$\s*([\d,]+(?:\.\d+)?)(\s*k)?\b/i, currency: 'USD', val: 1, suffix: 2 },
      { re: /\b([\d,]+(?:\.\d+)?)(\s*k)?\s*(usd|\$)\b/i, currency: 'USD', val: 1, suffix: 2 }
    ];

    let match = null;
    let currency = 'PKR';
    let price = 0;
    for (const p of patterns) {
      const m = seg.match(p.re);
      if (m) {
        match = m;
        currency = p.currency;
        price = parsePriceNumber(m[p.val], m[p.suffix]);
        break;
      }
    }

    if (!match) {
      const m = seg.match(/\b([\d,]+(?:\.\d+)?)(\s*k)\b/i);
      if (m && /(sale|sell|seller|available|avail|price|rate|plan|monthly|month|year|account|subscription|tool|premium|chatgpt|canva|netflix|spotify|grammarly|adobe|vpn|license)/i.test(seg)) {
        match = m;
        price = parsePriceNumber(m[1], m[2]);
        currency = 'PKR';
      }
    }

    if (!match || !price) continue;

    let product = seg
      .replace(match[0], '')
      .replace(/\b(price|rate|only|available|avail|seller|sale|for sale|contact|dm|inbox)\b/ig, ' ')
      .replace(/[:=]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    if (!product || product.length < 2) product = seg.replace(match[0], '').trim() || 'Offer';

    out.push({
      title: product.slice(0, 90),
      product: product.slice(0, 90),
      plan: '',
      brand: '',
      category: '',
      price,
      currency,
      condition: '',
      duration: '',
      notes: '',
      confidence: 0.55,
      source: 'regex'
    });
  }

  const seen = new Set();
  return out.filter(x => {
    const k = `${(x.product || '').toLowerCase()}|${x.currency}|${x.price}`;
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
}

function parseAIJSON(raw = '') {
  const text = (raw || '').toString().trim()
    .replace(/^```(?:json)?/i, '')
    .replace(/```$/i, '')
    .trim();
  const candidates = [text];
  const obj = text.match(/\{[\s\S]*\}/);
  const arr = text.match(/\[[\s\S]*\]/);
  if (obj) candidates.push(obj[0]);
  if (arr) candidates.push(arr[0]);
  for (const c of candidates) {
    try { return JSON.parse(c); } catch {}
  }
  return null;
}

function normalizeAIProvider(value = '') {
  const v = String(value || '').trim().toLowerCase();
  if (v.includes('anthropic') || v.includes('claude')) return 'anthropic';
  if (v.includes('gemini') || v.includes('google')) return 'gemini';
  if (v.includes('openai') || v.includes('gpt')) return 'openai';
  return 'groq';
}

function aiProviderLabel(provider) {
  return {
    groq: 'Groq',
    anthropic: 'Anthropic Claude',
    gemini: 'Google Gemini',
    openai: 'OpenAI'
  }[normalizeAIProvider(provider)] || 'AI';
}

function aiProviderConfig(provider = settings.active_ai_provider || process.env.ACTIVE_AI_PROVIDER) {
  const id = normalizeAIProvider(provider);
  const map = {
    groq: {
      id,
      key: settings.groq_api_key || process.env.GROQ_API_KEY,
      model: settings.groq_model || process.env.GROQ_MODEL || 'llama3-8b-8192'
    },
    anthropic: {
      id,
      key: settings.anthropic_api_key || process.env.ANTHROPIC_API_KEY,
      model: settings.anthropic_model || process.env.ANTHROPIC_MODEL || 'claude-3-5-haiku-latest'
    },
    gemini: {
      id,
      key: settings.gemini_api_key || process.env.GEMINI_API_KEY,
      model: settings.gemini_model || process.env.GEMINI_MODEL || 'gemini-1.5-flash'
    },
    openai: {
      id,
      key: settings.openai_api_key || process.env.OPENAI_API_KEY,
      model: settings.openai_model || process.env.OPENAI_MODEL || 'gpt-4o-mini'
    }
  };
  return map[id] || map.groq;
}

function hasAIProvider(provider = settings.active_ai_provider) {
  return !!String(aiProviderConfig(provider).key || '').trim();
}

function getConfiguredAIProviders(preferred = settings.active_ai_provider || process.env.ACTIVE_AI_PROVIDER, strict = false) {
  const active = normalizeAIProvider(preferred);
  if (strict) {
    const cfg = aiProviderConfig(active);
    return String(cfg.key || '').trim() ? [cfg] : [];
  }
  const order = [active, 'groq', 'anthropic', 'gemini', 'openai'];
  return [...new Set(order)]
    .map(provider => aiProviderConfig(provider))
    .filter(cfg => !!String(cfg.key || '').trim());
}

function hasAnyAIProvider() {
  return getConfiguredAIProviders().length > 0;
}

const aiProviderFailureUntil = new Map();

function markAIProviderFailure(providerId, error) {
  const cooldownUntil = Date.now() + Number(process.env.AI_PROVIDER_FAILURE_COOLDOWN_MS || 60 * 1000);
  aiProviderFailureUntil.set(providerId, cooldownUntil);
  const msg = String(error?.message || error || '').toLowerCase();
  if (/fetch failed|aborted|eai_again|enotfound|etimedout|econnreset|network/.test(msg)) {
    for (const cfg of getConfiguredAIProviders()) {
      aiProviderFailureUntil.set(cfg.id, cooldownUntil);
    }
  }
}

async function callOpenAICompatibleProvider(cfg, prompt, systemPrompt, opts) {
  const endpoint = cfg.id === 'groq'
    ? 'https://api.groq.com/openai/v1/chat/completions'
    : 'https://api.openai.com/v1/chat/completions';
  const response = await fetch(endpoint, {
    method: 'POST',
    signal: opts.signal,
    headers: { 'Authorization': `Bearer ${cfg.key}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: cfg.model,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: prompt }
      ],
      temperature: opts.temperature,
      max_tokens: opts.maxTokens
    })
  });
  if (!response.ok) throw new Error(`${aiProviderLabel(cfg.id)} HTTP ${response.status}`);
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || `${aiProviderLabel(cfg.id)} error`);
  return (data.choices?.[0]?.message?.content || '').trim();
}

async function callAnthropicProvider(cfg, prompt, systemPrompt, opts) {
  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    signal: opts.signal,
    headers: {
      'x-api-key': cfg.key,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: cfg.model,
      system: systemPrompt,
      messages: [{ role: 'user', content: prompt }],
      temperature: opts.temperature,
      max_tokens: opts.maxTokens
    })
  });
  if (!response.ok) throw new Error(`Anthropic HTTP ${response.status}`);
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || 'Anthropic error');
  return (data.content || []).map(part => part.text || '').join('').trim();
}

async function callGeminiProvider(cfg, prompt, systemPrompt, opts) {
  const model = encodeURIComponent(cfg.model);
  const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${encodeURIComponent(cfg.key)}`, {
    method: 'POST',
    signal: opts.signal,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      systemInstruction: { parts: [{ text: systemPrompt }] },
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: {
        temperature: opts.temperature,
        maxOutputTokens: opts.maxTokens
      }
    })
  });
  if (!response.ok) throw new Error(`Gemini HTTP ${response.status}`);
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || 'Gemini error');
  return (data.candidates?.[0]?.content?.parts || []).map(part => part.text || '').join('').trim();
}

async function callAIProvider(prompt, systemPrompt, options = {}) {
  const candidates = getConfiguredAIProviders(options.provider || settings.active_ai_provider, options.strictProvider === true);
  if (!candidates.length) throw new Error('No AI provider key configured');
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), Number(options.timeoutMs || process.env.AI_REPLY_TIMEOUT_MS || 6000));
  if (timeout.unref) timeout.unref();
  const opts = {
    signal: controller.signal,
    temperature: Number.isFinite(Number(options.temperature)) ? Number(options.temperature) : 0.4,
    maxTokens: Number(options.maxTokens || 180)
  };
  let lastError = null;
  try {
    for (const cfg of candidates) {
      const failureUntil = Number(aiProviderFailureUntil.get(cfg.id) || 0);
      if (options.strictProvider !== true && failureUntil > Date.now()) {
        lastError = new Error(`${aiProviderLabel(cfg.id)} is cooling down after a recent failure`);
        continue;
      }
      try {
        let text = '';
        if (cfg.id === 'anthropic') text = await callAnthropicProvider(cfg, prompt, systemPrompt, opts);
        else if (cfg.id === 'gemini') text = await callGeminiProvider(cfg, prompt, systemPrompt, opts);
        else text = await callOpenAICompatibleProvider(cfg, prompt, systemPrompt, opts);
        if (text) return { text, provider: cfg.id, model: cfg.model };
        lastError = new Error(`${aiProviderLabel(cfg.id)} returned an empty response`);
      } catch (error) {
        lastError = error;
        markAIProviderFailure(cfg.id, error);
        console.warn(`[AI] ${aiProviderLabel(cfg.id)} failed:`, error.message);
      }
    }
    throw lastError || new Error('AI provider failed');
  } finally {
    clearTimeout(timeout);
  }
}

async function callGroqRaw(prompt, systemPrompt, maxTokens = 900) {
  const result = await callAIProvider(prompt, systemPrompt, {
    maxTokens,
    temperature: 0.1,
    timeoutMs: Number(process.env.AI_RAW_TIMEOUT_MS || 9000)
  });
  return result.text;
}

async function extractPriceMentionsAI(text, ctx = {}) {
  const raw = (text || '').toString().trim();
  if (!raw || raw.length < 4 || !/\d/.test(raw) || !hasAnyAIProvider()) return [];

  const systemPrompt = [
    'You extract seller offers from WhatsApp group posts.',
    'Return only valid JSON in this exact shape: {"offers":[...]}',
    'Each offer must include: title, product, plan, brand, category, price, currency, condition, duration, notes, socialCaption, confidence.',
    'price must be a number only. currency should be PKR, USD, or UNKNOWN.',
    'If the message has no sellable offer with a price, return {"offers":[]}.',
    'Keep socialCaption short and ready for Facebook/Instagram/WhatsApp posting.'
  ].join(' ');

  const prompt = [
    `Group: ${ctx.groupName || ''}`,
    `Seller: ${ctx.seller || ''} ${ctx.sellerNumber ? '(' + ctx.sellerNumber + ')' : ''}`,
    'WhatsApp post:',
    raw.slice(0, 3500)
  ].join('\n');

  try {
    const ai = await callGroqRaw(prompt, systemPrompt, 1000);
    const parsed = parseAIJSON(ai);
    const offers = Array.isArray(parsed) ? parsed : (Array.isArray(parsed?.offers) ? parsed.offers : []);
    return offers.map(o => {
      const price = Number((o.price || '').toString().replace(/[^\d.]/g, ''));
      if (!Number.isFinite(price) || price <= 0) return null;
      return {
        title: (o.title || o.product || 'Offer').toString().trim().slice(0, 120),
        product: (o.product || o.title || 'Offer').toString().trim().slice(0, 120),
        plan: (o.plan || '').toString().trim().slice(0, 80),
        brand: (o.brand || '').toString().trim().slice(0, 80),
        category: (o.category || '').toString().trim().slice(0, 80),
        price,
        currency: (o.currency || 'PKR').toString().toUpperCase().slice(0, 12),
        condition: (o.condition || '').toString().trim().slice(0, 80),
        duration: (o.duration || '').toString().trim().slice(0, 80),
        notes: (o.notes || '').toString().trim().slice(0, 280),
        socialCaption: (o.socialCaption || '').toString().trim().slice(0, 700),
        confidence: Math.max(0, Math.min(1, Number(o.confidence || 0.82))),
        source: 'ai'
      };
    }).filter(Boolean);
  } catch (e) {
    console.warn('[PriceIntel] Groq extraction failed:', e.message);
    return [];
  }
}

function buildSocialCaption(item = {}, ctx = {}) {
  if (item.socialCaption) return item.socialCaption;
  const cur = item.currency === 'USD' ? '$' : 'Rs.';
  const price = Number(item.price || 0).toLocaleString();
  const lines = [
    `ðŸ”¥ ${item.title || item.product || 'New Offer'}`,
    `${cur} ${price}${item.duration ? ' | ' + item.duration : ''}`,
    item.plan ? `Plan: ${item.plan}` : '',
    item.notes ? item.notes : '',
    'DM for details.'
  ].filter(Boolean);
  return lines.join('\n');
}

function normalizeOffer(item = {}, ctx = {}) {
  const price = Number((item.price || '').toString().replace(/[^\d.]/g, ''));
  if (!Number.isFinite(price) || price <= 0) return null;
  const product = (item.product || item.title || 'Offer').toString().trim();
  if (!product) return null;
  return {
    id: uuid(),
    date: ctx.timestamp || new Date().toISOString(),
    groupId: ctx.groupId || '',
    groupName: ctx.groupName || '',
    seller: ctx.seller || ctx.sellerName || 'Unknown',
    sellerNumber: ctx.sellerNumber || '',
    sellerId: ctx.sellerId || '',
    messageId: ctx.messageId || '',
    rawPost: (ctx.body || '').toString().slice(0, 5000),
    title: (item.title || product).toString().trim().slice(0, 140),
    product: product.slice(0, 140),
    plan: (item.plan || '').toString().trim().slice(0, 90),
    brand: (item.brand || '').toString().trim().slice(0, 90),
    category: (item.category || '').toString().trim().slice(0, 90),
    condition: (item.condition || '').toString().trim().slice(0, 90),
    duration: (item.duration || '').toString().trim().slice(0, 90),
    notes: (item.notes || '').toString().trim().slice(0, 350),
    price,
    currency: (item.currency || 'PKR').toString().toUpperCase().slice(0, 12),
    socialCaption: buildSocialCaption(item, ctx),
    source: item.source || 'regex',
    confidence: Math.max(0, Math.min(1, Number(item.confidence || 0.6)))
  };
}

function isDuplicatePriceIntel(record) {
  const keyMsg = record.messageId && `${record.messageId}|${record.product}|${record.price}|${record.currency}`;
  return (priceIntel || []).some(r => {
    if (keyMsg && `${r.messageId}|${r.product}|${r.price}|${r.currency}` === keyMsg) return true;
    return false;
  });
}

async function extractGroupPriceOffers(ctx = {}, opts = {}) {
  const body = (ctx.body || '').toString();
  if (!body.trim() || !/\d/.test(body)) return [];
  let offers = extractAIToolRateMentions(body);
  if (opts.useAI !== false && hasAnyAIProvider()) {
    const aiOffers = await extractPriceMentionsAI(body, ctx);
    if (aiOffers.length) {
      const seen = new Set(offers.map(o => `${(o.toolSlug || o.product || '').toLowerCase()}|${(o.plan || '').toLowerCase()}|${o.price}`));
      for (const offer of aiOffers) {
        const key = `${(offer.toolSlug || offer.product || '').toLowerCase()}|${(offer.plan || '').toLowerCase()}|${offer.price}`;
        if (!seen.has(key)) {
          offers.push(offer);
          seen.add(key);
        }
      }
    }
  }
  if (!offers.length) offers = extractPriceMentionsHeuristic(body);
  return offers.map(o => normalizeOffer(o, ctx)).filter(Boolean);
}

async function captureGroupPriceIntel(ctx = {}, opts = {}) {
  const records = await extractGroupPriceOffers(ctx, opts);
  if (!records.length) return [];
  if (opts.persist === false) return records;
  const saved = [];
  for (const record of records) {
    if (isDuplicatePriceIntel(record)) continue;
    priceIntel.push(record);
    saved.push(record);
  }
  if (!saved.length) return [];
  if (priceIntel.length > 10000) priceIntel = priceIntel.slice(-10000);
  saveJSON('price_intel.json', priceIntel);
  try { writeSellerRatesFiles(); } catch (error) { console.warn('[SellerRates] export refresh failed:', error.message); }
  io.emit('price_intel:new', saved);
  return saved;
}

function sellerRateRows(limit = 500, filters = {}) {
  const q = String(filters.q || filters.search || '').trim().toLowerCase();
  const category = String(filters.category || '').trim().toLowerCase();
  const group = String(filters.group || '').trim().toLowerCase();
  const since = filters.hours ? Date.now() - (Number(filters.hours) * 60 * 60 * 1000) : 0;
  let rows = [...(priceIntel || [])].map(row => ({
    id: row.id || '',
    date: row.date || row.timestamp || row.createdAt || '',
    groupName: row.groupName || '',
    groupId: row.groupId || '',
    sellerName: row.seller || row.sellerName || row.senderName || 'Unknown',
    sellerNumber: row.sellerNumber || row.senderNumber || '',
    sellerId: row.sellerId || '',
    tool: row.product || row.title || row.productKeyword || '',
    plan: row.plan || '',
    price: Number(row.price || 0),
    currency: row.currency || 'PKR',
    rate: `${row.currency === 'USD' ? '$' : 'Rs.'} ${Number(row.price || 0).toLocaleString()}`,
    category: row.category || '',
    confidence: Number(row.confidence || 0),
    source: row.source || '',
    rawPost: row.rawPost || row.rawMessage || '',
    messageId: row.messageId || ''
  })).filter(row => row.price > 0);
  if (since) rows = rows.filter(row => Date.parse(row.date || 0) >= since);
  if (category) rows = rows.filter(row => String(row.category || '').toLowerCase().includes(category));
  if (group) rows = rows.filter(row => `${row.groupName} ${row.groupId}`.toLowerCase().includes(group));
  if (q) {
    rows = rows.filter(row => [
      row.tool, row.plan, row.groupName, row.sellerName, row.sellerNumber, row.rawPost, row.category
    ].some(value => String(value || '').toLowerCase().includes(q)));
  }
  rows.sort((a, b) => Date.parse(b.date || 0) - Date.parse(a.date || 0));
  return rows.slice(0, Math.min(10000, Math.max(1, Number(limit || 500))));
}

function sellerIdentityKey(row = {}) {
  return normalizeNumber(row.sellerNumber || row.sellerId || '') || String(row.sellerName || 'Unknown').trim().toLowerCase() || 'unknown';
}

function sellerToolKey(row = {}) {
  return `${String(row.tool || '').trim().toLowerCase()}|${String(row.plan || '').trim().toLowerCase()}`;
}

function medianNumber(values = []) {
  const nums = values.map(Number).filter(Number.isFinite).sort((a, b) => a - b);
  if (!nums.length) return 0;
  const mid = Math.floor(nums.length / 2);
  return nums.length % 2 ? nums[mid] : Math.round((nums[mid - 1] + nums[mid]) / 2);
}

function buildSellerProfiles(rows = sellerRateRows(10000)) {
  const map = new Map();
  for (const row of rows) {
    const key = sellerIdentityKey(row);
    const profile = map.get(key) || {
      sellerKey: key,
      sellerName: row.sellerName || 'Unknown',
      sellerNumber: row.sellerNumber || '',
      groups: new Set(),
      tools: new Set(),
      rates: [],
      latestAt: '',
      firstSeenAt: row.date || '',
      totalRates: 0
    };
    if (row.sellerName && (!profile.sellerName || profile.sellerName === 'Unknown')) profile.sellerName = row.sellerName;
    if (row.sellerNumber && !profile.sellerNumber) profile.sellerNumber = row.sellerNumber;
    if (row.groupName || row.groupId) profile.groups.add(row.groupName || row.groupId);
    if (row.tool) profile.tools.add(row.plan ? `${row.tool} ${row.plan}` : row.tool);
    if (row.price) profile.rates.push(Number(row.price));
    profile.totalRates += 1;
    if (!profile.latestAt || Date.parse(row.date || 0) > Date.parse(profile.latestAt || 0)) profile.latestAt = row.date || '';
    if (!profile.firstSeenAt || Date.parse(row.date || 0) < Date.parse(profile.firstSeenAt || 0)) profile.firstSeenAt = row.date || profile.firstSeenAt;
    map.set(key, profile);
  }
  return [...map.values()].map(profile => {
    const rates = profile.rates.filter(Number.isFinite);
    const avg = rates.length ? Math.round(rates.reduce((sum, value) => sum + value, 0) / rates.length) : 0;
    const lowest = rates.length ? Math.min(...rates) : 0;
    const highest = rates.length ? Math.max(...rates) : 0;
    const recencyHours = profile.latestAt ? (Date.now() - Date.parse(profile.latestAt)) / (60 * 60 * 1000) : 9999;
    const recencyScore = recencyHours <= 24 ? 35 : recencyHours <= 72 ? 25 : recencyHours <= 168 ? 15 : 5;
    const volumeScore = Math.min(35, profile.totalRates * 4);
    const varietyScore = Math.min(20, profile.tools.size * 4);
    const groupScore = Math.min(10, profile.groups.size * 3);
    return {
      sellerKey: profile.sellerKey,
      sellerName: profile.sellerName || 'Unknown',
      sellerNumber: profile.sellerNumber || '',
      groups: [...profile.groups].sort(),
      tools: [...profile.tools].sort(),
      totalRates: profile.totalRates,
      averagePrice: avg,
      medianPrice: medianNumber(rates),
      lowestPrice: lowest,
      highestPrice: highest,
      firstSeenAt: profile.firstSeenAt || '',
      latestAt: profile.latestAt || '',
      trustScore: Math.max(1, Math.min(100, recencyScore + volumeScore + varietyScore + groupScore))
    };
  }).sort((a, b) => b.trustScore - a.trustScore || b.totalRates - a.totalRates);
}

function buildBestRateByTool(rows = sellerRateRows(10000)) {
  const map = new Map();
  for (const row of rows) {
    const key = sellerToolKey(row);
    if (!key.replace('|', '').trim()) continue;
    const current = map.get(key);
    if (!current || Number(row.price || 0) < Number(current.price || Infinity)) {
      map.set(key, {
        tool: row.tool,
        plan: row.plan || '',
        price: row.price,
        rate: row.rate,
        currency: row.currency,
        sellerName: row.sellerName,
        sellerNumber: row.sellerNumber,
        groupName: row.groupName,
        date: row.date,
        confidence: row.confidence,
        source: row.source
      });
    }
  }
  return [...map.values()].sort((a, b) => String(a.tool).localeCompare(String(b.tool)) || Number(a.price) - Number(b.price));
}

function buildGroupRateSummary(rows = sellerRateRows(10000)) {
  const map = new Map();
  for (const row of rows) {
    const key = row.groupId || row.groupName || 'unknown';
    const item = map.get(key) || {
      groupId: row.groupId || '',
      groupName: row.groupName || row.groupId || 'Unknown Group',
      totalRates: 0,
      sellers: new Set(),
      tools: new Set(),
      latestAt: ''
    };
    item.totalRates += 1;
    item.sellers.add(sellerIdentityKey(row));
    if (row.tool) item.tools.add(row.tool);
    if (!item.latestAt || Date.parse(row.date || 0) > Date.parse(item.latestAt || 0)) item.latestAt = row.date || '';
    map.set(key, item);
  }
  return [...map.values()].map(item => ({
    groupId: item.groupId,
    groupName: item.groupName,
    totalRates: item.totalRates,
    uniqueSellers: item.sellers.size,
    tools: [...item.tools].sort(),
    latestAt: item.latestAt
  })).sort((a, b) => b.totalRates - a.totalRates);
}

function buildSellerRateDashboardSummary(rows = sellerRateRows(10000)) {
  const last24 = rows.filter(row => Date.parse(row.date || 0) >= Date.now() - 24 * 60 * 60 * 1000);
  const profiles = buildSellerProfiles(rows);
  const bestByTool = buildBestRateByTool(last24.length ? last24 : rows);
  const groups = buildGroupRateSummary(rows);
  return {
    updatedAt: new Date().toISOString(),
    totalRates: rows.length,
    last24hRates: last24.length,
    uniqueSellers: profiles.length,
    groupsMonitored: groups.length,
    topSellers: profiles.slice(0, 20),
    bestByTool: bestByTool.slice(0, 100),
    groupSummary: groups.slice(0, 100)
  };
}

function sellerRatesCsv(rows = []) {
  const headers = ['Date', 'Tool', 'Plan', 'Price', 'Rate', 'Seller Name', 'Seller Number', 'Group', 'Group ID', 'Source', 'Confidence', 'Message'];
  const lines = [headers.map(csvCell).join(',')];
  for (const row of rows) {
    lines.push([
      row.date,
      row.tool,
      row.plan,
      row.price,
      row.rate,
      row.sellerName,
      row.sellerNumber,
      row.groupName,
      row.groupId,
      row.source,
      row.confidence,
      row.rawPost
    ].map(csvCell).join(','));
  }
  return lines.join('\n');
}

function sellerRatesMarkdown(rows = []) {
  const summary = buildSellerRateDashboardSummary(rows);
  const tableRows = rows.slice(0, 500).map(row => {
    const date = row.date ? new Date(row.date).toLocaleString('en-PK', { timeZone: 'Asia/Karachi' }) : '';
    const clean = value => String(value || '').replace(/\|/g, '/').replace(/\r?\n/g, ' ').trim();
    return `| ${clean(date)} | ${clean(row.tool)} | ${clean(row.plan)} | ${clean(row.rate)} | ${clean(row.sellerName)} | ${clean(row.sellerNumber)} | ${clean(row.groupName)} |`;
  });
  const bestRows = summary.bestByTool.slice(0, 25).map(row => {
    const clean = value => String(value || '').replace(/\|/g, '/').replace(/\r?\n/g, ' ').trim();
    return `| ${clean(row.tool)} | ${clean(row.plan)} | ${clean(row.rate)} | ${clean(row.sellerName)} | ${clean(row.sellerNumber)} | ${clean(row.groupName)} |`;
  });
  return [
    '# Seller Rates Collector',
    '',
    `Updated: ${new Date().toLocaleString('en-PK', { timeZone: 'Asia/Karachi' })}`,
    `Total rows: ${rows.length}`,
    `Last 24h rows: ${summary.last24hRates}`,
    `Unique sellers: ${summary.uniqueSellers}`,
    `Groups monitored: ${summary.groupsMonitored}`,
    '',
    '## Best Current Rates',
    '',
    '| Tool | Plan | Best Rate | Seller | Number | Group |',
    '|---|---|---:|---|---|---|',
    ...(bestRows.length ? bestRows : ['| - | No rows yet | - | - | - | - |']),
    '',
    '## Latest Captured Rates',
    '',
    '| Date | Tool | Plan | Rate | Seller | Number | Group |',
    '|---|---|---|---:|---|---|---|',
    ...(tableRows.length ? tableRows : ['| - | No rows yet | - | - | - | - | - |'])
  ].join('\n');
}

function writeSellerRatesFiles() {
  const rows = sellerRateRows(10000);
  const summary = buildSellerRateDashboardSummary(rows);
  const profiles = buildSellerProfiles(rows);
  const bestByTool = buildBestRateByTool(rows);
  const groups = buildGroupRateSummary(rows);
  const jsonPath = path.join(dataDir, 'seller_rates.json');
  const csvPath = path.join(dataDir, 'seller_rates.csv');
  const mdPath = path.join(dataDir, 'seller_rates.md');
  const summaryPath = path.join(dataDir, 'seller_rates_summary.json');
  const profilesPath = path.join(dataDir, 'seller_profiles.json');
  const bestPath = path.join(dataDir, 'seller_best_rates.json');
  const groupsPath = path.join(dataDir, 'seller_group_summary.json');
  fs.writeFileSync(jsonPath, JSON.stringify(rows, null, 2), 'utf8');
  fs.writeFileSync(csvPath, sellerRatesCsv(rows), 'utf8');
  fs.writeFileSync(mdPath, sellerRatesMarkdown(rows), 'utf8');
  fs.writeFileSync(summaryPath, JSON.stringify(summary, null, 2), 'utf8');
  fs.writeFileSync(profilesPath, JSON.stringify(profiles, null, 2), 'utf8');
  fs.writeFileSync(bestPath, JSON.stringify(bestByTool, null, 2), 'utf8');
  fs.writeFileSync(groupsPath, JSON.stringify(groups, null, 2), 'utf8');
  return { rows, jsonPath, csvPath, mdPath, summaryPath, profilesPath, bestPath, groupsPath };
}

function formatSellerRatesReply(limit = 12) {
  const { rows } = writeSellerRatesFiles();
  const summary = buildSellerRateDashboardSummary(rows);
  const latest = rows.slice(0, Math.max(1, Number(limit || 12)));
  const lines = latest.map((row, index) => {
    const plan = row.plan ? ` ${row.plan}` : '';
    const seller = row.sellerName || row.sellerNumber || 'Unknown';
    return `${index + 1}. *${row.tool}${plan}* — ${row.rate}\n   Seller: ${seller}${row.sellerNumber ? ` (${row.sellerNumber})` : ''}\n   Group: ${row.groupName || row.groupId || '-'}`;
  }).join('\n');
  const bestLines = summary.bestByTool.slice(0, 5).map(item => `• ${item.tool}${item.plan ? ` ${item.plan}` : ''}: *${item.rate}* — ${item.sellerName || item.sellerNumber || 'Unknown'}`).join('\n');
  return `📊 *Seller Rates Collector*

Total rows: *${rows.length}*
Last 24h: *${summary.last24hRates}*
Sellers: *${summary.uniqueSellers}*
Groups: *${summary.groupsMonitored}*

🏆 *Best Rates*
${bestLines || 'No best-rate rows yet.'}

🆕 *Latest Captures*
${lines || 'Abhi seller rates empty hain. *!ratesweep 50* run karein ya groups mein new rate messages ka wait karein.'}

Files:
${path.join(dataDir, 'seller_rates.json')}
${path.join(dataDir, 'seller_rates.csv')}
${path.join(dataDir, 'seller_rates.md')}`;
}

async function runSellerRateSweep(options = {}) {
  const accountId = String(options.accountId || 'default').trim() || 'default';
  const limit = Math.min(200, Math.max(1, Number(options.limit || 50)));
  const inst = waClients.get(accountId);
  if (!inst?.isReady) throw new Error('WhatsApp is not connected');
  const providedGroups = Array.isArray(options.groupIds) ? options.groupIds.filter(Boolean) : [];
  const groups = providedGroups.length
    ? providedGroups.map(id => ({ id, name: id }))
    : await listWhatsAppGroups(accountId);
  let scanned = 0;
  let saved = 0;
  let skipped = 0;
  const failures = [];
  const savedRows = [];
  for (const group of groups) {
    try {
      let chat = null;
      let messages = [];
      try {
        chat = await getWAChatByAnyId(inst, group.id);
        messages = typeof chat.fetchMessages === 'function'
          ? await chat.fetchMessages({ limit })
          : (chat.lastMessage ? [chat.lastMessage] : []);
      } catch (chatError) {
        if (group.lastMessage) {
          messages = [{
            body: group.lastMessage,
            from: group.id,
            author: '',
            timestamp: group.timestamp || Math.floor(Date.now() / 1000),
            id: `cached-${group.id}-${group.timestamp || Date.now()}`,
            _data: { notifyName: group.name || 'Cached group' }
          }];
        } else {
          skipped += 1;
          continue;
        }
      }
      for (const msg of messages || []) {
        const body = String(msg.body || msg._data?.body || msg.caption || '').trim();
        if (!body || !/\d/.test(body)) continue;
        scanned += 1;
        let contact = null;
        try { if (typeof msg.getContact === 'function') contact = await msg.getContact(); } catch {}
        const author = msg.author || msg.from || contact?.id?._serialized || '';
        const sellerNumber = (contact?.number || contact?.id?.user || String(author).split('@')[0] || '').replace(/\D/g, '');
        const sellerName = contact?.pushname || contact?.name || msg._data?.notifyName || sellerNumber || 'Member';
        const timestamp = msg.timestamp ? new Date(Number(msg.timestamp) * 1000).toISOString() : new Date().toISOString();
        const rows = await captureGroupPriceIntel({
          body,
          groupId: group.id || chat?.id?._serialized || '',
          groupName: group.name || chat?.name || chat?.formattedTitle || 'Group',
          seller: sellerName,
          sellerNumber,
          sellerId: author,
          messageId: msg.id?._serialized || msg.id || `${group.id}-${timestamp}-${scanned}`,
          timestamp
        }, { useAI: false });
        if (rows.length) {
          saved += rows.length;
          savedRows.push(...rows);
        }
      }
    } catch (error) {
      failures.push({ groupId: group.id, groupName: group.name, error: error.message });
    }
    await sleep(300);
  }
  const files = writeSellerRatesFiles();
  return {
    success: true,
    accountId,
    groups: groups.length,
    scanned,
    saved,
    skipped,
    failures,
    files: { json: files.jsonPath, csv: files.csvPath },
    report: files.mdPath,
    latest: sellerRateRows(20)
  };
}

// ------------------------------------------------------------------
// WHATSAPP CLIENT MULTI-TENANT MANAGER
// ------------------------------------------------------------------
const waClients = new Map();
// Cache contact profiles (name + profilePicUrl) to keep UI snappy.
const waProfileCache = new Map(); // key: contactId, value: { data, fetchedAt }
let waLastState = { connected: false, status: 'idle', message: 'Idle', error: '' };
let waLastQR = { tenantId: null, data: null, generatedAt: 0 };
const WA_QR_TTL_MS = 60000;
const WA_STALE_STARTING_MS = 15000;
const WA_STARTUP_TIMEOUT_MS = 16000;
const WA_SESSION_STARTUP_TIMEOUT_MS = 18000;

function getWASessionDir(tenantId = 'default') {
  return path.join(WA_AUTH_ROOT, `session-${tenantId}`);
}

function hasWASession(tenantId = 'default') {
  try {
    return fs.existsSync(getWASessionDir(tenantId)) || fs.existsSync(path.join(BAILEYS_AUTH_ROOT, tenantId, 'creds.json'));
  } catch { return false; }
}

function safeTailText(filePath, maxLines = 20) {
  try {
    if (!fs.existsSync(filePath)) return [];
    const raw = fs.readFileSync(filePath, 'utf8');
    return raw.split(/\r?\n/).filter(Boolean).slice(-Math.max(1, Number(maxLines) || 20));
  } catch (error) {
    return [`Could not read ${path.basename(filePath)}: ${error.message}`];
  }
}

function waSessionDiagnostics(tenantId = 'default') {
  const wwebSessionDir = getWASessionDir(tenantId);
  const baileysSessionDir = path.join(BAILEYS_AUTH_ROOT, tenantId);
  const lockNames = ['SingletonLock', 'SingletonCookie', 'SingletonSocket', 'DevToolsActivePort', 'lockfile'];
  const locks = lockNames.filter(name => {
    try { return fs.existsSync(path.join(wwebSessionDir, name)); } catch { return false; }
  });
  const statSafe = (dir) => {
    try {
      if (!fs.existsSync(dir)) return null;
      const stat = fs.statSync(dir);
      return { exists: true, modifiedAt: stat.mtime.toISOString() };
    } catch {
      return { exists: false, modifiedAt: '' };
    }
  };
  return {
    tenantId,
    authRoot: WA_AUTH_ROOT,
    baileysAuthRoot: BAILEYS_AUTH_ROOT,
    wwebSessionDir,
    baileysSessionDir,
    wwebSession: statSafe(wwebSessionDir),
    baileysSession: statSafe(baileysSessionDir),
    hasSession: hasWASession(tenantId),
    lockFiles: locks,
    hasLocks: locks.length > 0
  };
}

function buildWAConnectionDiagnostics(tenantId = 'default', options = {}) {
  const inst = waClients.get(tenantId);
  const session = waSessionDiagnostics(tenantId);
  const generatedAt = inst?.qrGeneratedAt || (waLastQR.tenantId === tenantId ? waLastQR.generatedAt : 0);
  const qrAgeSec = generatedAt ? Math.round((Date.now() - generatedAt) / 1000) : null;
  const status = inst?.isReady ? 'ready' : (inst?.status || waLastState.status || (inst ? 'starting' : 'idle'));
  const message = inst?.isReady ? 'WhatsApp linked' : (inst?.statusMsg || waLastState.message || (inst ? 'Starting WhatsApp...' : 'Idle'));
  const error = inst?.error || waLastState.error || '';
  const staleStarting = !inst?.isReady && ['starting', 'launching', 'cleaning', 'authenticated', 'pairing'].includes(String(status || '')) && inst?.lastEventAt && (Date.now() - inst.lastEventAt > WA_STALE_STARTING_MS);
  const qrExpired = !inst?.isReady && !!(inst?.qr || (waLastQR.tenantId === tenantId && waLastQR.data)) && qrAgeSec !== null && qrAgeSec > Math.round(WA_QR_TTL_MS / 1000);
  let recommendation = 'Click Connect / Refresh QR and scan the current QR.';
  let action = 'connect';
  if (inst?.isReady) {
    recommendation = 'WhatsApp is linked. No action needed.';
    action = 'none';
  } else if (/auth|logged out|logout/i.test(`${status} ${message} ${error}`)) {
    recommendation = 'Auth/session looks invalid. Use Fresh Reset, then scan the new QR.';
    action = 'fresh_reset';
  } else if (staleStarting) {
    recommendation = 'Startup looks stuck. Use Soft Recover first; it keeps the saved session and relaunches WhatsApp.';
    action = 'soft_recover';
  } else if (qrExpired) {
    recommendation = 'QR expired. Click Connect / Refresh QR for a fresh QR.';
    action = 'refresh_qr';
  } else if (status === 'qr') {
    recommendation = 'Scan this QR from WhatsApp > Linked devices. If phone says cannot link, try Soft Recover, then Fresh Reset.';
    action = 'scan_qr';
  } else if (session.hasLocks && (!inst || ['idle', 'disconnected', 'error'].includes(String(status || '').toLowerCase()))) {
    recommendation = 'Session lock files are present but WhatsApp is not actively running. Soft Recover can clear stale browser locks without deleting auth.';
    action = 'soft_recover';
  }

  const diagnostics = {
    tenantId,
    engine: WA_ENGINE,
    connected: !!inst?.isReady,
    status,
    message,
    error,
    recommendation,
    action,
    startedAt: inst?.startedAt ? new Date(inst.startedAt).toISOString() : '',
    lastEventAt: inst?.lastEventAt ? new Date(inst.lastEventAt).toISOString() : '',
    qrAgeSec,
    qrExpired,
    staleStarting: !!staleStarting,
    pairing: {
      codeAvailable: !!inst?.pairingCode,
      phone: inst?.pairingPhone || '',
      generatedAt: inst?.pairingGeneratedAt || 0
    },
    proxy: {
      enabled: !!getWhatsAppProxyUrl(),
      url: getWhatsAppProxyUrl() ? getWhatsAppProxyUrl().replace(/\/\/.*@/, '//***@') : '',
      systemProxy: /^(1|true|yes)$/i.test(String(process.env.WA_USE_SYSTEM_PROXY || '')),
      disabled: /^(1|true|yes)$/i.test(String(process.env.WA_DISABLE_PROXY || ''))
    },
    browserPath: resolveBrowserExecutablePath() || '',
    session
  };
  if (options.includeLogs) {
    diagnostics.logs = {
      out: safeTailText(path.join(__dirname, 'server-runtime.out'), 30),
      err: safeTailText(path.join(__dirname, 'server-runtime.err'), 30)
    };
  }
  return diagnostics;
}

function emitWAState(update = {}) {
  waLastState = {
    ...waLastState,
    ...update,
    connected: update.connected !== undefined ? !!update.connected : !!waLastState.connected
  };
  io.emit('wa_status', {
    connected: !!waLastState.connected,
    msg: waLastState.message,
    message: waLastState.message,
    status: waLastState.status,
    error: waLastState.error || '',
    hasSession: hasWASession('default')
  });
}

function resolveBrowserExecutablePath() {
  const env = process.env.CHROME_PATH || process.env.PUPPETEER_EXECUTABLE_PATH;
  if (env && fs.existsSync(env)) return env;

  const candidates = [
    'C:\\\\Program Files\\\\Google\\\\Chrome\\\\Application\\\\chrome.exe',
    'C:\\\\Program Files (x86)\\\\Google\\\\Chrome\\\\Application\\\\chrome.exe',
    'C:\\\\Program Files\\\\Microsoft\\\\Edge\\\\Application\\\\msedge.exe',
    'C:\\\\Program Files (x86)\\\\Microsoft\\\\Edge\\\\Application\\\\msedge.exe'
  ];
  for (const c of candidates) {
    try { if (fs.existsSync(c)) return c; } catch {}
  }
  return undefined;
}

function removeSessionLockFiles(sessionDir) {
  const lockFiles = ['SingletonLock', 'SingletonCookie', 'SingletonSocket', 'DevToolsActivePort', 'lockfile'];
  const removed = [];
  for (const name of lockFiles) {
    const p = path.join(sessionDir, name);
    try {
      if (fs.existsSync(p)) {
        fs.rmSync(p, { force: true, recursive: true });
        removed.push(name);
      }
    } catch (e) {
      console.warn('[WA] Could not remove lock file:', p, e.message);
    }
  }
  return removed;
}

function hasSessionLockFiles(sessionDir) {
  return ['SingletonLock', 'SingletonCookie', 'SingletonSocket', 'DevToolsActivePort', 'lockfile'].some(name => {
    try { return fs.existsSync(path.join(sessionDir, name)); } catch { return false; }
  });
}

function killChromiumForSession(sessionDir) {
  const killed = [];
  const target = path.resolve(sessionDir);
  const root = path.resolve(WA_AUTH_ROOT);
  const marker = path.basename(sessionDir).toLowerCase();
  try {
    if (process.platform === 'win32') {
      const escaped = target.replace(/'/g, "''");
      const escapedRoot = root.replace(/'/g, "''");
      const escapedMarker = marker.replace(/'/g, "''");
      const script = `
$target = '${escaped}';
$root = '${escapedRoot}';
$marker = '${escapedMarker}';
$targetNorm = ($target -replace '/', '\\').ToLowerInvariant();
$rootNorm = ($root -replace '/', '\\').ToLowerInvariant();
Get-CimInstance Win32_Process | ForEach-Object {
  if ($_.Name -match '^(chrome|chromium|msedge)(\\.exe)?$' -and $_.CommandLine) {
    $cmd = ($_.CommandLine -replace '/', '\\').ToLowerInvariant();
    $matchesProfile = $cmd.Contains($targetNorm) -or ($cmd.Contains($rootNorm) -and $cmd.Contains($marker)) -or ($cmd.Contains('.wa-auth') -and $cmd.Contains($marker));
    if ($matchesProfile) {
      try {
        Stop-Process -Id $_.ProcessId -Force -ErrorAction Stop;
        Write-Output $_.ProcessId;
      } catch {}
    }
  }
}`;
      const out = execFileSync('powershell.exe', ['-NoProfile', '-ExecutionPolicy', 'Bypass', '-Command', script], { encoding: 'utf8', windowsHide: true });
      out.split(/\r?\n/).map(x => x.trim()).filter(Boolean).forEach(x => killed.push(x));
    } else {
      const out = execFileSync('ps', ['-eo', 'pid=,comm=,args='], { encoding: 'utf8' });
      for (const line of out.split('\n')) {
        if (!/(chrome|chromium|msedge)/i.test(line)) continue;
        const norm = line.replace(/\//g, path.sep).toLowerCase();
        if (!norm.includes(target.toLowerCase()) && !(norm.includes(root.toLowerCase()) && norm.includes(marker)) && !(norm.includes('.wa-auth') && norm.includes(marker))) continue;
        const pid = Number((line.trim().match(/^(\d+)/) || [])[1]);
        if (pid && pid !== process.pid) {
          try { process.kill(pid, 'SIGKILL'); killed.push(String(pid)); } catch {}
        }
      }
    }
  } catch (e) {
    console.warn('[WA] Chromium cleanup skipped:', e.message);
  }
  return killed;
}

async function preflightCleanupWA(tenantId = 'default', options = {}) {
  const sessionDir = getWASessionDir(tenantId);
  emitWAState({ connected: false, status: 'cleaning', message: 'Cleaning session...', error: '' });
  try { fs.mkdirSync(WA_AUTH_ROOT, { recursive: true }); } catch {}
  try { fs.mkdirSync(WA_WEB_CACHE_PATH, { recursive: true }); } catch {}
  const shouldScanProcesses = options.forceKill || fs.existsSync(sessionDir) || hasSessionLockFiles(sessionDir);
  const killed = shouldScanProcesses ? killChromiumForSession(sessionDir) : [];
  const removed = removeSessionLockFiles(sessionDir);
  if (options.removeSession) {
    try { if (fs.existsSync(sessionDir)) fs.rmSync(sessionDir, { recursive: true, force: true }); } catch (e) {
      console.warn('[WA] Session remove failed:', e.message);
    }
  }
  if (killed.length || removed.length) {
    console.log(`[WA] Cleanup complete. killed=${killed.join(',') || 'none'} removed=${removed.join(',') || 'none'}`);
  }
  await sleep(250);
}

function setWAInstanceStatus(instance, status, msg, extra = {}) {
  if (!instance) return;
  if (instance.tenantId && waClients.get(instance.tenantId) !== instance) return;
  instance.status = status;
  instance.statusMsg = msg || '';
  instance.lastEventAt = Date.now();
  if (extra.error !== undefined) instance.error = extra.error || '';
  // Only broadcast the user-facing fields.
  emitWAState({ connected: !!instance.isReady, status: instance.status, message: instance.statusMsg, error: instance.error || '' });
}

function isCurrentWAInstance(tenantId, instance) {
  return !!instance && waClients.get(tenantId) === instance;
}

async function destroyWAInstance(instance, tenantId = 'default', reason = 'cleanup') {
  if (!instance?.client) return;
  instance.destroying = true;
  try {
    await Promise.race([
      instance.client.destroy(),
      sleep(10000).then(() => { throw new Error('destroy_timeout'); })
    ]);
  } catch (error) {
    console.warn(`[WA] Destroy skipped/failed for ${tenantId} (${reason}): ${error.message}`);
  }
}

