function baileysToWWebId(jid = '') {
  if (!jid) return '';
  return jid.replace('@s.whatsapp.net', '@c.us');
}

function wwebToBaileysJid(id = '') {
  const raw = String(id || '').trim();
  if (!raw) return raw;
  if (raw.endsWith('@g.us')) return raw;
  if (raw.endsWith('@lid')) return raw;
  if (raw.endsWith('@newsletter')) return raw;
  if (raw.endsWith('@s.whatsapp.net')) return raw;
  if (raw.endsWith('@c.us')) return raw.replace('@c.us', '@s.whatsapp.net');
  if (looksLikeWhatsAppGroupId(raw)) return raw.replace(/\D/g, '') + '@g.us';
  return raw.replace(/\D/g, '') + '@s.whatsapp.net';
}

function baileysMessageText(message = {}) {
  const m = message.message || {};
  return m.conversation ||
    m.extendedTextMessage?.text ||
    m.imageMessage?.caption ||
    m.videoMessage?.caption ||
    m.documentMessage?.caption ||
    m.buttonsResponseMessage?.selectedDisplayText ||
    m.listResponseMessage?.title ||
    '';
}

function baileysMessageType(message = {}) {
  const m = message.message || {};
  if (m.imageMessage) return 'image';
  if (m.videoMessage) return 'video';
  if (m.audioMessage) return 'audio';
  if (m.documentMessage) return 'document';
  if (m.buttonsResponseMessage) return 'button_response';
  if (m.listResponseMessage) return 'list_response';
  return 'chat';
}

function appendLiveMessage(instance, chatId, message) {
  if (!instance?.liveMessages || !chatId) return;
  const list = instance.liveMessages.get(chatId) || [];
  list.push(message);
  instance.liveMessages.set(chatId, list.slice(-200));
}

function payloadMessageType(payload = {}) {
  if (payload.image) return 'image';
  if (payload.video) return 'video';
  if (payload.audio) return payload.ptt ? 'ptt' : 'audio';
  if (payload.document) return 'document';
  return 'chat';
}

function payloadMessageText(payload = {}, options = {}) {
  return payload.text || payload.caption || options.caption || '';
}

function makeBaileysAdapter(sock, instance) {
  const adapter = {
    sendMessage: async (chatId, content, options = {}) => {
      const jid = wwebToBaileysJid(chatId);
      let payload;
      if (typeof content === 'string') {
        payload = { text: cleanOutgoingText(content) };
      } else if (content?.data && content?.mimetype) {
        const buffer = Buffer.from(content.data, 'base64');
        const caption = cleanOutgoingText(options.caption || '');
        if (content.mimetype.startsWith('image/')) payload = { image: buffer, caption };
        else if (content.mimetype.startsWith('video/')) payload = { video: buffer, caption };
        else if (content.mimetype.startsWith('audio/')) payload = { audio: buffer, mimetype: content.mimetype, ptt: !!options.sendAudioAsVoice };
        else payload = { document: buffer, mimetype: content.mimetype, fileName: content.filename || 'file', caption };
      } else {
        payload = { text: cleanOutgoingText(String(content?.text || content?.body || '')) };
      }
      const sent = await sock.sendMessage(jid, payload);
      const wwebChatId = baileysToWWebId(jid);
      if (!instance.liveChats.has(wwebChatId)) {
        instance.liveChats.set(wwebChatId, {
          id: { _serialized: wwebChatId },
          name: wwebChatId,
          isGroup: wwebChatId.endsWith('@g.us'),
          participants: [],
          timestamp: Math.floor(Date.now() / 1000)
        });
      }
      appendLiveMessage(instance, wwebChatId, {
        id: { _serialized: sent?.key?.id || uuid() },
        body: payloadMessageText(payload, options),
        fromMe: true,
        timestamp: Math.floor(Date.now() / 1000),
        type: payloadMessageType(payload),
        from: 'me',
        to: wwebChatId,
        author: null
      });
      return { id: { _serialized: sent?.key?.id || uuid() }, raw: sent };
    },
    getChats: async () => Array.from(instance.liveChats.values()),
    getContacts: async () => Array.from(instance.liveContacts.values()),
    getContactById: async (id) => {
      const user = String(id || '').split('@')[0].replace(/\D/g, '');
      return { id: { _serialized: baileysToWWebId(id), user }, number: user, name: user, pushname: user };
    },
    getChatById: async (id) => {
      const jid = wwebToBaileysJid(id);
      const wwebId = baileysToWWebId(jid);
      const chat = instance.liveChats.get(wwebId) || { id: { _serialized: wwebId }, name: wwebId, isGroup: wwebId.endsWith('@g.us'), participants: [] };
      return {
        ...chat,
        id: { _serialized: wwebId },
        sendMessage: (text) => adapter.sendMessage(wwebId, text),
        fetchMessages: async ({ limit = 50 } = {}) => (instance.liveMessages.get(wwebId) || []).slice(-Number(limit || 50))
      };
    },
    destroy: async () => {
      try { sock.end(new Error('Manual disconnect')); } catch {}
    }
  };
  return adapter;
}

async function handleBaileysIncoming(instance, m) {
  const remoteJid = m.key?.remoteJid || '';
  if (!remoteJid || remoteJid === 'status@broadcast') return;
  const isNewsletter = remoteJid.endsWith('@newsletter');
  const isGroup = !isNewsletter && (remoteJid.endsWith('@g.us') || remoteJid.startsWith('120363'));
  const chatId = baileysToWWebId(remoteJid);
  const body = baileysMessageText(m);
  const fromMe = !!m.key?.fromMe;
  if (fromMe && !isWhatsAppSocialCommand(body)) return;
  const authorJid = isGroup ? (m.key.participant || '') : remoteJid;
  const senderNumber = (authorJid.split('@')[0] || '').replace(/\D/g, '');
  const senderName = m.pushName || senderNumber || 'Member';
  const chatName = instance.liveChats.get(chatId)?.name || (isGroup ? (instance.liveChats.get(remoteJid)?.name || chatId) : senderName);
  const messageId = m.key?.id || uuid();

  instance.liveChats.set(chatId, {
    id: { _serialized: chatId },
    name: chatName,
    isGroup,
    participants: [],
    timestamp: m.messageTimestamp ? Number(m.messageTimestamp) : Math.floor(Date.now() / 1000)
  });
  appendLiveMessage(instance, chatId, {
    id: { _serialized: messageId },
    body,
    fromMe: false,
    timestamp: m.messageTimestamp ? Number(m.messageTimestamp) : Math.floor(Date.now() / 1000),
    type: baileysMessageType(m),
    from: isGroup ? baileysToWWebId(authorJid) : chatId,
    to: 'me',
    author: isGroup ? baileysToWWebId(authorJid) : null
  });

  if (isNewsletter) {
    mergeWhatsAppChannelDiscoveries([{
      channelId: chatId,
      name: chatName,
      source: 'baileys-incoming',
      discoveredAt: new Date().toISOString()
    }]);
    try {
      const inboxMsg = {
        id: messageId || uuid(),
        source: 'whatsapp-channel',
        chatId,
        isGroup: false,
        groupId: null,
        groupName: null,
        authorId: null,
        authorName: chatName,
        authorNumber: null,
        number: null,
        name: chatName,
        body,
        timestamp: new Date((Number(m.messageTimestamp) || Math.floor(Date.now() / 1000)) * 1000).toISOString(),
        read: false
      };
      inbox.unshift(inboxMsg);
      if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
      saveInbox();
      io.emit('incoming_message', inboxMsg);
      triggerWebhooks('new_channel_message', inboxMsg);
    } catch {}
    try {
      await ingestWhatsAppChannelRelayMessage({
        channelId: chatId,
        channelName: chatName,
        messageId,
        body,
        timestamp: new Date((Number(m.messageTimestamp) || Math.floor(Date.now() / 1000)) * 1000).toISOString()
      });
    } catch (error) {
      console.warn('[ChannelCopy] Baileys channel relay skipped:', error.message);
    }
    return;
  }

  try {
    const inboxMsg = {
      id: messageId,
      source: 'whatsapp',
      chatId,
      isGroup,
      groupId: isGroup ? chatId : null,
      groupName: isGroup ? chatName : null,
      authorId: isGroup ? baileysToWWebId(authorJid) : null,
      authorName: isGroup ? senderName : null,
      authorNumber: isGroup ? senderNumber : null,
      number: isGroup ? null : senderNumber,
      name: isGroup ? chatName : (senderName || senderNumber || 'Customer'),
      body,
      timestamp: new Date((Number(m.messageTimestamp) || Math.floor(Date.now() / 1000)) * 1000).toISOString(),
      read: false
    };
    inbox.unshift(inboxMsg);
    if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
    saveInbox();
    io.emit('incoming_message', inboxMsg);
    triggerWebhooks('new_message', inboxMsg);
    if (!isGroup && settings.instant_message_alerts !== false) {
      createSystemAlert({
        type: 'message',
        title: 'New WhatsApp message',
        message: `${inboxMsg.name || inboxMsg.number}: ${(body || '').slice(0, 140)}`,
        severity: 'info',
        source: 'whatsapp',
        meta: { chatId, number: senderNumber, messageId }
      });
    }
  } catch {}

  try {
    if (!isGroup && settings.reply_speed_tracking_enabled !== false) {
      messageAnalytics.recordInboundMessage({
        from: senderNumber,
        number: senderNumber,
        chatId,
        content: body,
        type: baileysMessageType(m),
        source: 'whatsapp',
        name: senderName || senderNumber
      });
    }
  } catch {}

  try {
    const handledSocialCommand = await handleWhatsAppSocialAdminCommand({
      body,
      senderNumber,
      senderName,
      chatId,
      isGroup,
      fromMe,
      engine: 'baileys',
      reply: async (replyText) => instance.client.sendMessage(remoteJid, { text: replyText })
    });
    if (handledSocialCommand) return;
  } catch (e) {
    console.warn('[SocialCommand] Baileys command skipped:', e.message);
  }

  if (isGroup) {
    const groupMsg = {
      from: chatId,
      body,
      author: baileysToWWebId(authorJid),
      id: { _serialized: messageId },
      timestamp: Number(m.messageTimestamp) || Math.floor(Date.now() / 1000),
      fromMe: false,
      groupName: chatName,
      senderName,
      senderNumber,
      getChat: async () => ({ id: { _serialized: chatId }, name: chatName, isGroup: true }),
      getContact: async () => ({
        id: { _serialized: baileysToWWebId(authorJid), user: senderNumber },
        number: senderNumber,
        pushname: senderName,
        name: senderName
      }),
      reply: async (replyText) => instance.client.sendMessage(chatId, { text: replyText })
    };
    try {
      if (typeof groupPriceCapture.processGroupMessage === 'function') await groupPriceCapture.processGroupMessage(groupMsg);
    } catch (e) { console.warn('[Groups] price capture skipped:', e.message); }
    try {
      if (typeof groupAnalytics.trackGroupActivity === 'function') await groupAnalytics.trackGroupActivity(groupMsg);
      if (typeof groupAnalytics.detectBuyingSignal === 'function') await groupAnalytics.detectBuyingSignal(groupMsg);
    } catch (e) { console.warn('[Groups] analytics skipped:', e.message); }
    try {
      if (typeof groupAutoReply.checkGroupAutoReply === 'function') await groupAutoReply.checkGroupAutoReply(groupMsg);
    } catch (e) { console.warn('[Groups] auto-reply skipped:', e.message); }
    try {
      await captureGroupPriceIntel({
        body,
        groupId: chatId,
        groupName: chatName,
        seller: senderName || senderNumber || 'Unknown',
        sellerNumber,
        sellerId: baileysToWWebId(authorJid),
        messageId,
        timestamp: new Date((Number(m.messageTimestamp) || Math.floor(Date.now() / 1000)) * 1000).toISOString()
      }, { useAI: false });
    } catch {}
    try {
      await captureScholarshipFromWhatsApp({
        body,
        groupId: chatId,
        groupName: chatName,
        senderName: senderName || senderNumber,
        senderNumber,
        messageId,
        timestamp: new Date((Number(m.messageTimestamp) || Math.floor(Date.now() / 1000)) * 1000).toISOString()
      });
    } catch (e) { console.warn('[ScholarshipPipeline] capture skipped:', e.message); }
    try {
      await handleStockSourcingGroupOffer({
        body,
        groupId: chatId,
        groupName: chatName,
        authorNumber: senderNumber,
        authorName: senderName || senderNumber,
        messageId
      });
    } catch (e) { console.warn('[StockSourcing] group offer skipped:', e.message); }
    return;
  }

  let existingCustomer = customers.find(c => c.number === senderNumber);
  if (!existingCustomer) {
    existingCustomer = {
      id: uuid(),
      name: senderName || senderNumber,
      number: senderNumber,
      status: 'lead',
      tags: ['New'],
      messageCount: 1,
      lastActive: new Date().toISOString(),
      buyerIntent: 'COLD'
    };
    customers.push(existingCustomer);
    saveJSON('customers.json', customers);
    io.emit('new_lead', existingCustomer);
    triggerWebhooks('new_lead', existingCustomer);
  } else {
    existingCustomer.messageCount = (existingCustomer.messageCount || 0) + 1;
    existingCustomer.lastActive = new Date().toISOString();
    saveJSON('customers.json', customers);
  }

  if (existingCustomer?.id) {
    setImmediate(() => {
      sentimentAnalyzer.recordSentiment(existingCustomer.id, body, 'inbound')
        .catch(e => console.error('Sentiment analysis failed:', e.message));
    });
  }
  try { if (detectBuyingSignal(body || '')) await emitLeadSignal(senderNumber, senderName, body || '', existingCustomer || null); } catch {}
  try { if (await checkFlows(senderNumber, body || '', senderName)) return; } catch {}
  if (settings.laptop_bot_enabled) {
    try {
      await handleWAConversation(senderNumber, body, senderName);
    } catch (error) {
      console.error(`[Bot] Failed to handle Baileys conversation for ${senderNumber}:`, error.message);
    }
  }
}

async function getOrCreateBaileysClient(tenantId = 'default') {
  const { makeWASocket, useMultiFileAuthState, fetchLatestBaileysVersion, DisconnectReason, Browsers, pino } = getBaileys();
  const existing = waClients.get(tenantId);
  if (existing?.clientKind === 'baileys' && !['disconnected', 'error', 'auth_failure'].includes(existing.status)) return existing;
  if (existing?.client) await destroyWAInstance(existing, tenantId, 'replace-baileys');
  waClients.delete(tenantId);

  const authDir = path.join(BAILEYS_AUTH_ROOT, tenantId);
  fs.mkdirSync(authDir, { recursive: true });
  emitWAState({ connected: false, status: 'launching', message: 'Launching WhatsApp socket...', error: '' });
  const { state, saveCreds } = await useMultiFileAuthState(authDir);
  const version = await resolveBaileysVersion(fetchLatestBaileysVersion);
  const instance = {
    clientKind: 'baileys',
    authState: state,
    status: 'starting',
    statusMsg: 'Loading QR...',
    error: '',
    isReady: false,
    qr: null,
    info: null,
    liveChats: new Map(),
    liveContacts: new Map(),
    liveMessages: new Map(),
    lastEventAt: Date.now()
  };
  const socketOptions = {
    auth: state,
    printQRInTerminal: false,
    logger: pino({ level: 'silent' }),
    browser: Browsers?.macOS ? Browsers.macOS('Desktop') : ['Desktop', 'Chrome', '131.0.0.0'],
    syncFullHistory: false,
    markOnlineOnConnect: false
  };
  const waProxyAgent = createWhatsAppProxyAgent('WhatsApp Baileys websocket');
  if (waProxyAgent) {
    socketOptions.agent = waProxyAgent;
    socketOptions.options = {
      ...(socketOptions.options || {}),
      agent: waProxyAgent
    };
  }
  if (version) socketOptions.version = version;
  const sock = makeWASocket(socketOptions);
  instance.sock = sock;
  instance.client = makeBaileysAdapter(sock, instance);
  waClients.set(tenantId, instance);
  setWAInstanceStatus(instance, 'starting', 'Loading QR...');

  sock.ev.on('creds.update', saveCreds);
  sock.ev.on('connection.update', async (update) => {
    const { connection, lastDisconnect, qr } = update;
    if (qr) {
      instance.qr = await qrcode.toDataURL(qr);
      instance.qrGeneratedAt = Date.now();
      instance.pairingCode = null;
      instance.pairingGeneratedAt = 0;
      waLastQR = { tenantId, data: instance.qr, generatedAt: instance.qrGeneratedAt };
      io.emit('wa_qr', instance.qr);
      setWAInstanceStatus(instance, 'qr', 'Scan now');
    }
    if (connection === 'open') {
      instance.isReady = true;
      instance.qr = null;
      instance.qrGeneratedAt = 0;
      instance.pairingCode = null;
      instance.pairingGeneratedAt = 0;
      waLastQR = { tenantId: null, data: null, generatedAt: 0 };
      instance.info = sock.user || {};
      const rawId = sock.user?.id || '';
      const number = rawId ? ('+' + rawId.split(':')[0].replace(/\D/g, '')) : '';
      const name = sock.user?.name || sock.user?.verifiedName || 'Connected';
      io.emit('wa_ready', { name, number, raw: sock.user });
      setWAInstanceStatus(instance, 'ready', 'WhatsApp linked');
    }
    if (connection === 'close') {
      const code = lastDisconnect?.error?.output?.statusCode;
      try {
        const err = lastDisconnect?.error;
        console.warn('[Baileys] connection closed', {
          code,
          message: err?.message || '',
          name: err?.name || '',
          data: err?.data || null,
          output: err?.output || null,
          stack: process.env.WA_DEBUG_STACK === '1' ? err?.stack : undefined
        });
      } catch {}
      instance.isReady = false;
      instance.qr = null;
      instance.qrGeneratedAt = 0;
      instance.pairingCode = null;
      instance.pairingGeneratedAt = 0;
      if (code === DisconnectReason.loggedOut) {
        waClients.delete(tenantId);
        try { fs.rmSync(path.join(BAILEYS_AUTH_ROOT, tenantId), { recursive: true, force: true }); } catch {}
        waLastQR = { tenantId: null, data: null, generatedAt: 0 };
        setWAInstanceStatus(instance, 'disconnected', 'Logged out. Click Connect for a fresh QR.');
      } else if (code === 515) {
        waClients.delete(tenantId);
        setWAInstanceStatus(instance, 'starting', 'WhatsApp requested restart. Reconnecting...', { error: '' });
        setTimeout(() => {
          getOrCreateBaileysClient(tenantId).catch(error => {
            console.error('[Baileys] restart reconnect failed:', error.message);
            emitWAState({ connected: false, status: 'disconnected', message: 'Reconnect failed. Try Connect again.', error: error.message });
          });
        }, 1200);
      } else {
        waClients.delete(tenantId);
        setWAInstanceStatus(instance, 'disconnected', 'Disconnected. Click Connect to retry.', { error: lastDisconnect?.error?.message || '' });
      }
    }
  });
  sock.ev.on('messages.upsert', async ({ messages }) => {
    for (const m of messages || []) {
      try { await handleBaileysIncoming(instance, m); } catch (e) { console.error('[Baileys] incoming handler failed:', e.message); }
    }
  });
  sock.ev.on('chats.set', ({ chats }) => {
    for (const c of chats || []) {
      const id = baileysToWWebId(c.id);
      instance.liveChats.set(id, { id: { _serialized: id }, name: c.name || c.subject || id, isGroup: id.endsWith('@g.us'), participants: [] });
    }
  });
  sock.ev.on('chats.upsert', (chats) => {
    for (const c of chats || []) {
      const id = baileysToWWebId(c.id);
      instance.liveChats.set(id, { id: { _serialized: id }, name: c.name || c.subject || id, isGroup: id.endsWith('@g.us'), participants: [] });
    }
  });
  const upsertBaileysContacts = (items = []) => {
    for (const c of items || []) {
      const id = baileysToWWebId(c.id || c.jid || '');
      if (!id || id === 'status@broadcast' || id.endsWith('@g.us')) continue;
      const user = id.split('@')[0].replace(/\D/g, '');
      if (!user) continue;
      instance.liveContacts.set(id, {
        id: { _serialized: id, user, server: 'c.us' },
        number: user,
        name: c.name || c.notify || c.verifiedName || user,
        pushname: c.notify || c.name || user,
        isMyContact: true
      });
    }
  };
  sock.ev.on('contacts.set', ({ contacts }) => upsertBaileysContacts(contacts));
  sock.ev.on('contacts.upsert', upsertBaileysContacts);
  return instance;
}

async function getOrCreateWAClient(tenantId = 'default', attempt = 0) {
  if (WA_ENGINE === 'baileys') return getOrCreateBaileysClient(tenantId);
  const existing = waClients.get(tenantId);
  const qrAge = existing?.qrGeneratedAt ? Date.now() - existing.qrGeneratedAt : 0;
  const staleQR = existing && !existing.isReady && existing.status === 'qr' && qrAge > WA_QR_TTL_MS;
  const staleStarting = existing && !existing.isReady && ['starting', 'launching', 'cleaning', 'authenticated', 'retrying'].includes(existing.status) && (Date.now() - (existing.lastEventAt || 0) > WA_STALE_STARTING_MS);
  if (existing?.isReady) {
    return existing;
  }
  if (existing?.status === 'error' || existing?.status === 'auth_failure' || staleStarting || staleQR || existing?.status === 'disconnected') {
    await destroyWAInstance(existing, tenantId, 'replace-stale');
    waClients.delete(tenantId);
  } else if (existing) {
    return existing;
  }
  await preflightCleanupWA(tenantId, { forceKill: true });
   const exePath = resolveBrowserExecutablePath();
  const { Client, LocalAuth } = getWWebJS();
  const puppeteerProxyUrl = getWhatsAppProxyUrl();
  const puppeteerProxyArgs = puppeteerProxyUrl ? [`--proxy-server=${puppeteerProxyUrl}`] : [];
  if (puppeteerProxyUrl) console.log(`[Proxy] WhatsApp Web browser using ${puppeteerProxyUrl.replace(/\/\/.*@/, '//***@')}`);
  emitWAState({ connected: false, status: 'launching', message: 'Launching browser...', error: '' });
  const instance = {
    tenantId,
    client: new Client({
      authStrategy: new LocalAuth({ clientId: tenantId, dataPath: WA_AUTH_ROOT }),
      authTimeoutMs: 45000,
      qrMaxRetries: 8,
      restartOnAuthFail: true,
      takeoverOnConflict: true,
      takeoverTimeoutMs: 0,
      webVersionCache: {
        type: 'local',
        path: WA_WEB_CACHE_PATH,
        strict: false
      },
      puppeteer: { 
        headless: true,
        ...(exePath ? { executablePath: exePath } : {}),
        args: [
          '--no-sandbox',
          '--disable-setuid-sandbox',
          '--disable-dev-shm-usage',
            '--disable-gpu',
            '--no-first-run',
          '--no-zygote',
          '--disable-extensions',
          '--disable-background-networking',
            '--disable-sync',
            ...puppeteerProxyArgs
          ]
        }
      }),
    isReady: false,
    qr: null,
    info: null,
    status: 'starting',
      statusMsg: 'Starting WhatsApp...',
      error: '',
      initRetryCount: 0,
      startedAt: Date.now(),
      lastEventAt: Date.now()
    };
  
   instance.client.on('qr', async qr => {
      if (!isCurrentWAInstance(tenantId, instance) || instance.isReady || instance.destroying) return;
      if (instance.startupTimer) clearTimeout(instance.startupTimer);
      console.log(`[WA] QR ready in ${Math.round((Date.now() - instance.startedAt) / 1000)}s`);
      try {
      instance.qr = await qrcode.toDataURL(qr);
      instance.qrGeneratedAt = Date.now();
      waLastQR = { tenantId, data: instance.qr, generatedAt: instance.qrGeneratedAt };
    } catch {
      instance.qr = null;
      instance.qrGeneratedAt = 0;
    }
      io.emit('wa_qr', instance.qr);
      setWAInstanceStatus(instance, 'qr', 'Scan now');
    });

   instance.client.on('authenticated', () => {
     if (!isCurrentWAInstance(tenantId, instance) || instance.destroying) return;
     console.log(`[WA] Authenticated in ${Math.round((Date.now() - instance.startedAt) / 1000)}s`);
     setWAInstanceStatus(instance, 'authenticated', 'Authenticated... Finalizing');
   });

   instance.client.on('loading_screen', (percent, message) => {
     if (!isCurrentWAInstance(tenantId, instance) || instance.isReady || instance.destroying) return;
     setWAInstanceStatus(instance, 'starting', `Loading WhatsApp ${percent || 0}%${message ? ' - ' + message : ''}`);
   });

   instance.client.on('auth_failure', (msg) => {
     if (!isCurrentWAInstance(tenantId, instance) || instance.destroying) return;
     if (instance.startupTimer) clearTimeout(instance.startupTimer);
     setWAInstanceStatus(instance, 'auth_failure', 'Auth failed. Click Disconnect then Connect for a fresh QR.', { error: msg || 'auth_failure' });
     // Best-effort cleanup so "Connect" works again.
     (async () => {
       await destroyWAInstance(instance, tenantId, 'auth-failure');
       if (isCurrentWAInstance(tenantId, instance)) waClients.delete(tenantId);
     })();
   });
  
   instance.client.on('ready', () => {
      if (!isCurrentWAInstance(tenantId, instance) || instance.destroying) return;
      if (instance.startupTimer) clearTimeout(instance.startupTimer);
      console.log(`[WA] Ready in ${Math.round((Date.now() - instance.startedAt) / 1000)}s`);
      instance.isReady = true; instance.qr = null; instance.qrGeneratedAt = 0; waLastQR = { tenantId: null, data: null, generatedAt: 0 }; instance.info = instance.client.info;
     const info = instance.info || {};
     const name = info.pushname || info.name || 'Connected';
     const number = info?.wid?.user ? ('+' + info.wid.user) : (info?.me?.user ? ('+' + info.me.user) : '');
     io.emit('wa_ready', { name, number, raw: info });
     setWAInstanceStatus(instance, 'ready', 'WhatsApp linked');
     console.log(`WA Client ${tenantId} is ready!`);
     
     // Set up message event listeners for delivery tracking
     setupMessageEventListeners(instance.client, tenantId);
   });
  
  instance.client.on('disconnected', () => {
      if (!isCurrentWAInstance(tenantId, instance) || instance.destroying) return;
      if (instance.startupTimer) clearTimeout(instance.startupTimer);
      instance.isReady = false; instance.info = null;
    setWAInstanceStatus(instance, 'disconnected', 'Disconnected');
    waClients.delete(tenantId);
  });
  
    instance.client.on('message', async msg => {
      if (!isCurrentWAInstance(tenantId, instance) || instance.destroying) return;
      if (msg.from === 'status@broadcast') return;
      let isGroup = !!msg.isGroupMsg || (typeof msg.from === 'string' && msg.from.endsWith('@g.us'));
      const messageId = msg.id?._serialized || '';

      // Sender info
      let contact = null;
      try { contact = await msg.getContact(); } catch {}
      const senderName = contact?.pushname || contact?.name || contact?.number || '';
      const senderNumber = (contact?.number || contact?.id?.user || '').replace(/\D/g, '');

      // Chat info (group name etc)
      let chat = null;
      try { chat = await msg.getChat(); } catch {}
      const chatId = msg.from;
      const chatName = chat?.name || chatId;
      if (chat?.isGroup || msg.author || (typeof chatId === 'string' && (chatId.endsWith('@g.us') || chatId.startsWith('120363')))) {
        isGroup = true;
      }
      const isNewsletter = typeof chatId === 'string' && (
        chatId.endsWith('@newsletter') ||
        chat?.id?.server === 'newsletter' ||
        chat?.isNewsletter === true ||
        chat?.isChannel === true
      );

      if (isNewsletter) {
        isGroup = false;
        const channelBody = msg.body || msg.caption || msg._data?.caption || '';
        mergeWhatsAppChannelDiscoveries([{
          channelId: chatId,
          name: chatName,
          source: 'incoming-message',
          discoveredAt: new Date().toISOString()
        }]);
        try {
          const inboxMsg = {
            id: messageId || uuid(),
            source: 'whatsapp-channel',
            chatId,
            isGroup: false,
            groupId: null,
            groupName: null,
            authorId: null,
            authorName: chatName,
            authorNumber: null,
            number: null,
            name: chatName,
            body: channelBody,
            timestamp: msg.timestamp ? new Date(msg.timestamp * 1000).toISOString() : new Date().toISOString(),
            read: false
          };
          inbox.unshift(inboxMsg);
          if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
          saveInbox();
          io.emit('incoming_message', inboxMsg);
          triggerWebhooks('new_channel_message', inboxMsg);
        } catch {}
        try {
          await ingestWhatsAppChannelRelayMessage({
            channelId: chatId,
            channelName: chatName,
            messageId,
            body: channelBody,
            timestamp: msg.timestamp ? new Date(msg.timestamp * 1000).toISOString() : new Date().toISOString(),
            msg
          });
        } catch (error) {
          console.warn('[ChannelCopy] incoming channel relay skipped:', error.message);
        }
        return;
      }

      // Save to unified inbox + emit real-time event for UI
      try {
        const inboxMsg = {
          id: messageId || uuid(),
          source: 'whatsapp',
          chatId,
          isGroup,
          groupId: isGroup ? chatId : null,
          groupName: isGroup ? chatName : null,
          authorId: isGroup ? (msg.author || contact?.id?._serialized || null) : null,
          authorName: isGroup ? (senderName || senderNumber || 'Member') : null,
          authorNumber: isGroup ? senderNumber : null,
          number: isGroup ? null : senderNumber,
          name: isGroup ? chatName : (senderName || senderNumber || 'Customer'),
          body: msg.body || '',
          timestamp: msg.timestamp ? new Date(msg.timestamp * 1000).toISOString() : new Date().toISOString(),
          read: false
        };
        inbox.unshift(inboxMsg);
        if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
        saveInbox();
        io.emit('incoming_message', inboxMsg);
        triggerWebhooks('new_message', inboxMsg);
        if (!isGroup && settings.instant_message_alerts !== false) {
          createSystemAlert({
            type: 'message',
            title: 'New WhatsApp message',
            message: `${inboxMsg.name || inboxMsg.number}: ${(msg.body || '').slice(0, 140)}`,
            severity: 'info',
            source: 'whatsapp',
            meta: { chatId, number: senderNumber, messageId }
          });
        }
      } catch {}

      try {
        if (!isGroup && settings.reply_speed_tracking_enabled !== false) {
          messageAnalytics.recordInboundMessage({
            from: senderNumber,
            number: senderNumber,
            chatId,
            content: msg.body || '',
            type: msg.type || 'text',
            source: 'whatsapp',
            name: senderName || senderNumber
          });
        }
      } catch {}

      try {
        const handledSocialCommand = await handleWhatsAppSocialAdminCommand({
          body: msg.body || '',
          senderNumber,
          senderName,
          chatId,
          isGroup,
          fromMe: false,
          engine: 'wwebjs',
          reply: async (replyText) => msg.reply(replyText)
        });
        if (handledSocialCommand) return;
      } catch (e) {
        console.warn('[SocialCommand] wwebjs command skipped:', e.message);
      }

      // Group messages: do not create CRM leads; optional price intelligence capture.
      if (isGroup) {
        try {
          if (typeof groupPriceCapture.processGroupMessage === 'function') await groupPriceCapture.processGroupMessage(msg);
        } catch (e) { console.warn('[Groups] price capture skipped:', e.message); }
        try {
          if (typeof groupAnalytics.trackGroupActivity === 'function') await groupAnalytics.trackGroupActivity(msg);
          if (typeof groupAnalytics.detectBuyingSignal === 'function') await groupAnalytics.detectBuyingSignal(msg);
        } catch (e) { console.warn('[Groups] analytics skipped:', e.message); }
        try {
          if (typeof groupAutoReply.checkGroupAutoReply === 'function') await groupAutoReply.checkGroupAutoReply(msg);
        } catch (e) { console.warn('[Groups] auto-reply skipped:', e.message); }
        try {
          await captureGroupPriceIntel({
            body: msg.body || '',
            groupId: chatId,
            groupName: chatName,
            seller: senderName || senderNumber || 'Unknown',
            sellerNumber,
            sellerId: msg.author || contact?.id?._serialized || '',
            messageId,
            timestamp: msg.timestamp ? new Date(msg.timestamp * 1000).toISOString() : new Date().toISOString()
          }, { useAI: false });
        } catch {}
        try {
          await captureScholarshipFromWhatsApp({
            body: msg.body || '',
            groupId: chatId,
            groupName: chatName,
            senderName: senderName || senderNumber,
            senderNumber,
            messageId,
            timestamp: msg.timestamp ? new Date(msg.timestamp * 1000).toISOString() : new Date().toISOString()
          });
        } catch (e) { console.warn('[ScholarshipPipeline] capture skipped:', e.message); }
        try {
          await handleStockSourcingGroupOffer({
            body: msg.body || '',
            groupId: chatId,
            groupName: chatName,
            authorNumber: senderNumber,
            authorName: senderName || senderNumber,
            messageId
          });
        } catch (e) { console.warn('[StockSourcing] group offer skipped:', e.message); }
        return;
      }

      const number = senderNumber || msg.from.replace('@c.us', '').replace(/\D/g, '');
      const name = senderName || number;

      // Auto Lead Capture with enhanced tracking (non-group only)
      let existingCustomer = customers.find(c => c.number === number);
      if (!existingCustomer) {
        const newCustomer = {
          id: uuid(),
          name,
          number,
          status: 'lead',
          tags: ['New'],
          messageCount: 1,
          lastActive: new Date().toISOString(),
          buyerIntent: 'COLD' // Default intent
        };
        customers.push(newCustomer);
        saveJSON('customers.json', customers);
        io.emit('new_lead', newCustomer);
        triggerWebhooks('new_lead', newCustomer);
        existingCustomer = newCustomer;
      } else {
        // Update existing customer activity
        existingCustomer.messageCount = (existingCustomer.messageCount || 0) + 1;
        existingCustomer.lastActive = new Date().toISOString();
        saveJSON('customers.json', customers);
      }

      // Record sentiment for incoming message
      if (existingCustomer?.id) {
        setImmediate(() => {
          sentimentAnalyzer.recordSentiment(existingCustomer.id, msg.body, 'inbound')
            .catch(e => console.error('Sentiment analysis failed:', e.message));
        });
      }

      // Buying signal detection (pushes real-time lead signals into dashboard)
      try {
        if (detectBuyingSignal(msg.body || '')) {
          await emitLeadSignal(number, name, msg.body || '', existingCustomer || null);
        }
      } catch {}

      // Flow engine (if any flow triggers match, they can reply before AI)
      try {
        const didFlow = await checkFlows(number, msg.body || '', name);
        if (didFlow) return;
      } catch {}

      // Handle Bot (non-group only)
      if (settings.laptop_bot_enabled) {
        try {
          await handleWAConversation(number, msg.body, name);
        } catch (error) {
          console.error(`[Bot] Failed to handle WhatsApp conversation for ${number}:`, error.message);
        }
      }
    });
  
      waClients.set(tenantId, instance);
        setWAInstanceStatus(instance, 'starting', 'Loading QR...');
        instance.startupTimer = setTimeout(async () => {
          if (instance.isReady || instance.qr || waClients.get(tenantId) !== instance) return;
          if (attempt >= 2) {
            setWAInstanceStatus(instance, 'error', 'WhatsApp did not load QR in time. Click Fresh QR and try again.', { error: 'startup_timeout' });
            return;
          }
          const nextAttempt = attempt + 1;
          const forceFreshSession = nextAttempt >= 1;
          setWAInstanceStatus(instance, 'retrying', forceFreshSession ? 'Saved session was stale. Generating fresh QR...' : `Retrying WhatsApp launch... (${nextAttempt + 1}/3)`, { error: '' });
          await destroyWAInstance(instance, tenantId, 'startup-timeout');
          if (isCurrentWAInstance(tenantId, instance)) waClients.delete(tenantId);
          await preflightCleanupWA(tenantId, { removeSession: forceFreshSession, forceKill: true });
          await sleep(1000 * Math.pow(2, attempt));
          await getOrCreateWAClient(tenantId, nextAttempt);
        }, attempt === 0 && hasWASession(tenantId) ? WA_SESSION_STARTUP_TIMEOUT_MS : WA_STARTUP_TIMEOUT_MS);
        const initWA = async () => {
          try {
            await instance.client.initialize();
          } catch (e) {
            if (instance.startupTimer) clearTimeout(instance.startupTimer);
            const errMsg = e?.message || String(e);
          const retryable = /execution context was destroyed|navigation|detached|session closed|target closed|protocol error|net::err_aborted|err_aborted|timeout|browser is already running|userdataDir|userDataDir|main frame too early/i.test(errMsg);
          console.error('WA Init Error:', errMsg);
          if (retryable && attempt < 2 && waClients.get(tenantId) === instance) {
            const nextAttempt = attempt + 1;
            instance.initRetryCount = nextAttempt;
            setWAInstanceStatus(instance, 'starting', `Launching browser again... (${nextAttempt + 1}/3)`, { error: errMsg });
            await destroyWAInstance(instance, tenantId, 'init-retry');
            if (isCurrentWAInstance(tenantId, instance)) waClients.delete(tenantId);
            await preflightCleanupWA(tenantId, { removeSession: nextAttempt >= 1, forceKill: true });
            await sleep(1000 * Math.pow(2, attempt));
            if (waClients.get(tenantId) === instance) {
              waClients.delete(tenantId);
            }
            await getOrCreateWAClient(tenantId, nextAttempt);
            return;
          }
          setWAInstanceStatus(instance, 'error', 'WhatsApp failed to start: ' + errMsg, { error: errMsg });
        }
      };
      initWA();
    return instance;
  }

// Auto-start saved WhatsApp session so the bot replies after server restarts.
// Set WA_AUTO_CONNECT=false if you only want manual connection from the UI.
if (String(process.env.WA_AUTO_CONNECT || 'true').toLowerCase() !== 'false' && hasWASession('default')) {
  setTimeout(() => {
    getOrCreateWAClient('default').catch(error => {
      console.warn('[WA] Auto-connect skipped:', error.message);
    });
  }, 1500);
}

// ------------------------------------------------------------------
// MESSAGE SENDING WITH ANALYTICS
// ------------------------------------------------------------------
function looksLikeWhatsAppGroupId(value = '') {
  const raw = String(value || '').trim();
  const digits = raw.replace(/\D/g, '');
  return raw.includes('-') || /^120\d{8,}$/.test(digits);
}

function looksLikeWhatsAppLid(value = '') {
  const digits = String(value || '').replace(/\D/g, '');
  return /^\d{14,}$/.test(digits) && !/^92/.test(digits) && !looksLikeWhatsAppGroupId(value);
}

function resolveOutboundChatId(number = '') {
  const raw = String(number || '').trim().replace(/^whatsapp:/i, '').replace(/\s+/g, '');
  if (!raw) return '';
  if (raw.includes('@')) return raw;
  const digits = raw.replace(/\D/g, '');
  if (!digits) return raw;
  if (looksLikeWhatsAppGroupId(raw)) return `${digits}@g.us`;
  if (looksLikeWhatsAppLid(raw)) return `${digits}@lid`;
  return `${digits}@c.us`;
}

function noLidError(error) {
  return /No LID for user/i.test(String(error?.message || error || ''));
}

function outboundFallbackChatIds(chatId = '') {
  const id = String(chatId || '').trim();
  if (!id) return [];
  const user = id.split('@')[0] || '';
  const ids = [id];
  if (id.endsWith('@c.us') && looksLikeWhatsAppGroupId(user)) ids.unshift(`${user.replace(/\D/g, '')}@g.us`);
  if (id.endsWith('@c.us') && looksLikeWhatsAppLid(user)) ids.unshift(`${user.replace(/\D/g, '')}@lid`);
  if (id.endsWith('@lid') && /^92\d{8,}$/.test(user.replace(/\D/g, ''))) ids.push(`${user.replace(/\D/g, '')}@c.us`);
  return [...new Set(ids.filter(Boolean))];
}

async function sendClientMessageWithFallback(inst, chatId, content, options = {}) {
  let lastError = null;
  for (const candidate of outboundFallbackChatIds(chatId)) {
    try {
      return await inst.client.sendMessage(candidate, content, options);
    } catch (error) {
      lastError = error;
      if (!noLidError(error)) throw error;
      console.warn(`[WA] Send failed for ${candidate}: ${error.message}`);
    }
  }
  throw lastError || new Error('Message send failed');
}

