const CP1252_REVERSE_BYTES = new Map([
  [0x20AC, 0x80], [0x201A, 0x82], [0x0192, 0x83], [0x201E, 0x84], [0x2026, 0x85], [0x2020, 0x86], [0x2021, 0x87],
  [0x02C6, 0x88], [0x2030, 0x89], [0x0160, 0x8A], [0x2039, 0x8B], [0x0152, 0x8C], [0x017D, 0x8E],
  [0x2018, 0x91], [0x2019, 0x92], [0x201C, 0x93], [0x201D, 0x94], [0x2022, 0x95], [0x2013, 0x96], [0x2014, 0x97],
  [0x02DC, 0x98], [0x2122, 0x99], [0x0161, 0x9A], [0x203A, 0x9B], [0x0153, 0x9C], [0x017E, 0x9E], [0x0178, 0x9F]
]);

function decodeMojibakeRun(run = '') {
  try {
    const bytes = [];
    for (const ch of String(run || '')) {
      const code = ch.codePointAt(0);
      const byte = code <= 0xff ? code : CP1252_REVERSE_BYTES.get(code);
      if (byte === undefined) return run;
      bytes.push(byte);
    }
    const decoded = Buffer.from(bytes).toString('utf8');
    return decoded && !decoded.includes('\uFFFD') ? decoded : run;
  } catch {
    return run;
  }
}

function decodePossibleMojibake(text = '') {
  return String(text || '').replace(/(?:\u00f0[^\x00-\x7F]{2,6}(?:\u00ef\u00b8\u008f)?|\u00e2[^\x00-\x7F]{1,4}(?:\u00ef\u00b8\u008f)?|\u00c3[^\x00-\x7F]{1,2})/g, decodeMojibakeRun);
}

function cleanOutgoingText(text = '') {
  let value = String(text || '');
  for (const [bad, good] of OUTGOING_MOJIBAKE_REPLACEMENTS) {
    value = value.split(bad).join(good);
  }
  return decodePossibleMojibake(value);
}

const UNICODE_REPAIR_DATA_FILES = [
  'plans.json',
  'laptop_products.json',
  'templates.json',
  'carousel_templates.json',
  'group_message_templates.json',
  'whatsapp_catalogs.json',
  'whatsapp_channel_templates.json',
  'whatsapp_channel_posts.json',
  'whatsapp_channel_discoveries.json',
  'channel_relay_inbox.json',
  'channel_content_library.json',
  'scheduled_messages.json',
  'scholarship_website_posts.json',
  'social_auto_posts.json',
  'social_posts.json',
  'video_auto_posts.json'
];

function textHasLikelyMojibake(text = '') {
  return /(?:ðŸ|â€|âœ|â|âš|â¬|â­|âŒ|â”|Ã¢|Ã©|Ã±|ï¸|âƒ£|�)/.test(String(text || ''));
}

function repairUnicodeString(value = '') {
  let next = cleanOutgoingText(value);
  const replacements = [
    [/Ã¢â‚¬â€œ/g, '—'],
    [/Ã¢â‚¬â€/g, '—'],
    [/Ã¢â‚¬Ëœ/g, '‘'],
    [/Ã¢â‚¬â„¢/g, '’'],
    [/Ã¢â‚¬Å“/g, '“'],
    [/Ã¢â‚¬Â/g, '”'],
    [/Ã¢â‚¬Â¢/g, '•'],
    [/Ã¢Å“â€¦/g, '✅'],
    [/Ã¢ÂÅ’/g, '❌'],
    [/Ã°Å¸/g, ''],
    [/Â([ -~])/g, '$1']
  ];
  for (const [bad, good] of replacements) next = next.replace(bad, good);
  return next;
}

function repairUnicodeInValue(value, pathParts = [], samples = []) {
  if (typeof value === 'string') {
    const repaired = repairUnicodeString(value);
    if (repaired !== value && (textHasLikelyMojibake(value) || value.includes('Â'))) {
      if (samples.length < 20) {
        samples.push({
          path: pathParts.join('.') || '$',
          before: value.slice(0, 160),
          after: repaired.slice(0, 160)
        });
      }
      return { value: repaired, changed: 1 };
    }
    return { value, changed: 0 };
  }
  if (Array.isArray(value)) {
    let changed = 0;
    const arr = value.map((item, index) => {
      const result = repairUnicodeInValue(item, [...pathParts, String(index)], samples);
      changed += result.changed;
      return result.value;
    });
    return { value: arr, changed };
  }
  if (value && typeof value === 'object') {
    let changed = 0;
    const obj = {};
    for (const [key, item] of Object.entries(value)) {
      const result = repairUnicodeInValue(item, [...pathParts, key], samples);
      changed += result.changed;
      obj[key] = result.value;
    }
    return { value: obj, changed };
  }
  return { value, changed: 0 };
}

function runUnicodeRepair({ write = false, files = UNICODE_REPAIR_DATA_FILES } = {}) {
  const requested = Array.isArray(files) && files.length ? files : UNICODE_REPAIR_DATA_FILES;
  const safeFiles = requested
    .map(name => path.basename(String(name || '').trim()))
    .filter(name => UNICODE_REPAIR_DATA_FILES.includes(name));
  const backupDir = path.join(dataDir, 'backups', 'unicode-repair', new Date().toISOString().replace(/[:.]/g, '-'));
  const results = [];
  let totalChanges = 0;
  for (const fileName of safeFiles) {
    const filePath = path.join(dataDir, fileName);
    if (!fs.existsSync(filePath)) {
      results.push({ file: fileName, exists: false, changed: 0, samples: [] });
      continue;
    }
    try {
      const raw = fs.readFileSync(filePath, 'utf8');
      const parsed = JSON.parse(raw || 'null');
      const samples = [];
      const repaired = repairUnicodeInValue(parsed, [fileName], samples);
      totalChanges += repaired.changed;
      if (write && repaired.changed > 0) {
        fs.mkdirSync(backupDir, { recursive: true });
        fs.copyFileSync(filePath, path.join(backupDir, fileName));
        fs.writeFileSync(filePath, JSON.stringify(repaired.value, null, 2));
      }
      results.push({
        file: fileName,
        exists: true,
        changed: repaired.changed,
        samples
      });
    } catch (error) {
      results.push({ file: fileName, exists: true, changed: 0, error: error.message, samples: [] });
    }
  }
  const response = {
    success: true,
    mode: write ? 'write' : 'preview',
    files: results.length,
    totalChanges,
    backupDir: write && totalChanges ? backupDir : '',
    results
  };
  logs.push({ id: uuid(), type: 'unicode_repair', status: write ? 'applied' : 'preview', totalChanges, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  return response;
}

async function sendDirect(number, text, options = {}) {
  const { accountId, inst } = resolveOutboundWAInstance(options || {});
  if (!number) throw new Error('number is required');
  if (!text) throw new Error('text is required');
  const provider = resolveWhatsAppOutboundProvider(options || {});
  if (provider === 'cloud') {
    return sendWhatsAppCloudText(number, text, { source: options.source || 'sendDirect', dryRun: options.dryRun });
  }
  if (!inst?.isReady) {
    if (provider === 'auto' && shouldUseWhatsAppCloudFallback(options || {})) {
      return sendWhatsAppCloudText(number, text, { source: options.source || 'sendDirect_fallback', dryRun: options.dryRun });
    }
    throw new Error('WhatsApp not connected');
  }

  const chatId = resolveOutboundChatId(number);
  const finalText = cleanOutgoingText(text);
  try {
    const sentMsg = await sendClientMessageWithFallback(inst, chatId, finalText);
    markWAAccountSend(accountId);
    const whatsappId = sentMsg?.id?._serialized || sentMsg?.key?.id || null;

    // Record the message in analytics
    const analyticsRow = messageAnalytics.recordSentMessage({
      to: chatId,
      content: finalText,
      whatsappId,
      type: 'text',
      accountId
    });
    if (settings.reply_speed_tracking_enabled !== false) {
      try { messageAnalytics.recordReplyForConversation(chatId, analyticsRow?.id || null, { source: 'whatsapp' }); } catch {}
    }

    return sentMsg;
  } catch (error) {
    if (provider === 'auto' && shouldUseWhatsAppCloudFallback(options || {})) {
      try {
        return await sendWhatsAppCloudText(number, finalText, {
          source: options.source || 'sendDirect_fallback',
          dryRun: options.dryRun
        });
      } catch (cloudError) {
        console.error('WhatsApp Cloud fallback failed:', cloudError.message);
      }
    }
    // Still record failed messages
    messageAnalytics.recordSentMessage({
      to: chatId,
      content: finalText,
      whatsappId: null,
      type: 'text'
    });

    console.error("Failed to send message:", error);
    throw error;
  }
}

function normalizeWhatsAppChannelId(value = '') {
  const raw = String(value || '').trim().replace(/^whatsapp:/i, '').replace(/\s+/g, '');
  if (!raw) return '';
  if (raw.endsWith('@newsletter')) return raw;
  if (/^https?:\/\/(www\.)?whatsapp\.com\/channel\//i.test(raw)) {
    const key = raw.replace(/^https?:\/\/(www\.)?whatsapp\.com\/channel\//i, '').replace(/[/?#].*$/, '');
    return key.includes('@') ? key : `${key}@newsletter`;
  }
  const cleaned = raw.replace(/^channel:/i, '').replace(/[^\w.-]/g, '');
  if (!cleaned) return '';
  return cleaned.includes('@') ? cleaned : `${cleaned}@newsletter`;
}

function getConfiguredWhatsAppChannels() {
  return [...new Set([
    ...(Array.isArray(settings.whatsapp_channel_ids) ? settings.whatsapp_channel_ids : []),
    ...String(process.env.WHATSAPP_CHANNEL_IDS || '').split(',')
  ].map(normalizeWhatsAppChannelId).filter(Boolean))];
}

function getConfiguredWhatsAppChannelSources() {
  return [...new Set([
    ...(Array.isArray(settings.whatsapp_channel_source_ids) ? settings.whatsapp_channel_source_ids : []),
    ...String(process.env.WHATSAPP_CHANNEL_SOURCE_IDS || '').split(',')
  ].map(normalizeWhatsAppChannelId).filter(Boolean))];
}

function getWhatsAppChannelTargetsForSource(sourceChannelId = '') {
  const source = normalizeWhatsAppChannelId(sourceChannelId);
  const routes = settings.whatsapp_channel_source_routes && typeof settings.whatsapp_channel_source_routes === 'object'
    ? settings.whatsapp_channel_source_routes
    : {};
  const routed = Array.isArray(routes[source]) ? routes[source] : [];
  const normalized = [...new Set(routed.map(normalizeWhatsAppChannelId).filter(Boolean))];
  return normalized.length ? normalized : getConfiguredWhatsAppChannels();
}

function publicWhatsAppChannel(channelId = '') {
  const id = normalizeWhatsAppChannelId(channelId);
  const key = id.replace('@newsletter', '');
  return key ? `https://whatsapp.com/channel/${key}` : '';
}

function normalizeWhatsAppChannelLink(value = '') {
  const raw = String(value || '').trim();
  const match = raw.match(/https?:\/\/(?:www\.)?whatsapp\.com\/channel\/([^/?#\s]+)/i);
  if (!match) return '';
  return `https://whatsapp.com/channel/${match[1]}`;
}

function addWhatsAppChannelSourceLinks(values = []) {
  const links = splitChannelList(values)
    .map(normalizeWhatsAppChannelLink)
    .filter(Boolean);
  const current = Array.isArray(settings.whatsapp_channel_source_links) ? settings.whatsapp_channel_source_links : [];
  settings.whatsapp_channel_source_links = [...new Set([...current, ...links])].slice(0, 250);
  saveJSON('settings.json', settings);
  return settings.whatsapp_channel_source_links;
}

function whatsAppChannelDiscoveryRow(input = {}, source = 'unknown') {
  const rawId = typeof input === 'string'
    ? input
    : (input.channelId || input.id?._serialized || input.id?.id || input.id || input.jid || input.remoteJid || input.newsletterJid || input.newsletterId || '');
  const id = normalizeWhatsAppChannelId(rawId);
  if (!id || !id.endsWith('@newsletter')) return null;
  const name = String(
    input.name ||
    input.title ||
    input.subject ||
    input.formattedTitle ||
    input.verifiedName ||
    input.pushname ||
    input.displayName ||
    input.newsletterName ||
    input.metadata?.name ||
    input.metadata?.title ||
    ''
  ).replace(/\s+/g, ' ').trim();
  return {
    channelId: id,
    name: name || id.replace('@newsletter', ''),
    url: publicWhatsAppChannel(id),
    source,
    isConfigured: getConfiguredWhatsAppChannels().includes(id),
    isOwner: input.isOwner === true || input.owner === true || input.role === 'OWNER' || input.viewerRole === 'OWNER',
    subscribers: Number(input.subscribers || input.subscriberCount || input.membersCount || input.metadata?.subscribers || 0) || 0,
    discoveredAt: input.discoveredAt || new Date().toISOString()
  };
}

function mergeWhatsAppChannelDiscoveries(rows = [], { autoConfigure = false } = {}) {
  const byId = new Map();
  for (const row of [...(Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : []), ...rows]) {
    const normalized = whatsAppChannelDiscoveryRow(row, row.source || 'stored');
    if (!normalized) continue;
    byId.set(normalized.channelId, { ...byId.get(normalized.channelId), ...normalized, discoveredAt: normalized.discoveredAt || new Date().toISOString() });
  }
  whatsappChannelDiscoveries = [...byId.values()]
    .map(row => ({ ...row, isConfigured: getConfiguredWhatsAppChannels().includes(row.channelId) }))
    .sort((a, b) => Number(b.isConfigured) - Number(a.isConfigured) || String(a.name).localeCompare(String(b.name)));
  saveWhatsAppChannelDiscoveries();
  if (autoConfigure) {
    const existing = getConfiguredWhatsAppChannels();
    const next = [...new Set([...existing, ...rows.map(row => row.channelId || row.id).map(normalizeWhatsAppChannelId).filter(Boolean)])];
    settings.whatsapp_channel_ids = next;
    if (next.length) settings.whatsapp_channel_auto_share_enabled = true;
    saveJSON('settings.json', settings);
    whatsappChannelDiscoveries = whatsappChannelDiscoveries.map(row => ({ ...row, isConfigured: next.includes(row.channelId) }));
    saveWhatsAppChannelDiscoveries();
  }
  return whatsappChannelDiscoveries;
}

function configureWhatsAppChannelsFromDiscovery(selectors = []) {
  const tokens = (Array.isArray(selectors) ? selectors : String(selectors || '').split(','))
    .map(item => String(item || '').trim())
    .filter(Boolean);
  if (!tokens.length) throw new Error('Select channel numbers/names/IDs first.');
  const discovered = Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [];
  const selected = [];
  for (const token of tokens) {
    const numericIndex = /^\d+$/.test(token) ? Number(token) - 1 : -1;
    const match = numericIndex >= 0
      ? discovered[numericIndex]
      : discovered.find(row => {
        const hay = `${row.channelId || ''} ${row.name || ''} ${row.url || ''}`.toLowerCase();
        return hay.includes(token.toLowerCase());
      });
    if (match?.channelId) selected.push(normalizeWhatsAppChannelId(match.channelId));
    else {
      const id = normalizeWhatsAppChannelId(token);
      if (id.endsWith('@newsletter')) selected.push(id);
    }
  }
  const unique = [...new Set(selected.filter(Boolean))];
  if (!unique.length) throw new Error('No matching discovered channels found.');
  settings.whatsapp_channel_ids = unique;
  settings.whatsapp_channel_auto_share_enabled = true;
  settings.whatsapp_channel_auto_share_new_plans = true;
  saveJSON('settings.json', settings);
  whatsappChannelDiscoveries = discovered.map(row => ({ ...row, isConfigured: unique.includes(row.channelId) }));
  saveWhatsAppChannelDiscoveries();
  return unique.map(channelId => whatsappChannelDiscoveries.find(row => row.channelId === channelId) || whatsAppChannelDiscoveryRow(channelId, 'configured'));
}

function configureWhatsAppChannelSourcesFromDiscovery(selectors = []) {
  const tokens = (Array.isArray(selectors) ? selectors : String(selectors || '').split(','))
    .map(item => String(item || '').trim())
    .filter(Boolean);
  if (!tokens.length) throw new Error('Select source channel numbers/names/IDs first.');
  const discovered = Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [];
  const selected = [];
  for (const token of tokens) {
    const numericIndex = /^\d+$/.test(token) ? Number(token) - 1 : -1;
    const match = numericIndex >= 0
      ? discovered[numericIndex]
      : discovered.find(row => {
        const hay = `${row.channelId || ''} ${row.name || ''} ${row.url || ''}`.toLowerCase();
        return hay.includes(token.toLowerCase());
      });
    if (match?.channelId) selected.push(normalizeWhatsAppChannelId(match.channelId));
    else {
      const id = normalizeWhatsAppChannelId(token);
      if (id.endsWith('@newsletter')) selected.push(id);
    }
  }
  const targets = new Set(getConfiguredWhatsAppChannels());
  const unique = [...new Set(selected.filter(Boolean))].filter(id => !targets.has(id));
  if (!unique.length) throw new Error('No matching source channels found, or selected channels are already target channels.');
  settings.whatsapp_channel_source_ids = unique;
  settings.whatsapp_channel_copy_enabled = true;
  saveJSON('settings.json', settings);
  return unique.map(channelId => discovered.find(row => row.channelId === channelId) || whatsAppChannelDiscoveryRow(channelId, 'source'));
}

async function discoverWhatsAppChannels({ accountId = 'default', autoConfigure = false, save = true } = {}) {
  const inst = waClients.get(String(accountId || 'default').trim() || 'default');
  if (!inst?.isReady || !inst.client) throw new Error('WhatsApp not connected. Pehle QR scan/connect karein.');
  const found = [];
  const add = (item, source) => {
    const row = whatsAppChannelDiscoveryRow(item, source);
    if (row) found.push(row);
  };

  for (const id of getConfiguredWhatsAppChannels()) add({ channelId: id, name: id.replace('@newsletter', '') }, 'configured');

  try {
    const chats = await promiseTimeout(inst.client.getChats(), 30000, []);
    for (const chat of chats || []) {
      const id = waSerializedId(chat);
      const server = chat?.id?.server || '';
      if (server === 'newsletter' || id.endsWith('@newsletter') || chat?.isNewsletter || chat?.isChannel) {
        add(chat, 'getChats');
      }
    }
  } catch (error) {
    console.warn('[WA Channels] getChats discovery failed:', error.message);
  }

  try {
    if (typeof inst.client.getContacts === 'function') {
      const contacts = await promiseTimeout(inst.client.getContacts(), 30000, []);
      for (const contact of contacts || []) {
        const id = waSerializedId(contact);
        const server = contact?.id?.server || '';
        if (server === 'newsletter' || id.endsWith('@newsletter') || contact?.isNewsletter || contact?.isChannel) {
          add(contact, 'getContacts');
        }
      }
    }
  } catch (error) {
    console.warn('[WA Channels] getContacts discovery failed:', error.message);
  }

  try {
    const page = inst.client.pupPage || inst.client.pupBrowserPage || null;
    if (page?.evaluate) {
      const pageRows = await promiseTimeout(page.evaluate(() => {
        const rows = [];
        const seen = new Set();
        const getId = (item) => {
          if (!item) return '';
          const id = item.id || item.__x_id || item.__x_wid || item.wid || item.jid || item.newsletterJid || item.newsletterId || item.remoteJid || '';
          if (typeof id === 'string') return id;
          return id._serialized || id.id || (typeof id.toString === 'function' ? id.toString() : '');
        };
        const nameOf = (item) => item?.name || item?.title || item?.subject || item?.formattedTitle || item?.verifiedName || item?.displayName || item?.__x_name || item?.__x_title || item?.metadata?.name || '';
        const push = (item, source) => {
          const id = getId(item);
          const server = item?.id?.server || item?.__x_id?.server || '';
          const serialized = String(id || '');
          if (!(server === 'newsletter' || serialized.endsWith('@newsletter') || item?.isNewsletter || item?.isChannel)) return;
          const channelId = serialized.endsWith('@newsletter') ? serialized : `${serialized.split('@')[0]}@newsletter`;
          if (!channelId || seen.has(channelId)) return;
          seen.add(channelId);
          rows.push({
            channelId,
            name: nameOf(item),
            isOwner: item?.isOwner === true || item?.owner === true || item?.role === 'OWNER' || item?.viewerRole === 'OWNER',
            subscribers: item?.subscribers || item?.subscriberCount || item?.membersCount || item?.metadata?.subscribers || 0,
            source
          });
        };
        const scanCollection = (value, source) => {
          const arr = Array.isArray(value)
            ? value
            : (Array.isArray(value?.models) ? value.models : (Array.isArray(value?._models) ? value._models : (value instanceof Map ? Array.from(value.values()) : [])));
          for (const item of arr.slice(0, 2000)) push(item, source);
        };
        const store = window.Store || window.WWebJS?.Store || {};
        for (const key of ['Chat', 'Contact', 'Newsletter', 'NewsletterMetadata', 'NewsletterStore', 'Channel', 'ChannelStore']) {
          if (store[key]) scanCollection(store[key], `Store.${key}`);
        }
        for (const [key, value] of Object.entries(store)) {
          if (/newsletter|channel/i.test(key)) scanCollection(value, `Store.${key}`);
        }
        return rows.slice(0, 100);
      }), 30000, []);
      for (const row of pageRows || []) add(row, row.source || 'page');
    }
  } catch (error) {
    console.warn('[WA Channels] page discovery failed:', error.message);
  }

  const unique = [...new Map(found.map(row => [row.channelId, row])).values()];
  const stored = save ? mergeWhatsAppChannelDiscoveries(unique, { autoConfigure }) : unique;
  if (save && settings.whatsapp_channel_copy_enabled === true) {
    const targets = new Set(getConfiguredWhatsAppChannels());
    const keywords = channelAutoDiscoverKeywords();
    const existing = new Set(getConfiguredWhatsAppChannelSources());
    const autoSources = unique
      .filter(row => row?.channelId && !targets.has(row.channelId))
      .filter(row => {
        if (settings.whatsapp_channel_auto_source_all_followed === true) return true;
        if (!keywords.length) return false;
        const hay = `${row.name || ''} ${row.channelId || ''}`.toLowerCase();
        return keywords.some(keyword => keyword && hay.includes(keyword));
      })
      .map(row => row.channelId);
    if (autoSources.length) {
      settings.whatsapp_channel_source_ids = [...new Set([...existing, ...autoSources])].slice(0, Number(settings.whatsapp_channel_max_sources || 60));
      saveJSON('settings.json', settings);
    }
  }
  return {
    success: true,
    accountId,
    found: unique.length,
    autoConfigured: autoConfigure ? getConfiguredWhatsAppChannels().length : 0,
    channels: autoConfigure || save ? stored : unique,
    configured: getConfiguredWhatsAppChannels()
  };
}

function topProductsForChannel(limit = 5) {
  return (Array.isArray(laptopProducts) ? laptopProducts : [])
    .filter(product => product && product.stock !== false && Number(product.price || 0) > 0)
    .sort((a, b) => Number(a.price || 0) - Number(b.price || 0))
    .slice(0, limit);
}

function channelDateLabel(date = new Date()) {
  return date.toLocaleString('en-PK', {
    timeZone: 'Asia/Karachi',
    year: 'numeric',
    month: 'short',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit'
  });
}

function channelRatesText(limit = 8) {
  const rows = (Array.isArray(plans) ? plans : [])
    .filter(plan => !plan || typeof isPlanAvailableForWhatsApp !== 'function' ? true : isPlanAvailableForWhatsApp(plan))
    .slice(0, limit)
    .map((plan, i) => {
    const price = Number(plan.price || plan.sellPrice || 0);
    return `${i + 1}. ${plan.name || plan.plan_name || 'Plan'}${price ? ` - Rs. ${price.toLocaleString()}` : ''}`;
  });
  return cleanOutgoingText(rows.join('\n') || 'ChatGPT, Claude, Gemini, Cursor plans available.');
}

function channelProductsText(limit = 6) {
  return cleanOutgoingText(topProductsForChannel(limit).map((p, i) => {
    const price = Number(p.price || 0);
    const status = p.available === false || p.stock === false ? 'Out of stock' : 'Available';
    return `${i + 1}. ${p.name} - Rs. ${price.toLocaleString()} (${status})`;
  }).join('\n') || 'Catalog update coming soon.');
}

function channelPlanStockText(limit = 12) {
  const rows = (Array.isArray(plans) ? plans : [])
    .slice(0, limit)
    .map((plan, index) => {
      const available = typeof isPlanAvailableForWhatsApp === 'function' ? isPlanAvailableForWhatsApp(plan) : plan?.available !== false;
      const price = Number(plan.price || plan.sellPrice || 0);
      const category = typeof inferBotPlanCategory === 'function' ? inferBotPlanCategory(plan) : (plan.category || 'AI Tools');
      return `${index + 1}. ${available ? '✅' : '❌'} ${category} - ${plan.name || 'Plan'}${price ? ` - Rs. ${price.toLocaleString()}` : ''}`;
    });
  return cleanOutgoingText(rows.join('\n') || 'No stock rows available yet.');
}

function channelSellerRatesText(limit = 8) {
  try {
    const rows = typeof sellerRateRows === 'function' ? sellerRateRows(limit, { limit }) : [];
    if (!rows.length) return 'Seller rates abhi collect nahi hue. Pehle !ratesweep run karein.';
    return cleanOutgoingText(rows.slice(0, limit).map((row, index) => {
      const tool = row.tool || row.product || row.title || 'Item';
      const plan = row.plan ? ` ${row.plan}` : '';
      const price = Number(row.price || row.rate || 0);
      const seller = row.sellerName || row.seller || row.dealer || row.senderName || 'Seller';
      return `${index + 1}. ${tool}${plan} - Rs. ${price.toLocaleString()} (${seller})`;
    }).join('\n'));
  } catch (error) {
    return `Seller rates unavailable: ${error.message}`;
  }
}

function channelBestDealsText(limit = 8) {
  try {
    const rows = typeof sellerRateRows === 'function' ? sellerRateRows(10000, {}) : [];
    const best = new Map();
    for (const row of rows) {
      const tool = String(row.tool || row.product || row.title || '').trim() || 'Item';
      const plan = String(row.plan || '').trim();
      const key = `${tool.toLowerCase()}|${plan.toLowerCase()}`;
      const price = Number(row.price || row.rate || 0);
      if (!price) continue;
      const prev = best.get(key);
      if (!prev || price < Number(prev.price || prev.rate || 0)) best.set(key, row);
    }
    const lines = [...best.values()].slice(0, limit).map((row, index) => {
      const tool = row.tool || row.product || row.title || 'Item';
      const plan = row.plan ? ` ${row.plan}` : '';
      const price = Number(row.price || row.rate || 0);
      const seller = row.sellerName || row.seller || row.dealer || 'Seller';
      return `${index + 1}. 🔥 ${tool}${plan} - Rs. ${price.toLocaleString()} (${seller})`;
    });
    return cleanOutgoingText(lines.join('\n') || 'Best dealer deals abhi available nahi.');
  } catch (error) {
    return `Best deals unavailable: ${error.message}`;
  }
}

function channelGiveawayText() {
  const giveaway = typeof getGiveawayPlan === 'function' ? getGiveawayPlan() : null;
  if (!giveaway) return 'Giveaway abhi not available hai. Next update channel par announce hoga.';
  return cleanOutgoingText(`🎁 *Moclaw AI Giveaway*

🔥 DeepSeek V4 Pro free for 30 days
✅ 1,000 credits included
✅ No card required
🤖 DeepSeek V4 only

Link: https://moclaw.ai

Steps:
1. Register with your email
2. Scroll down and click Free Trial
3. Enjoy 30 days free 🎉`);
}

function buildChannelPlanAnnouncement(plan = {}) {
  const category = typeof inferBotPlanCategory === 'function' ? inferBotPlanCategory(plan) : (plan.category || 'AI Tools');
  const price = Number(plan.price || plan.sellPrice || 0);
  const features = Array.isArray(plan.features) ? plan.features : String(plan.features || '').split(/\r?\n/).map(x => x.trim()).filter(Boolean);
  const available = typeof isPlanAvailableForWhatsApp === 'function' ? isPlanAvailableForWhatsApp(plan) : plan?.available !== false;
  return cleanOutgoingText(`📣 *New Plan Update*

${plan.emoji || '🤖'} *${plan.name || 'Plan'}*
Category: ${category}
Price: ${price ? `Rs. ${price.toLocaleString()}` : 'Ask for price'}
Status: ${available ? '✅ Available' : '❌ Not Available'}

${features.slice(0, 6).map(item => `• ${item}`).join('\n') || 'DM for details.'}

📩 Order/rates ke liye WhatsApp par message karein.`);
}

function applyWhatsAppChannelTemplate(body = '', vars = {}) {
  const snap = businessSnapshot();
  const values = {
    business: storeDisplayName(),
    date: channelDateLabel(),
    rates: channelRatesText(10),
    products: channelProductsText(8),
    stock: channelPlanStockText(14),
    sellerRates: channelSellerRatesText(10),
    bestDeals: channelBestDealsText(10),
    revenue: Number(snap.revenue || 0).toLocaleString(),
    orders: snap.orders || 0,
    customers: snap.customers || 0,
    ...vars
  };
  return cleanOutgoingText(String(body || '').replace(/\{\{\s*([\w.-]+)\s*\}\}/g, (_all, key) => {
    const value = values[key];
    return value === undefined || value === null ? '' : String(value);
  }).trim());
}

function buildWhatsAppChannelDataMessage(kind = 'business-summary', customMessage = '') {
  const message = String(customMessage || '').trim();
  if (message) return cleanOutgoingText(message);
  const now = new Date().toLocaleString('en-PK', { timeZone: 'Asia/Karachi' });
  const store = storeDisplayName();
  const normalized = String(kind || settings.whatsapp_channel_default_kind || 'business-summary').toLowerCase();
  const template = ensureWhatsAppChannelTemplates().find(item => String(item.kind || '').toLowerCase() === normalized);
  if (template?.body) return applyWhatsAppChannelTemplate(template.body);
  if (normalized === 'products' || normalized === 'catalog') {
    const products = topProductsForChannel(6);
    const lines = products.map((p, i) => `${i + 1}. ${p.name} — Rs. ${Number(p.price || 0).toLocaleString()}`).join('\n');
    return cleanOutgoingText(`🛒 *${store} — Product Update*

${lines || 'Products loading soon.'}

📩 Order/price ke liye WhatsApp par message karein.
${now}`);
  }
  if (normalized === 'ai-rates' || normalized === 'rates') {
    const rows = (Array.isArray(plans) ? plans : []).slice(0, 8).map((plan, i) => {
      const price = Number(plan.price || plan.sellPrice || 0);
      return `${i + 1}. ${plan.name || plan.plan_name || 'Plan'}${price ? ` — Rs. ${price.toLocaleString()}` : ''}`;
    }).join('\n');
    return cleanOutgoingText(`🤖 *${store} — AI Tools Rates*

${rows || 'ChatGPT, Claude, Gemini, Cursor plans available.'}

✅ Fast delivery
📩 DM for today’s best price
${now}`);
  }
  if (['stock', 'availability', 'available'].includes(normalized)) {
    return cleanOutgoingText(`📦 *${store} — Stock Availability*

${channelPlanStockText(14)}

📩 Jo plan chahiye us ka naam reply karein.
${now}`);
  }
  if (['seller-rates', 'dealers', 'dealer-rates'].includes(normalized)) {
    return cleanOutgoingText(`📊 *${store} — Seller Rates Update*

${channelSellerRatesText(10)}

Data WhatsApp groups se auto-collected hai.
${now}`);
  }
  if (['best-deals', 'best', 'profit'].includes(normalized)) {
    return cleanOutgoingText(`🔥 *${store} — Best Deals Today*

${channelBestDealsText(10)}

Best margin ke liye admin se confirm karein.
${now}`);
  }
  if (['giveaway', 'free-trial'].includes(normalized)) {
    return channelGiveawayText();
  }
  const snap = businessSnapshot();
  const products = topProductsForChannel(4).map((p, i) => `${i + 1}. ${p.name} — Rs. ${Number(p.price || 0).toLocaleString()}`).join('\n');
  return cleanOutgoingText(`📊 *${store} — Daily Business Update*

Revenue: Rs. ${Number(snap.revenue || 0).toLocaleString()}
Orders: ${snap.orders}
Customers: ${snap.customers}
Products: ${snap.products}

🔥 Available now:
${products || 'Catalog update coming soon.'}

📩 Reply/DM for rates and order.
${now}`);
}

function buildWhatsAppChannelPreview({ kind = '', message = '', templateId = '', variables = {} } = {}) {
  const custom = String(message || '').trim();
  if (templateId) {
    const template = ensureWhatsAppChannelTemplates().find(item => item.id === templateId);
    if (template?.body) return applyWhatsAppChannelTemplate(template.body, variables);
  }
  return buildWhatsAppChannelDataMessage(kind || settings.whatsapp_channel_default_kind || 'business-summary', custom);
}

function isWhatsAppChannelPublishUnsupported(error = {}) {
  const msg = String(error?.message || error || '');
  return /getLastMsgKeyForAction|newsletter|channel|not implemented|not supported/i.test(msg);
}

function buildManualChannelPublishPacket({ channelIds = [], message = '', mediaUrl = '', failures = [] } = {}) {
  const links = (channelIds || []).map((id, index) => `${index + 1}. ${publicWhatsAppChannel(id)}\n   ${id}`).join('\n');
  const errors = (failures || []).map(f => `- ${f.channelId}: ${String(f.error || '').split('\n')[0]}`).join('\n');
  return `?? *Channel Auto Publish Needs Manual Send*\n\nWhatsApp Web direct Channel API failed, isliye post package ready hai.\n\n*Target channels:*\n${links || 'No target channel'}\n\n*Post text:*\n${message || '[media only]'}${mediaUrl ? `\n\n*Media:* ${mediaUrl}` : ''}${errors ? `\n\n*Reason:*\n${errors}` : ''}\n\nAction: channel open karein, post text copy/paste karein. System ne draft + logs save kar diye hain.`;
}

async function alertAdminManualChannelPublish(payload = {}) {
  const adminNumber = getAdminWhatsAppNumber();
  if (!adminNumber) return false;
  try {
    await sendDirect(adminNumber, buildManualChannelPublishPacket(payload));
    return true;
  } catch (error) {
    console.warn('[Channel] manual publish admin alert failed:', error.message);
    return false;
  }
}

function baileysChannelPublisherId() {
  return String(settings.whatsapp_channel_publisher_account_id || process.env.WHATSAPP_CHANNEL_PUBLISHER_ACCOUNT_ID || 'channel-publisher').trim() || 'channel-publisher';
}

function hasBaileysAuthSession(accountId = '') {
  return fs.existsSync(path.join(BAILEYS_AUTH_ROOT, accountId, 'creds.json'));
}

async function getReadyBaileysChannelPublisher({ autoStart = true } = {}) {
  const preferredId = baileysChannelPublisherId();
  const preferred = waClients.get(preferredId);
  if (preferred?.clientKind === 'baileys' && preferred?.isReady && preferred?.sock) return { accountId: preferredId, inst: preferred };
  for (const [id, inst] of waClients.entries()) {
    if (inst?.clientKind === 'baileys' && inst?.isReady && inst?.sock) return { accountId: id, inst };
  }
  if (autoStart && hasBaileysAuthSession(preferredId)) {
    const inst = await getOrCreateBaileysClient(preferredId);
    if (inst?.isReady && inst?.sock) return { accountId: preferredId, inst };
  }
  return { accountId: preferredId, inst: null };
}

function channelMediaKindFromMime(mimetype = '') {
  const type = String(mimetype || '').toLowerCase();
  if (type.startsWith('image/')) return 'image';
  if (type.startsWith('video/')) return 'video';
  if (type.startsWith('audio/')) return 'audio';
  return 'document';
}

async function baileyChannelMediaPayloadFromSource(source = '', caption = '') {
  const mediaSource = String(source || '').trim();
  if (!mediaSource) return { text: caption || ' ' };
  let buffer = null;
  let mimetype = '';
  let filename = safeMediaFilename(mediaSource, 'channel-media');
  if (/^https?:\/\//i.test(mediaSource)) {
    const response = await fetch(mediaSource, { headers: { 'User-Agent': 'SuperSender-Pro/1.0' } });
    if (!response.ok) throw new Error(`Channel media download failed (${response.status})`);
    mimetype = (response.headers.get('content-type') || guessMimeType(mediaSource)).split(';')[0].trim();
    buffer = Buffer.from(await response.arrayBuffer());
  } else {
    const filePath = mediaSource.startsWith('/uploads/')
      ? path.join(__dirname, mediaSource.replace(/^\/+/, ''))
      : mediaSource.startsWith('/assets/')
        ? path.join(__dirname, 'public', mediaSource.replace(/^\/+/, ''))
        : path.isAbsolute(mediaSource)
          ? mediaSource
          : path.join(__dirname, mediaSource);
    if (!fs.existsSync(filePath)) throw new Error('Channel media file not found');
    mimetype = guessMimeType(filePath);
    filename = path.basename(filePath);
    buffer = fs.readFileSync(filePath);
  }
  if (!buffer?.length) throw new Error('Channel media is empty');
  const kind = channelMediaKindFromMime(mimetype);
  if (kind === 'image') return { image: buffer, caption };
  if (kind === 'video') return { video: buffer, caption, mimetype };
  if (kind === 'audio') return { audio: buffer, mimetype, ptt: false };
  return { document: buffer, mimetype, fileName: filename, caption };
}

async function sendWhatsAppChannelViaBaileys(channelId = '', message = '', mediaSource = '', options = {}) {
  const jid = normalizeWhatsAppChannelId(channelId);
  if (!jid.endsWith('@newsletter')) throw new Error('Invalid WhatsApp Channel ID');
  const { accountId, inst } = await getReadyBaileysChannelPublisher({ autoStart: true });
  if (!inst?.sock || !inst?.isReady) {
    throw new Error(`Channel publisher not connected. Link Baileys account: POST /api/wa/channel-publisher/connect then scan QR for account ${accountId}`);
  }
  const finalMessage = cleanOutgoingText(message || ' ');
  const content = await baileyChannelMediaPayloadFromSource(mediaSource, finalMessage);
  const sent = await inst.sock.sendMessage(jid, content, { useCachedGroupMetadata: false });
  markWAAccountSend(accountId);
  return sent;
}

async function shareDataToWhatsAppChannels({ channelIds = [], message = '', kind = 'business-summary', mediaUrl = '', mediaPath = '', delayMs = 2000, accountId = '', useRotation = false, skipBridge = false } = {}) {
  const targets = [...new Set((Array.isArray(channelIds) && channelIds.length ? channelIds : getConfiguredWhatsAppChannels()).map(normalizeWhatsAppChannelId).filter(Boolean))];
  if (!targets.length) throw new Error('No WhatsApp Channel IDs configured. Add channel IDs first.');
  const finalMessage = applyChannelBrandingToText(buildWhatsAppChannelDataMessage(kind, message));
  let mediaSource = String(mediaUrl || mediaPath || '').trim();
  mediaSource = await applyChannelWatermarkToMediaSource(mediaSource);
  let media = null;
  if (mediaSource) {
    media = await createMediaFromSource(mediaSource);
  }
  const sent = [];
  const failed = [];
  for (const channelId of targets) {
    try {
      await sendWhatsAppChannelViaBaileys(channelId, finalMessage, mediaSource, { accountId, useRotation });
      sent.push({ channelId, url: publicWhatsAppChannel(channelId), engine: 'baileys-newsletter' });
      logs.push({ id: uuid(), type: 'whatsapp_channel_share', to: channelId, status: 'sent', engine: 'baileys-newsletter', message: finalMessage, mediaUrl: mediaSource, time: new Date().toISOString() });
    } catch (baileysError) {
      const mediaUploadFailed = mediaSource && /media upload failed|upload failed|all hosts/i.test(String(baileysError.message || ''));
      if (mediaUploadFailed) {
        try {
          const fallbackText = cleanOutgoingText([finalMessage, 'Media post copied from source channel.'].filter(Boolean).join('\n\n'));
          await sendWhatsAppChannelViaBaileys(channelId, fallbackText, '', { accountId, useRotation });
          sent.push({ channelId, url: publicWhatsAppChannel(channelId), engine: 'baileys-newsletter-text-fallback' });
          logs.push({ id: uuid(), type: 'whatsapp_channel_share', to: channelId, status: 'sent', engine: 'baileys-newsletter-text-fallback', warning: baileysError.message, message: fallbackText, mediaUrl: mediaSource, time: new Date().toISOString() });
          await sleep(Math.max(300, Number(delayMs || 2000)));
          continue;
        } catch (textFallbackError) {
          baileysError.message = `${baileysError.message}; text fallback failed: ${textFallbackError.message}`;
        }
      }
      try {
        if (media) await sendDirectMedia(channelId, media, finalMessage, { accountId, useRotation });
        else await sendDirect(channelId, finalMessage, { accountId, useRotation });
        sent.push({ channelId, url: publicWhatsAppChannel(channelId), engine: 'wwebjs-fallback' });
        logs.push({ id: uuid(), type: 'whatsapp_channel_share', to: channelId, status: 'sent', engine: 'wwebjs-fallback', message: finalMessage, mediaUrl: mediaSource, time: new Date().toISOString() });
      } catch (error) {
        const combinedError = `${baileysError.message}; ${error.message}`;
        const needsPublisher = /Channel publisher not connected/i.test(baileysError.message || '');
        const unsupported = needsPublisher || isWhatsAppChannelPublishUnsupported(baileysError) || isWhatsAppChannelPublishUnsupported(error);
        failed.push({ channelId, error: combinedError, manualRequired: unsupported, needsPublisher });
        logs.push({ id: uuid(), type: 'whatsapp_channel_share', to: channelId, status: unsupported ? 'manual_required' : 'failed', error: combinedError, message: finalMessage, mediaUrl: mediaSource, time: new Date().toISOString() });
      }
    }
    await sleep(Math.max(300, Number(delayMs || 2000)));
  }
  const manualRequired = failed.length > 0 && failed.every(item => item.manualRequired === true);
  let adminAlertSent = false;
  if (manualRequired) {
    adminAlertSent = await alertAdminManualChannelPublish({ channelIds: targets, message: finalMessage, mediaUrl: mediaSource, failures: failed });
    logs.push({ id: uuid(), type: 'whatsapp_channel_manual_publish_packet', status: adminAlertSent ? 'sent_to_admin' : 'saved_only', targets, message: finalMessage, mediaUrl: mediaSource, time: new Date().toISOString() });
  }
  let bridge = null;
  if (sent.length && skipBridge !== true) {
    bridge = await bridgeWhatsAppChannelContent({ message: finalMessage, mediaUrl: mediaSource, kind }).catch(error => ({ success: false, error: error.message }));
  }
  saveJSON('logs.json', logs);
  return { success: failed.length === 0, manualRequired, adminAlertSent, total: targets.length, sent: sent.length, failed: failed.length, sentChannels: sent, failures: failed, bridge, message: finalMessage, mediaUrl: mediaSource };
}

function normalizeChannelPostStatus(value = '') {
  const status = String(value || '').toLowerCase();
  return ['draft', 'scheduled', 'sent', 'failed', 'manual_required', 'cancelled'].includes(status) ? status : 'draft';
}

function channelPostPublic(row = {}) {
  return {
    id: row.id,
    title: row.title || '',
    kind: row.kind || 'custom',
    status: row.status || 'draft',
    message: row.message || '',
    mediaUrl: row.mediaUrl || row.mediaPath || '',
    preview: row.preview || row.message || '',
    channelIds: Array.isArray(row.channelIds) ? row.channelIds : [],
    scheduledAt: row.scheduledAt || '',
    sentAt: row.sentAt || '',
    createdAt: row.createdAt || '',
    updatedAt: row.updatedAt || '',
    result: row.result || null,
    error: row.error || ''
  };
}

function normalizeChannelRelayStatus(value = '') {
  const status = String(value || '').toLowerCase();
  return ['draft', 'pending', 'published', 'rejected', 'failed', 'manual_required'].includes(status) ? status : 'pending';
}

function channelRelayFingerprint(input = {}) {
  const basis = [
    normalizeWhatsAppChannelId(input.sourceChannelId || ''),
    String(input.sourceMessageId || ''),
    String(input.message || input.text || '').trim(),
    String(input.mediaUrl || input.mediaPath || '').trim()
  ].join('|');
  return crypto.createHash('sha1').update(basis).digest('hex');
}

function channelRelayMediaExtension(mimetype = '') {
  const map = {
    'image/jpeg': '.jpg',
    'image/png': '.png',
    'image/webp': '.webp',
    'image/gif': '.gif',
    'video/mp4': '.mp4',
    'video/quicktime': '.mov',
    'audio/mpeg': '.mp3',
    'audio/mp4': '.m4a',
    'audio/ogg': '.ogg',
    'application/pdf': '.pdf'
  };
  return map[String(mimetype || '').split(';')[0].trim().toLowerCase()] || '.bin';
}

async function saveChannelRelayMediaFromWWebMessage(msg = {}) {
  if (!msg?.hasMedia || typeof msg.downloadMedia !== 'function') return '';
  const media = await msg.downloadMedia();
  if (!media?.data) return '';
  const mimetype = String(media.mimetype || 'application/octet-stream').split(';')[0].trim();
  const ext = channelRelayMediaExtension(mimetype);
  const folder = path.join(__dirname, 'uploads', 'channel-relay');
  fs.mkdirSync(folder, { recursive: true });
  const filename = `${Date.now()}-${uuid()}${ext}`;
  const filePath = path.join(folder, filename);
  fs.writeFileSync(filePath, Buffer.from(media.data, 'base64'));
  return `/uploads/channel-relay/${filename}`;
}

function saveChannelRelayMediaFromBase64Payload(text = '', mimetype = '') {
  const raw = String(text || '').replace(/\s+/g, '').trim();
  if (!raw) return '';
  let type = String(mimetype || '').trim();
  let data = raw;
  const dataUrl = raw.match(/^data:([^;]+);base64,(.+)$/i);
  if (dataUrl) {
    type = dataUrl[1];
    data = dataUrl[2];
  } else if (raw.startsWith('/9j/')) {
    type = 'image/jpeg';
  } else if (raw.startsWith('iVBORw0KGgo')) {
    type = 'image/png';
  } else if (raw.startsWith('UklGR')) {
    type = 'image/webp';
  }
  if (!type || !/^(image|video|audio|application\/pdf)/i.test(type)) return '';
  const buffer = Buffer.from(data, 'base64');
  if (!buffer.length || buffer.length < 200) return '';
  const folder = path.join(__dirname, 'uploads', 'channel-relay');
  fs.mkdirSync(folder, { recursive: true });
  const filename = `${Date.now()}-${uuid()}${channelRelayMediaExtension(type)}`;
  fs.writeFileSync(path.join(folder, filename), buffer);
  return `/uploads/channel-relay/${filename}`;
}

function buildCopiedChannelRelayMessage({ message = '', sourceName = '', sourceUrl = '' } = {}) {
  const body = cleanOutgoingText(String(message || '').trim());
  const footerTemplate = String(settings.whatsapp_channel_copy_footer || '').trim();
  const footer = footerTemplate
    .replace(/\{\{\s*sourceName\s*\}\}/g, sourceName || 'WhatsApp Channel')
    .replace(/\{\{\s*sourceUrl\s*\}\}/g, sourceUrl || '')
    .trim();
  return cleanOutgoingText([body, footer ? `\n\n—\n${footer}` : ''].filter(Boolean).join('')).trim();
}

function channelBrandHandle() {
  return String(settings.whatsapp_channel_brand_handle || '').trim();
}

function applyChannelBrandingToText(message = '') {
  let text = cleanOutgoingText(String(message || '').trim());
  if (settings.whatsapp_channel_branding_enabled === false) return text;
  const handle = channelBrandHandle();
  if (!handle) return text;
  const footer = handle.startsWith('@') || /^https?:\/\//i.test(handle) ? handle : `@${handle}`;
  if (text.toLowerCase().includes(footer.toLowerCase())) return text;
  return cleanOutgoingText([text, `— ${footer}`].filter(Boolean).join('\n\n')).trim();
}

function channelPriorityKeywords() {
  return String(settings.whatsapp_channel_priority_keywords || '')
    .split(/[,\n|]+/)
    .map(item => item.trim().toLowerCase())
    .filter(Boolean);
}

function detectWhatsAppChannelPriorityKeywords(text = '') {
  if (settings.whatsapp_channel_keyword_alert_enabled === false) return [];
  const value = String(text || '').toLowerCase();
  return channelPriorityKeywords().filter(keyword => keyword && value.includes(keyword));
}

function splitChannelList(value = '') {
  if (Array.isArray(value)) return value.map(item => String(item || '').trim()).filter(Boolean);
  return String(value || '')
    .split(/[,\n|]+/)
    .map(item => item.trim())
    .filter(Boolean);
}

function channelCompetitorTerms() {
  return splitChannelList(settings.whatsapp_channel_competitor_blocklist).map(item => item.toLowerCase());
}

function channelBlacklistedSenders() {
  return splitChannelList(settings.whatsapp_channel_blacklisted_senders).map(item => normalizeWhatsAppChannelId(item) || item.toLowerCase());
}

function channelSourceWhitelist() {
  return splitChannelList(settings.whatsapp_channel_source_whitelist).map(item => normalizeWhatsAppChannelId(item) || item.toLowerCase());
}

function channelSourceBlacklist() {
  return splitChannelList(settings.whatsapp_channel_source_blacklist).map(item => normalizeWhatsAppChannelId(item) || item.toLowerCase());
}

function channelFlashSaleKeywords() {
  return splitChannelList(settings.whatsapp_channel_flash_sale_keywords).map(item => item.toLowerCase());
}

function channelAutoDiscoverKeywords() {
  return splitChannelList(settings.whatsapp_channel_auto_discover_keywords).map(item => item.toLowerCase());
}

function detectChannelLanguage(text = '') {
  const value = String(text || '');
  const urduChars = (value.match(/[\u0600-\u06FF]/g) || []).length;
  const latinChars = (value.match(/[A-Za-z]/g) || []).length;
  if (urduChars > latinChars * 0.4) return 'urdu';
  if (latinChars > 0) return 'english';
  return 'unknown';
}

function sourcePriorityScore(sourceId = '') {
  const id = normalizeWhatsAppChannelId(sourceId);
  const map = settings.whatsapp_channel_source_priority || {};
  return Math.max(0, Number(map[id] || 0));
}

function sourceCategory(sourceId = '', fallbackText = '') {
  const id = normalizeWhatsAppChannelId(sourceId);
  const map = settings.whatsapp_channel_source_categories || {};
  if (map[id]) return String(map[id]);
  const text = String(fallbackText || '').toLowerCase();
  if (/sticker|stickers/.test(text)) return 'stickers';
  if (/scholarship|admission|university|school/.test(text)) return 'scholarship';
  if (/ai|chatgpt|gemini|claude|tools/.test(text)) return 'ai-tools';
  if (/sale|deal|discount|price/.test(text)) return 'deals';
  return 'general';
}

function sourceRule(sourceId = '') {
  const id = normalizeWhatsAppChannelId(sourceId);
  const rules = settings.whatsapp_channel_source_rules || {};
  return rules[id] && typeof rules[id] === 'object' && !Array.isArray(rules[id]) ? rules[id] : {};
}

function allChannelConditionalRules() {
  const rules = settings.whatsapp_channel_conditional_rules;
  return Array.isArray(rules) ? rules.filter(rule => rule && rule.enabled !== false) : [];
}

function matchChannelConditionalRules({ sourceChannelId = '', sourceName = '', message = '' } = {}) {
  const sourceId = normalizeWhatsAppChannelId(sourceChannelId);
  const text = `${sourceName}\n${message}`.toLowerCase();
  return allChannelConditionalRules().filter(rule => {
    const sources = (Array.isArray(rule.sourceIds) ? rule.sourceIds : splitChannelList(rule.sourceIds || '')).map(normalizeWhatsAppChannelId).filter(Boolean);
    if (sources.length && !sources.includes(sourceId)) return false;
    const keywords = (Array.isArray(rule.keywords) ? rule.keywords : splitChannelList(rule.keywords || '')).map(item => String(item || '').toLowerCase()).filter(Boolean);
    if (keywords.length && !keywords.some(keyword => text.includes(keyword))) return false;
    const block = (Array.isArray(rule.blockKeywords) ? rule.blockKeywords : splitChannelList(rule.blockKeywords || '')).map(item => String(item || '').toLowerCase()).filter(Boolean);
    if (block.length && block.some(keyword => text.includes(keyword))) return false;
    return true;
  });
}

function sourceIsPaused(sourceId = '') {
  const id = normalizeWhatsAppChannelId(sourceId);
  return (Array.isArray(settings.whatsapp_channel_paused_sources) ? settings.whatsapp_channel_paused_sources : []).includes(id);
}

function sourceHealthStatus(sourceId = '') {
  const id = normalizeWhatsAppChannelId(sourceId);
  const silentHours = Math.max(1, Number(settings.whatsapp_channel_source_silent_hours || 24));
  const deadHours = Math.max(silentHours + 1, Number(settings.whatsapp_channel_source_dead_hours || 168));
  const sourceLogs = (Array.isArray(logs) ? logs : [])
    .filter(row => row.from === id || row.sourceChannelId === id || row.sourceName === id || row.relay?.sourceChannelId === id);
  const sourceRows = (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
    .filter(row => normalizeWhatsAppChannelId(row.sourceChannelId || '') === id || String(row.sourceName || '').trim() === id);
  const latest = [...sourceLogs, ...sourceRows]
    .map(row => Date.parse(row.time || row.createdAt || row.updatedAt || 0) || 0)
    .filter(Boolean)
    .sort((a, b) => b - a)[0] || 0;
  const ageHours = latest ? (Date.now() - latest) / 36e5 : Infinity;
  const publishedCount = sourceRows.filter(row => ['published', 'sent'].includes(String(row.status || '').toLowerCase())).length;
  const pendingCount = sourceRows.filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())).length;
  const rejectedCount = sourceRows.filter(row => ['rejected', 'blocked', 'skipped'].includes(String(row.status || '').toLowerCase())).length;
  const status = latest
    ? (ageHours <= silentHours ? 'active' : ageHours <= deadHours ? 'silent' : 'dead')
    : 'unknown';
  return {
    status,
    lastSeenAt: latest ? new Date(latest).toISOString() : '',
    ageHours: Number.isFinite(ageHours) ? Math.round(ageHours) : null,
    silentHours,
    deadHours,
    pendingCount,
    publishedCount,
    rejectedCount
  };
}

function runChannelSourceDoctor({ autoPause = false } = {}) {
  const targets = new Set(getConfiguredWhatsAppChannels());
  const configured = new Set(getConfiguredWhatsAppChannelSources());
  const ids = [...new Set([
    ...getConfiguredWhatsAppChannelSources(),
    ...(Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [])
      .map(row => normalizeWhatsAppChannelId(row.channelId))
      .filter(id => id && !targets.has(id))
  ])].filter(Boolean);
  const rows = rankChannelSources(ids).map(row => {
    const health = sourceHealthStatus(row.channelId);
    const paused = sourceIsPaused(row.channelId);
    const allowed = passesSourceIntelligenceFilters({
      sourceChannelId: row.channelId,
      sourceName: row.name,
      message: row.name || ''
    });
    const issue = paused
      ? 'paused'
      : health.status === 'dead'
        ? `no activity for ${health.ageHours || 'many'}h`
        : health.status === 'silent'
          ? `silent for ${health.ageHours || 0}h`
          : allowed.allowed ? '' : allowed.reason;
    const recommendation = paused
      ? 'Resume only if you still want this source.'
      : health.status === 'dead'
        ? 'Pause or replace this source; it is not feeding content.'
        : health.status === 'silent'
          ? 'Keep watching, or lower its priority if it stays silent.'
          : allowed.allowed ? 'Healthy source.' : 'Fix filters/rules before relying on this source.';
    return {
      ...row,
      configured: configured.has(row.channelId),
      paused,
      health,
      issue,
      recommendation,
      allowed: allowed.allowed,
      blockReason: allowed.reason || ''
    };
  });
  let autoPaused = 0;
  if (autoPause || settings.whatsapp_channel_auto_pause_dead_sources === true) {
    const set = new Set(Array.isArray(settings.whatsapp_channel_paused_sources) ? settings.whatsapp_channel_paused_sources : []);
    for (const row of rows) {
      if (row.health.status === 'dead' && !set.has(row.channelId)) {
        set.add(row.channelId);
        row.paused = true;
        row.issue = row.issue || 'auto-paused dead source';
        autoPaused += 1;
      }
    }
    if (autoPaused > 0) {
      settings.whatsapp_channel_paused_sources = [...set];
      saveJSON('settings.json', settings);
    }
  }
  const summary = rows.reduce((acc, row) => {
    const key = row.paused ? 'paused' : row.health.status;
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, { total: rows.length, active: 0, silent: 0, dead: 0, unknown: 0, paused: 0 });
  summary.autoPaused = autoPaused;
  logs.push({ id: uuid(), type: 'whatsapp_channel_source_doctor', status: 'done', summary, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  return { success: true, summary, sources: rows };
}

function channelPostScores({ text = '', sourceName = '', sourceChannelId = '' } = {}) {
  const value = `${sourceName}\n${text}`.toLowerCase();
  const priorityHits = detectWhatsAppChannelPriorityKeywords(value);
  const flashHits = channelFlashSaleKeywords().filter(keyword => keyword && value.includes(keyword));
  const hasPrice = /\b(?:rs\.?|pkr|price|rate)\s*[:=-]?\s*\d{2,6}|\b\d{2,6}\s*(?:pkr|rs\.?)/i.test(value);
  const hasCTA = /\b(dm|reply|order|buy|claim|join|available|limited)\b/i.test(value);
  const sourceBoost = Math.min(30, sourcePriorityScore(sourceChannelId) * 5);
  const engagementScore = Math.min(100, 20 + priorityHits.length * 14 + flashHits.length * 20 + (hasPrice ? 14 : 0) + (hasCTA ? 12 : 0) + sourceBoost);
  const viralScore = Math.min(100, 15 + flashHits.length * 22 + priorityHits.length * 10 + (/\bfree|giveaway|urgent|breaking|limited\b/i.test(value) ? 18 : 0) + sourceBoost);
  return {
    category: sourceCategory(sourceChannelId, value),
    language: detectChannelLanguage(text),
    priorityHits,
    flashHits,
    engagementScore,
    viralScore,
    predictedBestTime: engagementScore >= 70 ? 'ASAP' : '18:00-21:00 PKT',
    trending: flashHits.length > 0 || viralScore >= 65
  };
}

function passesSourceIntelligenceFilters({ sourceChannelId = '', sourceName = '', message = '' } = {}) {
  const id = normalizeWhatsAppChannelId(sourceChannelId);
  const whitelist = channelSourceWhitelist();
  const blacklist = channelSourceBlacklist();
  const hay = `${id} ${sourceName}`.toLowerCase();
  if (sourceIsPaused(id)) return { allowed: false, reason: 'source paused' };
  if (whitelist.length && !whitelist.some(item => item === id || hay.includes(item.toLowerCase()))) return { allowed: false, reason: 'source not whitelisted' };
  if (blacklist.some(item => item === id || hay.includes(item.toLowerCase()))) return { allowed: false, reason: 'source blacklisted' };
  const langFilter = String(settings.whatsapp_channel_source_language_filter || 'any').toLowerCase();
  const language = detectChannelLanguage(message);
  if (langFilter !== 'any' && language !== 'unknown' && langFilter !== language) return { allowed: false, reason: `language filter blocked: ${language}` };
  const rule = sourceRule(id);
  if (rule.block === true) return { allowed: false, reason: 'per-source rule blocked' };
  if (rule.requireKeywords) {
    const required = splitChannelList(rule.requireKeywords).map(item => item.toLowerCase());
    const value = String(message || '').toLowerCase();
    if (required.length && !required.some(keyword => value.includes(keyword))) return { allowed: false, reason: 'required source keyword missing' };
  }
  return { allowed: true, language };
}

function rankChannelSources(sourceIds = []) {
  const discoveries = Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [];
  const rows = sourceIds.map((id, index) => {
    const channelId = normalizeWhatsAppChannelId(id);
    const found = discoveries.find(row => row.channelId === channelId) || {};
    const health = sourceHealthStatus(channelId);
    const priority = sourcePriorityScore(channelId);
    const subscribers = Number(found.subscribers || 0);
    const score = priority * 1000 + (health.status === 'active' ? 100 : health.status === 'stale' ? 20 : 0) + Math.min(100, subscribers / 1000) - index;
    return { channelId, name: found.name || channelId.replace('@newsletter', ''), health, priority, subscribers, score, index };
  });
  const mode = String(settings.whatsapp_channel_forwarding_mode || 'priority');
  if (mode === 'round_robin') {
    const cursor = Math.max(0, Number(settings.whatsapp_channel_round_robin_cursor || 0));
    const ordered = rows.slice(cursor % Math.max(1, rows.length)).concat(rows.slice(0, cursor % Math.max(1, rows.length)));
    settings.whatsapp_channel_round_robin_cursor = rows.length ? (cursor + 1) % rows.length : 0;
    saveJSON('settings.json', settings);
    return ordered;
  }
  if (mode === 'weighted') {
    const expanded = [];
    const sorted = rows.slice().sort((a, b) => b.score - a.score);
    sorted.forEach(row => {
      const weight = Math.max(1, Math.min(10, Number(row.priority || 0) + (row.health.status === 'active' ? 2 : 1)));
      for (let i = 0; i < weight; i += 1) expanded.push(row);
    });
    const cursor = Math.max(0, Number(settings.whatsapp_channel_round_robin_cursor || 0));
    const seen = new Set();
    const ordered = expanded
      .slice(cursor % Math.max(1, expanded.length))
      .concat(expanded.slice(0, cursor % Math.max(1, expanded.length)))
      .filter(row => {
        if (seen.has(row.channelId)) return false;
        seen.add(row.channelId);
        return true;
      });
    settings.whatsapp_channel_round_robin_cursor = expanded.length ? (cursor + 1) % expanded.length : 0;
    saveJSON('settings.json', settings);
    return ordered.length ? ordered : sorted;
  }
  return rows.sort((a, b) => b.score - a.score);
}

function channelForwardDepth(text = '') {
  const value = String(text || '');
  const matches = value.match(/Forwarded update\. Source:|Source:/gi);
  return matches ? matches.length : 0;
}

function scrubChannelRelayText(text = '') {
  let value = String(text || '');
  if (settings.whatsapp_channel_scrub_phone_numbers !== false) {
    value = value
      .replace(/(?:\+?92|0)?3\d{2}[-\s]?\d{7}\b/g, '[phone hidden]')
      .replace(/\b(?:\+?\d[\d\s().-]{8,}\d)\b/g, match => match.length >= 10 ? '[phone hidden]' : match);
  }
  if (settings.whatsapp_channel_scrub_links === true) {
    value = value.replace(/https?:\/\/[^\s]+/gi, '[link hidden]');
    value = value.replace(/\b(?:www\.)[^\s]+/gi, '[link hidden]');
  }
  return cleanOutgoingText(value);
}

function estimateChannelMediaSizeMb(mediaSource = '') {
  const localPath = resolveLocalMediaSourcePath(mediaSource);
  try {
    if (localPath && fs.existsSync(localPath)) {
      return fs.statSync(localPath).size / (1024 * 1024);
    }
  } catch {}
  return 0;
}

function looksNsfwChannelContent(text = '', mediaSource = '') {
  if (settings.whatsapp_channel_nsfw_filter_enabled === false) return false;
  const value = `${text || ''}\n${mediaSource || ''}`.toLowerCase();
  return /\b(nsfw|adult|porn|xxx|nude|nudes|sex|sexy|18\+|onlyfans)\b/i.test(value);
}

function validateChannelRelayPolicy(input = {}) {
  const sourceChannelId = normalizeWhatsAppChannelId(input.sourceChannelId || input.channelId || '');
  const sourceName = String(input.sourceName || input.channelName || '').trim();
  const text = String(input.message || input.body || input.caption || '').trim();
  const mediaUrl = String(input.mediaUrl || input.mediaPath || '').trim();
  const sourceIntelligence = passesSourceIntelligenceFilters({ sourceChannelId, sourceName, message: text });
  if (!sourceIntelligence.allowed) return sourceIntelligence;
  const foundSource = (Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : []).find(row => row.channelId === sourceChannelId);
  if (foundSource?.discoveredAt && Number(settings.whatsapp_channel_source_min_age_days || 0) > 0) {
    const ageMs = Date.now() - (Date.parse(foundSource.discoveredAt) || Date.now());
    const minMs = Number(settings.whatsapp_channel_source_min_age_days || 0) * 24 * 60 * 60 * 1000;
    if (ageMs < minMs) return { allowed: false, reason: `source age filter blocked: ${settings.whatsapp_channel_source_min_age_days}d minimum` };
  }
  const blacklisted = channelBlacklistedSenders();
  if (blacklisted.includes(sourceChannelId) || blacklisted.includes(sourceName.toLowerCase())) {
    return { allowed: false, reason: 'blacklisted sender/source' };
  }
  const competitors = channelCompetitorTerms();
  const value = `${sourceName}\n${text}`.toLowerCase();
  const competitor = competitors.find(term => term && value.includes(term));
  if (competitor) return { allowed: false, reason: `competitor mention blocked: ${competitor}` };
  if (channelForwardDepth(text) >= settings.whatsapp_channel_max_forward_depth) {
    return { allowed: false, reason: 'forwarding chain depth limit reached' };
  }
  const sizeMb = estimateChannelMediaSizeMb(mediaUrl);
  if (sizeMb && sizeMb > Number(settings.whatsapp_channel_max_media_mb || 25)) {
    return { allowed: false, reason: `media too large: ${sizeMb.toFixed(1)} MB` };
  }
  if (looksNsfwChannelContent(text, mediaUrl)) {
    return { allowed: false, reason: 'NSFW content blocked' };
  }
  return { allowed: true };
}

function resolveLocalMediaSourcePath(mediaSource = '') {
  const raw = String(mediaSource || '').trim();
  if (!raw || /^https?:\/\//i.test(raw)) return '';
  if (raw.startsWith('/uploads/')) return path.join(__dirname, raw.replace(/^\/+/, ''));
  if (raw.startsWith('/assets/')) return path.join(__dirname, 'public', raw.replace(/^\/+/, ''));
  return path.isAbsolute(raw) ? raw : path.join(__dirname, raw);
}

function channelMediaPublicUrl(mediaSource = '') {
  const raw = String(mediaSource || '').trim();
  if (!raw) return '';
  if (/^https?:\/\//i.test(raw)) return raw;
  const base = String(settings.social_public_base_url || process.env.SOCIAL_PUBLIC_BASE_URL || process.env.PUBLIC_BASE_URL || '').replace(/\/+$/, '');
  if (!base) return raw;
  if (raw.startsWith('/')) return `${base}${raw}`;
  if (raw.startsWith('uploads/')) return `${base}/${raw}`;
  return raw;
}

function escapeSvgText(text = '') {
  return String(text || '').replace(/[<>&"']/g, char => ({ '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&apos;' }[char]));
}

async function applyChannelWatermarkToMediaSource(mediaSource = '') {
  const raw = String(mediaSource || '').trim();
  if (!raw || settings.whatsapp_channel_watermark_images === false) return raw;
  const localPath = resolveLocalMediaSourcePath(raw);
  if (!localPath || !fs.existsSync(localPath)) return raw;
  const ext = path.extname(localPath).toLowerCase();
  if (!['.jpg', '.jpeg', '.png', '.webp'].includes(ext)) return raw;
  try {
    const sharp = require('sharp');
    const metadata = await sharp(localPath).metadata();
    const width = Number(metadata.width || 1080);
    const height = Number(metadata.height || 1080);
    const label = channelBrandHandle() || settings.business_name || 'SuperSender Pro';
    const fontSize = Math.max(22, Math.round(width / 34));
    const padX = Math.max(28, Math.round(width / 38));
    const padY = Math.max(18, Math.round(height / 52));
    const boxWidth = Math.min(width - 36, Math.max(260, label.length * fontSize * 0.72 + padX * 2));
    const boxHeight = fontSize + padY * 2;
    const svg = `<svg width="${width}" height="${height}" xmlns="http://www.w3.org/2000/svg">
      <rect x="${width - boxWidth - 18}" y="${height - boxHeight - 18}" width="${boxWidth}" height="${boxHeight}" rx="${Math.round(boxHeight / 2)}" fill="rgba(7,16,20,0.72)"/>
      <text x="${width - boxWidth + padX - 18}" y="${height - Math.round(boxHeight / 2) + Math.round(fontSize / 3) - 18}" font-family="Arial, sans-serif" font-size="${fontSize}" font-weight="800" fill="#ffffff">${escapeSvgText(label)}</text>
    </svg>`;
    const folder = path.join(__dirname, 'uploads', 'channel-watermarked');
    fs.mkdirSync(folder, { recursive: true });
    const filename = `${Date.now()}-${uuid()}${ext === '.jpg' ? '.jpg' : ext}`;
    const out = path.join(folder, filename);
    await sharp(localPath).composite([{ input: Buffer.from(svg), top: 0, left: 0 }]).toFile(out);
    return `/uploads/channel-watermarked/${filename}`;
  } catch (error) {
    console.warn('[ChannelBranding] watermark skipped:', error.message);
    return raw;
  }
}

async function generateAIChannelCaption({ message = '', mediaUrl = '', sourceName = '' } = {}) {
  if (settings.whatsapp_channel_ai_caption_enabled === false) return '';
  const fallback = cleanOutgoingText([
    sourceName ? `Latest update from ${sourceName}` : 'Latest channel update',
    String(settings.whatsapp_channel_ai_caption_cta || 'DM for details.').trim()
  ].filter(Boolean).join('\n')).slice(0, 650);
  if (settings.whatsapp_channel_ai_caption_provider_enabled !== true || !hasAnyAIProvider()) return fallback;
  if (generateAIChannelCaption.cooldownUntil && Date.now() < generateAIChannelCaption.cooldownUntil) return fallback;
  const base = String(message || '').trim();
  const cta = String(settings.whatsapp_channel_ai_caption_cta || 'DM for details.').trim();
  const systemPrompt = `You write short WhatsApp Channel captions for Pakistani audiences.
Use Roman Urdu + English, natural business tone, 1-3 lines.
Do not invent facts. Add one clear CTA.`;
  const prompt = [
    `Source channel: ${sourceName || 'WhatsApp Channel'}`,
    `Existing text: ${base || '[image/video post with no caption]'}`,
    `Media: ${mediaUrl ? 'yes' : 'no'}`,
    `CTA: ${cta}`,
    'Write one improved caption under 450 characters.'
  ].join('\n');
  const reply = await callAI(prompt, systemPrompt).catch(error => {
    generateAIChannelCaption.cooldownUntil = Date.now() + Math.max(60_000, Number(settings.whatsapp_channel_ai_caption_cooldown_ms || 180_000));
    console.warn('[ChannelCaption] AI caption cooldown:', error.message);
    return '';
  });
  const text = cleanOutgoingText(reply || '').trim();
  if (!text || /AI is currently offline|temporary glitch|sorry/i.test(text)) return '';
  return text.slice(0, 650);
}

function shouldUseAICaptionForChannelPost({ message = '', mediaUrl = '' } = {}) {
  if (settings.whatsapp_channel_ai_caption_enabled === false) return false;
  if (!mediaUrl) return false;
  const body = meaningfulChannelRelayBody(message || '');
  return !body || body.length < 80;
}

async function sendTelegramBridgePost({ message = '', mediaUrl = '', parseMode = '' } = {}) {
  const token = String(settings.telegram_token || process.env.TELEGRAM_TOKEN || process.env.TELEGRAM_BOT_TOKEN || '').trim();
  const chatId = String(settings.telegram_channel_chat_id || process.env.TELEGRAM_CHANNEL_CHAT_ID || settings.telegram_chat_id || process.env.TELEGRAM_CHAT_ID || '').trim();
  if (!token) throw new Error('Telegram bot token missing');
  if (!chatId) throw new Error('Telegram channel/chat ID missing');
  const caption = cleanOutgoingText(message || '').slice(0, 1024);
  const text = cleanOutgoingText(message || '').slice(0, 3900);
  const mediaPublic = channelMediaPublicUrl(mediaUrl);
  const localPath = resolveLocalMediaSourcePath(mediaUrl);
  const ext = path.extname(String(mediaUrl || localPath || '')).toLowerCase();
  const endpointBase = `https://api.telegram.org/bot${token}`;
  let endpoint = '/sendMessage';
  let body;
  let headers;
  if (mediaUrl && ['.jpg', '.jpeg', '.png', '.webp'].includes(ext)) {
    endpoint = '/sendPhoto';
    if (localPath && fs.existsSync(localPath) && typeof FormData !== 'undefined' && typeof Blob !== 'undefined') {
      const form = new FormData();
      form.append('chat_id', chatId);
      form.append('caption', caption);
      if (parseMode) form.append('parse_mode', parseMode);
      form.append('photo', new Blob([fs.readFileSync(localPath)]), path.basename(localPath));
      body = form;
    } else {
      headers = { 'Content-Type': 'application/json' };
      body = JSON.stringify({ chat_id: chatId, photo: mediaPublic, caption, ...(parseMode ? { parse_mode: parseMode } : {}) });
    }
  } else if (mediaUrl && ['.mp4', '.mov', '.webm'].includes(ext)) {
    endpoint = '/sendVideo';
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ chat_id: chatId, video: mediaPublic, caption, ...(parseMode ? { parse_mode: parseMode } : {}) });
  } else {
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ chat_id: chatId, text, disable_web_page_preview: false, ...(parseMode ? { parse_mode: parseMode } : {}) });
  }
  const response = await fetchOutbound(`${endpointBase}${endpoint}`, { method: 'POST', headers, body });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error(data.description || `Telegram bridge failed (${response.status})`);
  logs.push({ id: uuid(), type: 'telegram_bridge_post', status: 'sent', message: text || caption, mediaUrl, response: data, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  return data;
}

async function bridgeWhatsAppChannelContent({ message = '', mediaUrl = '', kind = 'custom', platforms: forcedPlatforms = null } = {}) {
  if (settings.whatsapp_channel_bridge_enabled !== true) return { skipped: true, reason: 'bridge disabled' };
  const sourcePlatforms = Array.isArray(forcedPlatforms) && forcedPlatforms.length ? forcedPlatforms : settings.whatsapp_channel_bridge_platforms;
  const platforms = (Array.isArray(sourcePlatforms) ? sourcePlatforms : [])
    .map(item => String(item || '').trim().toLowerCase())
    .filter(Boolean);
  if (!platforms.length) return { skipped: true, reason: 'no bridge platforms' };
  const results = [];
  const imageUrl = channelMediaPublicUrl(mediaUrl);
  for (const platform of platforms) {
    try {
      if (platform === 'telegram') {
        const response = await sendTelegramBridgePost({ message, mediaUrl });
        results.push({ platform, success: true, response });
      } else if (['facebook', 'instagram', 'linkedin', 'tiktok'].includes(normalizeSocialPlatform(platform))) {
        const normalized = normalizeSocialPlatform(platform);
        if (normalized === 'instagram' && !imageUrl) {
          results.push({ platform: normalized, skipped: true, reason: 'Instagram requires public image/video URL' });
          continue;
        }
        const payload = {
          message,
          imageUrl: imageUrl && /\.(jpe?g|png|webp)(\?|$)/i.test(imageUrl) ? imageUrl : '',
          videoUrl: imageUrl && /\.(mp4|mov|webm)(\?|$)/i.test(imageUrl) ? imageUrl : '',
          publishMode: settings.tiktok_publish_mode || 'draft'
        };
        const response = await publishSocialPayloadToPlatform(normalized, payload);
        results.push({ platform: normalized, success: true, response });
      }
    } catch (error) {
      results.push({ platform, success: false, error: error.message });
      console.warn(`[ChannelBridge] ${platform} failed:`, error.message);
    }
  }
  logs.push({ id: uuid(), type: 'whatsapp_channel_bridge', status: results.some(r => r.success) ? 'sent' : 'partial', kind, results, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  return { success: true, results };
}

async function shareWhatsAppChannelContentToFacebook({ message = '', mediaUrl = '', relayId = '' } = {}) {
  const relay = relayId
    ? (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).find(row => String(row.id) === String(relayId))
    : (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).find(row => ['pending', 'draft', 'manual_required', 'failed', 'published'].includes(String(row.status || '').toLowerCase()));
  const rawMessage = String(message || relay?.message || relay?.preview || relay?.title || '').trim();
  const rawMedia = String(mediaUrl || relay?.mediaUrl || relay?.mediaPath || '').trim();
  if (!rawMessage && !rawMedia) throw new Error('Message/media or relayId is required for Facebook sharing');
  const finalMessage = applyChannelBrandingToText(rawMessage || 'WhatsApp Channel update');
  const result = await bridgeWhatsAppChannelContent({
    message: finalMessage,
    mediaUrl: rawMedia,
    kind: 'facebook-bridge',
    platforms: ['facebook']
  });
  const facebookResult = (result.results || []).find(row => row.platform === 'facebook');
  if (!facebookResult?.success) {
    throw new Error(facebookResult?.error || facebookResult?.reason || 'Facebook bridge did not publish');
  }
  return {
    success: true,
    relayId: relay?.id || '',
    message: finalMessage,
    mediaUrl: rawMedia,
    result: facebookResult
  };
}

function channelRelayBoostScore(row = {}) {
  const text = `${row.title || ''}\n${row.message || row.preview || ''}`.toLowerCase();
  const priorityKeywords = channelPriorityKeywords().map(item => String(item || '').toLowerCase()).filter(Boolean);
  const keywordHits = priorityKeywords.filter(keyword => keyword && text.includes(keyword)).length;
  const status = String(row.status || '').toLowerCase();
  const ageHours = Math.max(0, (Date.now() - (Date.parse(row.updatedAt || row.createdAt || 0) || Date.now())) / 36e5);
  const recencyBoost = Math.max(0, 18 - Math.min(18, ageHours));
  const statusBoost = status === 'published' ? 4 : ['pending', 'draft', 'manual_required', 'failed'].includes(status) ? 14 : 0;
  const mediaBoost = row.mediaUrl ? 8 : 0;
  const priorityBoost = row.priority === true ? 18 : 0;
  return Math.round(
    Number(row.viralScore || 0) * 1.35 +
    Number(row.engagementScore || 0) +
    priorityBoost +
    keywordHits * 7 +
    mediaBoost +
    statusBoost +
    recencyBoost
  );
}

function selectChannelBoostCandidate({ includePublished = true, relayId = '' } = {}) {
  const rows = Array.isArray(channelRelayInbox) ? channelRelayInbox : [];
  if (relayId) return rows.find(row => String(row.id) === String(relayId)) || null;
  const boostedRecently = new Set((Array.isArray(logs) ? logs : [])
    .filter(row => row.type === 'whatsapp_channel_boost' && Date.now() - (Date.parse(row.time || 0) || 0) < 24 * 60 * 60 * 1000)
    .map(row => String(row.relayId || ''))
    .filter(Boolean));
  const allowedStatuses = includePublished
    ? ['pending', 'draft', 'failed', 'manual_required', 'published']
    : ['pending', 'draft', 'failed', 'manual_required'];
  return rows
    .filter(row => allowedStatuses.includes(String(row.status || '').toLowerCase()))
    .filter(row => String(row.message || row.preview || row.title || row.mediaUrl || '').trim())
    .filter(row => !boostedRecently.has(String(row.id || '')))
    .sort((a, b) =>
      channelRelayBoostScore(b) - channelRelayBoostScore(a) ||
      Date.parse(b.updatedAt || b.createdAt || 0) - Date.parse(a.updatedAt || a.createdAt || 0)
    )[0] || rows
      .filter(row => allowedStatuses.includes(String(row.status || '').toLowerCase()))
      .filter(row => String(row.message || row.preview || row.title || row.mediaUrl || '').trim())
      .sort((a, b) => channelRelayBoostScore(b) - channelRelayBoostScore(a))[0] || null;
}

async function runChannelBoostEngine({ dryRun = true, facebook = true, whatsapp = false, relayId = '', message = '', mediaUrl = '' } = {}) {
  const customMessage = String(message || '').trim();
  const customMedia = String(mediaUrl || '').trim();
  const candidate = customMessage || customMedia ? null : selectChannelBoostCandidate({ includePublished: true, relayId });
  if (!candidate && !customMessage && !customMedia) throw new Error('No channel relay found to boost');
  const boostMessage = applyChannelBrandingToText(customMessage || candidate?.message || candidate?.preview || candidate?.title || 'WhatsApp Channel update');
  const boostMedia = customMedia || candidate?.mediaUrl || candidate?.mediaPath || '';
  const score = candidate ? channelRelayBoostScore(candidate) : 80;
  if (dryRun) {
    return {
      success: true,
      dryRun: true,
      action: 'preview',
      relay: candidate ? channelRelayPublic(candidate) : null,
      score,
      facebookReady: !!((settings.fb_page_access_token || settings.facebook_page_access_token || process.env.FB_PAGE_ACCESS_TOKEN) && (settings.facebook_page_id || process.env.FACEBOOK_PAGE_ID)),
      whatsappTargets: getConfiguredWhatsAppChannels().length,
      message: boostMessage,
      mediaUrl: boostMedia,
      recommendation: score >= 120 ? 'Post now. High boost score.' : score >= 80 ? 'Good candidate. Post when channel is active.' : 'Average candidate. Keep in queue or improve caption.'
    };
  }
  const results = {};
  if (whatsapp && candidate) {
    results.whatsapp = await publishChannelRelayDraft(candidate.id, { delayMs: candidate.priority ? 500 : 1200 });
  }
  if (facebook) {
    results.facebook = await shareWhatsAppChannelContentToFacebook({
      relayId: candidate?.id || '',
      message: customMessage,
      mediaUrl: boostMedia
    });
  }
  logs.push({
    id: uuid(),
    type: 'whatsapp_channel_boost',
    status: Object.values(results).some(item => item?.success !== false) ? 'sent' : 'failed',
    relayId: candidate?.id || '',
    score,
    facebook,
    whatsapp,
    message: boostMessage,
    mediaUrl: boostMedia,
    results,
    time: new Date().toISOString()
  });
  saveJSON('logs.json', logs);
  return { success: true, dryRun: false, relay: candidate ? channelRelayPublic(candidate) : null, score, results };
}

function channelBridgeConfiguredPlatforms() {
  const source = Array.isArray(settings.whatsapp_channel_bridge_platforms)
    ? settings.whatsapp_channel_bridge_platforms
    : String(settings.whatsapp_channel_bridge_platforms || '').split(/[,\n|]+/);
  const platforms = source.map(item => normalizeSocialPlatform(String(item || '').trim().toLowerCase())).filter(Boolean);
  return Array.from(new Set(platforms.length ? platforms : ['telegram', 'instagram', 'facebook']));
}

function getChannelBridgePlatformReadiness(platform = '') {
  const key = normalizeSocialPlatform(platform);
  if (key === 'telegram') {
    const token = String(settings.telegram_token || process.env.TELEGRAM_TOKEN || '').trim();
    const chatId = String(settings.telegram_channel_chat_id || process.env.TELEGRAM_CHANNEL_CHAT_ID || settings.telegram_chat_id || process.env.TELEGRAM_CHAT_ID || '').trim();
    return { ready: !!(token && chatId), missing: [!token && 'Telegram token', !chatId && 'Telegram channel/chat ID'].filter(Boolean) };
  }
  if (key === 'facebook') {
    const token = String(settings.fb_page_access_token || settings.facebook_page_access_token || process.env.FB_PAGE_ACCESS_TOKEN || '').trim();
    const pageId = String(settings.facebook_page_id || process.env.FACEBOOK_PAGE_ID || '').trim();
    return { ready: !!(token && pageId), missing: [!token && 'Facebook page token', !pageId && 'Facebook page ID'].filter(Boolean) };
  }
  if (key === 'instagram') {
    const token = String(settings.instagram_access_token || process.env.INSTAGRAM_ACCESS_TOKEN || settings.fb_page_access_token || process.env.FB_PAGE_ACCESS_TOKEN || '').trim();
    const igId = String(settings.instagram_ig_user_id || settings.instagram_business_account_id || process.env.INSTAGRAM_IG_USER_ID || '').trim();
    return { ready: !!(token && igId), missing: [!token && 'Instagram token', !igId && 'Instagram business account ID'].filter(Boolean) };
  }
  if (key === 'linkedin') {
    const token = String(settings.linkedin_access_token || process.env.LINKEDIN_ACCESS_TOKEN || '').trim();
    const owner = String(settings.linkedin_owner_urn || process.env.LINKEDIN_OWNER_URN || '').trim();
    return { ready: !!(token && owner), missing: [!token && 'LinkedIn token', !owner && 'LinkedIn owner/profile/org URN'].filter(Boolean) };
  }
  if (key === 'tiktok') {
    const token = String(settings.tiktok_access_token || process.env.TIKTOK_ACCESS_TOKEN || '').trim();
    return { ready: !!token, missing: [!token && 'TikTok token'].filter(Boolean) };
  }
  if (key === 'whatsapp') {
    return { ready: getConfiguredWhatsAppChannels().length > 0, missing: getConfiguredWhatsAppChannels().length ? [] : ['WhatsApp target channels'] };
  }
  return { ready: false, missing: ['Unsupported platform'] };
}

function pushBridgeAttempt(stats, platform = '', attempt = {}) {
  const key = normalizeSocialPlatform(platform) || String(platform || 'unknown').toLowerCase() || 'unknown';
  if (!stats[key]) {
    stats[key] = { platform: key, ready: false, missing: [], total: 0, success: 0, failed: 0, skipped: 0, lastSuccessAt: '', lastFailureAt: '', lastError: '' };
  }
  const row = stats[key];
  row.total += 1;
  const time = attempt.time || '';
  if (attempt.skipped) {
    row.skipped += 1;
    row.lastError = attempt.reason || row.lastError;
    row.lastFailureAt = time || row.lastFailureAt;
    return;
  }
  if (attempt.success) {
    row.success += 1;
    row.lastSuccessAt = time || row.lastSuccessAt;
    return;
  }
  row.failed += 1;
  row.lastFailureAt = time || row.lastFailureAt;
  row.lastError = attempt.error || attempt.reason || row.lastError;
}

function buildChannelBridgeHealthReport({ limit = 80 } = {}) {
  const configuredPlatforms = channelBridgeConfiguredPlatforms();
  const stats = {};
  for (const platform of configuredPlatforms) {
    const readiness = getChannelBridgePlatformReadiness(platform);
    stats[platform] = {
      platform,
      ready: readiness.ready,
      missing: readiness.missing,
      total: 0,
      success: 0,
      failed: 0,
      skipped: 0,
      lastSuccessAt: '',
      lastFailureAt: '',
      lastError: ''
    };
  }
  const bridgeLogTypes = new Set(['whatsapp_channel_bridge', 'whatsapp_channel_facebook_bridge', 'whatsapp_channel_boost', 'telegram_bridge_post']);
  const recent = (Array.isArray(logs) ? logs : [])
    .filter(row => bridgeLogTypes.has(String(row.type || '')))
    .slice(-Math.max(1, Number(limit || 80)))
    .reverse();

  for (const row of recent) {
    const time = row.time || row.createdAt || '';
    if (row.type === 'telegram_bridge_post') {
      pushBridgeAttempt(stats, 'telegram', { success: String(row.status || '').toLowerCase() === 'sent', error: row.error || '', time });
      continue;
    }
    if (row.type === 'whatsapp_channel_facebook_bridge') {
      pushBridgeAttempt(stats, 'facebook', { success: String(row.status || '').toLowerCase() === 'sent', error: row.error || '', time });
      continue;
    }
    if (row.type === 'whatsapp_channel_boost') {
      if (row.results?.facebook) pushBridgeAttempt(stats, 'facebook', { success: row.results.facebook?.success !== false, error: row.results.facebook?.error || '', time });
      if (row.results?.whatsapp) pushBridgeAttempt(stats, 'whatsapp', { success: row.results.whatsapp?.success !== false, error: row.results.whatsapp?.error || '', time });
      continue;
    }
    const resultRows = Array.isArray(row.results) ? row.results : [];
    for (const result of resultRows) {
      pushBridgeAttempt(stats, result.platform, {
        success: result.success === true,
        skipped: result.skipped === true,
        error: result.error || '',
        reason: result.reason || '',
        time
      });
    }
  }

  for (const platform of Object.keys(stats)) {
    const readiness = getChannelBridgePlatformReadiness(platform);
    stats[platform].ready = readiness.ready;
    stats[platform].missing = readiness.missing;
  }
  const platformRows = Object.values(stats).sort((a, b) => configuredPlatforms.indexOf(a.platform) - configuredPlatforms.indexOf(b.platform));
  const recommendations = [];
  if (settings.whatsapp_channel_bridge_enabled !== true) recommendations.push('Bridge OFF hai. Dashboard se Bridge ON karein ya !channelcopy auto on use karein.');
  for (const row of platformRows) {
    if (!row.ready) recommendations.push(`${row.platform}: ${row.missing.join(', ')} set karein.`);
    if (row.failed > 0 && row.lastError) recommendations.push(`${row.platform}: last error check karein - ${row.lastError}`);
    if (row.platform === 'instagram' && row.skipped > 0) recommendations.push('Instagram posts ke liye public image/video URL lazmi hota hai.');
  }
  return {
    success: true,
    generatedAt: new Date().toISOString(),
    bridgeEnabled: settings.whatsapp_channel_bridge_enabled === true,
    configuredPlatforms,
    whatsappTargets: getConfiguredWhatsAppChannels().length,
    relayQueue: (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).filter(row => ['pending', 'draft', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())).length,
    lastBridgeLogs: recent.slice(0, 10).map(row => ({ id: row.id, type: row.type, status: row.status, time: row.time, error: row.error || '', results: row.results || null })),
    platforms: platformRows,
    recommendations: recommendations.slice(0, 8)
  };
}

function formatChannelBridgeHealthReply(report = buildChannelBridgeHealthReport()) {
  const platformLines = (report.platforms || []).map(row => {
    const status = row.ready ? 'READY' : 'SETUP NEEDED';
    const last = row.lastSuccessAt || row.lastFailureAt || 'none';
    const err = row.lastError ? `\n   Last error: ${row.lastError.slice(0, 120)}` : '';
    return `• *${row.platform}* — ${status}\n   Sent: ${row.success}/${row.total} | Failed: ${row.failed} | Skipped: ${row.skipped}\n   Last: ${last}${err}`;
  }).join('\n\n');
  const tips = (report.recommendations || []).length
    ? '\n\n*Next fixes:*\n' + report.recommendations.map(item => `- ${item}`).join('\n')
    : '\n\n✅ Bridge healthy lag raha hai.';
  return `📡 *Channel Bridge Health*

Bridge: *${report.bridgeEnabled ? 'ON' : 'OFF'}*
Platforms: *${(report.configuredPlatforms || []).join(', ') || 'none'}*
WhatsApp targets: *${report.whatsappTargets || 0}*
Relay queue: *${report.relayQueue || 0}*

${platformLines || 'No platform activity yet.'}${tips}

Commands:
*!channelboost* - best post preview
*!channelboost now* - Facebook par post
*!channelfb preview* - Facebook preview`;
}

async function postChannelWebhook(url = '', payload = {}, headers = {}) {
  const target = String(url || '').trim();
  if (!target) return { skipped: true, reason: 'webhook missing' };
  try {
    const response = await fetchOutbound(target, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', ...headers },
      body: JSON.stringify(payload)
    });
    const raw = await response.text().catch(() => '');
    return { success: response.ok, status: response.status, body: raw.slice(0, 500) };
  } catch (error) {
    return { success: false, error: error.message };
  }
}

async function triggerChannelPostIntegrations(row = {}, stage = 'ingested') {
  const payload = {
    event: 'whatsapp_channel_post',
    stage,
    generatedAt: new Date().toISOString(),
    post: channelRelayPublic(row),
    source: {
      id: row.sourceChannelId || '',
      name: row.sourceName || '',
      url: row.sourceUrl || ''
    },
    mediaPublicUrl: channelMediaPublicUrl(row.mediaUrl || '')
  };
  const results = [];
  const push = (name, result) => results.push({ name, ...(result || {}) });
  if (settings.whatsapp_channel_webhook_url) push('webhook', await postChannelWebhook(settings.whatsapp_channel_webhook_url, payload));
  if (settings.whatsapp_channel_zapier_webhook_url) push('zapier', await postChannelWebhook(settings.whatsapp_channel_zapier_webhook_url, payload));
  if (settings.whatsapp_channel_make_webhook_url) push('make', await postChannelWebhook(settings.whatsapp_channel_make_webhook_url, payload));
  if (settings.whatsapp_channel_slack_webhook_url) {
    push('slack', await postChannelWebhook(settings.whatsapp_channel_slack_webhook_url, {
      text: `New channel post ${stage}: ${row.title || row.sourceName || 'WhatsApp Channel'}`,
      blocks: [
        { type: 'section', text: { type: 'mrkdwn', text: `*${row.title || 'WhatsApp Channel Post'}*\n${String(row.message || '').slice(0, 1200)}` } }
      ]
    }));
  }
  if (settings.whatsapp_channel_discord_webhook_url) {
    push('discord', await postChannelWebhook(settings.whatsapp_channel_discord_webhook_url, {
      content: `**${row.title || 'WhatsApp Channel Post'}**\n${String(row.message || '').slice(0, 1800)}`
    }));
  }
  if (settings.firebase_database_url) {
    const base = String(settings.firebase_database_url || '').replace(/\/+$/, '');
    const secret = settings.firebase_api_key ? `?auth=${encodeURIComponent(settings.firebase_api_key)}` : '';
    push('firebase', await postChannelWebhook(`${base}/whatsapp_channel_posts/${encodeURIComponent(row.id || uuid())}.json${secret}`, payload));
  }
  if (settings.airtable_api_key && settings.airtable_channel_base_id && settings.airtable_channel_table_name) {
    const table = encodeURIComponent(settings.airtable_channel_table_name);
    push('airtable', await postChannelWebhook(`https://api.airtable.com/v0/${settings.airtable_channel_base_id}/${table}`, {
      records: [{
        fields: {
          Title: row.title || '',
          Source: row.sourceName || '',
          Status: row.status || '',
          Message: String(row.message || '').slice(0, 100000),
          Media: row.mediaUrl || '',
          Priority: row.priority === true,
          CreatedAt: row.createdAt || new Date().toISOString()
        }
      }]
    }, { Authorization: `Bearer ${settings.airtable_api_key}` }));
  }
  if (settings.notion_api_key && settings.notion_channel_database_id) {
    push('notion', await postChannelWebhook('https://api.notion.com/v1/pages', {
      parent: { database_id: settings.notion_channel_database_id },
      properties: {
        Name: { title: [{ text: { content: String(row.title || 'WhatsApp Channel Post').slice(0, 120) } }] },
        Source: { rich_text: [{ text: { content: String(row.sourceName || '').slice(0, 200) } }] },
        Status: { rich_text: [{ text: { content: String(row.status || stage) } }] },
        Priority: { checkbox: row.priority === true }
      },
      children: [{
        object: 'block',
        type: 'paragraph',
        paragraph: { rich_text: [{ text: { content: String(row.message || '').slice(0, 1900) } }] }
      }]
    }, { Authorization: `Bearer ${settings.notion_api_key}`, 'Notion-Version': '2022-06-28' }));
  }
  try {
    const n8nResult = await n8nBridge.triggerWorkflow('whatsapp_channel_post', payload);
    results.push({ name: 'n8n', ...n8nResult });
  } catch (error) {
    results.push({ name: 'n8n', success: false, error: error.message });
  }
  if (results.length) {
    logs.push({ id: uuid(), type: 'whatsapp_channel_integrations', status: results.some(r => r.success) ? 'sent' : 'skipped', stage, relayId: row.id, results, time: new Date().toISOString() });
    saveJSON('logs.json', logs);
  }
  return { success: true, results };
}

function isLikelyEncodedMediaPayload(text = '') {
  const value = String(text || '').trim();
  if (value.length < 500) return false;
  if (/^\/9j\/[A-Za-z0-9+/=\s]+$/.test(value)) return true;
  if (/^[A-Za-z0-9+/=\s]{900,}$/.test(value) && !/\s{2,}|https?:\/\/|\p{L}/u.test(value.slice(0, 900))) return true;
  return false;
}

function meaningfulChannelRelayBody(text = '') {
  return String(text || '')
    .replace(/[\u200e\u200f\u202a-\u202e\u2066-\u2069]/g, '')
    .replace(/—\s*Forwarded update\. Source:.*/is, '')
    .replace(/Forwarded update\. Source:.*/is, '')
    .trim();
}

function formatWhatsAppChannelCopyStatus() {
  const targets = getConfiguredWhatsAppChannels();
  const sources = getConfiguredWhatsAppChannelSources();
  const sourceRows = sources.map((id, index) => {
    const found = (Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : []).find(row => row.channelId === id);
    return `${index + 1}. ${found?.name || id}\n   ${id}`;
  }).join('\n') || 'No source channels selected yet.';
  const targetRows = targets.map((id, index) => {
    const found = (Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : []).find(row => row.channelId === id);
    return `${index + 1}. ${found?.name || id}\n   ${id}`;
  }).join('\n') || 'No target channel configured.';
  return cleanOutgoingText(`📡 *Channel Copy Pipeline*

Capture: *${settings.whatsapp_channel_copy_enabled === true ? 'ON' : 'OFF'}*
Auto publish: *${settings.whatsapp_channel_relay_auto_publish === true ? 'ON' : 'OFF'}*

*Source channels:*
${sourceRows}

*Target channels:*
${targetRows}

Commands:
*!channelcatch* — channels scan
*!channelsource 2,3* — source channels choose
*!channeluse 1,9* — target channels choose
*!channelcopy on/off*
*!channelcopy scan 5*
*!relay yes* — latest draft publish`);
}

function saveChannelRelayInbox() {
  channelRelayInbox = (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
    .sort((a, b) => Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, 1000);
  saveJSON('channel_relay_inbox.json', channelRelayInbox);
}

function saveChannelAutomationJobs() {
  channelAutomationJobs = (Array.isArray(channelAutomationJobs) ? channelAutomationJobs : [])
    .sort((a, b) => String(a.name || '').localeCompare(String(b.name || '')))
    .slice(0, 500);
  saveJSON('channel_automation_jobs.json', channelAutomationJobs);
}

function saveChannelMediaPipeline() {
  channelMediaPipeline = (Array.isArray(channelMediaPipeline) ? channelMediaPipeline : [])
    .sort((a, b) => Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, 1000);
  saveJSON('channel_media_pipeline.json', channelMediaPipeline);
}

function saveChannelContentLibrary() {
  channelContentLibrary = (Array.isArray(channelContentLibrary) ? channelContentLibrary : [])
    .sort((a, b) => Date.parse(b.lastPublishedAt || b.createdAt || 0) - Date.parse(a.lastPublishedAt || a.createdAt || 0))
    .slice(0, 2000);
  saveJSON('channel_content_library.json', channelContentLibrary);
}

function saveChannelAutomationState() {
  if (Array.isArray(channelAutomationState.relayFingerprints)) {
    const cutoff = Date.now() - Math.max(1, Number(settings.whatsapp_channel_duplicate_window_hours || 48)) * 60 * 60 * 1000;
    channelAutomationState.relayFingerprints = channelAutomationState.relayFingerprints
      .filter(row => row?.fingerprint && (Date.parse(row.time || 0) || 0) >= cutoff)
      .slice(-5000);
  }
  saveJSON('channel_automation_state.json', channelAutomationState || {});
}

function rememberChannelRelayFingerprint(row = {}) {
  const fingerprint = String(row.fingerprint || '').trim();
  if (!fingerprint) return;
  const existing = (Array.isArray(channelAutomationState.relayFingerprints) ? channelAutomationState.relayFingerprints : [])
    .filter(item => item.fingerprint !== fingerprint);
  existing.push({
    fingerprint,
    sourceChannelId: row.sourceChannelId || '',
    sourceName: row.sourceName || '',
    time: row.publishedAt || row.updatedAt || new Date().toISOString()
  });
  channelAutomationState.relayFingerprints = existing;
}

function channelRelayRecentlySeen(fingerprint = '') {
  const fp = String(fingerprint || '').trim();
  if (!fp) return false;
  const cutoff = Date.now() - Math.max(1, Number(settings.whatsapp_channel_duplicate_window_hours || 48)) * 60 * 60 * 1000;
  return (Array.isArray(channelAutomationState.relayFingerprints) ? channelAutomationState.relayFingerprints : [])
    .some(row => row.fingerprint === fp && (Date.parse(row.time || 0) || 0) >= cutoff);
}

function sourceCooldownRemainingMs(sourceChannelId = '') {
  const id = normalizeWhatsAppChannelId(sourceChannelId || '');
  if (!id) return 0;
  const cooldownMs = Math.max(0, Number(settings.whatsapp_channel_source_cooldown_seconds || 90)) * 1000;
  if (!cooldownMs) return 0;
  const last = Date.parse(channelAutomationState.sourceLastPublishedAt?.[id] || 0) || 0;
  return Math.max(0, cooldownMs - (Date.now() - last));
}

function rememberSourcePublished(sourceChannelId = '') {
  const id = normalizeWhatsAppChannelId(sourceChannelId || '');
  if (!id) return;
  channelAutomationState.sourceLastPublishedAt = channelAutomationState.sourceLastPublishedAt && typeof channelAutomationState.sourceLastPublishedAt === 'object'
    ? channelAutomationState.sourceLastPublishedAt
    : {};
  channelAutomationState.sourceLastPublishedAt[id] = new Date().toISOString();
}

function runChannelQueueCleaner({ force = false } = {}) {
  if (settings.whatsapp_channel_queue_cleaner_enabled === false && !force) {
    return { skipped: true, reason: 'queue cleaner disabled' };
  }
  const now = Date.now();
  const openStatuses = new Set(['pending', 'draft', 'failed', 'manual_required']);
  const relayTtlMs = Math.max(1, Number(settings.whatsapp_channel_relay_ttl_hours || 24)) * 60 * 60 * 1000;
  const manualTtlMs = Math.max(1, Number(settings.whatsapp_channel_manual_packet_ttl_hours || 6)) * 60 * 60 * 1000;
  const maxPerSource = Math.max(1, Number(settings.whatsapp_channel_max_pending_per_source || 4));
  const stats = { stale: 0, duplicate: 0, capped: 0, totalRejected: 0, openBefore: 0, openAfter: 0 };
  const rows = Array.isArray(channelRelayInbox) ? channelRelayInbox : [];
  const openRows = rows.filter(row => openStatuses.has(String(row.status || '').toLowerCase()));
  stats.openBefore = openRows.length;

  for (const row of openRows) {
    const status = String(row.status || '').toLowerCase();
    const updatedAt = Date.parse(row.updatedAt || row.createdAt || 0) || 0;
    const ttl = status === 'manual_required' ? manualTtlMs : relayTtlMs;
    if (updatedAt && now - updatedAt > ttl) {
      row.status = 'rejected';
      row.error = status === 'manual_required'
        ? `Manual packet expired after ${Math.round(manualTtlMs / 3600000)}h`
        : `Relay expired after ${Math.round(relayTtlMs / 3600000)}h`;
      row.updatedAt = new Date().toISOString();
      row.cleanedAt = row.updatedAt;
      stats.stale += 1;
    }
  }

  const activeAfterTtl = rows
    .filter(row => openStatuses.has(String(row.status || '').toLowerCase()))
    .sort((a, b) => Number(b.priority === true) - Number(a.priority === true) || Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0));
  const seenFingerprints = new Set();
  for (const row of activeAfterTtl) {
    const fp = String(row.fingerprint || '').trim();
    if (!fp) continue;
    if (seenFingerprints.has(fp)) {
      row.status = 'rejected';
      row.error = 'Duplicate relay removed by queue cleaner';
      row.updatedAt = new Date().toISOString();
      row.cleanedAt = row.updatedAt;
      stats.duplicate += 1;
      continue;
    }
    seenFingerprints.add(fp);
  }

  const sourceBuckets = new Map();
  for (const row of rows.filter(row => openStatuses.has(String(row.status || '').toLowerCase()))) {
    const key = normalizeWhatsAppChannelId(row.sourceChannelId || '') || String(row.sourceName || 'unknown').trim().toLowerCase() || 'unknown';
    if (!sourceBuckets.has(key)) sourceBuckets.set(key, []);
    sourceBuckets.get(key).push(row);
  }
  for (const bucket of sourceBuckets.values()) {
    bucket.sort((a, b) => Number(b.priority === true) - Number(a.priority === true) || Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0));
    for (const row of bucket.slice(maxPerSource)) {
      row.status = 'rejected';
      row.error = `Per-source pending cap exceeded (${maxPerSource})`;
      row.updatedAt = new Date().toISOString();
      row.cleanedAt = row.updatedAt;
      stats.capped += 1;
    }
  }

  stats.totalRejected = stats.stale + stats.duplicate + stats.capped;
  stats.openAfter = rows.filter(row => openStatuses.has(String(row.status || '').toLowerCase())).length;
  if (stats.totalRejected > 0) {
    logs.push({ id: uuid(), type: 'whatsapp_channel_queue_cleaner', status: 'done', stats, time: new Date().toISOString() });
    saveJSON('logs.json', logs);
  }
  saveChannelRelayInbox();
  return {
    success: true,
    stats,
    settings: {
      enabled: settings.whatsapp_channel_queue_cleaner_enabled !== false,
      relayTtlHours: settings.whatsapp_channel_relay_ttl_hours || 24,
      manualPacketTtlHours: settings.whatsapp_channel_manual_packet_ttl_hours || 6,
      maxPendingPerSource: settings.whatsapp_channel_max_pending_per_source || 4
    }
  };
}

function createChannelAutomationAlert(type, message, meta = {}) {
  const now = Date.now();
  const throttleMinutes = type === 'low_queue' ? 60 : type === 'queue_stuck' ? 30 : 5;
  const recent = (Array.isArray(channelAutomationState.alerts) ? channelAutomationState.alerts : []).find(row =>
    row.type === type && String(row.message || '') === String(message || '') &&
    (now - Date.parse(row.time || 0)) < throttleMinutes * 60 * 1000
  );
  if (recent) return { ...recent, throttled: true };
  const row = { id: uuid(), type, message: String(message || ''), meta, time: new Date().toISOString(), status: 'new' };
  channelAutomationState.alerts = [row].concat(Array.isArray(channelAutomationState.alerts) ? channelAutomationState.alerts : []).slice(0, 300);
  logs.push({ id: uuid(), type: 'whatsapp_channel_automation_alert', status: type, message, meta, time: row.time });
  saveJSON('logs.json', logs);
  saveChannelAutomationState();
  return row;
}

function normalizeChannelAutomationJob(input = {}, existing = {}) {
  const kind = String(input.kind || existing.kind || 'webhook_post').trim().toLowerCase();
  const intervalMinutes = Math.max(1, Number(input.intervalMinutes ?? existing.intervalMinutes ?? 60));
  return {
    id: String(existing.id || input.id || uuid()),
    name: String(input.name || existing.name || kind).trim(),
    kind,
    enabled: input.enabled !== undefined ? input.enabled === true : existing.enabled !== false,
    schedule: String(input.schedule || existing.schedule || '').trim(),
    intervalMinutes,
    url: String(input.url || existing.url || '').trim(),
    method: String(input.method || existing.method || 'GET').toUpperCase(),
    body: input.body !== undefined ? input.body : (existing.body || ''),
    selector: String(input.selector || existing.selector || '').trim(),
    keywords: Array.isArray(input.keywords) ? input.keywords : splitChannelList(input.keywords ?? existing.keywords ?? ''),
    channelIds: (Array.isArray(input.channelIds) ? input.channelIds : splitChannelList(input.channelIds ?? existing.channelIds ?? '')).map(normalizeWhatsAppChannelId).filter(Boolean),
    template: String(input.template || existing.template || '').trim(),
    lastRunAt: existing.lastRunAt || '',
    lastStatus: existing.lastStatus || '',
    lastError: existing.lastError || '',
    createdAt: existing.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

async function processChannelMediaAsset(input = {}) {
  const mediaUrl = String(input.mediaUrl || input.url || '').trim();
  const source = String(input.source || input.sourceName || 'media-pipeline').trim();
  const fingerprint = crypto.createHash('sha1').update(`${mediaUrl}|${source}`).digest('hex');
  const duplicate = channelMediaPipeline.find(row => row.fingerprint === fingerprint);
  if (duplicate && settings.whatsapp_channel_media_dedup_enabled !== false) return { ...duplicate, duplicate: true };
  const ext = path.extname(mediaUrl.split('?')[0] || '').toLowerCase();
  const kind = ext === '.pdf' ? 'pdf' : /\.(mp4|mov|mkv|webm)$/i.test(ext) ? 'video' : /\.(jpg|jpeg|png|webp|gif)$/i.test(ext) ? 'image' : 'unknown';
  const actions = [];
  if (settings.whatsapp_channel_auto_download_media !== false) actions.push('download_registered');
  if (kind === 'image' && settings.whatsapp_channel_auto_compress_images !== false) actions.push('image_compress_ready');
  if (kind === 'image' && settings.whatsapp_channel_auto_resize_images !== false) actions.push('whatsapp_resize_ready');
  if (kind === 'video' && settings.whatsapp_channel_auto_convert_video === true) actions.push('video_convert_ready');
  if (kind === 'pdf' && settings.whatsapp_channel_pdf_to_image_enabled === true) actions.push('pdf_to_image_ready');
  if (settings.whatsapp_channel_google_drive_backup_enabled === true) actions.push('drive_backup_ready');
  const row = {
    id: uuid(),
    fingerprint,
    mediaUrl,
    kind,
    source,
    actions,
    status: 'registered',
    captionExtracted: settings.whatsapp_channel_caption_extract_enabled !== false ? String(input.caption || '').slice(0, 500) : '',
    createdAt: new Date().toISOString()
  };
  channelMediaPipeline.unshift(row);
  saveChannelMediaPipeline();
  return row;
}

function upsertChannelContentLibrary(row = {}) {
  if (!row || row.status !== 'published') return null;
  if (/^gap filler/i.test(String(row.sourceName || row.title || ''))) return null;
  const message = String(row.message || '').trim();
  const mediaUrl = String(row.mediaUrl || '').trim();
  if (!message && !mediaUrl) return null;
  const fingerprint = row.fingerprint || crypto.createHash('sha1').update(`${message}|${mediaUrl}|${row.sourceName || ''}`).digest('hex');
  const existingIndex = channelContentLibrary.findIndex(item => item.fingerprint === fingerprint);
  const existing = existingIndex >= 0 ? channelContentLibrary[existingIndex] : {};
  const item = {
    ...existing,
    id: existing.id || uuid(),
    fingerprint,
    title: row.title || existing.title || String(message || row.sourceName || 'Channel content').slice(0, 80),
    message,
    mediaUrl,
    sourceName: row.sourceName || existing.sourceName || '',
    sourceChannelId: row.sourceChannelId || existing.sourceChannelId || '',
    category: row.category || existing.category || sourceCategory(row.sourceChannelId || ''),
    language: row.language || existing.language || detectChannelLanguage(message),
    engagementScore: Math.max(Number(existing.engagementScore || 0), Number(row.engagementScore || 0)),
    viralScore: Math.max(Number(existing.viralScore || 0), Number(row.viralScore || 0)),
    publishCount: Number(existing.publishCount || 0) + 1,
    lastPublishedAt: row.publishedAt || new Date().toISOString(),
    createdAt: existing.createdAt || new Date().toISOString()
  };
  if (existingIndex >= 0) channelContentLibrary[existingIndex] = item;
  else channelContentLibrary.unshift(item);
  saveChannelContentLibrary();
  return item;
}

function cleanGapFillerReusableText(value = '') {
  return cleanOutgoingText(String(value || '')
    .replace(/^(?:\s*(?:🔥\s*)?Popular update(?: from our archive| once again)?:\s*)+/i, '')
    .replace(/^(?:\s*Gap filler:\s*)+/i, '')
    .trim());
}

function pickGapFillerContent(options = {}) {
  const category = String(options.category || '').trim().toLowerCase();
  const sinceHours = Math.max(1, Number(options.cooldownHours || 24));
  const cutoff = Date.now() - sinceHours * 60 * 60 * 1000;
  const candidates = (Array.isArray(channelContentLibrary) ? channelContentLibrary : [])
    .filter(item => item.message || item.mediaUrl)
    .filter(item => !category || String(item.category || '').toLowerCase() === category)
    .filter(item => Date.parse(item.lastGapFillAt || 0) < cutoff)
    .sort((a, b) => (Number(b.viralScore || 0) + Number(b.engagementScore || 0) + Number(b.publishCount || 0) * 2) - (Number(a.viralScore || 0) + Number(a.engagementScore || 0) + Number(a.publishCount || 0) * 2));
  return candidates[0] || null;
}

async function runChannelGapFiller(options = {}) {
  const item = pickGapFillerContent(options);
  if (!item) return { success: true, skipped: true, reason: 'No reusable content in library yet' };
  const reusableMessage = cleanGapFillerReusableText(item.message || '');
  const message = cleanOutgoingText([
    options.prefix || '🔥 Popular update once again:',
    reusableMessage
  ].filter(Boolean).join('\n\n'));
  const relay = createChannelRelayDraft({
    title: `Gap filler: ${String(item.title || 'popular post').replace(/^(?:Gap filler:\s*)+/i, '')}`,
    message,
    mediaUrl: item.mediaUrl || '',
    sourceName: `Gap Filler: ${item.sourceName || 'library'}`,
    sourceChannelId: item.sourceChannelId || '',
    channelIds: options.channelIds || getConfiguredWhatsAppChannels(),
    priority: options.priority === true,
    category: item.category || '',
    engagementScore: item.engagementScore || 0,
    viralScore: item.viralScore || 0
  });
  item.lastGapFillAt = new Date().toISOString();
  saveChannelContentLibrary();
  const shouldPublish = options.publishNow !== false && settings.whatsapp_channel_relay_auto_publish === true;
  const published = shouldPublish ? await publishChannelRelayDraft(relay.id, { delayMs: 1200 }) : relay;
  return { success: true, item, relay: published, published: shouldPublish };
}

async function channelFetchText(url, options = {}) {
  if (!/^https?:\/\//i.test(String(url || ''))) throw new Error('valid http/https URL required');
  const res = await fetch(url, {
    method: options.method || 'GET',
    headers: { 'User-Agent': 'SuperSenderPro/3.1 ChannelAutomation', ...(options.headers || {}) },
    body: options.body || undefined
  });
  const text = await res.text();
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${text.slice(0, 120)}`);
  return text;
}

function buildDailyChannelDigest() {
  const today = new Date().toISOString().slice(0, 10);
  const rows = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).filter(row => String(row.updatedAt || row.createdAt || '').startsWith(today));
  const published = rows.filter(row => row.status === 'published');
  const top = published.slice(0, 5).map((row, index) => `${index + 1}. ${row.sourceName || 'Source'} — ${(row.title || row.message || '').replace(/\s+/g, ' ').slice(0, 80)}`).join('\n') || 'Aaj koi channel post publish nahi hui.';
  return `📡 *Daily Channel Digest*\n\nPublished: *${published.length}*\nDrafts/Skipped: *${Math.max(0, rows.length - published.length)}*\nSources active: *${getConfiguredWhatsAppChannelSources().length}*\nTargets: *${getConfiguredWhatsAppChannels().length}*\n\n${top}\n\n— ${settings.whatsapp_channel_brand_handle || '@SuperSenderPro'}`;
}

function buildPrayerTimesPost() {
  const date = new Date().toLocaleDateString('en-PK', { weekday: 'long', day: '2-digit', month: 'short', timeZone: 'Asia/Karachi' });
  return `🕌 *Pakistan Prayer Reminder*\n${date}\n\nFajr: 4:10 AM\nDhuhr: 12:15 PM\nAsr: 5:05 PM\nMaghrib: 7:05 PM\nIsha: 8:35 PM\n\nTimes city-wise slightly change ho sakte hain.`;
}

async function buildCurrencyRatePost() {
  try {
    const text = await channelFetchText('https://open.er-api.com/v6/latest/USD');
    const data = JSON.parse(text);
    const pkr = Number(data?.rates?.PKR || 0);
    if (pkr > 0) return `💱 *Daily Currency Update*\n\nUSD → PKR: *Rs ${pkr.toFixed(2)}*\nUpdated: ${new Date().toLocaleString('en-PK', { timeZone: 'Asia/Karachi' })}`;
  } catch (error) {
    createChannelAutomationAlert('currency_fetch_failed', error.message);
  }
  return `💱 *Daily Currency Update*\n\nCurrency API abhi reachable nahi. Manual rate verify kar lein.`;
}

async function runChannelAutomationJob(jobInput, options = {}) {
  const job = normalizeChannelAutomationJob(jobInput);
  const now = new Date().toISOString();
  let message = '';
  let mediaUrl = '';
  try {
    if (job.kind === 'website_change') {
      const text = await channelFetchText(job.url);
      const hash = crypto.createHash('sha1').update(text).digest('hex');
      const old = channelAutomationState.websiteHashes[job.id];
      channelAutomationState.websiteHashes[job.id] = hash;
      saveChannelAutomationState();
      if (old && old === hash && !options.force) return { success: true, skipped: true, reason: 'no website change', job };
      message = job.template || `🌐 Website update detected\n${job.url}`;
    } else if (job.kind === 'api_monitor') {
      const text = await channelFetchText(job.url, { method: job.method, body: job.method === 'GET' ? undefined : String(job.body || '') });
      const hash = crypto.createHash('sha1').update(text).digest('hex');
      const old = channelAutomationState.apiHashes[job.id];
      channelAutomationState.apiHashes[job.id] = hash;
      saveChannelAutomationState();
      if (old && old === hash && !options.force) return { success: true, skipped: true, reason: 'no API change', job };
      message = (job.template || '📊 API update detected\n{{data}}').replace('{{data}}', text.slice(0, 1200));
    } else if (job.kind === 'daily_digest') {
      message = buildDailyChannelDigest();
    } else if (job.kind === 'prayer_times') {
      message = buildPrayerTimesPost();
    } else if (job.kind === 'currency_rate') {
      message = await buildCurrencyRatePost();
    } else if (job.kind === 'webhook_post') {
      message = String(job.template || job.body || '').trim();
    } else {
      throw new Error(`Unsupported job kind: ${job.kind}`);
    }
    const relay = createChannelRelayDraft({
      title: job.name,
      message,
      mediaUrl,
      sourceName: `Automation: ${job.name}`,
      sourceUrl: job.url || '',
      channelIds: job.channelIds.length ? job.channelIds : getConfiguredWhatsAppChannels()
    });
    const shouldPublish = options.publishNow !== false && settings.whatsapp_channel_relay_auto_publish === true;
    const published = shouldPublish ? await publishChannelRelayDraft(relay.id, { delayMs: 1200 }) : relay;
    job.lastRunAt = now;
    job.lastStatus = shouldPublish ? 'published' : 'drafted';
    job.lastError = '';
    channelAutomationState.lastJobRun[job.id] = now;
    saveChannelAutomationState();
    return { success: true, job, relay: published, published: shouldPublish };
  } catch (error) {
    job.lastRunAt = now;
    job.lastStatus = 'failed';
    job.lastError = error.message;
    createChannelAutomationAlert('job_failed', `${job.name}: ${error.message}`, { jobId: job.id, kind: job.kind });
    return { success: false, job, error: error.message };
  }
}

function channelRelayPublic(row = {}) {
  return {
    id: row.id || '',
    title: row.title || '',
    message: row.message || '',
    mediaUrl: row.mediaUrl || '',
    sourceName: row.sourceName || '',
    sourceUrl: row.sourceUrl || '',
    sourceChannelId: row.sourceChannelId || '',
    sourceMessageId: row.sourceMessageId || '',
    sourceTimestamp: row.sourceTimestamp || '',
    fingerprint: row.fingerprint || '',
    status: row.status || 'pending',
    channelIds: Array.isArray(row.channelIds) ? row.channelIds : [],
    createdBy: row.createdBy || '',
    priority: row.priority === true,
    matchedKeywords: Array.isArray(row.matchedKeywords) ? row.matchedKeywords : [],
    category: row.category || '',
    language: row.language || '',
    engagementScore: Number(row.engagementScore || 0),
    viralScore: Number(row.viralScore || 0),
    predictedBestTime: row.predictedBestTime || '',
    sponsoredInjected: row.sponsoredInjected === true,
    commissionValue: Number(row.commissionValue || 0),
    createdAt: row.createdAt || '',
    updatedAt: row.updatedAt || '',
    publishedAt: row.publishedAt || '',
    result: row.result || null,
    error: row.error || ''
  };
}

function normalizeChannelRelayDraft(input = {}, existing = {}) {
  const message = cleanOutgoingText(input.message || input.text || existing.message || '').trim();
  const mediaUrl = String(input.mediaUrl || input.mediaPath || existing.mediaUrl || '').trim();
  const sourceName = String(input.sourceName || input.source || existing.sourceName || 'Manual channel relay').trim();
  const sourceUrl = String(input.sourceUrl || input.url || existing.sourceUrl || '').trim();
  const sourceChannelId = normalizeWhatsAppChannelId(input.sourceChannelId || existing.sourceChannelId || '');
  const sourceMessageId = String(input.sourceMessageId || existing.sourceMessageId || '').trim();
  const sourceTimestamp = input.sourceTimestamp || existing.sourceTimestamp || '';
  const rawChannels = Array.isArray(input.channelIds)
    ? input.channelIds
    : String(input.channelIds || '').split(/\r?\n|,/).filter(Boolean);
  const channelIds = rawChannels.length
    ? [...new Set(rawChannels.map(normalizeWhatsAppChannelId).filter(Boolean))]
    : (Array.isArray(existing.channelIds) ? existing.channelIds : []);
  const now = new Date().toISOString();
  if (!message && !mediaUrl) throw new Error('Relay message or media is required');
  const firstLine = message.split(/\r?\n/).find(Boolean) || sourceName || 'Channel relay';
  const fingerprint = existing.fingerprint || input.fingerprint || channelRelayFingerprint({ ...input, message, mediaUrl, sourceChannelId, sourceMessageId });
  const seenAt = input.seenAt || existing.seenAt || now;
  return {
    ...existing,
    id: existing.id || input.id || uuid(),
    title: String(input.title || existing.title || firstLine.slice(0, 80)).trim(),
    message,
    mediaUrl,
    sourceName,
    sourceUrl,
    sourceChannelId,
    sourceMessageId,
    sourceTimestamp,
    fingerprint,
    seenAt,
    status: normalizeChannelRelayStatus(input.status || existing.status || 'pending'),
    channelIds,
    createdBy: input.createdBy || existing.createdBy || '',
    priority: input.priority === true || existing.priority === true,
    matchedKeywords: Array.isArray(input.matchedKeywords) ? input.matchedKeywords : (Array.isArray(existing.matchedKeywords) ? existing.matchedKeywords : []),
    category: input.category || existing.category || '',
    language: input.language || existing.language || '',
    engagementScore: Number(input.engagementScore ?? existing.engagementScore ?? 0),
    viralScore: Number(input.viralScore ?? existing.viralScore ?? 0),
    predictedBestTime: input.predictedBestTime || existing.predictedBestTime || '',
    sponsoredInjected: input.sponsoredInjected === true || existing.sponsoredInjected === true,
    commissionValue: Number(input.commissionValue ?? existing.commissionValue ?? 0),
    createdAt: existing.createdAt || now,
    updatedAt: now,
    publishedAt: existing.publishedAt || '',
    result: existing.result || null,
    error: ''
  };
}

function createChannelRelayDraft(input = {}) {
  const row = normalizeChannelRelayDraft(input);
  const duplicate = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).find(item => {
    if (row.sourceMessageId && item.sourceMessageId === row.sourceMessageId && normalizeWhatsAppChannelId(item.sourceChannelId) === row.sourceChannelId) return true;
    return row.fingerprint && item.fingerprint === row.fingerprint;
  });
  if (duplicate) return channelRelayPublic(duplicate);
  channelRelayInbox.unshift(row);
  saveChannelRelayInbox();
  logs.push({
    id: uuid(),
    type: 'whatsapp_channel_relay',
    status: 'draft',
    message: row.message || '[media relay]',
    mediaUrl: row.mediaUrl || '',
    time: new Date().toISOString()
  });
  saveJSON('logs.json', logs);
  return channelRelayPublic(row);
}

function latestPendingChannelRelay() {
  return (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
    .sort((a, b) => Number(b.priority === true) - Number(a.priority === true) || Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .find(row => ['pending', 'draft', 'failed', 'manual_required'].includes(String(row.status || '').toLowerCase())) || null;
}

function nextDripChannelRelay() {
  return (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
    .filter(row => ['pending', 'draft', 'failed', 'manual_required'].includes(String(row.status || '').toLowerCase()))
    .filter(row => row.priority === true || sourceCooldownRemainingMs(row.sourceChannelId || '') <= 0)
    .sort((a, b) =>
      Number(b.priority === true) - Number(a.priority === true) ||
      Number(b.engagementScore || 0) - Number(a.engagementScore || 0) ||
      Date.parse(a.createdAt || 0) - Date.parse(b.createdAt || 0)
    )[0] || null;
}

async function runChannelDripQueue(force = false) {
  if (settings.whatsapp_channel_drip_enabled === false && !force) return { skipped: true, reason: 'drip disabled' };
  if (!getConfiguredWhatsAppChannels().length) return { skipped: true, reason: 'target channels missing' };
  const intervalMs = Math.max(15, Number(settings.whatsapp_channel_drip_minutes || 120)) * 60 * 1000;
  const last = Date.parse(channelAutomationState.lastDripAt || 0) || 0;
  if (!force && last && Date.now() - last < intervalMs) {
    return { skipped: true, reason: 'drip interval not due', nextAt: new Date(last + intervalMs).toISOString() };
  }
  const row = nextDripChannelRelay();
  if (!row) return { skipped: true, reason: 'no pending relay draft' };
  const published = await publishChannelRelayDraft(row.id, { delayMs: row.priority ? 200 : 1200 });
  channelAutomationState.lastDripAt = new Date().toISOString();
  saveChannelAutomationState();
  return { success: true, relay: published, published: true };
}

function formatChannelRelayList(limit = 5) {
  const rows = (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
    .filter(row => ['pending', 'draft', 'failed', 'manual_required'].includes(String(row.status || '').toLowerCase()))
    .sort((a, b) => Number(b.priority === true) - Number(a.priority === true) || Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, limit);
  if (!rows.length) {
    return '📭 *Channel Relay Inbox*\n\nNo pending relay drafts.\n\nUse:\n*!relay Your copied channel post*\n*!relay yes*';
  }
  return cleanOutgoingText(`📥 *Channel Relay Inbox*

${rows.map((row, index) => `${index + 1}. *${row.title || 'Relay draft'}*
Status: ${row.status}
${row.mediaUrl ? `Media: ${row.mediaUrl}\n` : ''}${String(row.message || '').slice(0, 180)}`).join('\n\n')}

Commands:
*!relay yes* — latest draft publish
*!relay no* — latest draft reject
*!relay auto on/off* — auto publish copied posts`);
}

async function publishChannelRelayDraft(idOrRow = '', options = {}) {
  const row = typeof idOrRow === 'object'
    ? idOrRow
    : (idOrRow ? channelRelayInbox.find(item => item.id === idOrRow) : latestPendingChannelRelay());
  if (!row) throw new Error('No pending relay draft found');
  const targetIds = (Array.isArray(row.channelIds) && row.channelIds.length ? row.channelIds : getConfiguredWhatsAppChannels())
    .map(normalizeWhatsAppChannelId)
    .filter(Boolean);
  const sourceCopyMedia = row.createdBy === 'channel-copy' && !!String(row.mediaUrl || '').trim();
  const textOnly = options.textOnly === true || (sourceCopyMedia && options.allowMedia !== true);
  const publishMessage = textOnly
    ? cleanOutgoingText([row.message || '', 'Media post copied from source channel.'].filter(Boolean).join('\n\n'))
    : row.message;
  const result = await withTimeout(
    shareDataToWhatsAppChannels({
      channelIds: targetIds,
      kind: 'custom',
      message: publishMessage,
      mediaUrl: textOnly ? '' : row.mediaUrl,
      delayMs: options.delayMs || 2000,
      useRotation: true,
      skipBridge: textOnly && !!row.mediaUrl
    }),
    Number(options.timeoutMs || 18000),
    () => ({
      sent: 0,
      failed: targetIds.length,
      manualRequired: true,
      failures: targetIds.map(channelId => ({ channelId, error: 'Channel publish timed out. Draft saved for manual copy/paste.' }))
    })
  );
  if (textOnly && row.mediaUrl && result.sent > 0) {
    result.bridge = await bridgeWhatsAppChannelContent({ message: applyChannelBrandingToText(publishMessage), mediaUrl: row.mediaUrl, kind: 'custom' })
      .catch(error => ({ success: false, error: error.message }));
  }
  if (targetIds.length) row.channelIds = targetIds;
  row.status = result.manualRequired ? 'manual_required' : (result.failed ? 'failed' : 'published');
  row.publishedAt = new Date().toISOString();
  row.updatedAt = row.publishedAt;
  row.result = result;
  row.error = result.failures?.map(f => `${f.channelId}: ${f.error}`).join('; ') || '';
  if (result.sent > 0 || row.status === 'published') {
    rememberChannelRelayFingerprint(row);
    rememberSourcePublished(row.sourceChannelId || '');
  }
  saveChannelRelayInbox();
  saveChannelAutomationState();
  if (row.status === 'published') upsertChannelContentLibrary(row);
  triggerChannelPostIntegrations(row, row.status).catch(error => {
    console.warn('[ChannelIntegrations] publish trigger failed:', error.message);
  });
  return channelRelayPublic(row);
}

async function ingestWhatsAppChannelRelayMessage(input = {}) {
  if (settings.whatsapp_channel_copy_enabled !== true) {
    return { skipped: true, reason: 'Channel copy pipeline is OFF' };
  }
  const sourceChannelId = normalizeWhatsAppChannelId(input.channelId || input.sourceChannelId || input.chatId || '');
  if (!sourceChannelId || !sourceChannelId.endsWith('@newsletter')) {
    return { skipped: true, reason: 'Not a WhatsApp Channel message' };
  }
  const targets = new Set(getConfiguredWhatsAppChannels());
  if (targets.has(sourceChannelId)) {
    return { skipped: true, reason: 'Source is configured target channel, loop blocked' };
  }
  const configuredSources = getConfiguredWhatsAppChannelSources();
  const isKnownDiscoveredSource = (Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [])
    .some(row => normalizeWhatsAppChannelId(row.channelId) === sourceChannelId);
  if (
    settings.whatsapp_channel_auto_source_all_followed !== true &&
    configuredSources.length &&
    !configuredSources.includes(sourceChannelId)
  ) {
    return { skipped: true, reason: 'Source channel is not enabled' };
  }
  if (
    settings.whatsapp_channel_auto_source_all_followed === true &&
    configuredSources.length &&
    !configuredSources.includes(sourceChannelId) &&
    !isKnownDiscoveredSource
  ) {
    return { skipped: true, reason: 'Source channel is not discovered yet. Run channel scan once.' };
  }
  const sourceName = String(input.channelName || input.sourceName || '').trim()
    || (whatsappChannelDiscoveries.find(row => row.channelId === sourceChannelId)?.name)
    || sourceChannelId.replace('@newsletter', '');
  const sourceUrl = input.sourceUrl || publicWhatsAppChannel(sourceChannelId);
  const policy = validateChannelRelayPolicy({
    sourceChannelId,
    sourceName,
    message: input.message || input.body || input.caption || '',
    mediaUrl: input.mediaUrl || input.mediaPath || ''
  });
  if (!policy.allowed) {
    logs.push({ id: uuid(), type: 'whatsapp_channel_copy_blocked', status: 'blocked', from: sourceChannelId, sourceName, reason: policy.reason, time: new Date().toISOString() });
    saveJSON('logs.json', logs);
    return { skipped: true, blocked: true, reason: policy.reason };
  }
  let mediaUrl = String(input.mediaUrl || input.mediaPath || '').trim();
  if (!mediaUrl && input.msg?.hasMedia) {
    try { mediaUrl = await saveChannelRelayMediaFromWWebMessage(input.msg); } catch (error) { console.warn('[ChannelCopy] media save skipped:', error.message); }
  }
  const rawBody = String(input.message || input.body || input.caption || '').trim();
  if (isLikelyEncodedMediaPayload(rawBody) && !mediaUrl) {
    mediaUrl = saveChannelRelayMediaFromBase64Payload(rawBody, input.mimetype || '');
  }
  if (isLikelyEncodedMediaPayload(rawBody) && !mediaUrl) return { skipped: true, reason: 'Encoded media payload skipped' };
  if (!meaningfulChannelRelayBody(rawBody) && !mediaUrl) return { skipped: true, reason: 'Empty channel post' };
  let cleanBody = isLikelyEncodedMediaPayload(rawBody) ? '' : scrubChannelRelayText(rawBody);
  let aiCaption = '';
  if (shouldUseAICaptionForChannelPost({ message: cleanBody, mediaUrl })) {
    aiCaption = await withTimeout(
      generateAIChannelCaption({ message: cleanBody, mediaUrl, sourceName }),
      Number(settings.whatsapp_channel_ai_caption_timeout_ms || 5500),
      ''
    );
    if (aiCaption) cleanBody = cleanOutgoingText([cleanBody, aiCaption].filter(Boolean).join('\n\n'));
  }
  const matchedKeywords = detectWhatsAppChannelPriorityKeywords(`${cleanBody}\n${sourceName}`);
  const scores = channelPostScores({ text: cleanBody, sourceName, sourceChannelId });
  const conditionalRules = matchChannelConditionalRules({ sourceChannelId, sourceName, message: cleanBody });
  if (conditionalRules.some(rule => rule.action === 'block')) {
    logs.push({ id: uuid(), type: 'whatsapp_channel_conditional_block', status: 'blocked', from: sourceChannelId, sourceName, rules: conditionalRules.map(rule => rule.name || rule.id), time: new Date().toISOString() });
    saveJSON('logs.json', logs);
    return { skipped: true, blocked: true, reason: 'conditional rule blocked post' };
  }
  const priority = matchedKeywords.length > 0 || scores.trending || scores.engagementScore >= 70 || conditionalRules.some(rule => rule.action === 'priority' || rule.priority === true);
  const affiliateSuffix = String(settings.whatsapp_channel_affiliate_suffix || '').trim();
  if (affiliateSuffix && !cleanBody.includes(affiliateSuffix)) cleanBody = cleanOutgoingText([cleanBody, affiliateSuffix].filter(Boolean).join('\n\n'));
  const appendTexts = conditionalRules.map(rule => String(rule.appendText || '').trim()).filter(Boolean);
  if (appendTexts.length) cleanBody = cleanOutgoingText([cleanBody, ...appendTexts].join('\n\n'));
  let message = buildCopiedChannelRelayMessage({ message: cleanBody, sourceName, sourceUrl });
  if (!message && !mediaUrl) return { skipped: true, reason: 'Empty channel post' };
  let sponsoredInjected = false;
  const publishedCount = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).filter(row => row.status === 'published').length;
  if (settings.whatsapp_channel_sponsored_enabled === true && settings.whatsapp_channel_sponsored_text && publishedCount > 0 && publishedCount % Number(settings.whatsapp_channel_sponsored_every_n || 7) === 0) {
    message = cleanOutgoingText([message, `Sponsored:\n${settings.whatsapp_channel_sponsored_text}`].join('\n\n'));
    sponsoredInjected = true;
  }
  const commissionValue = settings.whatsapp_channel_commission_rate_pct > 0 ? Number((scores.engagementScore * settings.whatsapp_channel_commission_rate_pct / 100).toFixed(2)) : 0;
  const candidateFingerprint = channelRelayFingerprint({
    sourceChannelId,
    sourceMessageId: input.messageId || input.id || '',
    message,
    mediaUrl
  });
  if (channelRelayRecentlySeen(candidateFingerprint)) {
    logs.push({
      id: uuid(),
      type: 'whatsapp_channel_duplicate_blocked',
      status: 'skipped',
      from: sourceChannelId,
      sourceName,
      fingerprint: candidateFingerprint,
      time: new Date().toISOString()
    });
    saveJSON('logs.json', logs);
    return { skipped: true, duplicate: true, reason: 'duplicate channel post already forwarded recently' };
  }
  const row = createChannelRelayDraft({
    title: input.title || `${sourceName} update`,
    message,
    mediaUrl,
    sourceName,
    sourceUrl,
    sourceChannelId,
    sourceMessageId: input.messageId || input.id || '',
    sourceTimestamp: input.timestamp || new Date().toISOString(),
    fingerprint: candidateFingerprint,
    channelIds: conditionalRules.flatMap(rule => Array.isArray(rule.targetIds) ? rule.targetIds : splitChannelList(rule.targetIds || '')).length
      ? conditionalRules.flatMap(rule => Array.isArray(rule.targetIds) ? rule.targetIds : splitChannelList(rule.targetIds || '')).map(normalizeWhatsAppChannelId).filter(Boolean)
      : getWhatsAppChannelTargetsForSource(sourceChannelId),
    createdBy: 'channel-copy',
    priority,
    matchedKeywords,
    category: scores.category,
    language: scores.language,
    engagementScore: scores.engagementScore,
    viralScore: scores.viralScore,
    predictedBestTime: scores.predictedBestTime,
    sponsoredInjected,
    commissionValue
  });
  for (const rule of conditionalRules.filter(rule => String(rule.companionText || '').trim())) {
    createChannelRelayDraft({
      title: `Companion: ${rule.name || sourceName}`,
      message: cleanOutgoingText(String(rule.companionText || '').replace(/\{\{sourceName\}\}/g, sourceName).replace(/\{\{postTitle\}\}/g, input.title || `${sourceName} update`)),
      sourceName: `Conditional Rule: ${rule.name || 'companion'}`,
      sourceChannelId,
      channelIds: (Array.isArray(rule.targetIds) ? rule.targetIds : splitChannelList(rule.targetIds || '')).map(normalizeWhatsAppChannelId).filter(Boolean),
      createdBy: 'conditional-rule',
      priority: rule.priority === true,
      category: scores.category,
      language: scores.language,
      engagementScore: scores.engagementScore,
      viralScore: scores.viralScore
    });
  }
  const storedRow = channelRelayInbox.find(item => item.id === row.id);
  if (storedRow) {
    triggerChannelPostIntegrations(storedRow, 'ingested').catch(error => {
      console.warn('[ChannelIntegrations] trigger failed:', error.message);
    });
  }
  logs.push({
    id: uuid(),
    type: 'whatsapp_channel_copy_ingested',
    status: row.status || 'pending',
    from: sourceChannelId,
    sourceName,
    relayId: row.id,
    priority,
    matchedKeywords,
    aiCaptionGenerated: !!aiCaption,
    time: new Date().toISOString()
  });
  saveJSON('logs.json', logs);
  if (settings.whatsapp_channel_relay_auto_publish === true && row.status !== 'published') {
    const cooldownRemaining = sourceCooldownRemainingMs(sourceChannelId);
    if (cooldownRemaining > 0 && priority !== true) {
      logs.push({
        id: uuid(),
        type: 'whatsapp_channel_source_cooldown',
        status: 'queued',
        from: sourceChannelId,
        sourceName,
        relayId: row.id,
        cooldownSeconds: Math.ceil(cooldownRemaining / 1000),
        time: new Date().toISOString()
      });
      saveJSON('logs.json', logs);
      return { success: true, published: false, queued: true, reason: 'source cooldown active', relay: row };
    }
    const published = await publishChannelRelayDraft(row.id, { delayMs: priority ? 200 : 1200 });
    return { success: true, published: true, relay: published };
  }
  return { success: true, published: false, relay: row };
}

async function runWhatsAppChannelCopySweep({ accountId = 'default', limit = 5, autoPublish } = {}) {
  const inst = waClients.get(String(accountId || 'default').trim() || 'default');
  if (!inst?.isReady || !inst.client) throw new Error('WhatsApp not connected. Pehle QR scan/connect karein.');
  const targets = new Set(getConfiguredWhatsAppChannels());
  const configuredSources = getConfiguredWhatsAppChannelSources();
  const discoveredSources = (Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [])
    .map(row => normalizeWhatsAppChannelId(row.channelId))
    .filter(id => id && !targets.has(id));
  const sourcePool = settings.whatsapp_channel_auto_source_all_followed === true
    ? [...new Set([...configuredSources, ...discoveredSources].filter(Boolean))]
    : (configuredSources.length ? configuredSources : discoveredSources);
  const sources = rankChannelSources([...new Set(sourcePool.filter(Boolean))])
    .map(row => row.channelId)
    .filter(Boolean)
    .slice(0, Math.max(1, Number(settings.whatsapp_channel_max_sources || 60)));
  if (!sources.length) throw new Error('No source channels selected. Run !channelcatch then !channelsource 2,3');
  const previousAutoPublish = settings.whatsapp_channel_relay_auto_publish;
  if (autoPublish !== undefined) settings.whatsapp_channel_relay_auto_publish = autoPublish === true;
  const summary = { success: true, sources: sources.length, scanned: 0, drafted: 0, published: 0, skipped: 0, failures: [] };
  let loadedChats = null;
  const fetchStoreMessages = async (sourceId) => {
    const page = inst.client.pupPage || inst.client.pupBrowserPage || null;
    if (!page?.evaluate) return [];
    return promiseTimeout(page.evaluate(({ sourceId, limit }) => {
      const store = window.Store || window.WWebJS?.Store || {};
      const rows = [];
      const seen = new Set();
      const idString = (value) => {
        if (!value) return '';
        if (typeof value === 'string') return value;
        return value._serialized || value.id || value.user || value.toString?.() || '';
      };
      const remoteOf = (msg) => {
        const id = msg?.id || msg?.__x_id || {};
        return idString(id.remote) ||
          idString(msg?.chatId) ||
          idString(msg?.from) ||
          idString(msg?.to) ||
          idString(msg?.jid) ||
          idString(msg?.newsletterJid) ||
          idString(msg?.chat?.id) ||
          '';
      };
      const bodyOf = (msg) => msg?.body || msg?.caption || msg?.text || msg?.message || msg?.__x_body || msg?.__x_text || msg?.mediaData?.caption || '';
      const tsOf = (msg) => Number(msg?.t || msg?.timestamp || msg?.__x_t || msg?.messageTimestamp || 0) || 0;
      const push = (msg, source) => {
        const remote = remoteOf(msg);
        if (remote !== sourceId) return;
        const id = idString(msg?.id) || idString(msg?.__x_id) || `${remote}-${tsOf(msg)}-${rows.length}`;
        if (seen.has(id)) return;
        seen.add(id);
        rows.push({
          id,
          body: String(bodyOf(msg) || ''),
          mimetype: msg?.mimetype || msg?.mediaData?.mimetype || msg?.mediaData?.mediaStage || '',
          timestamp: tsOf(msg),
          hasMedia: !!(msg?.mediaData || msg?.type === 'image' || msg?.type === 'video' || msg?.mimetype),
          source
        });
      };
      const scanCollection = (value, source) => {
        const arr = Array.isArray(value)
          ? value
          : (Array.isArray(value?.models) ? value.models : (Array.isArray(value?._models) ? value._models : (value instanceof Map ? Array.from(value.values()) : [])));
        for (const item of arr.slice(-2000)) push(item, source);
      };
      for (const key of ['Msg', 'Message', 'Messages', 'MsgStore', 'WAWebMsgCollection']) {
        if (store[key]) scanCollection(store[key], `Store.${key}`);
      }
      for (const [key, value] of Object.entries(store)) {
        if (/msg|message/i.test(key)) scanCollection(value, `Store.${key}`);
      }
      return rows
        .sort((a, b) => Number(b.timestamp || 0) - Number(a.timestamp || 0))
        .slice(0, Math.max(1, Math.min(50, Number(limit || 5))));
    }, { sourceId, limit: Math.max(1, Math.min(50, Number(limit || 5))) }), 30000, []);
  };
  const findLoadedChannelChat = async (sourceId) => {
    if (!loadedChats) {
      try { loadedChats = await promiseTimeout(inst.client.getChats(), 30000, []); } catch { loadedChats = []; }
    }
    return (loadedChats || []).find(chat => waSerializedId(chat) === sourceId || chat?.id?._serialized === sourceId) || null;
  };
  try {
    for (const sourceId of sources) {
      try {
        let chat = await findLoadedChannelChat(sourceId);
        if (!chat && typeof inst.client.getChatById === 'function') {
          try { chat = await inst.client.getChatById(sourceId); } catch (error) { chat = null; }
        }
        const messages = chat && typeof chat?.fetchMessages === 'function'
          ? await promiseTimeout(chat.fetchMessages({ limit: Math.max(1, Math.min(50, Number(limit || 5))) }), 30000, [])
          : [];
        const normalizedMessages = [];
        for (const msg of messages || []) {
          normalizedMessages.push({
            body: msg.body || msg.caption || msg._data?.caption || '',
            messageId: msg.id?._serialized || msg.id?.id || '',
            timestamp: msg.timestamp ? new Date(Number(msg.timestamp) * 1000).toISOString() : new Date().toISOString(),
            msg,
            channelName: chat?.name || chat?.title || sourceId.replace('@newsletter', '')
          });
        }
        if (!normalizedMessages.length) {
          const storeMessages = await fetchStoreMessages(sourceId);
          const found = whatsappChannelDiscoveries.find(row => row.channelId === sourceId);
          for (const row of storeMessages || []) {
            normalizedMessages.push({
              body: row.body || '',
              messageId: row.id || '',
              timestamp: row.timestamp ? new Date(Number(row.timestamp) * 1000).toISOString() : new Date().toISOString(),
              msg: null,
              mimetype: row.mimetype || '',
              channelName: chat?.name || chat?.title || found?.name || sourceId.replace('@newsletter', '')
            });
          }
        }
        if (!normalizedMessages.length) throw new Error('Channel chat/message history is not loaded. Open/follow this channel once, then scan again.');
        for (const item of normalizedMessages) {
          summary.scanned += 1;
          const result = await ingestWhatsAppChannelRelayMessage({
            channelId: sourceId,
            channelName: item.channelName,
            messageId: item.messageId,
            body: item.body,
            mimetype: item.mimetype || '',
            timestamp: item.timestamp,
            msg: item.msg
          });
          if (result?.published) summary.published += 1;
          else if (result?.success) summary.drafted += 1;
          else summary.skipped += 1;
        }
      } catch (error) {
        summary.failures.push({ sourceId, error: error.message });
      }
    }
  } finally {
    if (autoPublish !== undefined) settings.whatsapp_channel_relay_auto_publish = previousAutoPublish;
  }
  logs.push({ id: uuid(), type: 'whatsapp_channel_copy_sweep', ...summary, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  return summary;
}

async function sendWhatsAppChannelPost(post, options = {}) {
  const row = whatsappChannelPosts.find(item => item.id === post.id) || post;
  const message = buildWhatsAppChannelPreview({
    kind: row.kind,
    message: row.message,
    templateId: row.templateId,
    variables: row.variables || {}
  });
  const result = await shareDataToWhatsAppChannels({
    channelIds: row.channelIds?.length ? row.channelIds : getConfiguredWhatsAppChannels(),
    message,
    kind: row.kind || 'custom',
    mediaUrl: row.mediaUrl || row.mediaPath || '',
    delayMs: options.delayMs || 2000,
    useRotation: true
  });
  row.status = result.manualRequired ? 'manual_required' : (result.failed ? 'failed' : 'sent');
  row.sentAt = new Date().toISOString();
  row.updatedAt = row.sentAt;
  row.preview = message;
  row.result = result;
  row.error = result.failures?.map(f => `${f.channelId}: ${f.error}`).join('; ') || '';
  saveWhatsAppChannelPosts();
  return channelPostPublic(row);
}

async function processDueWhatsAppChannelPosts() {
  if (!waClients.get('default')?.isReady) return { skipped: true, reason: 'WhatsApp is not ready' };
  const now = Date.now();
  const due = (Array.isArray(whatsappChannelPosts) ? whatsappChannelPosts : [])
    .filter(row => row.status === 'scheduled' && row.scheduledAt && Date.parse(row.scheduledAt) <= now)
    .slice(0, 5);
  const processed = [];
  for (const post of due) {
    try {
      processed.push(await sendWhatsAppChannelPost(post));
    } catch (error) {
      post.status = 'failed';
      post.error = error.message;
      post.updatedAt = new Date().toISOString();
      processed.push(channelPostPublic(post));
    }
  }
  if (processed.length) saveWhatsAppChannelPosts();
  return { success: true, processed };
}

function channelAutomationSchedule() {
  const raw = Array.isArray(settings.whatsapp_channel_auto_schedule) ? settings.whatsapp_channel_auto_schedule : [];
  return raw.map((slot, index) => {
    if (typeof slot === 'string') {
      const [time, kind = settings.whatsapp_channel_default_kind || 'business-summary'] = slot.split('|').map(x => String(x || '').trim());
      return { id: `slot-${index + 1}`, time, kind };
    }
    return {
      id: String(slot.id || `slot-${index + 1}`),
      time: String(slot.time || '').trim(),
      kind: String(slot.kind || settings.whatsapp_channel_default_kind || 'business-summary').trim()
    };
  }).filter(slot => /^\d{2}:\d{2}$/.test(slot.time));
}

function channelAutomationTodayKey(date = new Date()) {
  return date.toLocaleDateString('en-CA', { timeZone: 'Asia/Karachi' });
}

function channelAutomationMinuteKey(date = new Date()) {
  return date.toLocaleTimeString('en-GB', {
    timeZone: 'Asia/Karachi',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });
}

function channelAutomationStatus() {
  const manualPackets = getWhatsAppChannelManualPackets ? getWhatsAppChannelManualPackets(25) : [];
  const pendingRelay = Array.isArray(channelRelayInbox) ? channelRelayInbox.filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())).length : 0;
  return {
    enabled: settings.whatsapp_channel_auto_share_enabled === true,
    autoShareNewPlans: settings.whatsapp_channel_auto_share_new_plans !== false,
    configured: getConfiguredWhatsAppChannels().length > 0,
    channels: getConfiguredWhatsAppChannels(),
    sourceChannels: getConfiguredWhatsAppChannelSources(),
    copyEnabled: settings.whatsapp_channel_copy_enabled === true,
    copyAutoPublish: settings.whatsapp_channel_relay_auto_publish === true,
    defaultKind: settings.whatsapp_channel_default_kind || 'business-summary',
    schedule: channelAutomationSchedule(),
    lastShares: settings.whatsapp_channel_last_auto_shares || {},
    pendingRelay,
    manualPackets: manualPackets.length,
    lastManualPacketAt: manualPackets[0]?.time || ''
  };
}

function whatsAppChannelManualPacketSignature(row = {}) {
  const targets = Array.isArray(row.targets) ? row.targets : (row.to ? [row.to] : []);
  return [
    cleanOutgoingText(row.message || '').trim(),
    String(row.mediaUrl || '').trim(),
    targets.map(normalizeWhatsAppChannelId).filter(Boolean).sort().join(',')
  ].join('|');
}

function isWhatsAppChannelManualPacketResolved(row = {}) {
  const doneIds = new Set((Array.isArray(logs) ? logs : [])
    .filter(item => item.type === 'whatsapp_channel_manual_publish_done')
    .map(item => String(item.packetId || item.id || '').trim())
    .filter(Boolean));
  if (doneIds.has(String(row.id || ''))) return true;

  const message = cleanOutgoingText(row.message || '').trim();
  const mediaUrl = String(row.mediaUrl || '').trim();
  const targets = (Array.isArray(row.targets) ? row.targets : (row.to ? [row.to] : []))
    .map(normalizeWhatsAppChannelId)
    .filter(Boolean)
    .sort();
  const packetTime = Date.parse(row.time || row.createdAt || 0) || 0;
  const activeHours = Math.max(1, Number(settings.whatsapp_channel_manual_packet_active_hours || 2));
  if (packetTime && Date.now() - packetTime > activeHours * 60 * 60 * 1000) return true;

  const matchingPublishedRelay = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).some(relay => {
    if (String(relay.status || '').toLowerCase() !== 'published') return false;
    const relayMessage = cleanOutgoingText(relay.message || '').trim();
    const relayMedia = String(relay.mediaUrl || '').trim();
    if (mediaUrl && relayMedia === mediaUrl) return true;
    if (message && relayMessage && message === relayMessage) return true;
    if (message && relayMessage && (message.includes(relayMessage) || relayMessage.includes(message))) return true;
    return false;
  });
  if (matchingPublishedRelay) return true;

  const matchingSuccess = (Array.isArray(logs) ? logs : []).some(item => {
    if (item.type !== 'whatsapp_channel_share' || item.status !== 'sent') return false;
    const itemTime = Date.parse(item.time || 0) || 0;
    if (packetTime && itemTime && itemTime < packetTime) return false;
    const itemMessage = cleanOutgoingText(item.message || '').trim();
    const itemMedia = String(item.mediaUrl || '').trim();
    const itemTarget = normalizeWhatsAppChannelId(item.to || '');
    if (targets.length && itemTarget && !targets.includes(itemTarget)) return false;
    if (mediaUrl && itemMedia === mediaUrl) return true;
    if (message && itemMessage && (itemMessage === message || itemMessage.includes(message) || message.includes(itemMessage))) return true;
    return false;
  });
  return matchingSuccess;
}

function getWhatsAppChannelManualPackets(limit = 100) {
  const doneIds = new Set((Array.isArray(logs) ? logs : [])
    .filter(row => row.type === 'whatsapp_channel_manual_publish_done')
    .map(row => String(row.packetId || row.id || '').trim())
    .filter(Boolean));
  const rows = (Array.isArray(logs) ? logs : [])
    .filter(row => row.type === 'whatsapp_channel_manual_publish_packet' || (row.type === 'whatsapp_channel_share' && row.status === 'manual_required'))
    .filter(row => !isWhatsAppChannelManualPacketResolved(row))
    .slice()
    .reverse()
    .map(row => ({
      id: row.id,
      type: row.type || '',
      status: doneIds.has(row.id) ? 'done' : (row.status || 'manual_required'),
      targets: Array.isArray(row.targets) ? row.targets : (row.to ? [row.to] : []),
      targetLinks: (Array.isArray(row.targets) ? row.targets : (row.to ? [row.to] : [])).map(publicWhatsAppChannel),
      message: row.message || '',
      mediaUrl: row.mediaUrl || '',
      error: row.error || '',
      time: row.time || '',
      done: doneIds.has(row.id)
    }));
  return rows.slice(0, Math.max(1, Number(limit || 100)));
}

function whatsAppChannelAutomationHealth() {
  const publisherId = baileysChannelPublisherId();
  const publisher = waClients.get(publisherId);
  const defaultInst = waClients.get('default');
  const activeManualPackets = getWhatsAppChannelManualPackets(25);
  const pendingRelay = (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
    .filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase()))
    .map(channelRelayPublic);
  const channelLogs = (Array.isArray(logs) ? logs : [])
    .filter(row => /whatsapp_channel/i.test(String(row.type || '')))
    .slice()
    .reverse();
  const lastSuccess = channelLogs
    .filter(row => row.type === 'whatsapp_channel_share' && row.status === 'sent')
    .slice(0, 8)
    .map(row => ({
      time: row.time || '',
      to: row.to || '',
      engine: row.engine || '',
      message: String(row.message || '').slice(0, 140)
    }));
  const lastErrors = channelLogs
    .filter(row => ['failed', 'manual_required'].includes(String(row.status || '').toLowerCase()))
    .filter(row => row.type === 'whatsapp_channel_manual_publish_packet' || row.type === 'whatsapp_channel_share')
    .filter(row => !isWhatsAppChannelManualPacketResolved(row))
    .slice(0, 8)
    .map(row => ({
      time: row.time || '',
      to: row.to || '',
      status: row.status || '',
      error: String(row.error || '').slice(0, 240),
      message: String(row.message || '').slice(0, 140)
    }));
  const discoveredSourceCount = (Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : [])
    .map(row => normalizeWhatsAppChannelId(row.channelId))
    .filter(id => id && !getConfiguredWhatsAppChannels().includes(id)).length;
  const effectiveSourceCount = settings.whatsapp_channel_auto_source_all_followed === true
    ? Math.max(getConfiguredWhatsAppChannelSources().length, discoveredSourceCount)
    : getConfiguredWhatsAppChannelSources().length;
  const ok = !!publisher?.isReady
    && !!defaultInst?.isReady
    && getConfiguredWhatsAppChannels().length > 0
    && effectiveSourceCount > 0
    && activeManualPackets.length === 0;
  return {
    success: true,
    ok,
    status: ok ? 'healthy' : 'needs_attention',
    defaultWhatsAppReady: !!defaultInst?.isReady,
    publisherReady: !!publisher?.isReady,
    publisherAccount: publisherId,
    targets: getConfiguredWhatsAppChannels(),
    sources: getConfiguredWhatsAppChannelSources(),
    discoveredSourceCount,
    effectiveSourceCount,
    autoSourceAllFollowed: settings.whatsapp_channel_auto_source_all_followed === true,
    copyEnabled: settings.whatsapp_channel_copy_enabled === true,
    autoPublish: settings.whatsapp_channel_relay_auto_publish === true,
    textFallbackMode: true,
    addOns: {
      branding: settings.whatsapp_channel_branding_enabled !== false,
      brandHandle: channelBrandHandle(),
      imageWatermark: settings.whatsapp_channel_watermark_images !== false,
      keywordAlerts: settings.whatsapp_channel_keyword_alert_enabled !== false,
      priorityKeywords: channelPriorityKeywords(),
      aiCaptions: settings.whatsapp_channel_ai_caption_enabled !== false,
      bridge: settings.whatsapp_channel_bridge_enabled === true,
      bridgePlatforms: settings.whatsapp_channel_bridge_platforms || [],
      telegramReady: !!(settings.telegram_token && (settings.telegram_channel_chat_id || settings.telegram_chat_id)),
      sourceLinks: settings.whatsapp_channel_source_links || [],
      maxSources: settings.whatsapp_channel_max_sources || 60,
      sourceCooldownSeconds: settings.whatsapp_channel_source_cooldown_seconds || 90,
      duplicateWindowHours: settings.whatsapp_channel_duplicate_window_hours || 48,
      maxMediaMb: settings.whatsapp_channel_max_media_mb || 25,
      scrubPhoneNumbers: settings.whatsapp_channel_scrub_phone_numbers !== false,
      scrubLinks: settings.whatsapp_channel_scrub_links === true,
      nsfwFilter: settings.whatsapp_channel_nsfw_filter_enabled !== false,
      integrations: {
        webhook: !!settings.whatsapp_channel_webhook_url,
        slack: !!settings.whatsapp_channel_slack_webhook_url,
        discord: !!settings.whatsapp_channel_discord_webhook_url,
        zapier: !!settings.whatsapp_channel_zapier_webhook_url,
        make: !!settings.whatsapp_channel_make_webhook_url,
        notion: !!(settings.notion_api_key && settings.notion_channel_database_id),
        airtable: !!(settings.airtable_api_key && settings.airtable_channel_base_id && settings.airtable_channel_table_name),
        firebase: !!settings.firebase_database_url,
        n8n: settings.n8n_enabled === true
      }
    },
    pendingRelay: pendingRelay.length,
    pendingRelayRows: pendingRelay.slice(0, 10),
    activeManualPackets: activeManualPackets.length,
    manualPackets: activeManualPackets,
    lastSuccess,
    lastErrors,
    checkedAt: new Date().toISOString()
  };
}

const CHANNEL_AUTOMATION_PRESETS = {
  safe: {
    label: 'Safe Mode',
    description: 'Stable autoposting with slower pace, strong filters, and branding.',
    pollSeconds: 90,
    pollLimit: 5,
    sourceCooldownSeconds: 180,
    duplicateWindowHours: 72,
    maxMediaMb: 18,
    forwardingMode: 'priority',
    bridgeEnabled: false
  },
  fast: {
    label: 'Fast Mode',
    description: 'Best daily setting: fast source scan, auto-publish, branding, duplicate guard.',
    pollSeconds: 30,
    pollLimit: 10,
    sourceCooldownSeconds: 60,
    duplicateWindowHours: 48,
    maxMediaMb: 25,
    forwardingMode: 'priority',
    bridgeEnabled: true
  },
  max: {
    label: 'Max Automation',
    description: 'Aggressive monitoring for many source channels with queue protection.',
    pollSeconds: 20,
    pollLimit: 18,
    sourceCooldownSeconds: 25,
    duplicateWindowHours: 36,
    maxMediaMb: 35,
    forwardingMode: 'weighted',
    bridgeEnabled: true
  }
};

function applyWhatsAppChannelAutomationPreset(presetName = 'fast') {
  const key = String(presetName || 'fast').toLowerCase();
  const preset = CHANNEL_AUTOMATION_PRESETS[key];
  if (!preset) throw new Error(`Unknown preset. Use: ${Object.keys(CHANNEL_AUTOMATION_PRESETS).join(', ')}`);
  settings.whatsapp_channel_copy_enabled = true;
  settings.whatsapp_channel_relay_auto_publish = true;
  settings.whatsapp_channel_auto_share_enabled = true;
  settings.whatsapp_channel_auto_share_new_plans = true;
  settings.whatsapp_channel_auto_source_all_followed = true;
  settings.whatsapp_channel_branding_enabled = true;
  settings.whatsapp_channel_watermark_images = settings.whatsapp_channel_watermark_images !== false;
  settings.whatsapp_channel_keyword_alert_enabled = true;
  settings.whatsapp_channel_content_pipeline_enabled = true;
  settings.whatsapp_channel_auto_download_media = true;
  settings.whatsapp_channel_auto_compress_images = true;
  settings.whatsapp_channel_auto_resize_images = true;
  settings.whatsapp_channel_media_dedup_enabled = true;
  settings.whatsapp_channel_queue_cleaner_enabled = true;
  settings.whatsapp_channel_drip_enabled = true;
  settings.whatsapp_channel_daily_digest_enabled = true;
  settings.whatsapp_channel_bridge_enabled = preset.bridgeEnabled === true;
  settings.whatsapp_channel_bridge_platforms = channelBridgeConfiguredPlatforms();
  settings.whatsapp_channel_copy_poll_seconds = preset.pollSeconds;
  settings.whatsapp_channel_copy_poll_limit = preset.pollLimit;
  settings.whatsapp_channel_copy_retry_limit = preset.pollLimit;
  settings.whatsapp_channel_source_cooldown_seconds = preset.sourceCooldownSeconds;
  settings.whatsapp_channel_duplicate_window_hours = preset.duplicateWindowHours;
  settings.whatsapp_channel_max_media_mb = preset.maxMediaMb;
  settings.whatsapp_channel_forwarding_mode = preset.forwardingMode;
  settings.whatsapp_channel_scrub_phone_numbers = true;
  settings.whatsapp_channel_scrub_links = settings.whatsapp_channel_scrub_links === true;
  settings.whatsapp_channel_nsfw_filter_enabled = true;
  settings.whatsapp_channel_selected_preset = key;
  settings.whatsapp_channel_last_preset_applied_at = new Date().toISOString();
  saveJSON('settings.json', settings);
  return buildWhatsAppChannelCommandCenter({ preset: key });
}

function buildWhatsAppChannelCommandCenter(extra = {}) {
  const health = whatsAppChannelAutomationHealth();
  const bridge = buildChannelBridgeHealthReport({ limit: 60 });
  const sourceDoctor = runChannelSourceDoctor({ autoPause: false });
  const automation = channelAutomationStatus();
  const blockers = [];
  if (!health.publisherReady) blockers.push('Channel publisher WhatsApp session not connected');
  if (!health.defaultWhatsAppReady) blockers.push('Default WhatsApp session not connected');
  if (!health.targets.length) blockers.push('Target channel missing');
  if (!health.effectiveSourceCount) blockers.push('Source channel missing');
  if (!health.copyEnabled) blockers.push('Copy pipeline OFF');
  if (!health.autoPublish) blockers.push('Auto publish OFF');
  if (health.activeManualPackets > 0) blockers.push(`${health.activeManualPackets} manual packets pending`);
  const nextActions = [];
  if (!health.publisherReady) nextActions.push('Open /wa-channel-qr and scan publisher QR');
  if (!health.targets.length) nextActions.push('Select target channel and click Save Target Channels');
  if (!health.effectiveSourceCount) nextActions.push('Scan followed channels, then Save Source Channels');
  if (!health.copyEnabled || !health.autoPublish) nextActions.push('Click Fast Mode or run !channelpreset fast');
  if (health.activeManualPackets > 0) nextActions.push('Run Queue Cleaner or publish pending relay manually');
  if (bridge.recommendations?.length) nextActions.push(...bridge.recommendations.slice(0, 3));
  if (!nextActions.length) nextActions.push('System healthy. Use Run Copy Now or keep automation running.');
  return {
    success: true,
    preset: extra.preset || settings.whatsapp_channel_selected_preset || '',
    generatedAt: new Date().toISOString(),
    readyScore: Math.max(0, 100 - blockers.length * 14 - Math.min(24, health.lastErrors.length * 6)),
    status: blockers.length ? 'needs_attention' : 'ready',
    blockers,
    nextActions: nextActions.slice(0, 8),
    summary: {
      publisherReady: health.publisherReady,
      defaultWhatsAppReady: health.defaultWhatsAppReady,
      targets: health.targets.length,
      sources: health.effectiveSourceCount,
      configuredSources: health.sources.length,
      discoveredSources: health.discoveredSourceCount,
      pendingRelay: health.pendingRelay,
      manualPackets: health.activeManualPackets,
      copyEnabled: health.copyEnabled,
      autoPublish: health.autoPublish,
      bridgeEnabled: bridge.bridgeEnabled,
      bridgePlatforms: bridge.configuredPlatforms,
      sourceDoctor: sourceDoctor.summary || {},
      pollSeconds: settings.whatsapp_channel_copy_poll_seconds || 30,
      pollLimit: settings.whatsapp_channel_copy_poll_limit || 8,
      forwardingMode: settings.whatsapp_channel_forwarding_mode || 'priority',
      watchdogEnabled: settings.whatsapp_channel_watchdog_enabled !== false,
      watchdogAutoFix: settings.whatsapp_channel_watchdog_auto_fix !== false,
      watchdogLastStatus: channelAutomationState.watchdog?.lastStatus || ''
    },
    health,
    bridge,
    watchdog: {
      enabled: settings.whatsapp_channel_watchdog_enabled !== false,
      autoFix: settings.whatsapp_channel_watchdog_auto_fix !== false,
      alerts: settings.whatsapp_channel_watchdog_alerts !== false,
      publishOnFix: settings.whatsapp_channel_watchdog_share === true,
      intervalMinutes: Math.max(2, Number(settings.whatsapp_channel_watchdog_interval_minutes || 10)),
      minReadyScore: Math.max(10, Math.min(95, Number(settings.whatsapp_channel_watchdog_min_ready_score || 65))),
      lastRunAt: channelAutomationState.watchdog?.lastRunAt || '',
      lastStatus: channelAutomationState.watchdog?.lastStatus || '',
      lastReasons: Array.isArray(channelAutomationState.watchdog?.lastReasons) ? channelAutomationState.watchdog.lastReasons : [],
      lastAutoFixAt: channelAutomationState.watchdog?.lastAutoFixAt || ''
    },
    presets: Object.entries(CHANNEL_AUTOMATION_PRESETS).map(([id, row]) => ({ id, ...row })),
    automation
  };
}

function formatWhatsAppChannelCommandCenterReply(report = buildWhatsAppChannelCommandCenter()) {
  const s = report.summary || {};
  const blockerText = report.blockers?.length ? report.blockers.map(item => `- ${item}`).join('\n') : 'No blocker. Automation ready.';
  const nextText = report.nextActions?.length ? report.nextActions.map(item => `- ${item}`).join('\n') : '- Run Copy Now';
  return `📡 *Channel Automation Center*

Status: *${report.status}*
Ready score: *${report.readyScore}/100*
Preset: *${report.preset || 'custom'}*

Targets: *${s.targets || 0}*
Sources: *${s.sources || 0}*
Pending relay: *${s.pendingRelay || 0}*
Manual packets: *${s.manualPackets || 0}*
Poll: *${s.pollSeconds || 30}s*
Mode: *${s.forwardingMode || 'priority'}*
Bridge: *${s.bridgeEnabled ? 'ON' : 'OFF'}* (${(s.bridgePlatforms || []).join(', ') || 'none'})

*Blockers:*
${blockerText}

*Next actions:*
${nextText}

Quick commands:
*!channelpreset safe*
*!channelpreset fast*
*!channelpreset max*
*!channelwatch run*
*!channelrun*
*!next50*
*!bridgereport*`;
}

async function runWhatsAppChannelAutoFix({ preset = 'fast', runCopy = true, share = false, limit = null } = {}) {
  const startedAt = new Date().toISOString();
  const before = buildWhatsAppChannelCommandCenter();
  const applied = applyWhatsAppChannelAutomationPreset(preset || 'fast');
  const doctor = runChannelSourceDoctor({ autoPause: true });
  const cleaner = runChannelQueueCleaner({ force: true });
  const copyLimit = Math.max(1, Math.min(25, Number(limit || settings.whatsapp_channel_copy_poll_limit || 10)));
  let copySweep = null;
  if (runCopy !== false) {
    copySweep = await runWhatsAppChannelMaxAutomation({
      limit: copyLimit,
      discover: true,
      copySweep: true,
      share: share === true
    });
  }
  const after = buildWhatsAppChannelCommandCenter({ preset: applied.preset || preset || 'fast' });
  const result = {
    success: true,
    startedAt,
    finishedAt: new Date().toISOString(),
    preset: applied.preset || preset || 'fast',
    before: {
      status: before.status,
      readyScore: before.readyScore,
      blockers: before.blockers || []
    },
    after: {
      status: after.status,
      readyScore: after.readyScore,
      blockers: after.blockers || [],
      nextActions: after.nextActions || []
    },
    doctor: doctor.summary || {},
    cleaner: cleaner.stats || {},
    copySweep: copySweep ? {
      scanned: copySweep.copySweep?.scanned || 0,
      drafted: copySweep.copySweep?.drafted || 0,
      published: copySweep.copySweep?.published || 0,
      manualPacketsAfter: copySweep.manualPacketsAfter || 0,
      errors: (copySweep.errors || []).length
    } : null,
    commandCenter: after
  };
  logs.push({ id: uuid(), type: 'whatsapp_channel_autofix', status: 'done', result, time: result.finishedAt });
  saveJSON('logs.json', logs);
  return result;
}

function formatWhatsAppChannelAutoFixReply(result = {}) {
  const doctor = result.doctor || {};
  const cleaner = result.cleaner || {};
  const sweep = result.copySweep || {};
  const next = result.after?.nextActions?.length
    ? result.after.nextActions.slice(0, 5).map(item => `- ${item}`).join('\n')
    : '- System ready. Keep automation running.';
  return `🛠️ *Channel Auto-Fix Complete*

Preset: *${result.preset || 'fast'}*
Ready score: *${result.before?.readyScore || 0}/100 → ${result.after?.readyScore || 0}/100*
Status: *${result.after?.status || 'unknown'}*

Source Doctor:
Active: *${doctor.active || 0}* | Silent: *${doctor.silent || 0}* | Dead: *${doctor.dead || 0}*
Auto-paused: *${doctor.autoPaused || 0}*

Queue Cleaner:
Rejected: *${cleaner.totalRejected || 0}*
Open after: *${cleaner.openAfter || 0}*

Copy Sweep:
Scanned: *${sweep.scanned || 0}*
Drafted: *${sweep.drafted || 0}*
Published: *${sweep.published || 0}*
Manual packets: *${sweep.manualPacketsAfter || 0}*
Errors: *${sweep.errors || 0}*

Next:
${next}`;
}

function buildWhatsAppChannelWatchdogStatus(report = null) {
  const center = report || buildWhatsAppChannelCommandCenter();
  const state = channelAutomationState.watchdog && typeof channelAutomationState.watchdog === 'object'
    ? channelAutomationState.watchdog
    : {};
  const lastRunAt = state.lastRunAt || '';
  const intervalMinutes = Math.max(2, Number(settings.whatsapp_channel_watchdog_interval_minutes || 10));
  const minReadyScore = Math.max(10, Math.min(95, Number(settings.whatsapp_channel_watchdog_min_ready_score || 65)));
  const lastRunMs = Date.parse(lastRunAt || '');
  const dueAt = lastRunMs
    ? new Date(lastRunMs + intervalMinutes * 60 * 1000).toISOString()
    : new Date().toISOString();
  const now = Date.now();
  const due = !lastRunMs || now >= Date.parse(dueAt);
  return {
    enabled: settings.whatsapp_channel_watchdog_enabled !== false,
    autoFix: settings.whatsapp_channel_watchdog_auto_fix !== false,
    alerts: settings.whatsapp_channel_watchdog_alerts !== false,
    publishOnFix: settings.whatsapp_channel_watchdog_share === true,
    intervalMinutes,
    minReadyScore,
    lastRunAt,
    dueAt,
    due,
    lastStatus: state.lastStatus || '',
    lastReasons: Array.isArray(state.lastReasons) ? state.lastReasons : [],
    lastAutoFixAt: state.lastAutoFixAt || '',
    lastAutoFixStatus: state.lastAutoFixStatus || '',
    readyScore: center.readyScore || 0,
    status: center.status || 'unknown',
    blockers: center.blockers || [],
    nextActions: center.nextActions || []
  };
}

let whatsAppChannelWatchdogBusy = false;

async function runWhatsAppChannelWatchdog({ force = false, source = 'timer' } = {}) {
  if (whatsAppChannelWatchdogBusy) return { success: true, skipped: true, reason: 'watchdog already running' };
  const before = buildWhatsAppChannelCommandCenter();
  const status = buildWhatsAppChannelWatchdogStatus(before);
  if (!status.enabled && !force) return { success: true, skipped: true, reason: 'watchdog disabled', status };
  if (!status.due && !force) return { success: true, skipped: true, reason: 'watchdog not due', status };

  whatsAppChannelWatchdogBusy = true;
  const startedAt = new Date().toISOString();
  const reasons = [];
  const summary = before.summary || {};
  const doctor = summary.sourceDoctor || {};
  if ((before.readyScore || 0) < status.minReadyScore) reasons.push(`Ready score below target (${before.readyScore || 0}/${status.minReadyScore})`);
  if (!summary.defaultWhatsAppReady) reasons.push('Default WhatsApp session not ready');
  if (!summary.publisherReady) reasons.push('Channel publisher session not ready');
  if ((summary.manualPackets || 0) > 0) reasons.push(`${summary.manualPackets} manual packets pending`);
  if ((summary.pendingRelay || 0) > Number(settings.whatsapp_channel_low_queue_threshold || 2) + 10) reasons.push(`${summary.pendingRelay} relay items pending`);
  if ((doctor.dead || 0) > 0) reasons.push(`${doctor.dead} dead sources found`);
  if ((doctor.silent || 0) > 3) reasons.push(`${doctor.silent} silent sources found`);

  let autoFix = null;
  let after = before;
  try {
    if (reasons.length && status.autoFix) {
      autoFix = await runWhatsAppChannelAutoFix({
        preset: settings.whatsapp_channel_selected_preset || 'fast',
        runCopy: true,
        share: status.publishOnFix,
        limit: settings.whatsapp_channel_copy_poll_limit || 10
      });
      after = autoFix.commandCenter || buildWhatsAppChannelCommandCenter();
    }
    const result = {
      success: true,
      source,
      startedAt,
      finishedAt: new Date().toISOString(),
      action: reasons.length && status.autoFix ? 'autofix' : 'observe',
      reasons,
      before: {
        status: before.status,
        readyScore: before.readyScore,
        blockers: before.blockers || []
      },
      after: {
        status: after.status,
        readyScore: after.readyScore,
        blockers: after.blockers || [],
        nextActions: after.nextActions || []
      },
      autoFix: autoFix ? {
        preset: autoFix.preset,
        status: autoFix.after?.status || '',
        readyScore: autoFix.after?.readyScore || 0,
        doctor: autoFix.doctor || {},
        cleaner: autoFix.cleaner || {},
        copySweep: autoFix.copySweep || {}
      } : null,
      status: buildWhatsAppChannelWatchdogStatus(after)
    };
    channelAutomationState.watchdog = {
      lastRunAt: result.finishedAt,
      lastStatus: result.after.status,
      lastReasons: reasons,
      lastAutoFixAt: autoFix ? result.finishedAt : (channelAutomationState.watchdog?.lastAutoFixAt || ''),
      lastAutoFixStatus: autoFix ? result.after.status : (channelAutomationState.watchdog?.lastAutoFixStatus || '')
    };
    saveChannelAutomationState();
    logs.push({ id: uuid(), type: 'whatsapp_channel_watchdog', status: result.action, result, time: result.finishedAt });
    saveJSON('logs.json', logs);
    if (reasons.length && settings.whatsapp_channel_watchdog_alerts !== false) {
      createChannelAutomationAlert('watchdog_action', `Channel Watchdog ${result.action}: ${reasons.slice(0, 2).join('; ')}`, {
        reasons,
        before: result.before,
        after: result.after
      });
    }
    return result;
  } catch (error) {
    const failedAt = new Date().toISOString();
    channelAutomationState.watchdog = {
      ...(channelAutomationState.watchdog || {}),
      lastRunAt: failedAt,
      lastStatus: 'failed',
      lastReasons: [error.message]
    };
    saveChannelAutomationState();
    logs.push({ id: uuid(), type: 'whatsapp_channel_watchdog', status: 'failed', error: error.message, time: failedAt });
    saveJSON('logs.json', logs);
    createChannelAutomationAlert('watchdog_failed', error.message);
    return { success: false, error: error.message, reasons, before: { status: before.status, readyScore: before.readyScore } };
  } finally {
    whatsAppChannelWatchdogBusy = false;
  }
}

function formatWhatsAppChannelWatchdogReply(result = {}) {
  const status = result.status || buildWhatsAppChannelWatchdogStatus();
  const reasons = result.reasons?.length ? result.reasons : status.lastReasons || [];
  const next = result.after?.nextActions?.length ? result.after.nextActions : status.nextActions || [];
  return `🛡️ *Channel Watchdog*

Enabled: *${status.enabled ? 'ON' : 'OFF'}*
Auto-fix: *${status.autoFix ? 'ON' : 'OFF'}*
Interval: *${status.intervalMinutes} min*
Target score: *${status.minReadyScore}/100*

Last action: *${result.action || status.lastStatus || 'status'}*
Ready score: *${result.before?.readyScore ?? status.readyScore}/100 → ${result.after?.readyScore ?? status.readyScore}/100*

Reasons:
${reasons.length ? reasons.slice(0, 6).map(item => `- ${item}`).join('\n') : '- No issue detected'}

Next:
${next.length ? next.slice(0, 5).map(item => `- ${item}`).join('\n') : '- Keep automation running'}

Commands:
*!channelwatch on*
*!channelwatch off*
*!channelwatch run*`;
}

function readAntigravityNext50Plan() {
  const filePath = path.join(__dirname, 'ANTIGRAVITY_NEXT_50.md');
  let markdown = '';
  try {
    markdown = fs.readFileSync(filePath, 'utf8');
  } catch {
    markdown = '# SuperSender Pro - Antigravity Next 50 Steps\n\nPlan file missing. Pull latest repo and check ANTIGRAVITY_NEXT_50.md.';
  }
  const steps = markdown
    .split(/\r?\n/)
    .map(line => line.trim())
    .filter(line => /^\d+\.\s+/.test(line))
    .map(line => {
      const match = line.match(/^(\d+)\.\s+(.+)$/);
      return { number: Number(match?.[1] || 0), text: match?.[2] || line };
    })
    .filter(row => row.number > 0);
  return {
    success: true,
    title: 'SuperSender Pro - Antigravity Next 50 Steps',
    file: filePath,
    total: steps.length,
    steps,
    markdown,
    updatedAt: new Date().toISOString()
  };
}

function formatAntigravityNext50Reply(limit = 20) {
  const plan = readAntigravityNext50Plan();
  const shown = plan.steps.slice(0, Math.max(5, Math.min(50, Number(limit || 20))));
  return `*Antigravity Next ${plan.total} Steps*

${shown.map(step => `${step.number}. ${step.text}`).join('\n')}

Full file:
ANTIGRAVITY_NEXT_50.md

Browser:
http://localhost:3001/antigravity-next-50

Git:
https://github.com/abdulbasit742/supersenderpro.git`;
}

