async function runWhatsAppChannelAutoShareTick({ force = false, kind = '', message = '' } = {}) {
  const now = new Date();
  const today = channelAutomationTodayKey(now);
  const currentTime = channelAutomationMinuteKey(now);
  const channels = getConfiguredWhatsAppChannels();
  if (!channels.length) return { skipped: true, reason: 'No WhatsApp channels configured' };
  if (!waClients.get('default')?.isReady) return { skipped: true, reason: 'WhatsApp is not ready' };

  const slots = force
    ? [{ id: `manual-${Date.now()}`, time: currentTime, kind: kind || settings.whatsapp_channel_default_kind || 'business-summary' }]
    : channelAutomationSchedule().filter(slot => slot.time === currentTime);

  if (!force && settings.whatsapp_channel_auto_share_enabled !== true) {
    return { skipped: true, reason: 'Channel automation disabled' };
  }
  if (!slots.length) return { skipped: true, reason: 'No due channel slot' };

  const results = [];
  settings.whatsapp_channel_last_auto_shares = settings.whatsapp_channel_last_auto_shares || {};
  for (const slot of slots) {
    const runKey = `${today}:${slot.id}:${slot.time}:${slot.kind}`;
    if (!force && settings.whatsapp_channel_last_auto_shares[runKey]) {
      results.push({ slot, skipped: true, reason: 'Already sent today' });
      continue;
    }
    const result = await shareDataToWhatsAppChannels({
      channelIds: channels,
      message,
      kind: kind || slot.kind,
      delayMs: 2500,
      useRotation: true
    });
    settings.whatsapp_channel_last_auto_shares[runKey] = new Date().toISOString();
    logs.push({
      id: uuid(),
      type: force ? 'whatsapp_channel_manual_autopost' : 'whatsapp_channel_auto_post',
      status: result.success ? 'sent' : 'partial',
      slot,
      result,
      time: new Date().toISOString()
    });
    results.push({ slot, result });
  }
  saveJSON('settings.json', settings);
  saveJSON('logs.json', logs);
  return { success: true, force, results };
}

function appendWhatsAppChannelLog(entry = {}) {
  logs.push({
    id: uuid(),
    type: entry.type || 'whatsapp_channel_event',
    status: entry.status || 'info',
    message: cleanOutgoingText(entry.message || ''),
    to: entry.to || '',
    error: entry.error || '',
    time: entry.time || new Date().toISOString(),
    ...entry
  });
  saveJSON('logs.json', logs);
}

function saveAutomationAutopilot() {
  automationAutopilot = {
    enabled: settings.automation_autopilot_enabled !== false,
    channelEnabled: settings.automation_autopilot_channel_enabled !== false,
    adminAlerts: settings.automation_autopilot_admin_alerts !== false,
    ...(automationAutopilot || {})
  };
  automationAutopilot.runs = (Array.isArray(automationAutopilot.runs) ? automationAutopilot.runs : [])
    .slice(-Number(process.env.AUTOPILOT_MAX_RUNS || 80))
    .map(run => ({ ...run, summary: run.summary ? compactAutopilotSummary(run.summary) : undefined }));
  saveJSON('automation_autopilot.json', automationAutopilot);
}

function autopilotDayKey(date = new Date()) {
  return date.toLocaleDateString('en-CA', { timeZone: 'Asia/Karachi' });
}

function autopilotSummary() {
  const rows = (() => {
    try { return typeof sellerRateRows === 'function' ? sellerRateRows(10000, {}) : []; }
    catch { return []; }
  })();
  const availablePlans = (Array.isArray(plans) ? plans : []).filter(plan => typeof isPlanAvailableForWhatsApp === 'function' ? isPlanAvailableForWhatsApp(plan) : plan?.available !== false);
  const unavailablePlans = (Array.isArray(plans) ? plans : []).filter(plan => !(typeof isPlanAvailableForWhatsApp === 'function' ? isPlanAvailableForWhatsApp(plan) : plan?.available !== false));
  return {
    enabled: settings.automation_autopilot_enabled !== false,
    channelEnabled: settings.automation_autopilot_channel_enabled !== false,
    adminAlerts: settings.automation_autopilot_admin_alerts !== false,
    intervalMinutes: settings.automation_autopilot_interval_minutes || 15,
    whatsappReady: !!waClients.get('default')?.isReady,
    channelsConfigured: getConfiguredWhatsAppChannels().length,
    sellerRates: rows.length,
    availablePlans: availablePlans.length,
    unavailablePlans: unavailablePlans.length,
    lastRunAt: automationAutopilot?.lastRunAt || '',
    lastSellerRateCount: Number(automationAutopilot?.lastSellerRateCount || 0),
    lastStockPostDate: automationAutopilot?.lastStockPostDate || '',
    lastAdminDigestDate: automationAutopilot?.lastAdminDigestDate || '',
    recentRuns: (automationAutopilot?.runs || []).slice(-10).reverse()
  };
}

function compactAutopilotSummary(summary = {}) {
  return {
    enabled: summary.enabled,
    channelEnabled: summary.channelEnabled,
    adminAlerts: summary.adminAlerts,
    intervalMinutes: summary.intervalMinutes,
    whatsappReady: summary.whatsappReady,
    channelsConfigured: summary.channelsConfigured,
    sellerRates: summary.sellerRates,
    availablePlans: summary.availablePlans,
    unavailablePlans: summary.unavailablePlans,
    lastRunAt: summary.lastRunAt,
    lastSellerRateCount: summary.lastSellerRateCount,
    lastStockPostDate: summary.lastStockPostDate,
    lastAdminDigestDate: summary.lastAdminDigestDate
  };
}

function buildAutopilotAdminDigest(summary = {}, actions = []) {
  return cleanOutgoingText(`🤖 *AutoPilot Engine*

Status: *${summary.enabled ? 'ON' : 'OFF'}*
WhatsApp: *${summary.whatsappReady ? 'Ready' : 'Not ready'}*
Channels: *${summary.channelsConfigured}*
Seller rates saved: *${summary.sellerRates}*
Plans available: *${summary.availablePlans}*
Plans not available: *${summary.unavailablePlans}*

Actions:
${actions.length ? actions.map(item => `• ${item}`).join('\n') : '• No action needed right now'}

Commands:
*!autopilot on/off*
*!autopilot test*
*!channelnow best-deals*`);
}

async function runAutomationAutopilot({ force = false, source = 'cron' } = {}) {
  const now = new Date();
  const dayKey = autopilotDayKey(now);
  const summaryBefore = autopilotSummary();
  if (!force && settings.automation_autopilot_enabled === false) {
    return { skipped: true, reason: 'AutoPilot disabled', summary: summaryBefore };
  }
  if (!force) {
    const lastRun = Date.parse(automationAutopilot?.lastRunAt || 0);
    const intervalMs = Math.max(5, Number(settings.automation_autopilot_interval_minutes || 15)) * 60 * 1000;
    if (lastRun && Date.now() - lastRun < intervalMs - 1000) {
      return { skipped: true, reason: 'Interval not due yet', summary: summaryBefore };
    }
  }

  const actions = [];
  const errors = [];
  try { if (typeof writeSellerRatesFiles === 'function') writeSellerRatesFiles(); } catch (error) { errors.push(`seller export: ${error.message}`); }
  const summary = autopilotSummary();
  const newSellerRates = summary.sellerRates > Number(automationAutopilot?.lastSellerRateCount || 0);
  const channelReady = summary.whatsappReady && summary.channelsConfigured > 0 && settings.automation_autopilot_channel_enabled !== false;

  if ((force || newSellerRates) && channelReady) {
    const postKey = `${dayKey}:${summary.sellerRates}:best-deals`;
    if (force || automationAutopilot.lastBestDealsPostKey !== postKey) {
      try {
        const result = await shareDataToWhatsAppChannels({ kind: 'best-deals', delayMs: 2500, useRotation: true });
        actions.push(`Best deals posted to channel (${result.sent}/${result.total || result.sent})`);
        automationAutopilot.lastBestDealsPostKey = postKey;
      } catch (error) {
        errors.push(`best-deals channel: ${error.message}`);
      }
    }
  }

  if ((force || summary.unavailablePlans > 0) && channelReady && automationAutopilot.lastStockPostDate !== dayKey) {
    try {
      const result = await shareDataToWhatsAppChannels({ kind: 'stock', delayMs: 2500, useRotation: true });
      actions.push(`Stock status posted to channel (${result.sent}/${result.total || result.sent})`);
      automationAutopilot.lastStockPostDate = dayKey;
    } catch (error) {
      errors.push(`stock channel: ${error.message}`);
    }
  }

  if ((force || newSellerRates || automationAutopilot.lastAdminDigestDate !== dayKey) && settings.automation_autopilot_admin_alerts !== false && summary.whatsappReady) {
    try {
      const adminNumber = getAdminWhatsAppNumber();
      if (adminNumber) {
        await sendDirect(adminNumber, buildAutopilotAdminDigest(summary, actions));
        actions.push('Admin AutoPilot digest sent');
        automationAutopilot.lastAdminDigestDate = dayKey;
      }
    } catch (error) {
      errors.push(`admin digest: ${error.message}`);
    }
  }

  automationAutopilot.lastRunAt = now.toISOString();
  automationAutopilot.lastSellerRateCount = summary.sellerRates;
  automationAutopilot.runs = [...(automationAutopilot.runs || []), {
    id: uuid(),
    source,
    force,
    actions,
    errors,
    summary: compactAutopilotSummary(summary),
    ranAt: automationAutopilot.lastRunAt
  }].slice(-200);
  saveAutomationAutopilot();
  return { success: errors.length === 0, actions, errors, summary: autopilotSummary() };
}

async function notifyRealEstateAdmin(tenantId, text) {
  try {
    const config = realEstateBot.loadTenantConfig(tenantId) || {};
    const target = normalizeNumber(
      config.adminNumber ||
      config.agentNumber ||
      config.whatsappNumber ||
      config.phone ||
      settings.owner_whatsapp ||
      settings.support_whatsapp ||
      ''
    );
    if (!target || !text) return false;
    await sendDirect(target, text);
    return true;
  } catch (error) {
    console.warn('Real Estate admin notify skipped:', error.message);
    return false;
  }
}

async function sendDirectMedia(number, media, caption = '', options = {}) {
  const { accountId, inst } = resolveOutboundWAInstance(options || {});
  if (!number) throw new Error('number is required');
  if (!media) throw new Error('media is required');
  if (!inst?.isReady) throw new Error('WhatsApp not connected');

  const chatId = resolveOutboundChatId(number);
  const finalCaption = cleanOutgoingText(caption || '');
  try {
    const sentMsg = await sendClientMessageWithFallback(inst, chatId, media, finalCaption ? { caption: finalCaption } : {});
    markWAAccountSend(accountId);
    const whatsappId = sentMsg?.id?._serialized || sentMsg?.key?.id || null;

    const analyticsRow = messageAnalytics.recordSentMessage({
      to: chatId,
      content: finalCaption || '[Product image]',
      whatsappId,
      type: 'media',
      accountId
    });
    if (settings.reply_speed_tracking_enabled !== false) {
      try { messageAnalytics.recordReplyForConversation(chatId, analyticsRow?.id || null, { source: 'whatsapp_media' }); } catch {}
    }

    return sentMsg;
  } catch (error) {
    messageAnalytics.recordSentMessage({
      to: chatId,
      content: finalCaption || '[Product image]',
      whatsappId: null,
      type: 'media'
    });

    console.error('Failed to send media message:', error);
    throw error;
  }
}

function resolveWhatsAppOutboundProvider(options = {}) {
  const requested = String(options.provider || options.channel || settings.whatsapp_send_provider || process.env.WHATSAPP_SEND_PROVIDER || 'unofficial').toLowerCase();
  if (['cloud', 'official', 'meta', 'cloud_api'].includes(requested)) return 'cloud';
  if (['auto', 'hybrid', 'fallback'].includes(requested)) return 'auto';
  return 'unofficial';
}

function shouldUseWhatsAppCloudFallback(options = {}) {
  if (options.allowCloudFallback === false) return false;
  return settings.whatsapp_cloud_fallback_enabled !== false && getWhatsAppCloudStatus().ready;
}

function getWhatsAppCloudConfig() {
  const token = String(settings.whatsapp_cloud_access_token || process.env.WHATSAPP_CLOUD_ACCESS_TOKEN || '').trim().replace(/^Bearer\s+/i, '');
  const phoneNumberId = String(settings.whatsapp_cloud_phone_number_id || process.env.WHATSAPP_CLOUD_PHONE_NUMBER_ID || '').trim();
  const graphVersion = String(settings.whatsapp_cloud_graph_version || process.env.WHATSAPP_CLOUD_GRAPH_VERSION || process.env.META_GRAPH_VERSION || 'v21.0').trim().replace(/^\/+/, '');
  return {
    enabled: settings.whatsapp_cloud_api_enabled === true || String(process.env.WHATSAPP_CLOUD_API_ENABLED || '').toLowerCase() === 'true',
    fallbackEnabled: settings.whatsapp_cloud_fallback_enabled !== false,
    dryRunDefault: settings.whatsapp_cloud_dry_run !== false,
    graphVersion,
    phoneNumberId,
    businessAccountId: String(settings.whatsapp_cloud_business_account_id || process.env.WHATSAPP_CLOUD_BUSINESS_ACCOUNT_ID || '').trim(),
    accessToken: token,
    verifyToken: String(settings.whatsapp_cloud_verify_token || process.env.WHATSAPP_CLOUD_VERIFY_TOKEN || process.env.FB_VERIFY_TOKEN || '').trim(),
    webhookSecret: String(settings.whatsapp_cloud_webhook_secret || process.env.WHATSAPP_CLOUD_WEBHOOK_SECRET || '').trim(),
    defaultTemplate: String(settings.whatsapp_cloud_default_template || process.env.WHATSAPP_CLOUD_DEFAULT_TEMPLATE || 'hello_world').trim(),
    defaultLanguage: String(settings.whatsapp_cloud_default_language || process.env.WHATSAPP_CLOUD_DEFAULT_LANGUAGE || 'en_US').trim()
  };
}

function getWhatsAppCloudStatus() {
  const cfg = getWhatsAppCloudConfig();
  const missing = [];
  if (!cfg.phoneNumberId) missing.push('WHATSAPP_CLOUD_PHONE_NUMBER_ID');
  if (!cfg.accessToken) missing.push('WHATSAPP_CLOUD_ACCESS_TOKEN');
  if (!cfg.verifyToken) missing.push('WHATSAPP_CLOUD_VERIFY_TOKEN');
  return {
    enabled: cfg.enabled,
    ready: cfg.enabled && !missing.includes('WHATSAPP_CLOUD_PHONE_NUMBER_ID') && !missing.includes('WHATSAPP_CLOUD_ACCESS_TOKEN'),
    webhookReady: !!cfg.verifyToken,
    fallbackEnabled: cfg.fallbackEnabled,
    dryRunDefault: cfg.dryRunDefault,
    graphVersion: cfg.graphVersion,
    phoneNumberId: cfg.phoneNumberId ? `${cfg.phoneNumberId.slice(0, 4)}...${cfg.phoneNumberId.slice(-4)}` : '',
    businessAccountId: cfg.businessAccountId ? `${cfg.businessAccountId.slice(0, 4)}...${cfg.businessAccountId.slice(-4)}` : '',
    tokenMasked: cfg.accessToken ? maskSecret(cfg.accessToken) : '',
    defaultTemplate: cfg.defaultTemplate,
    defaultLanguage: cfg.defaultLanguage,
    missing,
    webhookUrl: `${settings.social_public_base_url || settings.gmail_public_base_url || `http://localhost:${PORT}`}/api/whatsapp-cloud/webhook`
  };
}

function normalizeWhatsAppCloudRecipient(value = '') {
  const raw = String(value || '').trim().replace(/@c\.us$/i, '').replace(/^whatsapp:/i, '');
  return raw.replace(/[^\d]/g, '');
}

let whatsappCloudApiLogCache = null;
function logWhatsAppCloudApiEvent(row = {}) {
  const event = {
    id: row.id || uuid(),
    type: row.type || 'whatsapp_cloud_api',
    status: row.status || 'info',
    createdAt: row.createdAt || new Date().toISOString(),
    ...row
  };
  if (!Array.isArray(whatsappCloudApiLogCache)) whatsappCloudApiLogCache = loadJSON('whatsapp_cloud_api_log.json', []);
  whatsappCloudApiLogCache.push(event);
  trimArrayInPlace(whatsappCloudApiLogCache, Number(process.env.WHATSAPP_CLOUD_API_LOG_MAX_ROWS || 1000), 'tail');
  saveJSON('whatsapp_cloud_api_log.json', whatsappCloudApiLogCache);
  if (typeof logs !== 'undefined' && Array.isArray(logs)) {
    logs.push({ id: event.id, type: event.type, status: event.status, time: event.createdAt, error: event.error || '', meta: event.meta || undefined });
    saveJSON('logs.json', logs);
  }
  return event;
}

async function callWhatsAppCloudApi(edgePath, body, options = {}) {
  const cfg = getWhatsAppCloudConfig();
  if (!cfg.enabled) throw new Error('WhatsApp Cloud API is disabled in Settings');
  if (!cfg.phoneNumberId) throw new Error('WhatsApp Cloud phone_number_id missing');
  if (!cfg.accessToken) throw new Error('WhatsApp Cloud access token missing');
  const url = `https://graph.facebook.com/${cfg.graphVersion}/${edgePath.replace(/^\/+/, '')}`;
  const response = await fetchOutbound(url, {
    method: options.method || 'POST',
    headers: {
      'Authorization': `Bearer ${cfg.accessToken}`,
      'Content-Type': 'application/json'
    },
    body: body === undefined ? undefined : JSON.stringify(body)
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.error) {
    throw new Error(data.error?.message || data.error?.error_user_msg || `WhatsApp Cloud API failed (${response.status})`);
  }
  return data;
}

async function sendWhatsAppCloudText(number, text, options = {}) {
  const recipient = normalizeWhatsAppCloudRecipient(number);
  const finalText = cleanOutgoingText(text || '').slice(0, 4096);
  if (!recipient) throw new Error('recipient number is required');
  if (!finalText) throw new Error('message text is required');
  const cfg = getWhatsAppCloudConfig();
  const dryRun = options.dryRun !== undefined ? options.dryRun === true : cfg.dryRunDefault;
  const payload = {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to: recipient,
    type: 'text',
    text: { preview_url: options.previewUrl === true, body: finalText }
  };
  if (dryRun) {
    const event = logWhatsAppCloudApiEvent({ type: 'whatsapp_cloud_text_dry_run', status: 'preview', to: recipient, source: options.source || 'manual', meta: { payload } });
    return { id: { _serialized: event.id }, dryRun: true, provider: 'whatsapp_cloud', to: recipient, payload };
  }
  const data = await callWhatsAppCloudApi(`${cfg.phoneNumberId}/messages`, payload);
  const messageId = data.messages?.[0]?.id || data.message_id || '';
  logWhatsAppCloudApiEvent({ type: 'whatsapp_cloud_text_sent', status: 'sent', to: recipient, source: options.source || 'manual', whatsappId: messageId });
  try {
    messageAnalytics.recordSentMessage({
      to: recipient,
      content: finalText,
      whatsappId: messageId,
      type: 'cloud_text',
      accountId: 'whatsapp_cloud_api'
    });
  } catch {}
  return { id: { _serialized: messageId }, provider: 'whatsapp_cloud', to: recipient, data };
}

async function sendWhatsAppCloudTemplate(number, templateName, languageCode, components = [], options = {}) {
  const recipient = normalizeWhatsAppCloudRecipient(number);
  if (!recipient) throw new Error('recipient number is required');
  const cfg = getWhatsAppCloudConfig();
  const name = String(templateName || cfg.defaultTemplate || 'hello_world').trim();
  const language = String(languageCode || cfg.defaultLanguage || 'en_US').trim();
  const dryRun = options.dryRun !== undefined ? options.dryRun === true : cfg.dryRunDefault;
  const payload = {
    messaging_product: 'whatsapp',
    to: recipient,
    type: 'template',
    template: {
      name,
      language: { code: language },
      ...(Array.isArray(components) && components.length ? { components } : {})
    }
  };
  if (dryRun) {
    const event = logWhatsAppCloudApiEvent({ type: 'whatsapp_cloud_template_dry_run', status: 'preview', to: recipient, source: options.source || 'manual', meta: { payload } });
    return { id: { _serialized: event.id }, dryRun: true, provider: 'whatsapp_cloud', to: recipient, payload };
  }
  const data = await callWhatsAppCloudApi(`${cfg.phoneNumberId}/messages`, payload);
  const messageId = data.messages?.[0]?.id || data.message_id || '';
  logWhatsAppCloudApiEvent({ type: 'whatsapp_cloud_template_sent', status: 'sent', to: recipient, source: options.source || 'manual', whatsappId: messageId, meta: { template: name, language } });
  try {
    messageAnalytics.recordSentMessage({
      to: recipient,
      content: `[Template] ${name}`,
      whatsappId: messageId,
      type: 'cloud_template',
      accountId: 'whatsapp_cloud_api'
    });
  } catch {}
  return { id: { _serialized: messageId }, provider: 'whatsapp_cloud', to: recipient, data };
}

function extractWhatsAppCloudMessageText(message = {}) {
  if (message.text?.body) return message.text.body;
  if (message.button?.text) return message.button.text;
  if (message.interactive?.button_reply?.title) return message.interactive.button_reply.title;
  if (message.interactive?.list_reply?.title) return message.interactive.list_reply.title;
  if (message.image?.caption) return message.image.caption;
  if (message.document?.caption) return message.document.caption;
  if (message.audio) return '[Audio message]';
  if (message.image) return '[Image message]';
  if (message.document) return '[Document message]';
  return `[${message.type || 'message'}]`;
}

function recordWhatsAppCloudInboundMessage(message = {}, value = {}) {
  const from = normalizeWhatsAppCloudRecipient(message.from || '');
  const contact = (Array.isArray(value.contacts) ? value.contacts : []).find(item => normalizeWhatsAppCloudRecipient(item.wa_id || '') === from) || {};
  const text = extractWhatsAppCloudMessageText(message);
  const name = contact.profile?.name || `Cloud WA ${from.slice(-6)}`;
  const row = {
    id: message.id || uuid(),
    source: 'whatsapp_cloud',
    chatId: from,
    recipientId: value.metadata?.phone_number_id || '',
    number: from,
    name,
    body: text,
    timestamp: new Date(Number(message.timestamp || Date.now() / 1000) * 1000).toISOString(),
    read: false
  };
  if (typeof inbox !== 'undefined' && Array.isArray(inbox)) {
    inbox.unshift(row);
    if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
    try { saveInbox(); } catch {}
  }
  try { ensureGuestCustomer(from, name, 'whatsapp_cloud'); } catch {}
  try {
    messageAnalytics.recordInboundMessage({
      from,
      number: from,
      recipientId: row.recipientId,
      chatId: from,
      content: text,
      type: message.type || 'text',
      source: 'whatsapp_cloud',
      name
    });
  } catch {}
  try { io.emit('incoming_message', row); } catch {}
  try { triggerWebhooks('new_message', row); } catch {}
  logWhatsAppCloudApiEvent({ id: row.id, type: 'whatsapp_cloud_inbound', status: 'received', from, meta: { messageType: message.type || 'text' } });
  return row;
}

function handleWhatsAppCloudWebhookPayload(body = {}) {
  const entries = Array.isArray(body.entry) ? body.entry : [];
  const inbound = [];
  const statuses = [];
  for (const entry of entries) {
    for (const change of (Array.isArray(entry.changes) ? entry.changes : [])) {
      const value = change.value || {};
      for (const message of (Array.isArray(value.messages) ? value.messages : [])) {
        inbound.push(recordWhatsAppCloudInboundMessage(message, value));
      }
      for (const status of (Array.isArray(value.statuses) ? value.statuses : [])) {
        statuses.push(status);
        logWhatsAppCloudApiEvent({
          id: status.id || uuid(),
          type: 'whatsapp_cloud_status',
          status: status.status || 'status',
          to: normalizeWhatsAppCloudRecipient(status.recipient_id || ''),
          meta: status
        });
      }
    }
  }
  return { inbound, statuses };
}

function promiseTimeout(promise, ms, fallback) {
  return Promise.race([
    promise,
    new Promise(resolve => setTimeout(() => resolve(fallback), ms))
  ]);
}

function waSerializedId(row = {}) {
  const id = row?.id?._serialized || row?.id?.id || row?.id || row?.jid || row?.remoteJid || '';
  return String(id || '');
}

function normalizeWAContactNumber(row = {}) {
  if (typeof row === 'string') return normalizeNumber(row.split('@')[0]);
  const id = waSerializedId(row);
  const raw = row.number || row.phone || row.id?.user || row.user || (id.includes('@') ? id.split('@')[0] : id);
  return normalizeNumber(raw);
}

function waTimestampToISO(value) {
  const n = Number(value || 0);
  if (!n) return '';
  const ms = n > 100000000000 ? n : n * 1000;
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? '' : d.toISOString();
}

function cleanWAContactName(row = {}, fallback = '') {
  const id = waSerializedId(row);
  const name = row.name || row.pushname || row.shortName || row.verifiedName || row.formattedTitle || row.notify || row.subject || fallback || id;
  return String(name || fallback || 'Contact').replace(/\s+/g, ' ').trim();
}

function waContactFromChat(chat = {}) {
  const id = waSerializedId(chat);
  const isGroup = !!chat.isGroup || id.endsWith('@g.us');
  if (isGroup || id === 'status@broadcast') return null;
  const number = normalizeWAContactNumber(chat);
  if (!number) return null;
  const last = chat.lastMessage || {};
  const timestamp = chat.timestamp || last.timestamp || last._data?.t || 0;
  return {
    id: id || `${number}@c.us`,
    name: cleanWAContactName(chat, number),
    number,
    lastActive: waTimestampToISO(timestamp),
    source: 'chat'
  };
}

function waContactFromContact(contact = {}) {
  const id = waSerializedId(contact);
  const server = contact.id?.server || '';
  const isGroup = contact.isGroup || server === 'g.us' || id.endsWith('@g.us');
  if (isGroup || id === 'status@broadcast') return null;
  const number = normalizeWAContactNumber(contact);
  if (!number) return null;
  return {
    id: id || `${number}@c.us`,
    name: cleanWAContactName(contact, number),
    number,
    lastActive: contact.lastActive || '',
    source: contact.isMyContact ? 'phonebook' : 'contact'
  };
}

function dedupeWAContacts(rows = []) {
  const byNumber = new Map();
  for (const row of rows) {
    if (!row?.number) continue;
    const prev = byNumber.get(row.number);
    if (!prev) {
      byNumber.set(row.number, row);
      continue;
    }
    const betterName = !prev.name || prev.name === prev.number ? row.name : prev.name;
    const betterLast = Date.parse(row.lastActive || 0) > Date.parse(prev.lastActive || 0) ? row.lastActive : prev.lastActive;
    byNumber.set(row.number, { ...prev, ...row, name: betterName, lastActive: betterLast || prev.lastActive || row.lastActive });
  }
  return Array.from(byNumber.values()).sort((a, b) => {
    const at = Date.parse(a.lastActive || 0) || 0;
    const bt = Date.parse(b.lastActive || 0) || 0;
    return bt - at || String(a.name || '').localeCompare(String(b.name || ''));
  });
}

function savedContactRowsFromCRM() {
  const rows = [];
  const clean = (value) => String(value || '').replace(/\D/g, '');
  for (const c of customers || []) {
    const number = clean(c.number || c.phone || c.whatsapp || c.customerNumber);
    if (!number || number.length < 8 || /^120363/.test(number) || /^2026/.test(number)) continue;
    rows.push({
      id: `${number}@c.us`,
      name: c.name || c.customerName || number,
      number,
      lastActive: c.lastActive || c.updated || c.created || '',
      source: 'crm'
    });
  }
  for (const [numberKey, conv] of Object.entries(waConversations || {})) {
    const rawKey = String(numberKey || '').toLowerCase();
    if (rawKey.includes('@g.us') || /^(test|bot-sim|codex)/.test(rawKey)) continue;
    const number = clean(numberKey);
    if (!number || number.length < 8 || /^2026/.test(number) || /^120363/.test(number)) continue;
    const last = [...(conv.history || [])].reverse().find(m => m.time)?.time || conv.updated || '';
    rows.push({
      id: `${number}@c.us`,
      name: conv.name || conv.pushName || number,
      number,
      lastActive: last,
      source: 'saved-chat'
    });
  }
  return dedupeWAContacts(rows);
}

function mergedContactRows(includeLive = true) {
  const liveRows = includeLive ? (waContacts || []) : [];
  return dedupeWAContacts([...(Array.isArray(liveRows) ? liveRows : []), ...savedContactRowsFromCRM()]);
}

function contactRowsToCSV(rows = []) {
  const headers = ['name', 'number', 'lastActive', 'source', 'id'];
  const escapeCell = (value) => {
    const text = String(value ?? '');
    if (/["\n,]/.test(text)) return `"${text.replace(/"/g, '""')}"`;
    return text;
  };
  const lines = [headers.join(',')];
  for (const row of rows || []) {
    lines.push(headers.map(key => escapeCell(row?.[key] || '')).join(','));
  }
  return lines.join('\n');
}

function customerNumberValue(customer = {}) {
  return (customer.number || customer.phone || customer.whatsapp || customer.customerNumber || '').toString();
}

function findCustomerByIdentifier(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const clean = raw.replace(/@(c|g|lid)\.us$/i, '').replace(/\D/g, '');
  return customers.find(c => {
    if (c.id === raw) return true;
    const number = customerNumberValue(c).replace(/\D/g, '');
    return clean && number && number === clean;
  }) || null;
}

function buildCustomerMessageContext(customerOrId, extras = {}) {
  const customer = typeof customerOrId === 'object'
    ? (customerOrId || {})
    : (findCustomerByIdentifier(customerOrId) || {});
  const customFields = {
    ...normalizeCustomFields(customer.customFields),
    ...normalizeCustomFields(customer.custom_fields),
    ...normalizeCustomFields(customer.fields),
    ...normalizeCustomFields(extras.customFields),
    ...normalizeCustomFields(extras.custom_fields),
    ...normalizeCustomFields(extras.mergeFields)
  };
  return {
    settings,
    customer,
    contact: customer,
    customFields,
    variables: extras.variables || extras.vars || {},
    ...customer,
    ...extras
  };
}

function maskPhoneValue(value = '') {
  const text = String(value || '');
  const digits = text.replace(/\D/g, '');
  if (digits.length <= 5) return text ? '***' : '';
  const masked = `${digits.slice(0, 2)}${'*'.repeat(Math.max(3, digits.length - 5))}${digits.slice(-3)}`;
  return text.includes('@') ? `${masked}@c.us` : masked;
}

function maskEmailValue(value = '') {
  const text = String(value || '');
  const at = text.indexOf('@');
  if (at <= 1) return text ? '***' : '';
  return `${text.slice(0, 1)}***${text.slice(at)}`;
}

function requestStaffRole(req) {
  return String(req.headers['x-staff-role'] || req.query.role || req.body?.role || 'admin').trim().toLowerCase();
}

function shouldMaskCustomerData(req) {
  if (settings.staff_privacy_enabled !== true) return false;
  const role = requestStaffRole(req);
  const allowed = (settings.staff_privacy_allowed_roles || []).map(r => String(r).toLowerCase());
  return !allowed.includes(role);
}

function maskCustomerForRole(customer = {}, req) {
  if (!customer || !shouldMaskCustomerData(req)) return customer;
  const masked = { ...customer, privacyMasked: true };
  if (settings.staff_privacy_mask_phone) {
    ['number', 'phone', 'whatsapp', 'customerNumber'].forEach(key => {
      if (masked[key]) masked[key] = maskPhoneValue(masked[key]);
    });
  }
  if (settings.staff_privacy_mask_email && masked.email) masked.email = maskEmailValue(masked.email);
  return masked;
}

function maskWAProfileForRole(profile = {}, req) {
  if (!profile || !shouldMaskCustomerData(req)) return profile;
  const masked = { ...profile, privacyMasked: true };
  if (settings.staff_privacy_mask_phone && masked.number) masked.number = maskPhoneValue(masked.number);
  if (settings.staff_privacy_mask_email && masked.email) masked.email = maskEmailValue(masked.email);
  return masked;
}

function normalizeCustomerPayload(body = {}) {
  const payload = { ...body };
  const customFields = {
    ...normalizeCustomFields(body.customFields),
    ...normalizeCustomFields(body.custom_fields),
    ...normalizeCustomFields(body.fields),
    ...normalizeCustomFields(body.mergeFields)
  };
  delete payload.custom_fields;
  delete payload.fields;
  delete payload.mergeFields;
  if (Object.keys(customFields).length) payload.customFields = customFields;
  if (payload.phone && !payload.number) payload.number = payload.phone;
  if (payload.whatsapp && !payload.number) payload.number = payload.whatsapp;
  return payload;
}

function mergeCustomerPayload(customer, body = {}) {
  const payload = normalizeCustomerPayload(body);
  Object.entries(payload).forEach(([key, value]) => {
    if (value === undefined) return;
    if (key === 'customFields') {
      customer.customFields = {
        ...normalizeCustomFields(customer.customFields),
        ...normalizeCustomFields(value)
      };
      return;
    }
    customer[key] = value;
  });
  return customer;
}

async function fetchWAContactRows(inst) {
  const chats = await promiseTimeout(inst.client.getChats(), 25000, []);
  let contacts = [];
  if (typeof inst.client.getContacts === 'function') {
    contacts = await promiseTimeout(inst.client.getContacts(), 25000, []);
  } else if (inst.liveContacts instanceof Map) {
    contacts = Array.from(inst.liveContacts.values());
  }
  const contactRows = (contacts || []).map(waContactFromContact).filter(Boolean);
  const chatRows = (chats || []).map(waContactFromChat).filter(Boolean);
  const groupCount = (chats || []).filter(c => !!c?.isGroup || waSerializedId(c).endsWith('@g.us')).length;
  return { contacts: dedupeWAContacts([...contactRows, ...chatRows]), groups: groupCount };
}

function personalizeBulkMessage(text, contact = {}) {
  return renderMergeFields(text, buildCustomerMessageContext(contact));
}

// ------------------------------------------------------------------
// AI ENGINE (Groq Integration) with Language Detection
// ------------------------------------------------------------------
async function callAI(prompt, systemPrompt) {
  if (!hasAnyAIProvider()) return "AI is currently offline. Please set at least one AI API key in Settings.";
  try {
    // Detect language from the prompt for better language-specific responses
    const { detectLanguage } = require('./ai/languageDetector');
    const languageCode = detectLanguage(prompt);
    const result = await callAIProvider(prompt, `${systemPrompt}\n\nDetected language code: ${languageCode}. Reply in the customer's language.`, {
      maxTokens: 180,
      temperature: 0.4
    });
    return result.text;
  } catch (err) {
    console.error("AI Error:", err);
    return "Sorry, my AI engine is facing a temporary glitch.";
  }
}

// ------------------------------------------------------------------
// LAPTOP BOT LOGIC
// ------------------------------------------------------------------
function productSearchTerms(text) {
  const stop = new Set(['the', 'and', 'for', 'with', 'hai', 'hy', 'ki', 'ka', 'ke', 'price', 'prices', 'laptop', 'laptops', 'rs', 'pkr', 'budget', 'under', 'below', 'tak', 'chahiye', 'need']);
  return String(text || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(term => term.length > 1 && !stop.has(term));
}

function isSellableLaptopProduct(product) {
  const price = Number(product?.price || 0);
  const hay = [product?.name, product?.brand, product?.specs, product?.description].join(' ').toLowerCase();
  const nameAndTags = [product?.name, product?.subcategory, ...(Array.isArray(product?.tags) ? product.tags : [])].join(' ').toLowerCase();
  const accessoryWords = /\b(mouse|keyboard|keyboards|headset|headphone|backpack|bag|charger|cable|stand|cover|sleeve|adapter|speaker|handsfree)\b/i;
  const laptopWords = /\b(core i[3579]|i[3579][-\s]?\d{3,5}|ryzen|celeron|pentium|latitude|elitebook|probook|thinkpad|ideapad|inspiron|pavilion|ram|ssd|nvme|generation|gen)\b/i;
  return product &&
    product.stock !== false &&
    price >= 15000 &&
    String(product.category || '').toLowerCase() === 'laptops' &&
    !accessoryWords.test(nameAndTags) &&
    laptopWords.test(hay);
}

function getSellableLaptopProducts() {
  return laptopProducts.filter(isSellableLaptopProduct);
}

