function searchAccessoriesFast(query, limit = 5) {
  const group = detectAccessoryGroupFromText(query);
  const terms = productSearchTerms(query);
  const budget = parseBudgetFromText(query);
  const products = getSellableAccessoryProducts(group?.id || '');
  const scored = products
    .filter(product => !budget || Number(product.price || 0) <= budget)
    .map(product => {
      const hay = accessoryCatalogText(product).toLowerCase();
      let score = group ? 15 : 0;
      for (const term of terms) {
        if (hay.includes(term)) score += 5;
      }
      if (budget) score += 3;
      return { product, score };
    })
    .filter(item => group || terms.length || budget ? item.score > 0 : true)
    .sort((a, b) => b.score - a.score || Number(a.product.price || 0) - Number(b.product.price || 0));
  return { group, results: scored.slice(0, limit).map(item => item.product), budget, terms };
}

