function laptopCatalogText(product = {}) {
  return decodeHtmlEntities([
    product.name,
    product.brand,
    product.processor,
    product.specs,
    product.description,
    product.condition,
    product.category,
    product.subcategory,
    ...(Array.isArray(product.tags) ? product.tags : [])
  ].filter(Boolean).join(' ')).replace(/\s+/g, ' ').trim();
}

function normalizeLaptopBrandName(value = '') {
  const raw = String(value || '').trim();
  const lower = raw.toLowerCase();
  if (!lower) return 'Other';
  if (/\b(hp|hewlett|elitebook|probook|pavilion)\b/.test(lower)) return 'HP';
  if (/\bdell|latitude|inspiron|xps\b/.test(lower)) return 'Dell';
  if (/\blenovo|lovone|lenevo|thinkpad|ideapad|yoga\b/.test(lower)) return 'Lenovo';
  if (/\basus|vivobook|zenbook\b/.test(lower)) return 'Asus';
  if (/\bacer|aspire|travelmate\b/.test(lower)) return 'Acer';
  if (/\bapple|macbook|imac\b/.test(lower)) return 'Apple';
  if (/\bmsi\b/.test(lower)) return 'MSI';
  if (/\bmicrosoft|surface\b/.test(lower)) return 'Microsoft';
  if (/\btoshiba\b/.test(lower)) return 'Toshiba';
  if (/\bsamsung\b/.test(lower)) return 'Samsung';
  return raw.replace(/\s+/g, ' ').replace(/\b\w/g, ch => ch.toUpperCase()) || 'Other';
}

function extractLaptopBrand(product = {}) {
  const known = ['HP', 'Dell', 'Lenovo', 'Asus', 'Acer', 'Toshiba', 'Samsung', 'Apple', 'MSI', 'Microsoft'];
  const text = laptopCatalogText(product).toLowerCase();
  return normalizeLaptopBrandName(product.brand || known.find(b => text.includes(b.toLowerCase())) || 'Other');
}

function extractLaptopProcessor(product = {}) {
  const text = laptopCatalogText(product).toLowerCase();
  if (/ryzen\s*7/.test(text)) return 'Ryzen 7';
  if (/ryzen\s*5/.test(text)) return 'Ryzen 5';
  if (/ryzen\s*3/.test(text)) return 'Ryzen 3';
  if (/\bi9\b|core\s*i9/.test(text)) return 'Core i9';
  if (/\bi7\b|core\s*i7/.test(text)) return 'Core i7';
  if (/\bi5\b|core\s*i5/.test(text)) return 'Core i5';
  if (/\bi3\b|core\s*i3/.test(text)) return 'Core i3';
  if (/celeron/.test(text)) return 'Celeron';
  if (/pentium/.test(text)) return 'Pentium';
  return 'Unknown';
}

function extractLaptopGeneration(product = {}) {
  const text = laptopCatalogText(product);
  const explicit = text.match(/\b(\d{1,2})(?:st|nd|rd|th)?\s*(?:gen|generation)\b/i);
  if (explicit) return Number(explicit[1]);
  const code = text.match(/\bi[3579][-\s]?(\d{4,5})[a-z]{0,2}\b/i);
  if (code) {
    const digits = code[1];
    return digits.length === 5 ? Number(digits.slice(0, 2)) : Number(digits[0]);
  }
  const g = text.match(/\bG(\d{1,2})\b/);
  return g ? Number(g[1]) : 0;
}

function extractLaptopRam(product = {}) {
  const text = laptopCatalogText(product);
  const match = text.match(/\b(\d{1,2})\s*GB\s*(?:DDR\d\s*)?(?:RAM|Memory)\b/i) || text.match(/\b(\d{1,2})\s*GB\b/i);
  return match ? Number(match[1]) : 0;
}

function extractLaptopStorage(product = {}) {
  const text = laptopCatalogText(product);
  const match = text.match(/\b(\d+(?:\.\d+)?)\s*(TB|GB)\s*(NVMe|M\.2|SSD|HDD)\b/i);
  if (!match) return { label: 'Storage N/A', type: '', gb: 0 };
  const amount = Number(match[1]);
  const unit = match[2].toUpperCase();
  const type = match[3].replace(/\./g, '').toUpperCase();
  const gb = unit === 'TB' ? amount * 1024 : amount;
  return { label: `${match[1]}${unit} ${type}`, type, gb };
}

function laptopProfile(product = {}) {
  return {
    brand: extractLaptopBrand(product),
    processor: extractLaptopProcessor(product),
    generation: extractLaptopGeneration(product),
    ram: extractLaptopRam(product),
    storage: extractLaptopStorage(product)
  };
}

function parseBudgetFromText(text) {
  const match = String(text || '').replace(/,/g, '').match(/\b([1-9][0-9]{3,6})\b/);
  return match ? Number(match[1]) : null;
}

function rankProductsForQuery(product, terms, budget) {
  const name = String(product.name || '').toLowerCase();
  const profile = laptopProfile(product);
  const brand = String(profile.brand || product.brand || '').toLowerCase();
  const processor = String(profile.processor || '').toLowerCase();
  const hay = laptopCatalogText(product).toLowerCase();
  const query = terms.join(' ');
  let score = 0;
  for (const term of terms) {
    if (name.includes(term)) score += 8;
    else if (brand.includes(term)) score += 5;
    else if (processor.includes(term)) score += 5;
    else if (hay.includes(term)) score += 3;
  }
  if (/\bi7\b|core i7/.test(query) && profile.processor === 'Core i7') score += 10;
  if (/\bi5\b|core i5/.test(query) && profile.processor === 'Core i5') score += 10;
  if (/\bi3\b|core i3/.test(query) && profile.processor === 'Core i3') score += 10;
  if (/ryzen/.test(query) && /^Ryzen/.test(profile.processor)) score += 9;
  const genMatch = query.match(/\b(\d{1,2})\s*(?:th|st|nd|rd)?\s*(?:gen|generation)\b/i);
  if (genMatch && profile.generation === Number(genMatch[1])) score += 7;
  const ramMatch = query.match(/\b(\d{1,2})\s*gb\b/i);
  if (ramMatch && profile.ram >= Number(ramMatch[1])) score += 4;
  if (/nvme/.test(query) && profile.storage.type.includes('NVME')) score += 5;
  if (/ssd/.test(query) && /SSD|NVME|M2/.test(profile.storage.type)) score += 3;
  if (budget && Number(product.price || 0) <= budget) score += 6;
  if (score > 0) {
    if (product.stock !== false) score += 2;
    if (product.source === 'infinitytouchstore.com') score += 1;
  }
  return score;
}

function searchLaptopsFast(query, limit = 5) {
  const inStock = getSellableLaptopProducts();
  const terms = productSearchTerms(query);
  const budget = parseBudgetFromText(query);
  const prices = inStock.map(p => Number(p.price || 0)).filter(Boolean);
  const minPrice = prices.length ? Math.min(...prices) : 0;
  if (budget && minPrice && budget < minPrice) return { results: [], noStock: true, minPrice, budget, terms };

  const scored = inStock
    .filter(product => !budget || Number(product.price || 0) <= budget)
    .map(product => ({ product, score: rankProductsForQuery(product, terms, budget) }))
    .filter(item => (terms.length || budget) ? item.score > 0 : true)
    .sort((a, b) => b.score - a.score || Number(a.product.price || 0) - Number(b.product.price || 0));

  return { results: scored.slice(0, limit).map(item => item.product), noStock: false, minPrice, budget, terms };
}

function isSmartProductFinderIntent(text = '') {
  const raw = String(text || '').trim();
  if (!raw) return false;
  const lower = raw.toLowerCase();
  return /\b(best|suggest|recommend|recommendation|under|budget|range|cheap|sasta|sasti|gift|office|study|student|gaming|formal|casual|storage|upgrade|finder|show me|dikhao|chahiye|need)\b/i.test(lower)
    && (parseBudgetFromText(raw) || productSearchTerms(raw).length >= 2 || isAccessoryIntent(raw) || isRetailProductIntent(raw) || /\b(laptop|hp|dell|lenovo|core i[3579]|ryzen)\b/i.test(lower));
}

function smartProductCategory(product = {}) {
  const category = String(product.category || '').toLowerCase();
  if (category === 'accessories' || category === 'accessory') return 'Accessory';
  if (category === 'dry-fruits') return 'Dry Fruit';
  if (category === 'shirts') return 'Shirt';
  if (category === 'pizza') return 'Pizza';
  return 'Laptop';
}

function rankGenericProductForQuery(product = {}, terms = [], budget = null, rawQuery = '') {
  const category = String(product.category || '').toLowerCase();
  const hay = accessoryCatalogText(product).toLowerCase();
  let score = 0;
  for (const term of terms) {
    if (hay.includes(term)) score += 5;
    if (String(product.name || '').toLowerCase().includes(term)) score += 4;
  }
  if (category === 'laptops') score += rankProductsForQuery(product, terms, budget);
  if (isAccessoryIntent(rawQuery) && (category === 'accessories' || category === 'accessory')) score += 12;
  if (isRetailProductIntent(rawQuery) && ['dry-fruits', 'shirts'].includes(category)) score += 12;
  if (/\b(laptop|hp|dell|lenovo|core i[3579]|ryzen|study|student|office|gaming)\b/i.test(rawQuery) && category === 'laptops') score += 10;
  if (/\b(gift|badam|kaju|khajoor|dry\s*fruit)\b/i.test(rawQuery) && category === 'dry-fruits') score += 10;
  if (/\b(formal|casual|polo|shirt|tshirt|t-shirt)\b/i.test(rawQuery) && category === 'shirts') score += 10;
  if (/\b(pizza|piza|fajita|tikka|pepperoni|cheese|family deal|large|medium|small)\b/i.test(rawQuery) && category === 'pizza') score += 10;
  if (/\b(upgrade|storage|speed|ssd|ram|keyboard|mouse)\b/i.test(rawQuery) && (category === 'accessories' || category === 'accessory')) score += 10;
  if (budget && Number(product.price || 0) <= budget) score += 8;
  if (productImageSource(product)) score += 2;
  if (product.stock !== false) score += 2;
  return score;
}

function searchSmartProducts(query, limit = 6) {
  const terms = productSearchTerms(query);
  const budget = parseBudgetFromText(query);
  const retailGroup = detectRetailGroupFromText(query);
  const accessoryGroup = detectAccessoryGroupFromText(query);
  const wantsLaptop = /\b(laptop|laptops|notebook|hp|dell|lenovo|apple|asus|acer|core i[3579]|ryzen|student|study|office|gaming)\b/i.test(String(query || ''));
  let pool;
  if (retailGroup?.id) {
    pool = getSellableRetailProducts(retailGroup.id);
  } else if (accessoryGroup?.id || isAccessoryIntent(query)) {
    pool = getSellableAccessoryProducts(accessoryGroup?.id || '');
  } else if (wantsLaptop) {
    pool = getSellableLaptopProducts();
  } else {
    pool = [
      ...getSellableLaptopProducts(),
      ...getSellableAccessoryProducts(),
      ...getSellableRetailProducts()
    ];
  }
  const scored = pool
    .filter(product => product && product.stock !== false && Number(product.price || 0) > 0)
    .filter(product => !budget || Number(product.price || 0) <= budget)
    .map(product => ({ product, score: rankGenericProductForQuery(product, terms, budget, query) }))
    .filter(item => item.score > 0)
    .sort((a, b) => b.score - a.score || Number(a.product.price || 0) - Number(b.product.price || 0));
  return { results: scored.slice(0, limit).map(item => item.product), budget, terms };
}

