function getLaptopBrandGroups() {
  const priority = ['HP', 'Dell', 'Lenovo', 'Apple', 'Asus', 'Acer', 'Microsoft', 'MSI', 'Toshiba', 'Samsung', 'Other'];
  const groups = new Map();
  for (const product of getSellableLaptopProducts()) {
    const brand = normalizeLaptopBrandName(extractLaptopBrand(product));
    if (!groups.has(brand)) groups.set(brand, []);
    groups.get(brand).push(product);
  }
  const sorted = [...groups.entries()].map(([brand, products]) => {
    const byPrice = products.slice().sort((a, b) => Number(a.price || 0) - Number(b.price || 0));
    const prices = byPrice.map(p => Number(p.price || 0)).filter(Boolean);
    return { brand, products: byPrice, count: byPrice.length, fromPrice: prices.length ? Math.min(...prices) : 0 };
  }).sort((a, b) => {
    const ai = priority.indexOf(a.brand);
    const bi = priority.indexOf(b.brand);
    const ao = ai === -1 ? 999 : ai;
    const bo = bi === -1 ? 999 : bi;
    return ao - bo || b.count - a.count || a.brand.localeCompare(b.brand);
  });
  return sorted.map((item, index) => ({ id: String(index + 1), ...item }));
}

function findLaptopBrandSelection(text) {
  const raw = String(text || '').trim();
  const groups = getLaptopBrandGroups();
  if (!raw || !groups.length) return null;
  const byId = groups.find(item => item.id === raw);
  if (byId) return byId;
  const wanted = normalizeLaptopBrandName(raw);
  return groups.find(item => item.brand.toLowerCase() === wanted.toLowerCase()) || null;
}

