function inferBotPlanCategory(plan = {}) {
  const raw = (plan.category || plan.type || plan.name || '').toString().toLowerCase();
  if (raw.includes('giveaway') || raw.includes('moclaw') || raw.includes('deepseek') || raw.includes('free trial')) return 'Giveaway';
  if (raw.includes('claude')) return 'Claude';
  if (raw.includes('perplexity')) return 'Perplexity';
  if (raw.includes('gemini')) return 'Gemini';
  if (raw.includes('canva')) return 'Canva';
  if (raw.includes('capcut') || raw.includes('cap cut')) return 'CapCut';
  if (raw.includes('kimi')) return 'Kimi';
  if (raw.includes('turnitin')) return 'Turnitin';
  if (raw.includes('bundle')) return 'Bundles';
  if (raw.includes('chatgpt') || raw.includes('gpt')) return 'ChatGPT';
  return plan.category || 'AI Tools';
}

function botCategoryEmoji(category = '') {
  const cat = String(category || '');
  if (cat === 'Giveaway') return 'ðŸŽ';
  if (cat === 'Claude') return 'ðŸ§ ';
  if (cat === 'Perplexity') return 'ðŸ”';
  if (cat === 'Gemini') return 'âœ¨';
  if (cat === 'Canva') return 'ðŸŽ¨';
  if (cat === 'CapCut') return 'ðŸŽ¬';
  if (cat === 'Kimi') return 'ðŸŒ™';
  if (cat === 'Turnitin') return 'ðŸ“';
  if (cat === 'Bundles') return 'ðŸ“¦';
  return 'ðŸ¤–';
}

function botPlanEmoji(plan = {}) {
  if (plan.emoji) return plan.emoji;
  return botCategoryEmoji(inferBotPlanCategory(plan));
}

function normalizeBotSearchText(value = '') {
  return String(value || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function aiPlanBasePrice(plan = {}) {
  return Number(plan.price || 0);
}

function inferAIPlanAccountType(plan = {}) {
  const text = normalizeBotSearchText([
    plan.accountType,
    plan.account_type,
    plan.type,
    plan.name,
    plan.label,
    plan.duration,
    planFeatures(plan).join(' ')
  ].filter(Boolean).join(' '));
  if (/\b(non|no|without)\s+(warranty|waranty|warrnty)\b/.test(text) || /\bnonwarranty\b/.test(text)) return 'non_warranty';
  if (/\b(warranty|waranty|warrnty)\b/.test(text)) return 'warranty';
  if (/\b(private|shared|share)\b/.test(text)) return 'private';
  return '';
}

function isChatGPTCategory(category = '') {
  return String(category || '').toLowerCase() === 'chatgpt';
}

function isChatGPTPlan(plan = {}) {
  return isChatGPTCategory(inferBotPlanCategory(plan));
}

function inferChatGPTAccessMode(plan = {}) {
  const text = normalizeBotSearchText([
    plan.accessMode,
    plan.access_mode,
    plan.access,
    plan.name,
    plan.label,
    plan.duration,
    planFeatures(plan).join(' ')
  ].filter(Boolean).join(' '));
  if (/\b(shared|share|sharing)\b/.test(text)) return 'shared';
  if (/\b(private|dedicated|personal)\b/.test(text)) return 'private';
  return '';
}

function chatGPTAccessModeFromText(text = '') {
  const normalized = normalizeBotSearchText(text);
  if (/\b(shared|share|sharing)\b/.test(normalized)) return 'shared';
  if (/\b(private|dedicated|personal)\b/.test(normalized)) return 'private';
  return '';
}

function chatGPTAccessLabel(mode = '') {
  if (mode === 'shared') return 'Shared Access';
  if (mode === 'private') return 'Private Access';
  return '';
}

function filterChatGPTPlanOptionsByAccess(options = [], accessMode = '') {
  if (!accessMode) return options;
  return (Array.isArray(options) ? options : []).filter(item => {
    const mode = inferChatGPTAccessMode(item.plan || {});
    return mode ? mode === accessMode : accessMode === 'private';
  }).map((item, index) => ({ ...item, id: String(index + 1) }));
}

function getAIPlanSlots(plan = {}, typeId = '') {
  const stock = plan.stock && typeof plan.stock === 'object' ? plan.stock : {};
  const defaults = { private: 3, warranty: 5, non_warranty: 7 };
  const candidates = [
    stock[typeId],
    plan[`${typeId}Slots`],
    plan[`slots_${typeId}`],
    plan.availableSlots,
    plan.stockCount
  ];
  const found = candidates.find(value => Number.isFinite(Number(value)));
  return Math.max(0, Number(found ?? defaults[typeId] ?? 0));
}

function getAIPlanAccountTypeOffers(plan = {}) {
  const base = aiPlanBasePrice(plan);
  const explicitType = inferAIPlanAccountType(plan);
  const planAvailable = isPlanAvailableForWhatsApp(plan);
  const accountTypes = explicitType
    ? AI_ACCOUNT_TYPES.filter(type => type.id === explicitType)
    : AI_ACCOUNT_TYPES;
  return accountTypes.map(type => {
    let price = base;
    if (!explicitType) {
      if (type.priceMode === 'fixed_999') price = 999;
      if (type.priceMode === 'discount') price = Math.max(699, Math.round((base * 0.72) / 50) * 50);
    }
    const slots = planAvailable ? getAIPlanSlots(plan, type.id) : 0;
    return {
      ...type,
      price,
      slots,
      available: planAvailable && slots > 0
    };
  });
}

function findAIAccountTypeOffer(plan = {}, text = '') {
  const normalized = normalizeBotSearchText(text);
  const offers = getAIPlanAccountTypeOffers(plan);
  if (/^[123]$/.test(String(text || '').trim())) {
    return offers[Number(text) - 1] || null;
  }
  if (offers.length === 1 && /\b(confirm|yes|order|buy|ok|done)\b/.test(normalized)) return offers[0];
  return offers.find(offer => {
    const aliases = [
      offer.id,
      offer.label,
      offer.id.replace('_', ' '),
      offer.id === 'private' ? 'shared' : '',
      offer.id === 'warranty' ? 'warranty account' : '',
      offer.id === 'non_warranty' ? 'non warranty' : '',
      offer.id === 'non_warranty' ? 'non-warranty' : ''
    ].filter(Boolean);
    return aliases.some(alias => normalized.includes(normalizeBotSearchText(alias)));
  }) || null;
}

function aiAccountTypeStatusLine(offer = {}) {
  if (offer.slots <= 0) return '❌ Out of stock';
  if (offer.id === 'private') return `📦 Slots: ${offer.slots} remaining`;
  return `📦 In Stock (${offer.slots} ready)`;
}

function buildAIAvailabilityMenu(category = '') {
  const planOptions = getBotPlanOptions(category, { includeUnavailable: true });
  if (!planOptions.length) {
    return `📦 *Availability*\n\nAbhi AI tools availability configured nahi hai.`;
  }
  const lines = planOptions.slice(0, 8).map(({ plan }) => {
    if (!isPlanAvailableForWhatsApp(plan)) {
      return `${botPlanEmoji(plan)} *${plan.name || 'Plan'}*\n❌ *Not Available*\n🔔 Reply *notify me* to save alert for this plan.`;
    }
    const offers = getAIPlanAccountTypeOffers(plan)
      .map(offer => `${offer.available ? '✅' : '❌'} ${offer.label} - *Rs.${Number(offer.price || 0).toLocaleString()}*${offer.limited ? ' (Limited Time!)' : ''}\n${aiAccountTypeStatusLine(offer)}\n${offer.summary}`)
      .join('\n\n');
    return `${botPlanEmoji(plan)} *${plan.name || 'Plan'}*\n${offers}`;
  });
  return `📦 *AI Tools Availability*\n\n${lines.join('\n\n━━━━━━━━━━━━━━━━━━━━\n\n')}\n\nTool ya plan name bhej dein for exact order help.`;
}

