function parseIlmDanishGender(text = '') {
  const raw = String(text || '').toLowerCase();
  if (/\b(boy|male|bacha|beta|larka|ladka)\b/i.test(raw) || /لڑکا|بیٹا/i.test(String(text || ''))) return 'boy';
  if (/\b(girl|female|bachi|beti|larki|ladki)\b/i.test(raw) || /لڑکی|بیٹی/i.test(String(text || ''))) return 'girl';
  return null;
}

function parseIlmDanishDate(text = '') {
  const raw = String(text || '').replace(/x/gi, '0').trim();
  const m = raw.match(/\b(\d{1,2})[\/\-. ](\d{1,2})[\/\-. ](\d{2,4})\b/);
  if (m) {
    let year = Number(m[3]);
    if (year < 100) year += 2000;
    const d = new Date(year, Number(m[2]) - 1, Number(m[1]));
    if (!Number.isNaN(d.getTime())) return d;
  }
  const y = raw.match(/\b(20\d{2}|19\d{2})\b/);
  if (y) {
    const d = new Date(Number(y[1]), 5, 15);
    if (!Number.isNaN(d.getTime())) return d;
  }
  return null;
}

function ageOnReferenceDate(birthDate, refDate) {
  let age = refDate.getFullYear() - birthDate.getFullYear();
  const m = refDate.getMonth() - birthDate.getMonth();
  if (m < 0 || (m === 0 && refDate.getDate() < birthDate.getDate())) age -= 1;
  return age;
}

