function buildIlmDanishAgeResult(date, gender) {
  const cutoff = new Date(2027, 2, 31);
  const ageCutoff = ageOnReferenceDate(date, cutoff);
  const ageNow = ageOnReferenceDate(date, new Date());
  const maxAge = gender === 'girl' ? 13 : 12;
  const eligible = ageCutoff >= 10 && ageCutoff <= maxAge;
  if (eligible) {
    return withIlmDanishFooter(`✅ *Eligible hai!*

Current age: *${ageNow} years*
31 March 2027 par age: *${ageCutoff} years*
Allowed range: *10-${maxAge} years*

Next:
1️⃣ Admission Form Urdu PDF
5️⃣ Admission form instructions
4️⃣ Guide book details`);
  }
  const reason = ageCutoff < 10 ? 'abhi age kam hai' : 'age limit se zyada hai';
  return withIlmDanishFooter(`⚠️ *Eligible nahi lag raha*

31 March 2027 par age: *${ageCutoff} years*
Allowed range: *10-${maxAge} years*
Reason: ${reason}

Final confirmation ke liye admin se rabta karein:
*03151725388*`);
}

function buildIlmDanishReplyForSelection(text = '', conv = {}) {
  const lower = String(text || '').toLowerCase().trim();
  if (lower === '5' || /\b(instruction|instructions|how to fill|fill form|form guide)\b/i.test(lower) || /ہدایات|طریقہ/i.test(String(text || ''))) {
    return { reply: buildIlmDanishAdmissionInstructions(), mediaAssets: ILM_DANISH_MEDIA.admissionForm, state: 'ilm_danish_menu' };
  }
  if (lower === '1' || isIlmDanishFormIntent(text)) {
    return { reply: buildIlmDanishAdmissionForm(), mediaAssets: ILM_DANISH_MEDIA.admissionForm, state: 'ilm_danish_menu' };
  }
  if (lower === '2' || isIlmDanishSchoolIntent(text)) {
    return { reply: buildIlmDanishSchoolIntro(), mediaAssets: ILM_DANISH_MEDIA.schoolIntro, state: 'ilm_danish_menu' };
  }
  if (lower === '6' || /\b(order|buy|price|delivery|book lena|kitab chahiye)\b/i.test(lower)) {
    return { reply: buildIlmDanishBookOrder(), mediaAssets: ILM_DANISH_MEDIA.bookIntro, state: 'ilm_danish_menu' };
  }
  if (lower === '4' || isIlmDanishBookIntent(text)) {
    return { reply: buildIlmDanishBookIntro(), mediaAssets: ILM_DANISH_MEDIA.bookIntro, state: 'ilm_danish_menu' };
  }
  if (lower === '3' || /\b(age|umar|eligib|birth|dob)\b/i.test(lower) || /عمر|پیدائش/i.test(String(text || ''))) {
    return { reply: buildIlmDanishAgeStart(), state: 'ilm_danish_age_gender', data: { ...(conv.botData || {}) } };
  }
  if (lower === '7' || /\b(contact|admin|help|phone|number)\b/i.test(lower)) {
    return { reply: buildIlmDanishContact(), state: 'ilm_danish_menu' };
  }
  return { reply: buildIlmDanishMenu(), state: 'ilm_danish_menu' };
}

function firstReplyLine(reply = '') {
  return String(reply || '').split('\n').map(line => line.trim()).find(Boolean) || '';
}

const BOT_IDLE_FOLLOWUP_DELAY_MS = Number(process.env.BOT_IDLE_FOLLOWUP_DELAY_MS || 5 * 60 * 1000);

function latestConversationRoleTime(conv = {}, role = '') {
  let latest = 0;
  for (const item of (conv.history || [])) {
    if (role && item?.role !== role) continue;
    const ts = Date.parse(item?.time || item?.createdAt || 0);
    if (Number.isFinite(ts) && ts > latest) latest = ts;
  }
  return latest;
}

function clearBotIdleFollowup(conv = {}, reason = 'cleared') {
  if (!conv.botData?.idleFollowup) return;
  conv.botData = {
    ...(conv.botData || {}),
    idleFollowup: {
      ...(conv.botData.idleFollowup || {}),
      cancelledAt: new Date().toISOString(),
      cancelReason: reason,
      sent: true
    }
  };
}

function scheduleBotIdleFollowup(conv = {}, details = {}) {
  if (!details.bot || !details.section) return;
  const now = new Date();
  const lastUserAt = latestConversationRoleTime(conv, 'user') || Date.now();
  conv.botData = {
    ...(conv.botData || {}),
    idleFollowup: {
      bot: details.bot,
      section: details.section,
      title: details.title || details.section,
      message: details.message || '',
      scheduledAt: now.toISOString(),
      dueAt: new Date(now.getTime() + Math.max(60 * 1000, BOT_IDLE_FOLLOWUP_DELAY_MS)).toISOString(),
      lastUserAt: new Date(lastUserAt).toISOString(),
      sent: false
    }
  };
}

