function detectIlmDanishIdleFollowup(reply = '', state = '', mediaAssets = []) {
  const text = String(Array.isArray(reply) ? reply.join('\n') : reply || '').toLowerCase();
  const assetText = (mediaAssets || []).map(asset => `${asset?.source || ''} ${asset?.caption || ''}`).join(' ').toLowerCase();
  if (state === 'ilm_danish_age_gender') return { bot: 'ilm_danish', section: 'age', title: 'Age calculator', message: buildIlmDanishIdleFollowupMessage('age') };
  if (state === 'ilm_danish_age_dob') return { bot: 'ilm_danish', section: 'age_dob', title: 'Age DOB', message: buildIlmDanishIdleFollowupMessage('age_dob') };
  if (text.includes('eligible hai') || text.includes('eligible nahi')) {
    return { bot: 'ilm_danish', section: 'age_result', title: 'Age result', message: buildIlmDanishIdleFollowupMessage('age_result') };
  }
  if (text.includes('guide book order')) {
    return { bot: 'ilm_danish', section: 'book_order', title: 'Guide book order', message: buildIlmDanishIdleFollowupMessage('book_order') };
  }
  if (text.includes('admission guide book') || assetText.includes('book-')) {
    return { bot: 'ilm_danish', section: 'book', title: 'Guide book', message: buildIlmDanishIdleFollowupMessage('book') };
  }
  if (text.includes('admission form instructions')) {
    return { bot: 'ilm_danish', section: 'form_instructions', title: 'Form instructions', message: buildIlmDanishIdleFollowupMessage('form_instructions') };
  }
  if (text.includes('admission form urdu pdf') || assetText.includes('annex-e1')) {
    return { bot: 'ilm_danish', section: 'form', title: 'Admission form', message: buildIlmDanishIdleFollowupMessage('form') };
  }
  if (text.includes('daanish school boys hasilpur') || assetText.includes('school-')) {
    return { bot: 'ilm_danish', section: 'school', title: 'School intro', message: buildIlmDanishIdleFollowupMessage('school') };
  }
  if (text.includes('ilm o danish contact')) {
    return { bot: 'ilm_danish', section: 'contact', title: 'Contact', message: buildIlmDanishIdleFollowupMessage('contact') };
  }
  return null;
}

function updateIdleFollowupForReply(conv = {}, reply = '', mediaAssets = []) {
  const state = conv.botState || '';
  if (isIlmDanishState(state)) {
    const followup = detectIlmDanishIdleFollowup(reply, state, mediaAssets);
    if (followup) scheduleBotIdleFollowup(conv, followup);
  }
}

function ilmDanishAssetFilePath(source = '') {
  const value = String(source || '').trim();
  if (value.startsWith('/assets/')) return path.join(__dirname, 'public', value.replace(/^\/+/, ''));
  if (value.startsWith('/uploads/')) return path.join(__dirname, value.replace(/^\/+/, ''));
  if (!value.startsWith('/') && !value.includes('://')) return path.join(__dirname, value);
  return '';
}

function validateIlmDanishAssets() {
  const assets = [];
  for (const [group, groupAssets] of Object.entries(ILM_DANISH_MEDIA || {})) {
    for (const asset of groupAssets || []) {
      const filePath = ilmDanishAssetFilePath(asset.source);
      const exists = !!filePath && fs.existsSync(filePath);
      const size = exists ? fs.statSync(filePath).size : 0;
      assets.push({
        group,
        source: asset.source,
        caption: asset.caption || '',
        exists,
        size,
        mimetype: guessMimeType(asset.source || filePath)
      });
    }
  }
  return assets;
}

function runIlmDanishDiagnostics() {
  const routeChecks = [
    { input: '1', expect: 'Admission Form Urdu PDF' },
    { input: '2', expect: 'Daanish School Boys Hasilpur' },
    { input: '3', expect: 'Age Eligibility Check' },
    { input: '4', expect: 'Admission Guide Book' },
    { input: '5', expect: 'Admission Form Instructions' },
    { input: '6', expect: 'Guide Book Order' },
    { input: '7', expect: 'Ilm o Danish Contact' },
    { input: 'form', expect: 'Admission Form Urdu PDF' },
    { input: 'admission form', expect: 'Admission Form Urdu PDF' },
    { input: 'form instructions', expect: 'Admission Form Instructions' },
    { input: 'book', expect: 'Admission Guide Book' },
    { input: 'order book', expect: 'Guide Book Order' },
    { input: 'school intro', expect: 'Daanish School Boys Hasilpur' }
  ].map(check => {
    const result = buildIlmDanishReplyForSelection(check.input, { botData: {} });
    const first = firstReplyLine(result.reply);
    return {
      input: check.input,
      expected: check.expect,
      firstLine: first,
      state: result.state || '',
      mediaCount: Number(result.mediaAssets?.length || 0),
      ok: first.toLowerCase().includes(check.expect.toLowerCase())
    };
  });
  const assets = validateIlmDanishAssets();
  return {
    ok: routeChecks.every(item => item.ok) && assets.every(item => item.exists && item.size > 0),
    menuFirstLine: firstReplyLine(buildIlmDanishMenu()),
    siteUrl: ILM_DANISH_SITE_URL,
    routes: routeChecks,
    assets
  };
}

