function normalizePlanSearchText(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\b(order|buy|but|purchase|book|reserve|checkout|confirm|final|please|plz|mujhe|mjy|muje|chahiye|lena|hai|do|de|kr|kar|karo|activate|setup)\b/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function isPlanOrderIntent(text) {
  const raw = String(text || '').trim();
  const lower = raw.toLowerCase();
  return isOrderIntent(raw) ||
    /\bbut\s+(chatgpt|claude|perplexity|gemini|canva|kimi|turnitin|bundle|plan)\b/i.test(lower) ||
    /(activate|setup|de do|day do|kr do|kar do|chalu kar|plan chahiye|subscription chahiye)/i.test(lower);
}

function findAIPlanForOrder(text, category = '', conv = {}) {
  const scoped = getBotPlanOptions(category, { includeUnavailable: true });
  const all = getBotPlanOptions('', { includeUnavailable: true });
  const baseOptions = scoped.length ? scoped : all;
  const requestedAccess = isChatGPTCategory(category)
    ? (conv?.botData?.chatGPTAccessMode || chatGPTAccessModeFromText(text))
    : '';
  const options = filterChatGPTPlanOptionsByAccess(baseOptions, requestedAccess);
  const directNumber = String(text || '').trim();
  const byMenuNumber = /^[1-9]$/.test(directNumber)
    ? options.find(item => item.id === directNumber)?.plan
    : null;
  if (byMenuNumber) return byMenuNumber;

  const lastPlanId = conv.botData?.lastSelectedPlanId;
  const lastPlan = lastPlanId ? all.find(item => String(item.plan.id) === String(lastPlanId))?.plan : null;
  const query = normalizePlanSearchText(text);
  if (!query && lastPlan) return lastPlan;

  const words = query.split(' ').filter(word => word.length > 1);
  let best = null;
  let bestScore = 0;
  for (const { plan } of all) {
    const haystack = normalizePlanSearchText([
      plan.id,
      plan.name,
      plan.category,
      plan.label,
      plan.duration,
      ...(planFeatures(plan) || [])
    ].join(' '));
    let score = 0;
    for (const word of words) {
      if (haystack.includes(word)) score += word.length >= 4 ? 2 : 1;
    }
    if (query && haystack.includes(query)) score += 6;
    if (category && inferBotPlanCategory(plan) === category) score += 1;
    if (lastPlan && String(plan.id) === String(lastPlan.id)) score += 2;
    if (score > bestScore) {
      bestScore = score;
      best = plan;
    }
  }
  if (bestScore >= 2) return best;
  return lastPlan || null;
}

function getOrCreateOrderCustomer(number, name) {
  const cleanNumber = normalizeNumber(number || '') || String(number || '').trim();
  let cust = customers.find(c => normalizeNumber(c.number) === normalizeNumber(cleanNumber) || c.number === cleanNumber);
  if (!cust) {
    cust = {
      id: uuid(),
      name: customerFirstName(name, 'Customer'),
      number: cleanNumber,
      status: 'lead',
      tags: ['New', 'AI Tools Lead'],
      messageCount: 0,
      lastActive: new Date().toISOString(),
      buyerIntent: 'HOT'
    };
    customers.push(cust);
  } else {
    cust.status = cust.status || 'lead';
    cust.tags = [...new Set([...(cust.tags || []), 'AI Tools Lead', 'Hot Lead'])];
    cust.buyerIntent = 'HOT';
    cust.lastActive = new Date().toISOString();
  }
  saveJSON('customers.json', customers);
  return cust;
}

function createAIPlanOrder(number, name, plan, rawMessage, accountOffer = null) {
  const cust = getOrCreateOrderCustomer(number, name);
  const offer = accountOffer || getAIPlanAccountTypeOffers(plan)[0];
  const price = Number(offer?.price || plan?.price || 0);
  const item = {
    name: plan?.name || 'AI Tools Plan',
    planId: plan?.id || null,
    category: inferBotPlanCategory(plan),
    duration: plan?.label || plan?.duration || '',
    price,
    accountType: offer?.id || 'private',
    accountTypeLabel: offer?.label || 'Private Account',
    accountTypePolicy: offer?.policy || '',
    limitedTime: !!offer?.limited,
    slotsAtOrder: Number(offer?.slots || 0),
    qty: 1,
    type: 'ai_plan'
  };
  const now = new Date().toISOString();
  const order = {
    id: uuid(),
    orderNumber: generateOrderNumber(),
    customerId: cust.id,
    customerNumber: cust.number,
    customerName: cust.name,
    items: [item],
    total: price,
    notes: `WhatsApp bot order request: ${rawMessage || 'Order requested'}\nAccount type: ${item.accountTypeLabel}\nPolicy: ${item.accountTypePolicy}`,
    deliveryAddress: '',
    status: 'pending',
    source: 'whatsapp_bot',
    kind: 'ai_plan',
    statusHistory: [{ status: 'pending', time: now, note: 'AI plan order created by bot' }],
    aiMeta: {
      accountType: item.accountType,
      accountTypeLabel: item.accountTypeLabel,
      policy: item.accountTypePolicy,
      warrantyIssuesResolved: 0,
      warrantyReplacementsUsed: 0
    },
    trackingNumber: null,
    deliveryEta: null,
    cancelReason: null,
    created: now,
    updated: now
  };
  orders.push(order);
  saveJSON('orders.json', orders);
  cust.totalOrders = (cust.totalOrders || 0) + 1;
  cust.totalSpent = (cust.totalSpent || 0) + price;
  cust.lastOrderDate = now;
  saveJSON('customers.json', customers);
  io.emit('new_order', order);
  n8nBridge.triggerOrderCreated({
    orderId: order.orderNumber,
    sourceOrderId: order.id,
    customerId: cust.id,
    customerNumber: cust.number,
    customerName: cust.name,
    total: Number(order.total || 0),
    status: order.status,
    source: order.source,
    createdAt: order.created,
    rawMessage: rawMessage || '',
    item
  }, {
    channel: 'supersender_ai_tools',
    stage: 'order_created'
  }).catch(() => {});
  return order;
}

