async function notifyAIPlanOrderToAdmin(order, plan, customerNumber, customerName, rawMessage) {
  const admin = orderAdminNumber();
  const cleanCustomer = normalizeNumber(customerNumber || '');
  if (!admin || admin === cleanCustomer || /^(test|bot-sim|codex)/i.test(String(customerNumber || ''))) return false;
  try {
    await sendDirect(admin, formatAIPlanAdminAlert(order, plan, customerNumber, customerName, rawMessage));
    return true;
  } catch (error) {
    console.warn('AI plan order admin notify failed:', error.message);
    return false;
  }
}

function sourcingRequestCode() {
  return `SRC-${new Date().toISOString().slice(2, 10).replace(/-/g, '')}-${Math.random().toString(36).slice(2, 6).toUpperCase()}`;
}

function normalizeSourcingGroupId(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return '';
  if (raw.includes('@')) return raw;
  const digits = raw.replace(/\D/g, '');
  return digits ? `${digits}@g.us` : raw;
}

function getAllowedSourcingGroups() {
  const configured = Array.isArray(settings.auto_stock_sourcing_group_ids)
    ? settings.auto_stock_sourcing_group_ids
    : [];
  const envGroups = String(process.env.AUTO_STOCK_SOURCING_GROUPS || process.env.SELLING_GROUPS || '').split(',').map(x => x.trim()).filter(Boolean);
  return [...new Set([...configured, ...envGroups].map(normalizeSourcingGroupId).filter(Boolean))];
}

function sourcingPlanKeywords(plan = {}) {
  return normalizeBotSearchText([
    plan.name,
    plan.category,
    inferBotPlanCategory(plan),
    ...(planFeatures(plan) || [])
  ].filter(Boolean).join(' ')).split(/\s+/).filter(Boolean);
}

function sourcingTextMatchesPlan(text = '', plan = {}) {
  const normalized = normalizeBotSearchText(text);
  if (!normalized || !plan) return false;
  const nameWords = normalizeBotSearchText(plan.name || '').split(/\s+/).filter(Boolean);
  if (nameWords.length && nameWords.every(word => normalized.includes(word))) return true;
  const category = normalizeBotSearchText(inferBotPlanCategory(plan));
  if (category && normalized.includes(category)) return true;
  const important = sourcingPlanKeywords(plan).filter(word => word.length >= 3);
  return important.some(word => normalized.includes(word));
}

function activeStockSourcingRequests() {
  const ttlMs = Number(settings.auto_stock_sourcing_timeout_minutes || 120) * 60 * 1000;
  const now = Date.now();
  return (stockSourcingRequests || []).filter(req =>
    ['searching', 'offer_found', 'dealer_contacted'].includes(req.status) &&
    (!req.createdAt || now - new Date(req.createdAt).getTime() <= ttlMs)
  );
}

function findStockSourcingByCode(text = '') {
  const match = String(text || '').match(/\bSRC-[A-Z0-9-]+\b/i);
  if (!match) return null;
  const code = match[0].toUpperCase();
  return stockSourcingRequests.find(req => String(req.code || '').toUpperCase() === code) || null;
}

function formatDealerSourcingGroupAsk(req = {}) {
  return `ðŸ”Ž *Stock Required*

Code: *${req.code}*
Tool/Plan: *${req.planName}*
Type: *${req.accountTypeLabel || req.accountType || 'Any'}*
Client needs it now.

Dealer bhai agar available ho to isi group mein reply karein:
*AVAILABLE ${req.code}*
Price: Rs [amount]
Warranty: [yes/no + policy]
Delivery: [time]
Details: [account/private/key]`;
}

function formatCustomerWaitForSourcing(req = {}) {
  return `â³ *Please wait*

${req.planName} ka selected type abhi stock mein ready nahi mila.
Main dealer groups mein availability check kar raha hoon.

Request: *${req.code}*
Jaise hi best price/warranty confirm hoti hai, main yahin update kar dunga.`;
}

