function parseSourcingOfferText(text = '') {
  const raw = String(text || '');
  const withoutRequestCode = raw.replace(/\bSRC-[A-Z0-9-]+\b/gi, ' ');
  const lower = raw.toLowerCase();
  if (/\b(not available|not avail|nahi|nahin|no stock|out of stock|sold)\b/i.test(lower)) return null;
  const hasAvailability = /\b(available|avail|stock|yes|hai|hy|ha|mil jayega|mil jaega|ready)\b/i.test(lower);
  const priceMatch = withoutRequestCode.match(/(?:rs\.?|pkr|price|rate)\s*[:=-]?\s*([0-9]{3,6})(?!\d)/i)
    || withoutRequestCode.match(/\b([0-9]{3,6})(?!\d)\b/i);
  if (!hasAvailability && !priceMatch) return null;
  const warranty = /non[-\s]?warranty|no warranty|without warranty/i.test(lower)
    ? 'Non-warranty / no claim'
    : /warranty|replacement|replace|claim|support/i.test(lower)
      ? 'Warranty mentioned'
      : '';
  const deliveryMatch = raw.match(/(?:delivery|time|eta)\s*[:=-]?\s*([^\n|,]+)/i);
  return {
    price: priceMatch ? Number(priceMatch[1]) : null,
    warranty,
    delivery: deliveryMatch ? deliveryMatch[1].trim().slice(0, 120) : '',
    details: raw.replace(/\s+/g, ' ').trim().slice(0, 600)
  };
}

async function broadcastStockSourcingToGroups(req = {}) {
  const groups = req.groups || getAllowedSourcingGroups();
  const msg = formatDealerSourcingGroupAsk(req);
  const results = [];
  for (const groupId of groups) {
    try {
      await sendDirect(groupId, msg, { useRotation: true });
      results.push({ groupId, success: true });
      await sleep(1500);
    } catch (error) {
      results.push({ groupId, success: false, error: error.message });
      console.warn('[StockSourcing] Group ask failed:', groupId, error.message);
    }
  }
  req.broadcastResults = results;
  req.updatedAt = new Date().toISOString();
  saveStockSourcingRequests();
  return results;
}

async function startStockSourcingRequest({ customerNumber, customerName, customerText, plan, offer }) {
  if (settings.auto_stock_sourcing_enabled === false) return null;
  const groups = getAllowedSourcingGroups();
  if (!groups.length) return null;
  const existing = activeStockSourcingRequests().find(req =>
    normalizeNumber(req.customerNumber) === normalizeNumber(customerNumber) &&
    String(req.planId || '') === String(plan?.id || '') &&
    String(req.accountType || '') === String(offer?.id || '')
  );
  if (existing) return existing;
  const req = {
    id: uuid(),
    code: sourcingRequestCode(),
    status: 'searching',
    customerNumber: normalizeNumber(customerNumber || '') || String(customerNumber || ''),
    customerName: customerFirstName(customerName, 'Customer'),
    customerText: customerText || '',
    planId: plan?.id || '',
    planName: plan?.name || 'AI Tools Plan',
    category: inferBotPlanCategory(plan || {}),
    accountType: offer?.id || '',
    accountTypeLabel: offer?.label || '',
    policy: offer?.policy || '',
    requestedSlots: 1,
    groups,
    offers: [],
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  stockSourcingRequests.unshift(req);
  if (stockSourcingRequests.length > 1000) stockSourcingRequests = stockSourcingRequests.slice(0, 1000);
  saveStockSourcingRequests();
  setImmediate(async () => {
    try { await broadcastStockSourcingToGroups(req); } catch (error) { console.warn('[StockSourcing] Broadcast failed:', error.message); }
    try {
      const admin = orderAdminNumber();
      if (admin) await sendDirect(admin, formatStockSourcingAdminAlert(req));
    } catch (error) {
      console.warn('[StockSourcing] Admin alert failed:', error.message);
    }
  });
  io.emit('stock_sourcing:new', req);
  return req;
}

async function contactSourcingDealer(req = {}, offer = {}) {
  const dealerNumber = normalizeNumber(offer.dealerNumber || '');
  if (!dealerNumber) return false;
  const msg = `Assalam o Alaikum!

*${req.planName}* stock ke liye request hai.
Code: *${req.code}*
Type: *${req.accountTypeLabel || req.accountType || 'Any'}*

Please confirm:
1. Final price
2. Warranty/replacement policy
3. Delivery time
4. Account/key details type

Reply with code *${req.code}* so system attach kar sake.`;
  try {
    await sendDirect(dealerNumber, msg, { useRotation: true });
    offer.dealerContactedAt = new Date().toISOString();
    req.status = 'dealer_contacted';
    req.updatedAt = new Date().toISOString();
    saveStockSourcingRequests();
    return true;
  } catch (error) {
    offer.dealerContactError = error.message;
    saveStockSourcingRequests();
    return false;
  }
}

async function handleStockSourcingGroupOffer(ctx = {}) {
  if (settings.auto_stock_sourcing_enabled === false) return [];
  const text = String(ctx.body || '').trim();
  if (!text) return [];
  const byCode = findStockSourcingByCode(text);
  const candidates = byCode
    ? [byCode]
    : activeStockSourcingRequests().filter(req => {
        const groupOk = !req.groups?.length || req.groups.map(normalizeSourcingGroupId).includes(normalizeSourcingGroupId(ctx.groupId || ''));
        const plan = plans.find(p => String(p.id) === String(req.planId));
        return groupOk && sourcingTextMatchesPlan(text, plan || { name: req.planName, category: req.category });
      });
  if (!candidates.length) return [];
  const parsed = parseSourcingOfferText(text);
  if (!parsed) return [];
  const saved = [];
  for (const req of candidates) {
    const duplicate = (req.offers || []).some(o =>
      normalizeNumber(o.dealerNumber) === normalizeNumber(ctx.authorNumber || ctx.from || '') &&
      String(o.rawMessage || '').trim() === text
    );
    if (duplicate) continue;
    const offer = {
      id: uuid(),
      dealerNumber: normalizeNumber(ctx.authorNumber || ctx.from || '') || ctx.authorNumber || ctx.from || '',
      dealerName: ctx.authorName || ctx.senderName || 'Dealer',
      groupId: ctx.groupId || '',
      groupName: ctx.groupName || '',
      rawMessage: text,
      receivedAt: new Date().toISOString(),
      price: parsed.price,
      warranty: parsed.warranty,
      delivery: parsed.delivery,
      details: parsed.details,
      status: 'pending_admin'
    };
    req.offers = Array.isArray(req.offers) ? req.offers : [];
    req.offers.unshift(offer);
    req.status = 'offer_found';
    req.updatedAt = new Date().toISOString();
    saved.push({ req, offer });
    setImmediate(async () => {
      await contactSourcingDealer(req, offer);
      try {
        const admin = orderAdminNumber();
        if (admin) await sendDirect(admin, formatStockSourcingAdminAlert(req, offer));
      } catch (error) {
        console.warn('[StockSourcing] Offer admin alert failed:', error.message);
      }
    });
  }
  if (saved.length) {
    saveStockSourcingRequests();
    io.emit('stock_sourcing:offer', saved.map(x => ({ request: x.req, offer: x.offer })));
  }
  return saved;
}

function reserveSourcedStock(req = {}, offer = {}) {
  const plan = plans.find(p => String(p.id) === String(req.planId));
  if (!plan) return null;
  const type = req.accountType || 'private';
  plan.stock = plan.stock && typeof plan.stock === 'object' ? plan.stock : {};
  plan.stock[type] = Math.max(0, Number(plan.stock[type] || 0)) + 1;
  plan.sourcedStockHistory = Array.isArray(plan.sourcedStockHistory) ? plan.sourcedStockHistory : [];
  plan.sourcedStockHistory.unshift({
    requestCode: req.code,
    dealerNumber: offer.dealerNumber || '',
    dealerName: offer.dealerName || '',
    price: offer.price || null,
    warranty: offer.warranty || '',
    details: offer.details || '',
    addedAt: new Date().toISOString()
  });
  saveJSON('plans.json', plans);
  return plan;
}

async function approveStockSourcing(req = {}) {
  const offer = (req.offers || []).find(o => o.status !== 'rejected') || null;
  if (!offer) return `No dealer offer found yet for *${req.code}*`;
  offer.status = 'approved';
  req.status = 'approved';
  req.approvedOfferId = offer.id;
  req.approvedAt = new Date().toISOString();
  req.updatedAt = new Date().toISOString();
  const updatedPlan = reserveSourcedStock(req, offer);
  saveStockSourcingRequests();
  const customerMsg = `âœ… *Stock Available*

Good news! *${req.planName}* ka stock arrange ho gaya hai.
Type: *${req.accountTypeLabel || req.accountType || 'Account'}*
${offer.price ? `Dealer rate: Rs.${Number(offer.price).toLocaleString()}\n` : ''}${offer.warranty ? `Warranty: ${offer.warranty}\n` : ''}${offer.delivery ? `Delivery: ${offer.delivery}\n` : ''}

Agar order proceed karna hai to *CONFIRM* reply karein.`;
  const dealerMsg = `âœ… Admin approved *${req.code}*.
Please reserve *${req.planName}* (${req.accountTypeLabel || req.accountType || 'account'}).
Customer will confirm/payment next.`;
  try { await sendDirect(req.customerNumber, customerMsg); } catch (error) { console.warn('[StockSourcing] Customer notify failed:', error.message); }
  try { if (offer.dealerNumber) await sendDirect(offer.dealerNumber, dealerMsg); } catch (error) { console.warn('[StockSourcing] Dealer approve notify failed:', error.message); }
  return `âœ… Approved *${req.code}*.
Stock updated: ${updatedPlan?.name || req.planName} / ${req.accountTypeLabel || req.accountType}.
Customer and dealer notified.`;
}

async function rejectStockSourcing(req = {}) {
  req.status = 'rejected';
  req.rejectedAt = new Date().toISOString();
  req.updatedAt = new Date().toISOString();
  for (const offer of req.offers || []) {
    if (offer.status !== 'approved') offer.status = 'rejected';
  }
  saveStockSourcingRequests();
  try {
    await sendDirect(req.customerNumber, `â³ *Update*

${req.planName} ke liye abhi best verified stock confirm nahi hua.
Main search continue kar raha hoon. Agar alternate plan chahiye ho to *AI Tools* reply karein.`);
  } catch {}
  return `âŒ Rejected *${req.code}*. Customer ko wait/update message bhej diya.`;
}

async function handleStockSourcingAdminOrDealerReply(number, body, name) {
  const text = String(body || '').trim();
  const req = findStockSourcingByCode(text);
  if (!req) return null;
  const admin = normalizeNumber(orderAdminNumber());
  const sender = normalizeNumber(number || '');
  const decision = text.match(/^\s*(yes|approve|ok|no|reject)\b/i)?.[1]?.toLowerCase();
  if (sender && admin && sender === admin && decision) {
    return /^(yes|approve|ok)$/i.test(decision)
      ? await approveStockSourcing(req)
      : await rejectStockSourcing(req);
  }
  const offer = (req.offers || []).find(o => normalizeNumber(o.dealerNumber) === sender);
  if (!offer) return null;
  const parsed = parseSourcingOfferText(text) || { details: text };
  offer.price = parsed.price || offer.price || null;
  offer.warranty = parsed.warranty || offer.warranty || '';
  offer.delivery = parsed.delivery || offer.delivery || '';
  offer.details = parsed.details || text;
  offer.dealerName = offer.dealerName || name || 'Dealer';
  offer.privateReplyAt = new Date().toISOString();
  req.status = 'offer_found';
  req.updatedAt = new Date().toISOString();
  saveStockSourcingRequests();
  try {
    const adminNumber = orderAdminNumber();
    if (adminNumber) await sendDirect(adminNumber, formatStockSourcingAdminAlert(req, offer));
  } catch {}
  return `Thanks! Details attach ho gayi hain for *${req.code}*. Admin approval ke baad confirm kar denge.`;
}

