function isRenewedAIPlanOrder(order = {}) {
  const currentTime = Date.parse(order.created || order.updated || 0);
  const currentItem = Array.isArray(order.items) ? order.items[0] : {};
  return orders.some(other => {
    if (!other || other.id === order.id || String(other.kind || '') !== 'ai_plan') return false;
    if (normalizeNumber(other.customerNumber || '') !== normalizeNumber(order.customerNumber || '')) return false;
    if (Date.parse(other.created || other.updated || 0) <= currentTime) return false;
    if (/cancelled|canceled/i.test(String(other.status || ''))) return false;
    const otherItem = Array.isArray(other.items) ? other.items[0] : {};
    return normalizeBotSearchText(otherItem?.name || '') === normalizeBotSearchText(currentItem?.name || '');
  });
}

