function studentWebsiteConfig() {
  return {
    enabled: settings.student_website_bot_enabled !== false,
    name: String(settings.student_website_name || process.env.STUDENT_WEBSITE_NAME || 'Student Website Bot').trim(),
    baseUrl: String(settings.student_website_base_url || process.env.STUDENT_WEBSITE_BASE_URL || '').trim(),
    lookupUrl: String(settings.student_website_lookup_url || process.env.STUDENT_WEBSITE_LOOKUP_URL || '').trim(),
    apiKey: String(settings.student_website_api_key || process.env.STUDENT_WEBSITE_API_KEY || '').trim(),
    allowUserUrls: settings.student_website_allow_user_urls !== false,
    allowPrivateUrls: settings.student_website_allow_private_urls === true
  };
}

function isStudentWebsiteIntent(text = '') {
  return /\b(student\s*(website|portal|bot|data|record)|roll\s*(no|number)?|result|marks?|admission\s*(status|record)?|notice|notices|attendance|fee\s*(status)?|student\s*lookup)\b/i.test(String(text || ''));
}

function extractUrlFromText(text = '') {
  const match = String(text || '').match(/https?:\/\/[^\s<>"')]+/i);
  return match ? match[0].replace(/[.,;!?]+$/g, '') : '';
}

function isPrivateHost(hostname = '') {
  const host = String(hostname || '').toLowerCase();
  if (!host) return true;
  if (host === 'localhost' || host.endsWith('.local')) return true;
  if (/^(127\.|10\.|0\.0\.0\.0|169\.254\.)/.test(host)) return true;
  if (/^192\.168\./.test(host)) return true;
  const private172 = host.match(/^172\.(\d{1,2})\./);
  if (private172 && Number(private172[1]) >= 16 && Number(private172[1]) <= 31) return true;
  if (host === '::1' || host === '[::1]') return true;
  return false;
}

function safeStudentUrl(rawUrl = '', config = studentWebsiteConfig()) {
  try {
    const url = new URL(String(rawUrl || '').trim());
    if (!['http:', 'https:'].includes(url.protocol)) return { ok: false, error: 'Only http/https URLs allowed.' };
    if (!config.allowPrivateUrls && isPrivateHost(url.hostname)) {
      return { ok: false, error: 'Private/local URL blocked for safety. Enable student_website_allow_private_urls only for trusted local use.' };
    }
    return { ok: true, url: url.toString() };
  } catch {
    return { ok: false, error: 'Invalid URL.' };
  }
}

function extractStudentLookupQuery(text = '') {
  const withoutUrl = String(text || '').replace(/https?:\/\/[^\s<>"')]+/ig, ' ');
  const explicit = withoutUrl.match(/\b(?:roll\s*(?:no|number)?|reg(?:istration)?|admission\s*no|student\s*id|id|name)\s*[:#-]?\s*([A-Za-z0-9._/\- ]{2,60})/i);
  if (explicit) return explicit[1].trim();
  const hyphenRoll = withoutUrl.match(/\b[A-Z]?\d{2,6}[-/]\d{2,8}[A-Z]?\b/i);
  if (hyphenRoll) return hyphenRoll[0].trim();
  const compact = withoutUrl.match(/\b[A-Z]?\d{3,12}[A-Z]?\b/i);
  if (compact) return compact[0].trim();
  return withoutUrl
    .replace(/\b(student|website|portal|bot|data|fetch|check|result|marks|roll|number|no|notice|attendance|fee|status|please|plz|mera|meri|my|ka|ki|ke)\b/ig, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 80);
}

function buildStudentLookupUrl(query = '', config = studentWebsiteConfig()) {
  const q = String(query || '').trim();
  const template = config.lookupUrl || '';
  if (template) {
    const encoded = encodeURIComponent(q);
    const filled = template
      .replace(/\{query\}/gi, encoded)
      .replace(/\{roll\}/gi, encoded)
      .replace(/\{q\}/gi, encoded)
      .replace(/\{name\}/gi, encoded);
    return filled.includes('{') ? template : filled;
  }
  if (config.baseUrl) {
    const url = new URL(config.baseUrl);
    if (q) url.searchParams.set('q', q);
    return url.toString();
  }
  return '';
}

function websiteTextFromHtml(html = '') {
  return decodeHtmlEntities(String(html || ''))
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<\/(tr|p|li|div|section|article|h[1-6])>/gi, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .split(/\r?\n/)
    .map(line => line.replace(/\s+/g, ' ').trim())
    .filter(Boolean)
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function summarizeJsonForWhatsApp(data, depth = 0) {
  if (data == null) return '';
  if (typeof data !== 'object') return String(data);
  if (Array.isArray(data)) {
    return data.slice(0, 5).map((item, index) => `${index + 1}. ${summarizeJsonForWhatsApp(item, depth + 1)}`).join('\n');
  }
  const preferred = ['name', 'studentName', 'roll', 'rollNo', 'rollNumber', 'class', 'status', 'result', 'marks', 'grade', 'attendance', 'feeStatus', 'message'];
  const keys = [...preferred.filter(key => Object.prototype.hasOwnProperty.call(data, key)), ...Object.keys(data).filter(key => !preferred.includes(key))].slice(0, depth ? 8 : 12);
  return keys.map(key => {
    const value = data[key];
    if (value && typeof value === 'object') return `${key}: ${summarizeJsonForWhatsApp(value, depth + 1)}`;
    return `${key}: ${String(value ?? '').slice(0, 180)}`;
  }).join('\n');
}

function relevantStudentTextSnippet(text = '', query = '') {
  const clean = String(text || '').replace(/\s+\n/g, '\n').trim();
  if (!query) return clean.slice(0, 1700);
  const lines = clean.split(/\r?\n/).map(line => line.trim()).filter(Boolean);
  const q = String(query || '').toLowerCase();
  const hit = lines.findIndex(line => line.toLowerCase().includes(q));
  if (hit >= 0) {
    return lines.slice(Math.max(0, hit - 3), hit + 8).join('\n').slice(0, 1700);
  }
  return clean.slice(0, 1700);
}

async function fetchStudentWebsiteData(rawUrl, query = '') {
  const config = studentWebsiteConfig();
  const safe = safeStudentUrl(rawUrl, config);
  if (!safe.ok) return { success: false, error: safe.error };
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), Math.max(3000, Number(process.env.STUDENT_WEBSITE_TIMEOUT_MS || 12000)));
  try {
    const headers = {
      'user-agent': 'SuperSenderPro-StudentBot/1.0',
      'accept': 'text/html,application/json;q=0.9,text/plain;q=0.8,*/*;q=0.5'
    };
    if (config.apiKey) headers.authorization = `Bearer ${config.apiKey}`;
    const response = await fetchOutbound(safe.url, { headers, signal: controller.signal });
    const contentType = response.headers.get('content-type') || '';
    const body = await response.text();
    if (!response.ok) return { success: false, status: response.status, error: `Website returned HTTP ${response.status}` };
    let summary = '';
    if (/json/i.test(contentType) || /^[\s\r\n]*[\[{]/.test(body)) {
      try {
        summary = summarizeJsonForWhatsApp(JSON.parse(body));
      } catch {
        summary = body.replace(/\s+/g, ' ').trim().slice(0, 1700);
      }
    } else {
      summary = relevantStudentTextSnippet(websiteTextFromHtml(body), query);
    }
    return {
      success: true,
      url: safe.url,
      contentType,
      summary: summary || 'Website data fetched, lekin readable text nahi mila.'
    };
  } catch (error) {
    return { success: false, error: error.name === 'AbortError' ? 'Website response timeout.' : error.message };
  } finally {
    clearTimeout(timeout);
  }
}

