function htmlAttrValue(tag = '', attr = '') {
  const re = new RegExp(`${attr}\\s*=\\s*["']([^"']*)["']`, 'i');
  return (String(tag || '').match(re) || [])[1] || '';
}

function parseHtmlInputs(html = '') {
  const fields = {};
  for (const match of String(html || '').matchAll(/<input\b[^>]*>/gi)) {
    const tag = match[0];
    const name = htmlAttrValue(tag, 'name') || htmlAttrValue(tag, 'id');
    if (!name) continue;
    fields[name] = htmlAttrValue(tag, 'value');
  }
  return fields;
}

function listHtmlFormFields(html = '') {
  const fields = [];
  const seen = new Set();
  const raw = String(html || '');
  const addField = (tag = '', type = '') => {
    const name = htmlAttrValue(tag, 'name');
    const id = htmlAttrValue(tag, 'id');
    const key = `${type}:${name}:${id}:${htmlAttrValue(tag, 'value')}`;
    if ((!name && !id) || seen.has(key)) return;
    seen.add(key);
    fields.push({
      tag: type,
      id,
      name,
      type: htmlAttrValue(tag, 'type') || type,
      value: htmlAttrValue(tag, 'value'),
      placeholder: htmlAttrValue(tag, 'placeholder'),
      text: stripHTML(tag).slice(0, 80)
    });
  };
  for (const match of raw.matchAll(/<input\b[^>]*>/gi)) addField(match[0], 'input');
  for (const match of raw.matchAll(/<select\b[^>]*>[\s\S]*?<\/select>/gi)) addField(match[0], 'select');
  for (const match of raw.matchAll(/<textarea\b[^>]*>[\s\S]*?<\/textarea>/gi)) addField(match[0], 'textarea');
  for (const match of raw.matchAll(/<button\b[^>]*>[\s\S]*?<\/button>/gi)) addField(match[0], 'button');
  return fields;
}

function extractHtmlTitle(html = '') {
  const match = String(html || '').match(/<title\b[^>]*>([\s\S]*?)<\/title>/i);
  return match ? stripHTML(match[1]) : '';
}

function scoreStudentField(field = {}, kind = 'roll') {
  const type = String(field.type || '').toLowerCase();
  if (type === 'hidden' && kind !== 'roll') return 0;
  const haystack = [
    field.id,
    field.name,
    field.type,
    field.value,
    field.placeholder,
    field.text
  ].map(item => String(item || '').toLowerCase()).join(' ');
  if (!haystack.trim()) return 0;
  const rules = {
    roll: [
      [/roll|rno|student.*no|admission|reg|registration|cnic|idno|studentid|student_id/i, 10],
      [/txt|input|number|search/i, 2]
    ],
    class: [
      [/class|grade|cls|studentclass|ddlclass|drpclass/i, 10],
      [/select|ddl|dropdown/i, 3]
    ],
    access: [
      [/access|password|pass|code|pin|secret|pwd/i, 12],
      [/input|text/i, 2]
    ],
    submit: [
      [/ibtn|login|imagebutton/i, 12],
      [/search|submit|find|show|view|result|btn|button|check/i, 10],
      [/submit|button/i, 4]
    ]
  };
  return (rules[kind] || []).reduce((sum, [re, points]) => sum + (re.test(haystack) ? points : 0), 0);
}

function listLikelyStudentFields(fields = []) {
  const rank = (kind) => fields
    .map(field => ({ ...field, score: scoreStudentField(field, kind) }))
    .filter(field => field.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 6);
  return {
    roll: rank('roll'),
    class: rank('class'),
    access: rank('access'),
    submit: rank('submit')
  };
}

function studentFieldKey(field = {}) {
  return String(field.name || field.id || '').trim();
}

function findHtmlFormField(html = '', key = '') {
  const wanted = String(key || '').trim();
  if (!wanted) return null;
  return listHtmlFormFields(html).find(field => field.name === wanted || field.id === wanted) || null;
}

function isSraEmptyParse(data = {}) {
  const profile = data.profile || {};
  const values = ['name', 'class', 'section', 'father', 'dob', 'phone', 'address'].map(key => String(profile[key] || '').trim().toUpperCase());
  const profileEmpty = values.every(value => !value || value === 'N/A');
  const attendanceEmpty = !Number(data.attendance?.total || 0);
  const resultEmpty = !Array.isArray(data.result?.subjects) || !data.result.subjects.length;
  return profileEmpty && attendanceEmpty && resultEmpty;
}

async function diagnoseSraPortal() {
  const cfg = studentSraConfig();
  const safe = safeStudentUrl(cfg.loginUrl, { ...studentWebsiteConfig(), allowPrivateUrls: settings.student_website_allow_private_urls === true });
  if (!safe.ok) return { ok: false, error: safe.error, url: cfg.loginUrl };
  try {
    const response = await fetchOutbound(safe.url, {
      headers: { 'user-agent': 'SuperSenderPro-SRA-Diagnostics/1.0', accept: 'text/html,*/*' }
    });
    const html = await response.text();
    const fields = listHtmlFormFields(html);
    const likely = listLikelyStudentFields(fields);
    return {
      ok: response.ok,
      status: response.status,
      url: safe.url,
      title: extractHtmlTitle(html),
      fields,
      likely,
      hiddenCount: fields.filter(field => String(field.type || '').toLowerCase() === 'hidden').length,
      formCount: (String(html || '').match(/<form\b/gi) || []).length,
      htmlLength: html.length,
      error: response.ok ? '' : `HTTP ${response.status}`
    };
  } catch (error) {
    return { ok: false, error: error.message || 'SRA diagnostics failed.', url: cfg.loginUrl };
  }
}

function formatSraDiagnosticsReply(diag = {}) {
  if (!diag.ok) {
    return `❌ *SRA Diagnose Failed*
URL: ${diag.url || studentSraConfig().loginUrl}
Error: ${diag.error || 'Unknown error'}`;
  }
  const fieldLine = (field) => {
    const key = studentFieldKey(field) || '-';
    const label = [field.tag, field.type].filter(Boolean).join('/');
    const value = field.value ? ` value=${field.value}` : '';
    return `• ${key} (${label})${value}`;
  };
  const roll = diag.likely?.roll?.[0];
  const classField = diag.likely?.class?.[0];
  const access = diag.likely?.access?.[0];
  const submit = diag.likely?.submit?.[0];
  const suggested = [
    `roll=${studentFieldKey(roll) || studentSraConfig().rollField}`,
    classField ? `class=${studentFieldKey(classField)}` : '',
    access ? `accessfield=${studentFieldKey(access)}` : '',
    access ? 'accesscode=YOUR_CODE' : '',
    `submit=${studentFieldKey(submit) || studentSraConfig().submitField}`,
    submit?.value ? `value=${submit.value}` : `value=${studentSraConfig().submitValue || 'Search'}`
  ].filter(Boolean).join(' ');
  const allFields = (diag.fields || [])
    .filter(field => String(field.type || '').toLowerCase() !== 'hidden')
    .slice(0, 18)
    .map(fieldLine)
    .join('\n') || 'No visible input fields found.';
  return `🧪 *SRA Portal Diagnostics*
URL: ${diag.url}
Status: HTTP ${diag.status}
Title: ${diag.title || '-'}
Forms: ${diag.formCount || 0}
Hidden fields: ${diag.hiddenCount || 0}
Visible fields:
${allFields}

Best guess:
Roll: ${studentFieldKey(roll) || '-'}
Class: ${studentFieldKey(classField) || '-'}
Access code field: ${studentFieldKey(access) || '-'}
Submit: ${studentFieldKey(submit) || '-'}

Apply command:
*!studentbot fields ${suggested}*`;
}

function textByHtmlId(html = '', id = '') {
  if (!id) return '';
  const escaped = String(id).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(`<([a-z0-9]+)\\b[^>]*(?:id|name)\\s*=\\s*["']${escaped}["'][^>]*>([\\s\\S]*?)<\\/\\1>`, 'i');
  const match = String(html || '').match(re);
  return match ? stripHTML(match[2]) : '';
}

function firstNonEmpty(...values) {
  return values.map(item => String(item || '').trim()).find(Boolean) || '';
}

function parseSraProfile(html = '', roll = '') {
  return {
    roll_no: roll,
    name: firstNonEmpty(textByHtmlId(html, 'lblStudentName'), textByHtmlId(html, 'Label_Name'), textByHtmlId(html, 'lblName'), 'N/A'),
    class: firstNonEmpty(textByHtmlId(html, 'lblClass'), textByHtmlId(html, 'Label_Class'), textByHtmlId(html, 'lblClassName'), 'N/A'),
    section: firstNonEmpty(textByHtmlId(html, 'lblSection'), textByHtmlId(html, 'Label_Section'), 'N/A'),
    father: firstNonEmpty(textByHtmlId(html, 'lblFatherName'), textByHtmlId(html, 'Label_FatherName'), textByHtmlId(html, 'lblFather'), 'N/A'),
    dob: firstNonEmpty(textByHtmlId(html, 'lblDOB'), textByHtmlId(html, 'Label_DOB'), 'N/A'),
    phone: firstNonEmpty(textByHtmlId(html, 'lblPhone'), textByHtmlId(html, 'lblContact'), textByHtmlId(html, 'Label_Phone'), 'N/A'),
    address: firstNonEmpty(textByHtmlId(html, 'lblAddress'), textByHtmlId(html, 'Label_Address'), 'N/A')
  };
}

function numberFromText(text = '') {
  const n = String(text || '').replace(/[^\d.]/g, '');
  return Number(n || 0) || 0;
}

function parseSraAttendance(html = '') {
  const present = numberFromText(firstNonEmpty(textByHtmlId(html, 'lblPresent'), textByHtmlId(html, 'Label_Present')));
  const absent = numberFromText(firstNonEmpty(textByHtmlId(html, 'lblAbsent'), textByHtmlId(html, 'Label_Absent')));
  const total = numberFromText(firstNonEmpty(textByHtmlId(html, 'lblTotal'), textByHtmlId(html, 'Label_Total'))) || (present + absent);
  const percent = total > 0 ? Number(((present / total) * 100).toFixed(1)) : 0;
  return {
    present,
    absent,
    total,
    percent,
    status: percent >= 85 ? 'Regular ✅' : percent >= 75 ? 'Warning ⚠️' : 'Critical ❌'
  };
}

function parseSraResult(html = '') {
  const result = { subjects: [], total: 0, max: 0, avg: 0 };
  const tables = String(html || '').match(/<table\b[\s\S]*?<\/table>/gi) || [];
  for (const table of tables) {
    const rows = table.match(/<tr\b[\s\S]*?<\/tr>/gi) || [];
    if (rows.length < 2) continue;
    const header = stripHTML(rows[0]).toLowerCase();
    if (!/(subject|marks|obtained|total|grade|مضمون|نمبر)/i.test(header)) continue;
    for (const row of rows.slice(1)) {
      const cols = [...row.matchAll(/<t[dh]\b[^>]*>([\s\S]*?)<\/t[dh]>/gi)].map(col => stripHTML(col[1]));
      if (cols.length < 2) continue;
      const subject = cols[0];
      const obtained = numberFromText(cols[1]);
      const max = numberFromText(cols[2]) || 100;
      if (!subject || (!obtained && !/\d/.test(cols.join(' ')))) continue;
      const pct = max ? Number(((obtained / max) * 100).toFixed(1)) : 0;
      const grade = pct >= 90 ? 'A+' : pct >= 80 ? 'A' : pct >= 70 ? 'B+' : pct >= 60 ? 'B' : pct >= 50 ? 'C' : pct >= 40 ? 'D' : 'F';
      result.subjects.push({ subject, obtained, total: max, percent: pct, grade });
    }
    if (result.subjects.length) break;
  }
  if (result.subjects.length) {
    result.total = result.subjects.reduce((sum, row) => sum + Number(row.obtained || 0), 0);
    result.max = result.subjects.reduce((sum, row) => sum + Number(row.total || 0), 0);
    result.avg = result.max ? Number(((result.total / result.max) * 100).toFixed(1)) : 0;
  }
  return result;
}

async function fetchSraStudentInfo(roll = '', className = '') {
  const cfg = studentSraConfig();
  const safe = safeStudentUrl(cfg.loginUrl, { ...studentWebsiteConfig(), allowPrivateUrls: settings.student_website_allow_private_urls === true });
  if (!safe.ok) return { error: safe.error };
  try {
    const getResponse = await fetchOutbound(safe.url, {
      headers: { 'user-agent': 'SuperSenderPro-SRA-Bot/1.0', accept: 'text/html,*/*' }
    });
    const firstHtml = await getResponse.text();
    if (!getResponse.ok) return { error: `School website HTTP ${getResponse.status}` };
    const fields = parseHtmlInputs(firstHtml);
    fields[cfg.rollField] = String(roll || '').trim();
    if (cfg.classField) fields[cfg.classField] = String(className || '').trim();
    if (cfg.accessField && cfg.accessCode) fields[cfg.accessField] = cfg.accessCode;
    if (fields.chkRollNoAllow !== undefined) fields.chkRollNoAllow = 'on';
    if (cfg.submitField) {
      const submitMeta = findHtmlFormField(firstHtml, cfg.submitField);
      if (String(submitMeta?.type || '').toLowerCase() === 'image') {
        fields[`${cfg.submitField}.x`] = '12';
        fields[`${cfg.submitField}.y`] = '12';
      } else {
        fields[cfg.submitField] = cfg.submitValue || 'Search';
      }
    }
    const postResponse = await fetchOutbound(safe.url, {
      method: 'POST',
      headers: {
        'user-agent': 'SuperSenderPro-SRA-Bot/1.0',
        'content-type': 'application/x-www-form-urlencoded',
        referer: safe.url
      },
      body: new URLSearchParams(fields).toString()
    });
    const html = await postResponse.text();
    if (!postResponse.ok) return { error: `School website HTTP ${postResponse.status}` };
    if (/no\s*record|not\s*found|invalid|نہیں\s*ملا/i.test(stripHTML(html))) {
      return { error: `Roll No ${roll} nahi mila. Sahi roll number bhejein.` };
    }
    const data = {
      profile: parseSraProfile(html, roll),
      attendance: parseSraAttendance(html),
      result: parseSraResult(html),
      error: null
    };
    data.emptyParse = isSraEmptyParse(data);
    return data;
  } catch (error) {
    return { error: error.message || 'School website connection failed.' };
  }
}

function progressBar(percent = 0, length = 10) {
  const filled = Math.max(0, Math.min(length, Math.round((Number(percent || 0) / 100) * length)));
  return '█'.repeat(filled) + '░'.repeat(length - filled);
}

function formatSraProfile(data = {}) {
  const p = data.profile || {};
  const parseWarning = data.emptyParse
    ? `\n\n⚠️ Portal connected, lekin student fields map nahi huay.\nAdmin command: *!studentbot diagnose*`
    : '';
  return `🏫 *SRA School Portal*
━━━━━━━━━━━━━━━━━━
👤 *Student Info*
Name: ${p.name || 'N/A'}
Roll No: ${p.roll_no || 'N/A'}
Class: ${p.class || 'N/A'} - ${p.section || 'N/A'}
Father: ${p.father || 'N/A'}
DOB: ${p.dob || 'N/A'}
Phone: ${p.phone || 'N/A'}
━━━━━━━━━━━━━━━━━━
Reply:
*1* - Attendance
*2* - Result / Marks
*3* - Full Report
*0* - New Search${parseWarning}`;
}

function formatSraAttendance(data = {}) {
  const p = data.profile || {};
  const a = data.attendance || {};
  const pct = Number(a.percent || 0);
  const warn = pct < 75
    ? '\n\n⚠️ *Attendance bahut kam hai!*\nSchool se rabta karein.'
    : pct < 85
      ? '\n\n🔔 Attendance improve karein.'
      : '';
  return `📅 *Attendance Report*
Student: ${p.name || 'N/A'}
Class: ${p.class || 'N/A'}
━━━━━━━━━━━━━━━━━━
Present: ${a.present || 0} days
Absent: ${a.absent || 0} days
Total: ${a.total || 0} days
━━━━━━━━━━━━━━━━━━
${progressBar(pct)} ${pct}%
Status: ${a.status || 'N/A'}${warn}

Reply *menu* for main menu.`;
}

function formatSraResult(data = {}) {
  const p = data.profile || {};
  const r = data.result || {};
  const subjects = Array.isArray(r.subjects) ? r.subjects : [];
  if (!subjects.length) {
    return `📊 *Result*
Student: ${p.name || 'N/A'}
━━━━━━━━━━━━━━━━━━
Abhi result available nahi hai.
School portal check karein: ${studentSraConfig().baseUrl}

Reply *menu* for main menu.`;
  }
  const rows = subjects.slice(0, 12).map(s => {
    const dot = Number(s.percent || 0) >= 80 ? '🟢' : Number(s.percent || 0) >= 60 ? '🟡' : '🔴';
    return `${dot} ${s.subject}: ${s.obtained}/${s.total} (${s.grade})`;
  }).join('\n');
  const avg = Number(r.avg || 0);
  const overall = avg >= 80 ? '🟢 Excellent' : avg >= 60 ? '🟡 Good' : '🔴 Needs Improvement';
  return `📊 *Result / Marks*
Student: ${p.name || 'N/A'}
Class: ${p.class || 'N/A'}
━━━━━━━━━━━━━━━━━━
${rows}
━━━━━━━━━━━━━━━━━━
Total: ${r.total || 0}/${r.max || 0}
Avg: ${avg}% - ${overall}

Reply *menu* for main menu.`;
}

function formatSraFullReport(data = {}) {
  const a = data.attendance || {};
  const r = data.result || {};
  return `${formatSraProfile(data)}

📅 *Attendance:* ${a.percent || 0}% - ${a.status || 'N/A'}
📊 *Avg Marks:* ${r.avg || 0}%
Total: ${r.total || 'N/A'}/${r.max || 'N/A'}

Full details ke liye *1* ya *2* reply karein.`;
}

function buildStudentWebsiteReadiness(diag = null) {
  const config = studentWebsiteConfig();
  const sra = studentSraConfig();
  const mode = String(settings.student_website_mode || 'sra').toLowerCase();
  const items = [];
  const add = (key, label, status, message) => items.push({ key, label, status, message });
  add('enabled', 'Bot enabled', config.enabled ? 'ok' : 'bad', config.enabled ? 'Student bot WhatsApp menu mein active hai.' : 'Student bot OFF hai. Use !studentbot on');
  add('mode', 'Mode selected', ['sra', 'api'].includes(mode) ? 'ok' : 'bad', `Current mode: ${mode.toUpperCase()}`);
  if (mode === 'sra') {
    add('sra_url', 'SRA URL', /^https?:\/\//i.test(sra.loginUrl) ? 'ok' : 'bad', sra.loginUrl || 'SRA URL missing.');
    add('roll_field', 'Roll field', sra.rollField ? 'ok' : 'bad', sra.rollField || 'Run diagnose and apply roll field.');
    add('class_field', 'Class/program field', sra.classField ? 'ok' : 'warn', sra.classField || 'Optional unless portal requires class/program.');
    const diagAccess = diag?.likely?.access?.[0] ? studentFieldKey(diag.likely.access[0]) : '';
    const accessNeeded = !!(diagAccess || sra.accessField);
    add('access_field', 'Access code field', accessNeeded ? 'ok' : 'warn', accessNeeded ? (sra.accessField || diagAccess) : 'Run diagnose to detect if access code is required.');
    add('access_code', 'Access code saved', accessNeeded ? (sra.accessCode ? 'ok' : 'bad') : 'warn', accessNeeded ? (sra.accessCode ? 'Code saved securely.' : 'Access code missing. Save it in /student-bot or use accesscode=YOUR_CODE') : 'Unknown until diagnose runs.');
    add('submit_field', 'Submit field', sra.submitField ? 'ok' : 'bad', sra.submitField || 'Run diagnose and apply submit field.');
    if (diag) {
      add('portal_check', 'Portal reachable', diag.ok ? 'ok' : 'bad', diag.ok ? `HTTP ${diag.status} - ${diag.title || 'Portal loaded'}` : (diag.error || 'Portal check failed.'));
    }
  } else {
    add('lookup_url', 'Lookup URL', config.lookupUrl ? 'ok' : 'bad', config.lookupUrl || 'Set API lookup URL with {query}.');
  }
  const needsSraConfirmation = mode === 'sra' && !diag && !sra.accessField;
  const ready = items.every(item => item.status !== 'bad') && !needsSraConfirmation;
  return { ready, mode, items };
}

function formatStudentWebsiteReadiness(readiness = buildStudentWebsiteReadiness()) {
  const icon = (status) => status === 'ok' ? '✅' : status === 'warn' ? '⚠️' : '❌';
  const rows = (readiness.items || []).map(item => `${icon(item.status)} *${item.label}:* ${item.message}`).join('\n');
  return `🎓 *Student Bot Readiness*
Status: *${readiness.ready ? 'READY' : 'NEEDS SETUP'}*
Mode: *${String(readiness.mode || 'sra').toUpperCase()}*
━━━━━━━━━━━━━━━━━━
${rows}`;
}

function formatStudentWebsiteAdminReply() {
  const config = studentWebsiteConfig();
  const sra = studentSraConfig();
  return `🎓 *Student Website Bot Admin*

Status: *${config.enabled ? 'ON' : 'OFF'}*
Mode: *${String(settings.student_website_mode || 'sra').toUpperCase()}*
Name: ${config.name}

API/Base:
Lookup URL: ${config.lookupUrl || '-'}
Base URL: ${config.baseUrl || '-'}
User URLs: ${config.allowUserUrls ? 'ON' : 'OFF'}
Private URLs: ${config.allowPrivateUrls ? 'ON' : 'OFF'}
API key: ${config.apiKey ? 'saved' : '-'}

SRA:
URL: ${sra.loginUrl}
Roll field: ${sra.rollField}
Class field: ${sra.classField || '-'}
Access field: ${sra.accessField || '-'} (${sra.accessCode ? 'code saved' : 'no code'})
Submit: ${sra.submitField}=${sra.submitValue}

Commands:
*!studentbot on/off*
*!studentbot mode sra*
*!studentbot mode api*
*!studentbot lookup https://site.com/result?roll={query}*
*!studentbot sraurl http://111.68.99.200/SRA-n/mainselcfrmx.aspx*
*!studentbot fields roll=txtRegNo class=ddlDegreeProg accessfield=a63542B5 accesscode=YOUR_CODE submit=ibtnLogin value=Search*
*!studentbot diagnose*
*!studentbot quicksetup*
*!studentbot test 2024-0045*`;
}

function parseStudentBotFieldPairs(text = '') {
  const out = {};
  for (const match of String(text || '').matchAll(/\b(roll|class|submit|value|accessfield|accesscode)\s*=\s*([^\s]+)/gi)) {
    out[match[1].toLowerCase()] = match[2];
  }
  return out;
}

async function handleStudentWebsiteAdminCommand(args = [], fullText = '') {
  const mode = String(args[1] || 'status').toLowerCase();
  if (['status', 'config', 'settings'].includes(mode)) return formatStudentWebsiteAdminReply();
  if (mode === 'on' || mode === 'off') {
    settings.student_website_bot_enabled = mode === 'on';
    saveJSON('settings.json', settings);
    return `✅ Student Website Bot is now *${settings.student_website_bot_enabled ? 'ON' : 'OFF'}*.`;
  }
  if (mode === 'mode') {
    const value = String(args[2] || '').toLowerCase();
    if (!['sra', 'api', 'generic'].includes(value)) return 'Format:\n*!studentbot mode sra*\n*!studentbot mode api*';
    settings.student_website_mode = value === 'generic' ? 'api' : value;
    saveJSON('settings.json', settings);
    return `✅ Student Website Bot mode set to *${settings.student_website_mode.toUpperCase()}*.`;
  }
  if (mode === 'lookup' || mode === 'api') {
    const url = fullText.replace(/^!studentbot\s+(lookup|api)\s*/i, '').trim();
    if (!url || !/\{query\}|\{roll\}|\{q\}/i.test(url)) {
      return 'Format:\n*!studentbot lookup https://site.com/result?roll={query}*';
    }
    settings.student_website_mode = 'api';
    settings.student_website_lookup_url = url;
    saveJSON('settings.json', settings);
    return `✅ Student API lookup URL saved.\nMode: *API*\n${url}`;
  }
  if (mode === 'baseurl') {
    const url = fullText.replace(/^!studentbot\s+baseurl\s*/i, '').trim();
    if (!/^https?:\/\//i.test(url)) return 'Format:\n*!studentbot baseurl https://site.com/results*';
    settings.student_website_base_url = url;
    saveJSON('settings.json', settings);
    return `✅ Student base URL saved.\n${url}`;
  }
  if (mode === 'sraurl') {
    const url = fullText.replace(/^!studentbot\s+sraurl\s*/i, '').trim();
    if (!/^https?:\/\//i.test(url)) return 'Format:\n*!studentbot sraurl http://111.68.99.200/SRA-n/mainselcfrmx.aspx*';
    const parsed = new URL(url);
    settings.student_website_mode = 'sra';
    settings.student_sra_base_url = `${parsed.protocol}//${parsed.host}${parsed.pathname.replace(/\/[^/]*$/, '')}`.replace(/\/+$/g, '');
    settings.student_sra_login_path = `/${parsed.pathname.split('/').filter(Boolean).slice(-1)[0] || 'mainselcfrmx.aspx'}`;
    saveJSON('settings.json', settings);
    return `✅ SRA URL saved.\n${studentSraConfig().loginUrl}`;
  }
  if (mode === 'fields') {
    const pairs = parseStudentBotFieldPairs(fullText);
    if (!Object.keys(pairs).length) {
      return 'Format:\n*!studentbot fields roll=txtRollNo class=txtClass submit=btnSearch value=Search*';
    }
    if (pairs.roll) settings.student_sra_roll_field = pairs.roll;
    if (pairs.class) settings.student_sra_class_field = pairs.class;
    if (pairs.accessfield) settings.student_sra_access_field = pairs.accessfield;
    if (pairs.accesscode) settings.student_sra_access_code = pairs.accesscode;
    if (pairs.submit) settings.student_sra_submit_field = pairs.submit;
    if (pairs.value) settings.student_sra_submit_value = pairs.value;
    saveJSON('settings.json', settings);
    return `✅ SRA fields updated.\nRoll: ${settings.student_sra_roll_field}\nClass: ${settings.student_sra_class_field || '-'}\nAccess: ${settings.student_sra_access_field || '-'} (${settings.student_sra_access_code ? 'code saved' : 'no code'})\nSubmit: ${settings.student_sra_submit_field}=${settings.student_sra_submit_value}`;
  }
  if (mode === 'diagnose' || mode === 'scan') {
    const diag = await diagnoseSraPortal();
    return formatSraDiagnosticsReply(diag);
  }
  if (mode === 'quicksetup' || mode === 'ready' || mode === 'readiness') {
    const diag = String(settings.student_website_mode || 'sra').toLowerCase() === 'sra' ? await diagnoseSraPortal() : null;
    const readiness = buildStudentWebsiteReadiness(diag);
    const suggested = diag?.ok ? formatSraDiagnosticsReply(diag).split('Apply command:\n')[1] || '' : '';
    return `${formatStudentWebsiteReadiness(readiness)}

${readiness.ready ? '✅ Setup complete. Ab *!studentbot test ROLLNO* run karein.' : 'Next step: missing ❌ items fix karein.'}
${suggested ? `\nSuggested command:\n${suggested}` : ''}

Browser panel:
http://localhost:3001/student-bot`;
  }
  if (mode === 'test') {
    const query = fullText.replace(/^!studentbot\s+test\s*/i, '').trim();
    if (!query) return 'Format:\n*!studentbot test 2024-0045*';
    if (String(settings.student_website_mode || 'sra').toLowerCase() === 'sra') {
      const data = await fetchSraStudentInfo(query);
      return data.error ? `❌ Test failed:\n${data.error}` : `✅ Test success:\n\n${formatSraProfile(data)}`;
    }
    const url = buildStudentLookupUrl(query, studentWebsiteConfig());
    if (!url) return '❌ No lookup URL configured. Use:\n*!studentbot lookup https://site.com/result?roll={query}*';
    const result = await fetchStudentWebsiteData(url, query);
    return result.success ? `✅ Test success:\n${result.summary.slice(0, 1200)}` : `❌ Test failed:\n${result.error || 'Unknown error'}`;
  }
  return formatStudentWebsiteAdminReply();
}

async function handleStudentWebsiteBotMessage(conv, body, number, name) {
  const config = studentWebsiteConfig();
  if (!config.enabled) return 'Student Website Bot abhi disabled hai.';
  const mode = String(settings.student_website_mode || 'sra').toLowerCase();
  const text = String(body || '').trim();
  const lower = text.toLowerCase();
  if (mode === 'sra') {
    if (text === '11' || ['menu', 'start', 'hi', 'hello'].includes(lower)) {
      conv.botState = 'student_website_bot';
      conv.botData = {};
      return buildStudentWebsiteMenu();
    }
    const existing = conv.botData?.studentWebsiteData;
    if (existing && ['1', 'attendance', 'hazri'].includes(lower)) return formatSraAttendance(existing);
    if (existing && ['2', 'result', 'marks', 'result/marks'].includes(lower)) return formatSraResult(existing);
    if (existing && ['3', 'full', 'full report', 'report'].includes(lower)) return formatSraFullReport(existing);
    const query = extractStudentLookupQuery(text);
    if (!query) {
      conv.botState = 'student_website_bot';
      return buildStudentWebsiteMenu();
    }
    const data = await fetchSraStudentInfo(query);
    logStudentWebsiteLookup({
      customerNumber: number,
      customerName: name,
      query,
      url: studentSraConfig().loginUrl,
      mode: 'sra',
      success: !data.error,
      error: data.error || ''
    });
    if (data.error) {
      return `❌ *SRA School Lookup Failed*

${data.error}

Roll no dobara check karein. Example: *2024-0045*
0️⃣ Back to Main Menu`;
    }
    conv.botState = 'student_website_menu';
    conv.botData = { ...(conv.botData || {}), studentWebsiteData: data, studentWebsiteRoll: query };
    return formatSraProfile(data);
  }
  const urlInMessage = extractUrlFromText(body);
  const query = extractStudentLookupQuery(body);
  let targetUrl = '';
  if (urlInMessage) {
    if (!config.allowUserUrls) return 'Public URL lookup disabled hai. Roll number ya configured website query bhejein.';
    targetUrl = urlInMessage;
  } else {
    targetUrl = buildStudentLookupUrl(query, config);
  }
  if (!targetUrl || (!query && !urlInMessage)) {
    conv.botState = 'student_website_bot';
    return buildStudentWebsiteMenu();
  }
  const result = await fetchStudentWebsiteData(targetUrl, query);
  logStudentWebsiteLookup({
    customerNumber: number,
    customerName: name,
    query,
    url: targetUrl,
    success: result.success,
    error: result.error || '',
    status: result.status || ''
  });
  if (!result.success) {
    return `❌ *Student Website Lookup Failed*

Reason: ${result.error || 'Unknown error'}

Roll no dobara check karein ya admin se website/API URL verify karwa dein.
0️⃣ Back to Main Menu`;
  }
  return `🎓 *Student Website Result*

Query: *${query || 'Website page'}*
Source: ${result.url}

${result.summary}

0️⃣ Back to Main Menu`;
}

function buildPizzaOrderPrompt(product) {
  const price = Number(product?.price || 0);
  return `🍕 *Pizza Order Details*

Selected: *${product?.name || 'Pizza'}*
Price: *Rs. ${price.toLocaleString()}*

Please ek hi message mein ye details bhej dein:
1. Quantity
2. Flavour/change request
3. Delivery address
4. Contact number

Example:
*1 large, extra cheese, Model Town Lahore, 0300xxxxxxx*

0️⃣ Back to Main Menu`;
}

function parsePizzaOrderDetails(text = '', fallbackNumber = '') {
  const raw = String(text || '').trim();
  const phone = (raw.match(/(?:\+?92|0)?3\d{9}/) || [normalizeNumber(fallbackNumber || '')])[0] || '';
  const quantityMatch =
    raw.match(/\b([1-9]\d?)\s*(?:x|qty|quantity|pizza|pizzas|large|medium|small|family\s*deals?|deals?|combo|piece|pcs)\b/i) ||
    raw.match(/\b(?:qty|quantity|x)\s*([1-9]\d?)\b/i);
  const quantity = quantityMatch ? Math.max(1, Math.min(20, Number(quantityMatch[1]))) : 1;
  const peopleMatch = raw.match(/\b([2-9]|1[0-5])\s*(?:person|persons|people|log|guests?|friends?|bachay|kids|family)\b/i);
  const people = peopleMatch ? Number(peopleMatch[1]) : 0;
  return {
    raw,
    quantity,
    phone,
    people,
    addressLikely: raw.length >= 12 && /\d|street|road|town|colony|phase|sector|gali|mohalla|lahore|karachi|islamabad|multan|bahawalpur|hasilpur|address|near/i.test(raw)
  };
}

function shouldUsePizzaFamilyDeal(text = '', details = {}) {
  const raw = String(text || '');
  if (/\b(family|deal|combo|party|friends|guests|people|persons|log|bachay|kids|cold\s*drink|garlic\s*bread)\b/i.test(raw)) return true;
  if (Number(details?.people || 0) >= 3) return true;
  if (Number(details?.quantity || 0) >= 3 && !/\bsmall\b/i.test(raw)) return true;
  return false;
}

function findPizzaProductForDetails(text = '', selectedProduct = null, details = {}) {
  const products = getSellableRetailProducts('pizza');
  if (!products.length) return selectedProduct;
  const normalized = normalizeBotSearchText(text);
  const byNeed = (matcher) => products.find(product => matcher(normalizeBotSearchText(`${product.name || ''} ${product.specs || ''} ${product.tags?.join?.(' ') || ''}`)));

  if (shouldUsePizzaFamilyDeal(text, details)) {
    return byNeed(hay => hay.includes('family') || hay.includes('deal')) || selectedProduct || products[0];
  }
  if (/\b(large|bari|bara|big)\b/i.test(normalized)) {
    return byNeed(hay => hay.includes('large')) || selectedProduct || products[0];
  }
  if (/\b(medium|med)\b/i.test(normalized)) {
    const medium = byNeed(hay => hay.includes('medium'));
    if (medium) return medium;
  }
  if (/\b(small|choti|chota)\b/i.test(normalized)) {
    const small = byNeed(hay => hay.includes('small'));
    if (small) return small;
  }
  if (/\btikka\b/i.test(normalized)) {
    return byNeed(hay => hay.includes('tikka')) || selectedProduct || products[0];
  }
  if (/\bfajita\b/i.test(normalized)) {
    return byNeed(hay => hay.includes('fajita')) || selectedProduct || products[0];
  }
  if (/\bspecial\b/i.test(normalized)) {
    return byNeed(hay => hay.includes('special')) || selectedProduct || products[0];
  }
  return selectedProduct || products[0];
}

function createRetailOrderRecord({ customerNumber, customerName, product, details, sourceMessage }) {
  const quantity = Math.max(1, Number(details?.quantity || 1));
  const unitPrice = Number(product?.price || 0);
  const order = {
    id: uuid(),
    orderNumber: `ORD-${Date.now().toString().slice(-6)}`,
    kind: String(product?.category || 'retail'),
    source: 'whatsapp-bot',
    customerNumber: normalizeNumber(customerNumber || ''),
    customerName: customerName || 'Customer',
    status: 'pending_contact',
    paymentStatus: 'pending',
    total: unitPrice * quantity,
    items: [{
      id: product?.id || '',
      name: product?.name || 'Product',
      category: product?.category || 'retail',
      quantity,
      price: unitPrice
    }],
    deliveryDetails: details || {},
    note: sourceMessage || '',
    created: new Date().toISOString(),
    updated: new Date().toISOString()
  };
  orders.push(order);
  saveJSON('orders.json', orders);
  return order;
}

function formatRetailOrderAlert(order) {
  const item = Array.isArray(order.items) ? order.items[0] || {} : {};
  const category = String(item.category || order.kind || 'retail').toUpperCase();
  return `🛍️ *NEW ${category} ORDER*

Order: *${order.orderNumber || order.id}*
Customer: ${order.customerName || 'Customer'}
Number: ${order.customerNumber || '-'}
Product: *${item.name || 'Product'}*
Qty: ${item.quantity || 1}
Total: *Rs. ${Number(order.total || 0).toLocaleString()}*

Details:
${order.deliveryDetails?.raw || order.note || '-'}

Reply/call customer and confirm delivery.`;
}

async function notifyRetailOrderToAdmin(order) {
  const adminNumber = normalizeNumber(settings.owner_whatsapp || settings.support_whatsapp || process.env.ADMIN_NUMBER || '');
  if (!adminNumber || adminNumber === normalizeNumber(order.customerNumber || '')) return false;
  if (/^(test|bot-sim|codex)/i.test(String(order.customerNumber || ''))) return false;
  try {
    await sendDirect(adminNumber, formatRetailOrderAlert(order));
    return true;
  } catch (error) {
    console.error('Retail order admin notify failed:', error.message);
    return false;
  }
}

async function startPizzaOrderWizard(conv, product, number, name, body) {
  conv.botState = 'pizza_order_details';
  conv.botData = {
    ...(conv.botData || {}),
    pizzaOrderProductId: product?.id || '',
    lastLaptopMatches: product?.id ? [product.id] : conv.botData?.lastLaptopMatches || [],
    awaitingLaptopOrder: false,
    pizzaOrderStartedAt: new Date().toISOString(),
    pizzaOrderSourceMessage: body
  };
  return buildPizzaOrderPrompt(product);
}

async function completePizzaOrderWizard(conv, body, number, name) {
  const initiallySelected = findProductById(conv.botData?.pizzaOrderProductId) || laptopProductsFromIds(conv.botData?.lastLaptopMatches || [])[0];
  const details = parsePizzaOrderDetails(body, number);
  const product = findPizzaProductForDetails(body, initiallySelected, details);
  if (!product) {
    conv.botState = 'retail_menu';
    return `Pizza item select nahi hua. Please *10* type karke pizza menu dobara open karein.`;
  }
  if (!details.raw || details.raw.length < 8 || !details.addressLikely) {
    return `Thori si delivery detail missing lag rahi hai.

Please ek message mein bhejein:
*quantity + flavour + address + contact number*

Example: *1 large, extra cheese, Model Town Lahore, 0300xxxxxxx*`;
  }
  const order = createRetailOrderRecord({
    customerNumber: number,
    customerName: name,
    product,
    details,
    sourceMessage: conv.botData?.pizzaOrderSourceMessage || body
  });
  await notifyRetailOrderToAdmin(order);
  conv.botState = 'retail_menu';
  conv.botData = { selectedRetailGroup: 'pizza', lastLaptopMatches: [product.id], lastRetailOrderId: order.id };
  return `✅ *Pizza Order Received*

Order ID: *${order.orderNumber}*
Product: *${product.name}*
Qty: ${details.quantity}
Total: *Rs. ${Number(order.total || 0).toLocaleString()}*
ETA: *30-45 minutes approx*

Team abhi confirm karegi. Payment/delivery details ke liye yahin reply karein.
0️⃣ Back to Main Menu`;
}

async function notifyLaptopOrderToAdmin(customerNumber, customerName, product, rawMessage) {
  const adminNumber = normalizeNumber(settings.owner_whatsapp || settings.support_whatsapp || process.env.ADMIN_NUMBER || '');
  const customerClean = normalizeNumber(customerNumber || '');
  if (!adminNumber || adminNumber === customerClean) return false;
  if (/^(test|bot-sim|codex)/i.test(String(customerNumber || ''))) return false;
  try {
    await sendDirect(adminNumber, formatLaptopOrderAlert(customerName, customerClean || customerNumber, product, rawMessage));
    return true;
  } catch (error) {
    console.error('Laptop order admin notify failed:', error.message);
    return false;
  }
}

const WA_MAIN_MENU = buildMainWelcomeMenu();

function isMenuCommand(text) {
  const lower = String(text || '').trim().toLowerCase().replace(/[.!?]+$/g, '');
  if (!lower) return false;
  const commands = new Set([
    'menu', 'main menu', 'start', 'restart', 'help', 'back',
    'hi', 'hello', 'helo', 'hey',
    'aoa', 'a.o.a', 'slm', 'salam', 'salaam',
    'assalam', 'assalamualaikum', 'assalam o alaikum', 'assalamu alaikum', 'asalam o alaikum'
  ]);
  return commands.has(lower);
}

function resetConversationToMainMenu(conv, name) {
  conv.botState = 'idle';
  conv.botData = {};
  return buildMainWelcomeMenu(name);
}

function lastConversationActivityMs(conv) {
  const last = Array.isArray(conv.history) && conv.history.length ? conv.history[conv.history.length - 1] : null;
  const lastTime = last?.time ? Date.parse(last.time) : 0;
  return Number.isFinite(lastTime) && lastTime > 0 ? Date.now() - lastTime : 0;
}

async function buildProductBotReply(conv, body, number = '', name = 'Customer') {
  conv.botData = conv.botData || {};
  if (isOrderIntent(body) && Array.isArray(conv.botData.lastLaptopMatches) && conv.botData.lastLaptopMatches.length) {
    const selected = findProductById(conv.botData.lastLaptopMatches[0]);
    if (selected && isPizzaProduct(selected)) {
      return startPizzaOrderWizard(conv, selected, number, name, body);
    }
    clearLaptopOfferPending(conv);
    await notifyLaptopOrderToAdmin(number, name, selected, body);
    if (selected) {
      return `âœ… *Order Request Bhej Di!*

Hamara team aap se jald rabta karega.
ðŸ’» ${selected.name}
ðŸ’° Rs. ${Number(selected.price || 0).toLocaleString()}

Payment details ke liye *payment* type karein.
0ï¸âƒ£ Back to Main Menu`;
    }
    return `âœ… Aapki inquiry admin ko bhej di gayi hai. Team jald contact karegi.

0ï¸âƒ£ Back to Main Menu`;
  }

  const fastResult = searchLaptopsFast(body, 5);
  conv.botData.lastLaptopQuery = body;
  conv.botData.lastLaptopMatches = fastResult.results.map(p => p.id);
  if (fastResult.results.length) markLaptopOfferPending(conv, fastResult.results, 'search');

  const useProductAI = settings.product_bot_ai_enabled === true || String(process.env.PRODUCT_BOT_AI || '').toLowerCase() === '1';
  if (!useProductAI || fastResult.noStock || fastResult.results.length) return buildInventoryFallbackReply(body);

  const catalog = buildCatalogPrompt(body);
  const historyContext = conv.history.slice(-6).map(h => `${h.role === 'user' ? 'Customer' : 'Bot'}: ${h.msg}`).join('\n');
  const { getLanguageSpecificSystemPrompt } = require('./ai/languageDetector');
  const systemPrompt = getLanguageSpecificSystemPrompt('und', settings) + `\n\nFULL LIVE INVENTORY:\n${catalog || 'No products are currently in stock.'}\n\nAnswer only from this inventory. Keep reply under 6 lines. If no exact match is listed, ask for budget or model instead of inventing products.`;

  let reply = hasAnyAIProvider()
    ? await callAI(`Conversation History:\n${historyContext}\n\nCustomer's newest message: ${body}\n\nUse the live inventory above.`, systemPrompt)
      .catch(error => {
        console.warn('[Bot] Product AI reply failed:', error.message);
        return buildInventoryFallbackReply(body);
      })
    : buildInventoryFallbackReply(body);
  if (isAIUnavailableReply(reply)) reply = buildInventoryFallbackReply(body);
  return reply;
}

async function buildGeneralAIReply(conv, body, name) {
  const historyContext = conv.history.slice(-8).map(h => `${h.role === 'user' ? 'Customer' : 'Bot'}: ${h.msg}`).join('\n');
  if (!hasAnyAIProvider()) return 'AI chat is offline because no AI API key is configured. Type *2* for products, *3* for scholarships, or *4* for real estate.';
  const systemPrompt = `You are SuperSender Pro AI assistant. Reply in the same language as the user. Keep the answer concise and practical. Customer name: ${name || 'Customer'}.`;
  const reply = await callAI(`Conversation History:\n${historyContext}\n\nCustomer's newest message: ${body}`, systemPrompt)
    .catch(error => {
      console.warn('[Bot] General AI reply failed:', error.message);
      return '';
    });
  return isAIUnavailableReply(reply)
    ? 'AI service is temporarily unavailable. Type *2* for products, *3* for scholarships, or *4* for real estate.'
    : (reply || buildLocalFriendlyFallbackReply(body, name));
}

function buildBusinessSnapshotForAI(body = '') {
  const categories = getBotPlanCategories().slice(0, 8).map(item => {
    const price = Number.isFinite(item.fromPrice) ? `from Rs.${Number(item.fromPrice || 0).toLocaleString()}` : 'price in plans';
    return `${item.id}. ${item.category}: ${item.count} plan(s), ${price}`;
  });
  const matchedPlans = getBotPlanOptions()
    .filter(({ plan }) => String(plan.name || '').toLowerCase().includes(String(body || '').toLowerCase().trim()))
    .slice(0, 4)
    .map(({ plan }) => `${plan.name} - Rs.${Number(plan.price || 0).toLocaleString()} (${plan.label || plan.duration || 'duration available'})`);
  const laptopMatches = searchLaptopsFast(body, 5).results.map(product => {
    const profile = laptopProfile(product);
    const gen = profile.generation ? ` ${profile.generation}th Gen` : '';
    return `${product.name} - ${profile.processor}${gen}, ${profile.ram || '-'}GB RAM, ${profile.storage.label}, Rs.${Number(product.price || 0).toLocaleString()}`;
  });
  const laptopBrands = getLaptopBrandGroups().slice(0, 6).map(item => `${item.brand}: ${item.count} laptop(s) from Rs.${Number(item.fromPrice || 0).toLocaleString()}`);
  const payments = paymentDetailLines();
  return [
    `Store: ${storeDisplayName()}`,
    `Main services: AI tool subscriptions, laptops, scholarship finder, real estate bot, payments/invoices.`,
    categories.length ? `AI tool categories:\n${categories.join('\n')}` : '',
    matchedPlans.length ? `Relevant plans:\n${matchedPlans.join('\n')}` : '',
    laptopMatches.length ? `Relevant laptop matches:\n${laptopMatches.join('\n')}` : `Laptop brands:\n${laptopBrands.join('\n')}`,
    `Scholarship bot flow: type 3, then choose degree BS/MS/PhD, then department.`,
    `Real estate bot flow: type 4, then choose property search, post property, valuation, agent contact, latest listings, or site visit booking.`,
    payments.length ? `Payment accounts:\n${payments.join('\n')}` : 'Payment accounts are not fully configured yet.'
  ].filter(Boolean).join('\n\n');
}

