async function runAIPlanOrderFollowups() {
  const inst = waClients.get('default');
  if (!inst?.isReady) return;

  const now = Date.now();
  let changed = false;

  for (const order of orders || []) {
    if (!order || String(order.kind || '') !== 'ai_plan') continue;
    if (/cancelled|canceled/i.test(String(order.status || ''))) continue;
    const number = order.customerNumber || '';
    if (!number || shouldSkipLaptopFollowupNumber(number) || isBlacklistedNumber(number)) continue;

    const item = Array.isArray(order.items) ? order.items[0] : {};
    const accountType = String(item.accountType || order.aiMeta?.accountType || '').toLowerCase();
    const createdAt = Date.parse(order.created || order.updated || order.statusHistory?.[0]?.time || '');
    if (!Number.isFinite(createdAt) || createdAt <= 0) continue;

    order.aiMeta = order.aiMeta || {};
    const orderAgeDays = (now - createdAt) / (24 * 60 * 60 * 1000);
    const planName = item?.name || 'AI Tools Plan';
    const amount = Number(item?.price || order.total || 0).toLocaleString();
    const renewalText = `ðŸ” *Renewal Reminder*\n\nOrder: *${order.orderNumber}*\nPlan: *${planName}*\nType: *${item?.accountTypeLabel || 'Account'}*\nPrice: *Rs.${amount}*\n\nAgar next cycle bhi chahiye ho to isi chat mein *renew* likh dein.`;

    try {
      if (accountType === 'warranty' && !order.aiMeta.day1WarrantyFollowupSent && orderAgeDays >= 1) {
        await sendDirect(number, `ðŸ›¡ï¸ *Warranty Check-in*\n\nOrder: *${order.orderNumber}*\nSab theek chal raha hai?\nAgar koi issue ho to isi chat mein detail bhej dein, main pehle guide karunga phir zarurat par admin ko forward kar dunga.`);
        order.aiMeta.day1WarrantyFollowupSent = new Date().toISOString();
        changed = true;
        await sleep(1200);
      }

      if (!order.aiMeta.day3ReviewFollowupSent && orderAgeDays >= 3) {
        await sendDirect(number, `â­ *Quick Review Request*\n\nAgar *${planName}* sahi chal raha hai to short feedback ya screenshot share kar dein.\nAap ka testimonial next buyers ko help karta hai ðŸ™Œ`);
        order.aiMeta.day3ReviewFollowupSent = new Date().toISOString();
        changed = true;
        await sleep(1200);
      }

      if (!order.aiMeta.day25RenewalReminderSent && orderAgeDays >= 25) {
        await sendDirect(number, renewalText);
        order.aiMeta.day25RenewalReminderSent = new Date().toISOString();
        changed = true;
        await sleep(1200);
      }

      if (!order.aiMeta.day28RenewalUrgencySent && orderAgeDays >= 28 && !isRenewedAIPlanOrder(order)) {
        await sendDirect(number, `â° *Subscription Expiry Alert*\n\nOrder: *${order.orderNumber}*\nAap ki *${planName}* subscription khatam hone ke qareeb hai.\nRenewal ke liye abhi reply karein taake access break na ho.`);
        order.aiMeta.day28RenewalUrgencySent = new Date().toISOString();
        changed = true;
        await sleep(1200);
      }
    } catch (error) {
      console.error(`AI plan follow-up failed for ${number}:`, error.message);
    }
  }

  if (changed) saveJSON('orders.json', orders);
}

