function sanitizeImportedFieldKey(value = '', fallback = '') {
  const normalized = normalizeKey(value || fallback || '');
  return normalized || normalizeKey(fallback || '');
}

function buildImportedContactRow(rawRow = {}, fallbackCols = [], normalize = (n) => (n || '').toString().replace(/\D/g, '')) {
  const row = {};
  Object.entries(rawRow || {}).forEach(([key, value]) => {
    const safeKey = sanitizeImportedFieldKey(key);
    if (!safeKey) return;
    row[safeKey] = typeof value === 'string' ? value.trim() : value;
  });

  if (Array.isArray(fallbackCols)) {
    fallbackCols.forEach((value, index) => {
      const safeValue = typeof value === 'string' ? value.trim() : value;
      if (safeValue === undefined || safeValue === null || safeValue === '') return;
      const fallbackKey = index === 0 ? 'number' : index === 1 ? 'name' : `column_${index + 1}`;
      if (row[fallbackKey] === undefined || row[fallbackKey] === '') row[fallbackKey] = safeValue;
    });
  }

  const number = normalize(
    row.number ||
    row.phone ||
    row.mobile ||
    row.whatsapp ||
    row.whatsapp_number ||
    row.contact ||
    row.contact_number ||
    row.wa ||
    row.contacts ||
    ''
  );
  const name = String(
    row.name ||
    row.full_name ||
    row.fullname ||
    row.customer_name ||
    row.first_name ||
    fallbackCols?.[1] ||
    ''
  ).trim();
  if (!number) return null;

  const reserved = new Set([
    'number', 'phone', 'mobile', 'whatsapp', 'whatsapp_number', 'contact', 'contact_number', 'wa', 'contacts',
    'name', 'full_name', 'fullname', 'customer_name', 'first_name'
  ]);

  const contact = { number, name };
  const customFields = {};
  Object.entries(row).forEach(([key, value]) => {
    if (value === undefined || value === null || value === '') return;
    if (reserved.has(key)) return;
    contact[key] = value;
    customFields[key] = value;
  });
  if (Object.keys(customFields).length) contact.customFields = customFields;
  return contact;
}

function summarizeImportedContactFields(contacts = []) {
  const counts = new Map();
  for (const contact of Array.isArray(contacts) ? contacts : []) {
    Object.keys(contact || {}).forEach((key) => {
      if (['number', 'name', 'customFields'].includes(key)) return;
      counts.set(key, (counts.get(key) || 0) + 1);
    });
    Object.keys(normalizeCustomFields(contact?.customFields)).forEach((key) => {
      const safeKey = sanitizeImportedFieldKey(key);
      if (!safeKey) return;
      counts.set(safeKey, (counts.get(safeKey) || 0) + 1);
    });
  }
  return [...counts.entries()]
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .map(([field, count]) => ({ field, count }));
}

// Import contacts for campaigns (CSV/XLSX). Returns normalized list with merge-field-ready columns.
app.post('/api/import/contacts-file', upload.single('file'), (req, res) => {
  try {
    if (!req.file) return res.status(400).json({ error: 'No file' });
    const ext = (path.extname(req.file.originalname || '') || '').toLowerCase();
    const filePath = req.file.path;
    const normalize = (n) => (n || '').toString().replace(/\D/g, '');
    let contacts = [];

    if (ext === '.csv') {
      const csv = fs.readFileSync(filePath, 'utf8');
      const lines = csv.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
      if (!lines.length) return res.json({ contacts: [] });
      const header = lines[0].split(',').map(h => h.trim().toLowerCase());
      const hasHeader = header.some(h => ['number','phone','mobile','whatsapp','name'].includes(h));
      const start = hasHeader ? 1 : 0;
      for (let i = start; i < lines.length; i++) {
        const cols = lines[i].split(',').map(s => s.trim());
        const row = {};
        if (hasHeader) header.forEach((h, idx) => { row[h] = cols[idx]; });
        const contact = buildImportedContactRow(row, cols, normalize);
        if (contact) contacts.push(contact);
      }
    } else if (ext === '.xlsx' || ext === '.xls') {
      const XLSX = require('xlsx');
      const wb = XLSX.readFile(filePath);
      const sheet = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(sheet, { defval: '' });
      for (const r of rows) {
        const contact = buildImportedContactRow(r, [], normalize);
        if (contact) contacts.push(contact);
      }
    } else if (ext === '.txt') {
      const raw = fs.readFileSync(filePath, 'utf8');
      const lines = raw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
      for (const line of lines) {
        const numberMatch = line.match(/(?:\+?92|0)?3\d{9}|\d{10,15}/);
        if (!numberMatch) continue;
        const name = line
          .replace(numberMatch[0], '')
          .replace(/[,;|-]+/g, ' ')
          .replace(/\s+/g, ' ')
          .trim();
        const contact = buildImportedContactRow({ number: numberMatch[0], name }, [], normalize);
        if (contact) contacts.push(contact);
      }
    } else {
      return res.status(400).json({ error: 'Unsupported file type. Use CSV, XLSX, XLS, or TXT.' });
    }

    // dedupe
    const seen = new Set();
    contacts = contacts.filter(c => {
      const k = c.number;
      if (!k || seen.has(k)) return false;
      seen.add(k);
      return true;
    });

    const fields = summarizeImportedContactFields(contacts);
    res.json({
      contacts,
      fields,
      mergeFieldHints: ['name', 'number', ...fields.slice(0, 12).map(item => item.field)]
    });
  } catch (e) {
    res.status(500).json({ error: e.message });
  } finally {
    try { if (req.file?.path) fs.unlink(req.file.path, () => {}); } catch {}
  }
});

