app.get('/api/automations/status', (req, res) => {
  const names = [
    'dailySalesReport',
    'stockAlert',
    'paymentReminder',
    'weeklyReport',
    'welcomeNewCustomer',
    'orderConfirmation',
    'groupPriceCapture',
    'groupBroadcast',
    'groupAnalytics',
    'groupAutoReply'
  ];
  const files = {};
  const loaded = {};
  const errors = {};
  for (const name of names) {
    const exists = fs.existsSync(path.join(__dirname, 'automations', `${name}.js`));
    files[name] = exists;
    loaded[name] = !!automationModules[name];
    if (automationLoadErrors[name]) errors[name] = automationLoadErrors[name];
  }
  res.json({ success: true, files, loaded, errors });
});

app.post('/api/automations/trigger/:name', async (req, res) => {
  const triggers = {
    dailySalesReport: { module: 'dailySalesReport', fn: 'sendDailySalesReport' },
    stockAlert: { module: 'stockAlert', fn: 'checkLowStock' },
    paymentReminder: { module: 'paymentReminder', fn: 'sendPaymentReminders' },
    weeklyReport: { module: 'weeklyReport', fn: 'sendWeeklyReport' }
  };
  try {
    const key = req.params.name;
    const target = triggers[key];
    if (!target) return res.status(404).json({ error: 'Unknown automation trigger' });
    const mod = automationModules[target.module];
    const fn = mod?.[target.fn];
    if (typeof fn !== 'function') return res.status(500).json({ error: `${target.module}.${target.fn} is not loaded` });
    const result = await fn(req.body || {});
    res.json({ success: true, message: 'triggered', name: key, result });
  } catch (error) {
    const status = /not connected|required|limit reached|opt-in/i.test(error.message || '') ? 400 : 500;
    res.status(status).json({ error: error.message });
  }
});

app.get('/api/paperclip/status', async (req, res) => {
  try {
    const settings = loadJSON('settings.json', {});
    const bridge = paperclipBridge || {};
    const connection = typeof bridge.checkConnection === 'function'
      ? await bridge.checkConnection()
      : { connected: false, error: 'Paperclip bridge not loaded' };
    const agents = connection.connected && typeof bridge.getAgentStatus === 'function'
      ? await bridge.getAgentStatus()
      : { success: false, agents: [], error: connection.error || 'Paperclip is disconnected' };
    const recentLogs = typeof bridge.getRecentLogs === 'function'
      ? bridge.getRecentLogs(20)
      : [];
    const declaredAgents = Array.isArray(paperclipAgents.AGENT_CONFIGS)
      ? paperclipAgents.AGENT_CONFIGS
      : [];

    res.json({
      success: true,
      enabled: !!settings.paperclip_enabled,
      autoSync: !!settings.paperclip_auto_sync,
      connection,
      company: agents.company || null,
      agents: agents.agents || [],
      declaredAgents,
      recentLogs
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

app.post('/api/paperclip/trigger', async (req, res) => {
  try {
    const bridge = paperclipBridge || {};
    const action = String(req.body?.action || req.body?.name || '').trim().toLowerCase();
    const payload = req.body?.data || req.body || {};
    let result = null;

    if (action === 'deploy' || action === 'deployall' || action === 'deployallagents') {
      if (typeof paperclipAgents.deployAllAgents !== 'function') {
        return res.status(500).json({ success: false, error: 'Paperclip agents module not loaded' });
      }
      result = await paperclipAgents.deployAllAgents(payload);
    } else if (action === 'sales' || action === 'marketing') {
      if (typeof bridge.triggerMarketingAgent !== 'function') {
        return res.status(500).json({ success: false, error: 'Paperclip bridge not loaded' });
      }
      result = await bridge.triggerMarketingAgent(payload.goal || payload.message || 'Find new WhatsApp bot clients in Pakistan');
    } else if (action === 'sync' || action === 'catalog') {
      if (typeof bridge.syncProductsToPaperclip !== 'function') {
        return res.status(500).json({ success: false, error: 'Paperclip bridge not loaded' });
      }
      result = await bridge.syncProductsToPaperclip(payload);
    } else if (action === 'report' || action === 'dailyreport') {
      if (typeof bridge.triggerReportAgent !== 'function') {
        return res.status(500).json({ success: false, error: 'Paperclip bridge not loaded' });
      }
      result = await bridge.triggerReportAgent(payload);
    } else if (action === 'task') {
      if (typeof bridge.sendTaskToPaperclip !== 'function') {
        return res.status(500).json({ success: false, error: 'Paperclip bridge not loaded' });
      }
      result = await bridge.sendTaskToPaperclip(payload);
    } else {
      return res.status(400).json({ success: false, error: 'Unknown Paperclip action' });
    }

    res.json({ success: true, action, result });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

