app.post('/api/wa/recover', async (req, res) => {
  try {
    const fresh = req.body?.fresh === true || req.query.fresh === 'true';
    const inst = waClients.get('default');
    if (inst?.isReady && !fresh) {
      return res.json({ success: true, connected: true, message: 'WhatsApp already connected.', diagnostics: buildWAConnectionDiagnostics('default') });
    }
    if (inst?.client) await destroyWAInstance(inst, 'default', fresh ? 'fresh-recover' : 'soft-recover');
    waClients.delete('default');
    waLastQR = { tenantId: null, data: null, generatedAt: 0 };
    await preflightCleanupWA('default', { removeSession: fresh, forceKill: true });
    if (fresh) {
      try { fs.rmSync(path.join(BAILEYS_AUTH_ROOT, 'default'), { recursive: true, force: true }); } catch {}
    }
    emitWAState({
      connected: false,
      status: 'starting',
      message: fresh ? 'Fresh session reset. Starting WhatsApp...' : 'Soft recover complete. Starting WhatsApp...',
      error: ''
    });
    const nextInst = await getOrCreateWAClient('default');
    res.json({
      success: true,
      connected: !!nextInst?.isReady,
      mode: fresh ? 'fresh' : 'soft',
      message: nextInst?.statusMsg || 'WhatsApp restarting...',
      diagnostics: buildWAConnectionDiagnostics('default')
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message, diagnostics: buildWAConnectionDiagnostics('default') });
  }
});

