app.post('/api/wa/pairing-code', async (req, res) => {
  try {
    if (WA_ENGINE !== 'baileys') {
      return res.status(400).json({ error: 'Phone pairing is available only with the Baileys WhatsApp engine.' });
    }
    const phoneNumber = (req.body?.phoneNumber || req.body?.number || '').toString().replace(/\D/g, '');
    if (phoneNumber.length < 8) {
      return res.status(400).json({ error: 'Enter WhatsApp number with country code, e.g. 923001234567.' });
    }

    let inst = waClients.get('default');
    if (inst?.isReady) {
      return res.json({ success: true, connected: true, message: 'WhatsApp is already linked.' });
    }
    if (hasWASession('default')) {
      if (inst?.client) {
        await destroyWAInstance(inst, 'default', 'pairing-reset');
      }
      waClients.delete('default');
      waLastQR = { tenantId: null, data: null, generatedAt: 0 };
      await preflightCleanupWA('default', { removeSession: true });
      try { fs.rmSync(path.join(BAILEYS_AUTH_ROOT, 'default'), { recursive: true, force: true }); } catch {}
    }
    inst = await getOrCreateWAClient('default');
    if (!inst?.sock || typeof inst.sock.requestPairingCode !== 'function') {
      return res.status(400).json({ error: 'Pairing code is not supported by this WhatsApp socket version.' });
    }
    setWAInstanceStatus(inst, 'pairing', 'Generating mobile pairing code...');

    let code = '';
    let lastError = null;
    for (let attempt = 0; attempt < 8 && !code; attempt++) {
      try {
        if (attempt > 0) await sleep(750);
        code = await inst.sock.requestPairingCode(phoneNumber);
      } catch (e) {
        lastError = e;
      }
    }
    if (!code) throw lastError || new Error('Could not generate pairing code. Try Fresh QR, then request code again.');

    inst.pairingCode = code;
    inst.pairingPhone = phoneNumber;
    inst.pairingGeneratedAt = Date.now();
    setWAInstanceStatus(inst, 'pairing', 'Enter pairing code on your phone');
    res.json({ success: true, connected: false, code, phoneNumber, status: inst.status, message: inst.statusMsg });
  } catch (error) {
    const msg = error?.message || 'Could not generate pairing code';
    res.status(500).json({ error: msg });
  }
});

