app.post('/api/wa/send-status', async (req, res) => {
  try {
    const { text, mediaUrl } = req.body || {};
    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
    if (!text && !mediaUrl) return res.status(400).json({ error: 'text or mediaUrl is required' });

    const caption = (text || '').toString();
    if (mediaUrl && typeof mediaUrl === 'string' && mediaUrl.startsWith('/uploads/')) {
      const filePath = path.join(__dirname, mediaUrl.replace(/^\/+/, ''));
      if (!fs.existsSync(filePath)) return res.status(404).json({ error: 'Media file not found' });
      const media = createMediaFromFilePath(filePath);
      await inst.client.sendMessage('status@broadcast', media, { caption });
    } else if (inst.clientKind === 'baileys' && inst.sock) {
      await inst.sock.sendMessage('status@broadcast', { text: caption });
    } else {
      await inst.client.sendMessage('status@broadcast', caption);
    }
    logs.push({ id: uuid(), type: 'status', to: 'status@broadcast', status: 'sent', message: caption || '[Media status]', time: new Date().toISOString() });
    saveJSON('logs.json', logs);
    res.json({ success: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

