async function quickJob(kind){
  document.getElementById('jobKind').value=kind;
  document.getElementById('jobName').value=kind.replace(/_/g,' ').replace(/\\b\\w/g, s=>s.toUpperCase());
  document.getElementById('jobInterval').value=kind==='daily_digest'||kind==='prayer_times'||kind==='currency_rate'?1440:60;
  if(kind==='webhook_post') document.getElementById('jobTemplate').value='📢 Channel update\\n\\nYour message here';
}
async function createAutomationJob(){
  try{
    const payload={
      name:document.getElementById('jobName').value||document.getElementById('jobKind').value,
      kind:document.getElementById('jobKind').value,
      url:document.getElementById('jobUrl').value,
      intervalMinutes:Number(document.getElementById('jobInterval').value||60),
      template:document.getElementById('jobTemplate').value,
      enabled:true
    };
    const data=await jsonFetch('/api/wa/channels/jobs',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});
    document.getElementById('automationPackLog').textContent='Job created: '+data.job.name;
    await loadAutomationPack();
  }catch(e){document.getElementById('automationPackLog').textContent='Job create failed: '+e.message;}
}
async function runAutomationJob(id){
  try{
    const data=await jsonFetch('/api/wa/channels/jobs/'+encodeURIComponent(id)+'/run',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({force:true,publishNow:true})});
    document.getElementById('automationPackLog').textContent='Job run done\\nSuccess: '+(data.success!==false)+'\\nPublished: '+(data.published===true)+(data.error?'\\nError: '+data.error:'');
    await loadAutomationPack(); await loadActivity();
  }catch(e){document.getElementById('automationPackLog').textContent='Job run failed: '+e.message;}
}
async function deleteAutomationJob(id){
  try{
    await jsonFetch('/api/wa/channels/jobs/'+encodeURIComponent(id),{method:'DELETE'});
    document.getElementById('automationPackLog').textContent='Job deleted.';
    await loadAutomationPack();
  }catch(e){document.getElementById('automationPackLog').textContent='Job delete failed: '+e.message;}
}
