app.get('/api/wa/channels/source-intelligence', (_req, res) => {
  try {
    const targets = new Set(getConfiguredWhatsAppChannels());
    const configured = new Set(getConfiguredWhatsAppChannelSources());
    const rows = rankChannelSources([
      ...new Set([
        ...getConfiguredWhatsAppChannelSources(),
        ...(Array.isArray(whatsappChannelDiscoveries) ? whatsappChannelDiscoveries : []).map(row => row.channelId).filter(id => id && !targets.has(id))
      ])
    ]).map(row => {
      const rule = sourceRule(row.channelId);
      const health = sourceHealthStatus(row.channelId);
      const paused = sourceIsPaused(row.channelId);
      const blocked = channelSourceBlacklist().some(item => item === row.channelId || `${row.name} ${row.channelId}`.toLowerCase().includes(item.toLowerCase()));
      const recommendation = paused
        ? 'Paused. Resume only if this source should feed content.'
        : health.status === 'dead'
          ? 'Dead/silent too long. Replace, pause, or run source scan.'
          : health.status === 'silent'
            ? 'Silent source. Keep watching or lower priority.'
            : blocked
              ? 'Blacklisted by source rules.'
              : 'Healthy source.';
      return {
        ...row,
        health,
        configured: configured.has(row.channelId),
        paused,
        category: sourceCategory(row.channelId, row.name),
        rule,
        recommendation,
        whitelisted: channelSourceWhitelist().length ? channelSourceWhitelist().some(item => item === row.channelId || `${row.name} ${row.channelId}`.toLowerCase().includes(item.toLowerCase())) : true,
        blacklisted: blocked
      };
    });
    const recent = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).slice(0, 100);
    const categories = recent.reduce((acc, row) => {
      const key = row.category || 'general';
      acc[key] = (acc[key] || 0) + 1;
      return acc;
    }, {});
    const trending = recent
      .filter(row => row.viralScore >= 65 || row.priority === true)
      .slice(0, 20)
      .map(channelRelayPublic);
    res.json({
      success: true,
      mode: settings.whatsapp_channel_forwarding_mode || 'priority',
      maxSources: settings.whatsapp_channel_max_sources || 60,
      sources: rows,
      categories,
      trending,
      contentGap: Object.entries(categories).sort((a, b) => a[1] - b[1]).slice(0, 5).map(([category, count]) => ({ category, count })),
      recommendations: [
        'High viralScore posts ko ASAP publish rakhein.',
        'Low category count ko content gap samjhein aur us niche ka source add karein.',
        'Trusted sources ko priority 5-10 dein, low-quality ko pause/blacklist karein.'
      ]
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

app.post('/api/wa/channels/source-intelligence', (req, res) => {
  try {
    const sourceId = normalizeWhatsAppChannelId(req.body?.sourceId || req.body?.channelId || '');
    if (!sourceId) throw new Error('sourceId is required');
    if (req.body?.priority !== undefined) settings.whatsapp_channel_source_priority[sourceId] = Math.max(0, Math.min(10, Number(req.body.priority || 0)));
    if (req.body?.category !== undefined) settings.whatsapp_channel_source_categories[sourceId] = String(req.body.category || '').trim();
    if (req.body?.routeTargets !== undefined) {
      settings.whatsapp_channel_source_routes[sourceId] = (Array.isArray(req.body.routeTargets) ? req.body.routeTargets : splitChannelList(req.body.routeTargets)).map(normalizeWhatsAppChannelId).filter(Boolean);
    }
    if (req.body?.paused !== undefined) {
      const set = new Set(Array.isArray(settings.whatsapp_channel_paused_sources) ? settings.whatsapp_channel_paused_sources : []);
      if (req.body.paused === true) set.add(sourceId);
      else set.delete(sourceId);
      settings.whatsapp_channel_paused_sources = [...set];
    }
    if (req.body?.rule !== undefined && req.body.rule && typeof req.body.rule === 'object' && !Array.isArray(req.body.rule)) {
      settings.whatsapp_channel_source_rules[sourceId] = req.body.rule;
    }
    settings.whatsapp_channel_copy_enabled = true;
    saveJSON('settings.json', settings);
    res.json({
      success: true,
      sourceId,
      priority: settings.whatsapp_channel_source_priority[sourceId] || 0,
      category: settings.whatsapp_channel_source_categories[sourceId] || '',
      routeTargets: settings.whatsapp_channel_source_routes[sourceId] || [],
      paused: sourceIsPaused(sourceId),
      rule: sourceRule(sourceId)
    });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

app.post('/api/wa/channels/control', (req, res) => {
  try {
    const action = String(req.body?.action || req.query.action || '').trim().toLowerCase();
    if (action === 'pause_all_sources') {
      settings.whatsapp_channel_paused_sources = getConfiguredWhatsAppChannelSources();
    } else if (action === 'resume_all_sources') {
      settings.whatsapp_channel_paused_sources = [];
    } else if (action === 'pause_automation') {
      settings.whatsapp_channel_copy_enabled = false;
      settings.whatsapp_channel_relay_auto_publish = false;
    } else if (action === 'resume_automation') {
      settings.whatsapp_channel_copy_enabled = true;
      settings.whatsapp_channel_relay_auto_publish = true;
    } else if (action === 'mode') {
      const mode = String(req.body?.mode || '').trim().toLowerCase();
      if (!['priority', 'round_robin', 'weighted'].includes(mode)) throw new Error('mode must be priority, round_robin, or weighted');
      settings.whatsapp_channel_forwarding_mode = mode;
    } else {
      throw new Error('Unknown action. Use pause_all_sources, resume_all_sources, pause_automation, resume_automation, or mode.');
    }
    saveJSON('settings.json', settings);
    res.json({
      success: true,
      action,
      copyEnabled: settings.whatsapp_channel_copy_enabled === true,
      autoPublish: settings.whatsapp_channel_relay_auto_publish === true,
      pausedSources: settings.whatsapp_channel_paused_sources || [],
      mode: settings.whatsapp_channel_forwarding_mode || 'priority',
      health: whatsAppChannelAutomationHealth()
    });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

app.get('/api/wa/channels/activity', (_req, res) => {
  try {
    const relayRows = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).slice(0, 80).map(channelRelayPublic);
    const relayTimeline = relayRows.map(row => ({
      type: 'relay',
      time: row.updatedAt || row.createdAt || '',
      status: row.status || 'draft',
      source: row.sourceName || row.sourceChannelId || 'unknown',
      title: row.title || String(row.message || '').slice(0, 80),
      channelIds: row.channelIds || [],
      category: row.category || '',
      engagementScore: row.engagementScore || 0,
      viralScore: row.viralScore || 0,
      reason: row.reason || row.lastError || ''
    }));
    const logRows = (Array.isArray(logs) ? logs : []).slice(-120).reverse()
      .filter(row => String(row.type || row.event || '').toLowerCase().includes('channel') || String(row.message || '').toLowerCase().includes('channel'))
      .slice(0, 40)
      .map(row => ({
        type: 'log',
        time: row.time || row.createdAt || row.ts || '',
        status: row.level || row.status || 'info',
        source: row.source || row.type || 'system',
        title: row.message || row.event || JSON.stringify(row).slice(0, 120),
        channelIds: [],
        category: '',
        engagementScore: 0,
        viralScore: 0,
        reason: row.error || ''
      }));
    const timeline = relayTimeline.concat(logRows)
      .sort((a, b) => new Date(b.time || 0).getTime() - new Date(a.time || 0).getTime())
      .slice(0, 100);
    res.json({
      success: true,
      health: whatsAppChannelAutomationHealth(),
      timeline,
      pending: relayRows.filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())).slice(0, 30),
      published: relayRows.filter(row => String(row.status || '').toLowerCase() === 'published').slice(0, 30)
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

