app.post('/api/wa/channels/relay/reorder', (req, res) => {
  try {
    const ids = Array.isArray(req.body?.ids) ? req.body.ids.map(String) : [];
    if (!ids.length) throw new Error('ids array is required');
    const rank = new Map(ids.map((id, index) => [id, index]));
    channelRelayInbox = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).slice().sort((a, b) => {
      const ai = rank.has(a.id) ? rank.get(a.id) : 999999;
      const bi = rank.has(b.id) ? rank.get(b.id) : 999999;
      if (ai !== bi) return ai - bi;
      return new Date(b.createdAt || 0).getTime() - new Date(a.createdAt || 0).getTime();
    });
    saveChannelRelayInbox();
    res.json({ success: true, relay: channelRelayInbox.slice(0, 100).map(channelRelayPublic) });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

