app.post('/api/wa/channels/posts', (req, res) => {
  try {
    const status = normalizeChannelPostStatus(req.body?.status || (req.body?.scheduledAt ? 'scheduled' : 'draft'));
    const kind = String(req.body?.kind || 'custom').trim();
    const message = String(req.body?.message || req.body?.text || '').trim();
    const channelIds = Array.isArray(req.body?.channelIds)
      ? req.body.channelIds
      : String(req.body?.channelIds || '').split(/\r?\n|,/);
    const row = {
      id: uuid(),
      title: String(req.body?.title || `${kind} channel post`).trim(),
      kind,
      status,
      message,
      mediaUrl: String(req.body?.mediaUrl || req.body?.mediaPath || '').trim(),
      templateId: req.body?.templateId || '',
      variables: req.body?.variables || {},
      channelIds: [...new Set(channelIds.map(normalizeWhatsAppChannelId).filter(Boolean))],
      scheduledAt: req.body?.scheduledAt ? new Date(req.body.scheduledAt).toISOString() : '',
      preview: buildWhatsAppChannelPreview({ kind, message, templateId: req.body?.templateId || '', variables: req.body?.variables || {} }),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    if (row.status === 'scheduled' && !row.scheduledAt) throw new Error('Scheduled post needs scheduledAt');
    if (row.status === 'draft' && !row.message && !row.mediaUrl && !row.templateId && kind === 'custom') throw new Error('Message, media or template is required');
    whatsappChannelPosts.push(row);
    saveWhatsAppChannelPosts();
    res.json({ success: true, post: channelPostPublic(row) });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

