app.get('/api/wa/contacts', async (req, res) => {
  try {
    const refresh = ['1', 'true', 'yes'].includes(String(req.query.refresh || '').toLowerCase());
    const withMeta = ['1', 'true', 'yes'].includes(String(req.query.meta || '').toLowerCase());
    const inst = waClients.get('default');
    let warning = '';
    let groups = 0;
    if (refresh) {
      if (!inst?.isReady) {
        warning = 'WhatsApp is not connected. Showing saved contacts only.';
      } else {
        try {
          const fetched = await fetchWAContactRows(inst);
          waContacts = fetched.contacts;
          groups = fetched.groups || 0;
          saveWAContacts();
        } catch (fetchError) {
          warning = `Could not fetch live contacts (${fetchError.message}). Showing saved contacts only.`;
        }
      }
    }
    let rows = waContacts || [];
    if (!rows.length) {
      rows = savedContactRowsFromCRM();
      if (rows.length && !warning) warning = 'Live WhatsApp phonebook is empty right now. Showing saved CRM/chat contacts.';
    } else {
      rows = dedupeWAContacts([...(rows || []), ...savedContactRowsFromCRM()]);
    }
    if (withMeta) {
      return res.json({
        success: !warning,
        warning,
        contacts: rows.length,
        groups,
        rows
      });
    }
    res.json(rows);
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

app.get('/api/contacts/export', (req, res) => {
  try {
    const format = String(req.query?.format || 'json').toLowerCase();
    const rows = mergedContactRows(true);
    if (format === 'csv') {
      res.setHeader('Content-Type', 'text/csv; charset=utf-8');
      res.setHeader('Content-Disposition', 'attachment; filename="superSender-contacts.csv"');
      return res.send(contactRowsToCSV(rows));
    }
    const full = ['1', 'true', 'yes'].includes(String(req.query?.all || '').toLowerCase());
    const limit = Math.max(1, Math.min(5000, Number(req.query?.limit || 1000)));
    const payloadRows = full ? rows : rows.slice(0, limit);
    res.json({
      success: true,
      count: rows.length,
      returned: payloadRows.length,
      truncated: !full && payloadRows.length < rows.length,
      rows: payloadRows
    });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

app.post('/api/contacts/sync', async (req, res) => {
  try {
    const inst = waClients.get('default');
    let groups = 0;
    let liveRows = [];
    let source = 'crm';
    if (inst?.isReady) {
      try {
        const fetched = await fetchWAContactRows(inst);
        liveRows = Array.isArray(fetched.contacts) ? fetched.contacts : [];
        groups = fetched.groups || 0;
        waContacts = liveRows;
        saveWAContacts();
        source = 'whatsapp';
      } catch (fetchError) {
        source = 'crm';
      }
    }
    const rows = mergedContactRows(true);
    res.json({
      success: true,
      source,
      groups,
      contacts: rows.length,
      liveContacts: liveRows.length,
      rows
    });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

app.post('/api/wa/contacts/reply', async (req, res) => {
  try {
    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
    const message = (req.body?.message || req.body?.text || '').toString().trim();
    if (!message) return res.status(400).json({ error: 'Message is required' });

    const rawContacts = Array.isArray(req.body?.contacts) ? req.body.contacts : [];
    const useAll = req.body?.all === true || String(req.body?.mode || '').toLowerCase() === 'all';
    const source = useAll ? (waContacts || []) : rawContacts;
    const targets = dedupeWAContacts(source.map(c => {
      if (typeof c === 'string') {
        const number = normalizeWAContactNumber(c);
        return number ? { id: `${number}@c.us`, name: number, number } : null;
      }
      const number = normalizeWAContactNumber(c);
      return number ? { ...c, number, id: c.id || `${number}@c.us`, name: c.name || number } : null;
    }).filter(Boolean)).slice(0, 300);

    if (!targets.length) return res.status(400).json({ error: 'Select at least one contact' });

    const delayMs = Math.max(300, Math.min(safetyDelayMs(Number(req.body?.delayMs || 800)), 30000));
    const results = [];
    let sent = 0;
    let failed = 0;
    for (let i = 0; i < targets.length; i++) {
      const contact = targets[i];
      const text = personalizeBulkMessage(message, contact);
      try {
        const safety = validateSafetyRecipient(contact, { context: 'contacts_reply' });
        if (!safety.allowed) throw new Error(`Safety blocked: ${safety.reasons.join(', ')}`);
        await sendDirect(contact.number, text);
        recordSafetySend(contact.number, { type: 'contacts_reply' });
        sent++;
        results.push({ number: contact.number, status: 'sent' });
        logs.push({ id: uuid(), type: 'contacts', to: contact.number, status: 'sent', message: text, time: new Date().toISOString() });
        if (!waConversations[contact.number]) waConversations[contact.number] = { step: 'main', history: [], paused: false };
        waConversations[contact.number].history = waConversations[contact.number].history || [];
        waConversations[contact.number].history.push({ role: 'bot', msg: '(Contacts reply) ' + text, time: new Date().toISOString() });
      } catch (e) {
        failed++;
        results.push({ number: contact.number, status: 'failed', error: e.message });
        logs.push({ id: uuid(), type: 'contacts', to: contact.number, status: 'failed', message: text, error: e.message, time: new Date().toISOString() });
      }
      await safetyPauseIfNeeded(i + 1);
      if (i < targets.length - 1) await sleep(delayMs);
    }
    saveJSON('logs.json', logs);
    saveConversations();
    res.json({ success: true, total: targets.length, sent, failed, results });
  } catch (e) {
    const status = /not connected|required|select at least/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

function cachedWAChatRows(inst) {
  const values = inst?.liveChats instanceof Map ? Array.from(inst.liveChats.values()) : [];
  return values.map(c => {
    const id = c?.id?._serialized || c?.id || '';
    const last = c?.lastMessage || {};
    const lastBody = last.body || last._data?.body || last.caption || '';
    const timestamp = c?.timestamp || last.timestamp || last._data?.t || 0;
    return {
      id,
      name: c?.name || c?.formattedTitle || c?.pushname || c?.subject || id,
      number: c?.id?.user || (String(id).includes('@c.us') ? String(id).split('@')[0] : ''),
      isGroup: !!c?.isGroup || String(id).includes('@g.us') || String(id).startsWith('120363'),
      unreadCount: c?.unreadCount || 0,
      timestamp,
      lastMessage: lastBody
    };
  }).filter(row => row.id);
}

