async function runGroupEventReminderSweep() {
  const now = Date.now();
  for (const event of (groupEvents || [])) {
    if (event.active === false || event.reminderSentAt) continue;
    const scheduledTs = Date.parse(event.scheduledAt || 0);
    if (!Number.isFinite(scheduledTs)) continue;
    const reminderTs = scheduledTs - (Math.max(0, Number(event.reminderMinutes || 0)) * 60 * 1000);
    if (reminderTs > now) continue;
    const msg = String(event.message || '').trim() || `Reminder: *${event.title || 'Group Event'}* is scheduled for ${String(event.scheduledAt || '').replace('T', ' ').slice(0, 16)}.`;
    try {
      await sendDirect(event.groupId, msg, { accountId: event.accountId || 'default' });
      event.reminderSentAt = new Date().toISOString();
      event.updatedAt = event.reminderSentAt;
    } catch (error) {
      event.lastError = error.message;
      event.updatedAt = new Date().toISOString();
    }
  }
  saveGroupEvents();
}

try {
  cron.schedule('*/1 * * * *', () => {
    runGroupEventReminderSweep().catch(error => console.error('Group event reminder error:', error.message));
  });
} catch (error) {
  console.warn('Group event reminder scheduler not started:', error.message);
}

function groupMembersToCSV(rows = []) {
  const headers = ['name', 'number', 'groupName', 'groupId', 'isAdmin'];
  const esc = value => {
    const text = String(value ?? '');
    return /["\n,]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
  };
  return [headers.join(','), ...rows.map(row => headers.map(key => esc(row[key])).join(','))].join('\n');
}

function groupMembersToVCF(rows = []) {
  return rows.map(row => {
    const name = String(row.name || row.number || 'WhatsApp Contact').replace(/\r?\n/g, ' ').trim();
    const number = String(row.number || '').replace(/\D/g, '');
    return [
      'BEGIN:VCARD',
      'VERSION:3.0',
      `FN:${name}`,
      number ? `TEL;TYPE=CELL:+${number}` : '',
      `NOTE:Imported from ${String(row.groupName || 'WhatsApp Group').replace(/\r?\n/g, ' ')}`,
      'END:VCARD'
    ].filter(Boolean).join('\n');
  }).join('\n');
}

async function getGroupMembersForExport(groupId = '', accountId = 'default') {
  const inst = waClients.get(String(accountId || 'default').trim() || 'default');
  if (!inst?.isReady) throw new Error('WhatsApp not connected');
  const chat = await getWAChatByAnyId(inst, groupId);
  if (!chat?.isGroup) throw new Error('Not a group chat');
  const rows = [];
  for (const p of (chat.participants || [])) {
    const pid = p.id?._serialized || p.id || '';
    let c = null;
    try { c = await inst.client.getContactById(pid); } catch {}
    rows.push({
      id: pid,
      number: c?.number || p.id?.user || String(pid).split('@')[0].replace(/\D/g, ''),
      name: c?.pushname || c?.name || c?.number || (p.id?.user ? ('+' + p.id.user) : pid),
      isAdmin: !!p.isAdmin || !!p.isSuperAdmin,
      groupId: chat.id?._serialized || groupId,
      groupName: chat.name || chat.formattedTitle || chat.subject || 'Group'
    });
  }
  return rows;
}

