const groupMemberSendJobs = new Map();

async function runGroupMemberSendJob(job) {
  groupMemberSendJobs.set(job.id, job);
  try {
    const rows = job.members.slice(0, job.limit);
    for (const member of rows) {
      if (job.status === 'paused') {
        while (job.status === 'paused') await sleep(1000);
      }
      if (job.status === 'stopped') break;
      try {
        const context = buildCustomerMessageContext(member.number, {
          ...member,
          name: member.name || member.number,
          number: member.number,
          groupName: member.groupName,
          groupId: member.groupId
        });
        const text = renderDynamicTemplate(job.message, context);
        const safety = validateSafetyRecipient({ number: member.number, name: member.name }, { context: 'group_member_dm' });
        if (!safety.allowed) throw new Error(`Safety blocked: ${safety.reasons.join(', ')}`);
        await sendDirect(member.number, text, { preferredAccountId: job.accountId || 'default', disableRotation: true });
        recordSafetySend(member.number, { type: 'group_member_dm', groupId: member.groupId });
        job.sent.push({ number: member.number, name: member.name });
      } catch (error) {
        job.failed.push({ number: member.number, name: member.name, error: error.message });
      }
      job.updatedAt = new Date().toISOString();
      io.emit('group_member_send_progress', job);
      await sleep(job.delayMs);
    }
    job.status = job.status === 'stopped' ? 'stopped' : 'completed';
  } catch (error) {
    job.status = 'failed';
    job.error = error.message;
  } finally {
    job.finishedAt = new Date().toISOString();
    logs.push({
      id: uuid(),
      type: 'group_member_send',
      groupId: job.groupId,
      groupName: job.groupName,
      sent: job.sent.length,
      failed: job.failed.length,
      total: job.total,
      status: job.status,
      time: job.finishedAt
    });
    saveJSON('logs.json', logs);
    io.emit('group_member_send_progress', job);
  }
}

app.post('/api/groups/:id/members/send', async (req, res) => {
  try {
    const message = String(req.body?.message || '').trim();
    if (!message) return res.status(400).json({ error: 'message is required' });
    const requestedLimit = Number(req.body?.limit || 50);
    const limit = Math.min(200, Math.max(1, Number.isFinite(requestedLimit) ? requestedLimit : 50));
    const requestedDelay = Number(req.body?.delayMs || req.body?.delay || 3000);
    const delayMs = Math.max(3000, Number.isFinite(requestedDelay) ? requestedDelay : 3000);
    const members = await getGroupMembersForExport(req.params.id);
    const selected = members
      .filter(m => normalizeNumber(m.number))
      .filter(m => !m.isAdmin || req.body?.includeAdmins === true)
      .slice(0, limit);
    if (req.body?.dryRun === true) {
      const previews = selected.slice(0, 5).map(member => ({
        number: member.number,
        name: member.name,
        message: renderDynamicTemplate(message, buildCustomerMessageContext(member.number, member))
      }));
      return res.json({ success: true, dryRun: true, total: selected.length, previews });
    }
    const job = {
      id: uuid(),
      status: 'queued',
      accountId: String(req.body?.accountId || 'default').trim() || 'default',
      groupId: req.params.id,
      groupName: selected[0]?.groupName || req.params.id,
      message,
      total: selected.length,
      limit,
      delayMs,
      members: selected,
      sent: [],
      failed: [],
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    res.json({ success: true, queued: selected.length, jobId: job.id, delayMs });
    job.status = 'running';
    setImmediate(() => runGroupMemberSendJob(job));
  } catch (e) {
    const status = /not connected|not a group/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

