app.post('/api/groups/fetch-post', async (req, res) => {
  try {
    const accountId = String(req.body?.accountId || 'default').trim() || 'default';
    const inst = waClients.get(accountId);
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
    const groupIds = Array.isArray(req.body?.groupIds)
      ? req.body.groupIds
      : String(req.body?.groupIds || req.body?.groups || '').split(',').map(x => x.trim()).filter(Boolean);
    const uniqueGroupIds = [...new Set(groupIds)];
    if (!uniqueGroupIds.length) return res.status(400).json({ error: 'groupIds are required' });
    const message = String(req.body?.message || '').trim();
    const mediaTarget = resolveGroupMediaPath(req.body?.mediaUrl || req.body?.mediaPath || '');
    const exportMembers = req.body?.exportMembers === true;
    const syncContacts = req.body?.syncContacts === true;
    if (!message && !mediaTarget) return res.status(400).json({ error: 'message or media is required' });

    const sent = [];
    const failed = [];
    let exportedMembers = [];
    let syncedContacts = 0;
    const newCustomers = [];
    const existingNumbers = new Set(customers.map(c => normalizeNumber(c.number || c.phone || c.whatsapp || c.customerNumber || '')));

    for (const groupId of uniqueGroupIds) {
      try {
        const chat = await getWAChatByAnyId(inst, groupId);
        const chatId = chat?.id?._serialized || groupId;
        const groupName = chat?.name || chat?.formattedTitle || chat?.subject || groupId;
        if (mediaTarget) {
          const media = createMediaFromFilePath(mediaTarget);
          await inst.client.sendMessage(chatId, media, { caption: message || '' });
        } else {
          await inst.client.sendMessage(chatId, message);
        }
        sent.push({ groupId: chatId, groupName });
        if (exportMembers || syncContacts) {
          const members = await getGroupMembersForExport(chatId, accountId);
          exportedMembers = exportedMembers.concat(members);
          if (syncContacts) {
            for (const member of members) {
              const clean = normalizeNumber(member.number || '');
              if (!clean || existingNumbers.has(clean)) continue;
              existingNumbers.add(clean);
              newCustomers.push({
                id: uuid(),
                name: member.name || clean,
                number: clean,
                status: 'lead',
                tags: ['Group Sync'],
                source: 'group_fetch_post',
                created: new Date().toISOString()
              });
            }
          }
        }
        await sleep(1500);
      } catch (error) {
        failed.push({ groupId, error: error.message });
      }
    }

    if (newCustomers.length) {
      customers.unshift(...newCustomers);
      customers = customers.slice(0, 10000);
      saveJSON('customers.json', customers);
      syncedContacts = newCustomers.length;
    }

    res.json({
      success: true,
      accountId,
      sent,
      failed,
      exportedMembers: exportedMembers.length,
      syncedContacts
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

function defaultGroupMessageTemplates() {
  return [
    {
      id: 'dealer-stock-request',
      name: 'Dealer Stock Request',
      body: 'Assalam o Alaikum!\n{{tool}} stock required hai.\nQty: {{qty}}\nType: {{type}}\nPrice aur warranty details please share karein.'
    },
    {
      id: 'daily-rates-group',
      name: 'Daily Rates Group Post',
      body: 'ðŸ¤– *{{business}} â€” Aaj ke Rates*\n\n{{rates}}\n\nOrder/availability ke liye DM karein.'
    },
    {
      id: 'channel-cross-post',
      name: 'Channel Cross Post',
      body: '{{message}}\n\nðŸ“£ Channel updates bhi follow karein.'
    }
  ];
}

function ensureGroupMessageTemplates() {
  if (!Array.isArray(groupMessageTemplates) || !groupMessageTemplates.length) {
    groupMessageTemplates = defaultGroupMessageTemplates();
    saveGroupMessageTemplates();
  }
  return groupMessageTemplates;
}

function applyGroupMessageTemplate(body = '', vars = {}) {
  const values = {
    business: storeDisplayName(),
    date: channelDateLabel(),
    rates: channelRatesText(10),
    products: channelProductsText(8),
    tool: vars.tool || 'AI Tool',
    qty: vars.qty || 'as available',
    type: vars.type || 'Private/Warranty',
    message: vars.message || '',
    ...vars
  };
  return String(body || '').replace(/\{\{\s*([\w.-]+)\s*\}\}/g, (_all, key) => {
    const value = values[key];
    return value === undefined || value === null ? '' : String(value);
  }).trim();
}

function buildGroupDistributionPreview({ message = '', templateId = '', variables = {} } = {}) {
  if (templateId) {
    const template = ensureGroupMessageTemplates().find(row => row.id === templateId);
    if (template?.body) return applyGroupMessageTemplate(template.body, { ...variables, message });
  }
  return applyGroupMessageTemplate(message || '{{rates}}', variables);
}

function groupDistributionPublic(row = {}) {
  return {
    id: row.id,
    title: row.title || '',
    status: row.status || 'draft',
    message: row.message || '',
    preview: row.preview || row.message || '',
    groupIds: Array.isArray(row.groupIds) ? row.groupIds : [],
    targetMode: row.targetMode || 'selected',
    mediaUrl: row.mediaUrl || '',
    crossPostChannel: row.crossPostChannel === true,
    exportMembers: row.exportMembers === true,
    syncContacts: row.syncContacts === true,
    scheduledAt: row.scheduledAt || '',
    sentAt: row.sentAt || '',
    createdAt: row.createdAt || '',
    updatedAt: row.updatedAt || '',
    result: row.result || null,
    error: row.error || ''
  };
}

async function sendGroupDistributionPost(post = {}) {
  const accountId = String(post.accountId || 'default').trim() || 'default';
  const inst = waClients.get(accountId);
  if (!inst?.isReady) throw new Error('WhatsApp not connected');
  const message = buildGroupDistributionPreview({
    message: post.message,
    templateId: post.templateId,
    variables: post.variables || {}
  });
  let groupIds = Array.isArray(post.groupIds) ? post.groupIds.filter(Boolean) : [];
  if (post.targetMode === 'all') {
    const listed = await listWhatsAppGroups(accountId);
    groupIds = (listed.groups || listed || []).map(g => g.id || g.groupId).filter(Boolean);
  }
  groupIds = [...new Set(groupIds)];
  if (!groupIds.length) throw new Error('No groups selected');
  const sent = [];
  const failed = [];
  let exportedMembers = 0;
  let syncedContacts = 0;
  const mediaTarget = resolveGroupMediaPath(post.mediaUrl || post.mediaPath || '');
  const existingNumbers = new Set(customers.map(c => normalizeNumber(c.number || c.phone || c.whatsapp || c.customerNumber || '')));
  for (const groupId of groupIds) {
    try {
      const chat = await getWAChatByAnyId(inst, groupId);
      const chatId = chat?.id?._serialized || groupId;
      const groupName = chat?.name || chat?.formattedTitle || chat?.subject || groupId;
      if (mediaTarget) {
        const media = createMediaFromFilePath(mediaTarget);
        await inst.client.sendMessage(chatId, media, { caption: message });
      } else {
        await inst.client.sendMessage(chatId, message);
      }
      sent.push({ groupId: chatId, groupName });
      if (post.exportMembers || post.syncContacts) {
        const members = await getGroupMembersForExport(chatId, accountId);
        exportedMembers += members.length;
        if (post.syncContacts) {
          for (const member of members) {
            const clean = normalizeNumber(member.number || '');
            if (!clean || existingNumbers.has(clean)) continue;
            existingNumbers.add(clean);
            customers.unshift({
              id: uuid(),
              name: member.name || clean,
              number: clean,
              status: 'lead',
              tags: ['Group Sync'],
              source: 'group_distribution',
              created: new Date().toISOString()
            });
            syncedContacts++;
          }
        }
      }
      await sleep(Math.max(1000, Number(post.delayMs || 2000)));
    } catch (error) {
      failed.push({ groupId, error: error.message });
    }
  }
  if (syncedContacts) saveJSON('customers.json', customers.slice(0, 10000));
  let channelResult = null;
  if (post.crossPostChannel === true) {
    channelResult = await shareDataToWhatsAppChannels({ message, kind: 'custom', delayMs: 2000, useRotation: true }).catch(error => ({ success: false, error: error.message }));
  }
  const result = { success: failed.length === 0, sent, failed, exportedMembers, syncedContacts, channelResult, message };
  post.status = failed.length ? 'failed' : 'sent';
  post.sentAt = new Date().toISOString();
  post.updatedAt = post.sentAt;
  post.preview = message;
  post.result = result;
  post.error = failed.map(f => `${f.groupId}: ${f.error}`).join('; ');
  logs.push({ id: uuid(), type: 'group_distribution_post', status: post.status, sent: sent.length, failed: failed.length, message, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  saveGroupDistributionPosts();
  return groupDistributionPublic(post);
}

async function processDueGroupDistributionPosts() {
  const now = Date.now();
  const due = (Array.isArray(groupDistributionPosts) ? groupDistributionPosts : [])
    .filter(row => row.status === 'scheduled' && row.scheduledAt && Date.parse(row.scheduledAt) <= now)
    .slice(0, 5);
  const processed = [];
  for (const post of due) {
    try {
      processed.push(await sendGroupDistributionPost(post));
    } catch (error) {
      post.status = 'failed';
      post.error = error.message;
      post.updatedAt = new Date().toISOString();
      processed.push(groupDistributionPublic(post));
    }
  }
  if (processed.length) saveGroupDistributionPosts();
  return { success: true, processed };
}

