function decodeHtmlEntities(text = '') {
  return String(text)
    .replace(/&#x([0-9a-f]+);/gi, (_, hex) => String.fromCodePoint(parseInt(hex, 16)))
    .replace(/&#(\d+);/g, (_, code) => String.fromCodePoint(parseInt(code, 10)))
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
}

function stripHTML(text = '') {
  return decodeHtmlEntities(text)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/(p|li|div|ul|ol|h[1-6])>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function wooMoney(prices = {}, key = 'price') {
  const raw = Number(prices?.[key] || 0);
  const minor = Number.isFinite(Number(prices?.currency_minor_unit)) ? Number(prices.currency_minor_unit) : 2;
  return raw ? Math.round(raw / Math.pow(10, minor)) : 0;
}

function inferBrand(product, categories = []) {
  const text = [product?.name, ...(categories || []).map(c => c.name)].join(' ').toLowerCase();
  const brands = ['dell', 'hp', 'lenovo', 'apple', 'macbook', 'acer', 'asus', 'toshiba', 'microsoft', 'surface'];
  const found = brands.find(brand => text.includes(brand));
  if (!found) return '';
  return found === 'macbook' ? 'Apple' : found.charAt(0).toUpperCase() + found.slice(1);
}

function inferSubcategory(product, description) {
  const text = [product?.name, description].join(' ').toLowerCase();
  if (/gaming|rtx|gtx|nvidia|radeon/.test(text)) return 'gaming';
  if (/workstation|precision|xeon|quadro/.test(text)) return 'workstation';
  if (/student|school|basic|budget/.test(text)) return 'student';
  return 'business';
}

function mapWooProductToCatalog(product, sourceHost) {
  const categories = Array.isArray(product.categories) ? product.categories : [];
  const shortDescription = stripHTML(product.short_description || '');
  const description = stripHTML(product.description || '');
  const fullDescription = [shortDescription, description].filter(Boolean).join(' ');
  const images = Array.isArray(product.images) ? product.images : [];
  const gallery = images.map(img => img?.src || img?.thumbnail).filter(Boolean);
  const price = wooMoney(product.prices, 'price') || wooMoney(product.prices, 'sale_price') || wooMoney(product.prices, 'regular_price');
  const regularPrice = wooMoney(product.prices, 'regular_price') || price;

  return {
    id: `its-${product.id}`,
    source: sourceHost,
    sourceProductId: String(product.id),
    name: decodeHtmlEntities(product.name || '').trim(),
    category: 'laptops',
    subcategory: inferSubcategory(product, fullDescription),
    price,
    regularPrice,
    currency: product.prices?.currency_code || 'PKR',
    brand: inferBrand(product, categories),
    condition: 'Imported / Used',
    specs: fullDescription.slice(0, 500),
    description: fullDescription.slice(0, 1800),
    image: gallery[0] || '',
    gallery,
    url: product.permalink || '',
    stock: product.is_in_stock !== false,
    sku: product.sku || '',
    onSale: !!product.on_sale,
    tags: ['infinity-import', sourceHost, ...categories.map(c => c.name).filter(Boolean)],
    importedAt: new Date().toISOString()
  };
}

async function fetchWooStoreProducts(storeUrl) {
  const root = new URL(storeUrl || 'https://infinitytouchstore.com/');
  const sourceHost = root.hostname.replace(/^www\./, '');
  const imported = [];

  for (let page = 1; page <= 20; page += 1) {
    const endpoint = new URL('/wp-json/wc/store/v1/products', root.origin);
    endpoint.searchParams.set('per_page', '100');
    endpoint.searchParams.set('page', String(page));
    const batch = await fetchStoreProductsPage(endpoint.toString());
    if (!Array.isArray(batch) || !batch.length) break;
    imported.push(...batch.map(product => mapWooProductToCatalog(product, sourceHost)));
    if (batch.length < 100) break;
  }

  return { products: imported, sourceHost };
}

async function fetchStoreProductsPage(endpoint) {
  let lastError = null;
  for (let attempt = 0; attempt < 2; attempt += 1) {
    try {
      const response = await fetch(endpoint, { headers: { accept: 'application/json' } });
      if (!response.ok) throw new Error(`Store API returned ${response.status}`);
      return await response.json();
    } catch (error) {
      lastError = error;
      await sleep(500 * (attempt + 1));
    }
  }

  if (process.platform === 'win32') {
    const escapedEndpoint = endpoint.replace(/'/g, "''");
    const script = `$ProgressPreference='SilentlyContinue'; (Invoke-WebRequest -UseBasicParsing -Uri '${escapedEndpoint}' -TimeoutSec 45).Content`;
    try {
      const out = execFileSync('powershell.exe', ['-NoProfile', '-ExecutionPolicy', 'Bypass', '-Command', script], {
        encoding: 'utf8',
        maxBuffer: 30 * 1024 * 1024
      });
      return JSON.parse(out);
    } catch (error) {
      throw new Error(`Store fetch failed: ${lastError?.message || 'fetch failed'}; PowerShell fallback failed: ${error.message}`);
    }
  }

  throw lastError || new Error('Store fetch failed');
}

app.post('/api/products/import-store', async (req, res) => {
  try {
    const storeUrl = req.body?.storeUrl || 'https://infinitytouchstore.com/';
    const replaceCatalog = req.body?.replaceCatalog === true;
    const { products: imported, sourceHost } = await fetchWooStoreProducts(storeUrl);
    if (!imported.length) return res.status(400).json({ error: 'No products found on store API' });

    let added = 0;
    let updated = 0;
    if (replaceCatalog) {
      laptopProducts = imported;
      added = imported.length;
    } else {
      const byKey = new Map(laptopProducts.map((p, index) => [`${p.source || ''}:${p.sourceProductId || p.id || p.url || index}`, index]));
      for (const item of imported) {
        const key = `${item.source}:${item.sourceProductId}`;
        const existingIndex = byKey.get(key);
        if (existingIndex === undefined) {
          laptopProducts.push(item);
          added += 1;
        } else {
          laptopProducts[existingIndex] = { ...laptopProducts[existingIndex], ...item, updated: new Date().toISOString() };
          updated += 1;
        }
      }
    }

    if (req.body?.trainBot !== false) {
      settings.business_name = req.body?.businessName || 'Infinity Touch Store';
      settings.laptop_bot_enabled = true;
      saveJSON('settings.json', settings);
    }
    saveJSON('laptop_products.json', laptopProducts);

    res.json({
      success: true,
      source: sourceHost,
      fetched: imported.length,
      added,
      updated,
      total: laptopProducts.length,
      inStock: laptopProducts.filter(p => p.stock !== false).length,
      botTrained: req.body?.trainBot !== false
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

