function filterProducts(list, query = {}) {
  const search = (query.search || '').toString().trim().toLowerCase();
  const sub = (query.sub || query.subcategory || '').toString().trim().toLowerCase();
  return (Array.isArray(list) ? list : []).filter(p => {
    if (search) {
      const hay = [p.name, p.brand, p.specs, p.condition, p.category, p.subcategory].join(' ').toLowerCase();
      if (!hay.includes(search)) return false;
    }
    if (sub && (p.subcategory || '').toString().toLowerCase() !== sub) return false;
    return true;
  });
}

function formatProductShareMessage(product, note = '') {
  const price = Number(product.price || 0);
  const orderLink = buildProductOrderLink(product);
  const lines = [
    `*${product.name || 'Product'}*`,
    price ? `Price: Rs. ${price.toLocaleString()}` : '',
    product.condition ? `Condition: ${product.condition}` : '',
    product.stock === false ? 'Stock: Out of stock' : 'Stock: Available',
    product.specs ? `Details: ${String(product.specs).replace(/\s+/g, ' ').slice(0, 900)}` : '',
    product.url ? `Product link: ${product.url}` : '',
    orderLink ? `Order now: ${orderLink}` : '',
    product.image && !product.url ? `Image: ${product.image}` : '',
    note ? `\n${note}` : ''
  ].filter(Boolean);
  return lines.join('\n');
}

function formatProductImageCaption(product = {}) {
  const price = Number(product.price || 0);
  return [
    `*${product.name || 'Product'}*`,
    price ? `Rs. ${price.toLocaleString()}` : '',
    product.stock === false ? 'Out of stock' : 'Available'
  ].filter(Boolean).join('\n').slice(0, 900);
}

async function sendProductPictureAndDetails(number, media, detailsText, product = {}, options = {}) {
  await sendDirectMedia(number, media, formatProductImageCaption(product), options);
  const finalText = String(detailsText || '').trim();
  if (finalText) {
    await sleep(Number(process.env.PRODUCT_TEXT_SEND_DELAY_MS || 1200));
    try {
      await sendDirect(number, finalText, options);
    } catch (error) {
      console.warn('[Products] Retrying text message after media send:', error.message);
      await sleep(1200);
      await sendDirect(number, finalText, options);
    }
  }
}

function getAdminWhatsAppNumber() {
  return normalizeNumber(settings.owner_whatsapp || settings.support_whatsapp || process.env.ADMIN_NUMBER || '');
}

function buildProductOrderLink(product = {}) {
  const adminNumber = getAdminWhatsAppNumber();
  if (!adminNumber) return '';
  const price = Number(product.price || 0);
  const message = [
    'Assalam o Alaikum, mujhe is product ka order/book karna hai:',
    product.name || 'Product',
    price ? `Price: Rs. ${price.toLocaleString()}` : '',
    product.url ? `Link: ${product.url}` : ''
  ].filter(Boolean).join('\n');
  return `https://wa.me/${adminNumber}?text=${encodeURIComponent(message)}`;
}

function productRecipientFromCustomer(customer = {}) {
  const number = normalizeNumber(customer.number || customer.phone || customer.whatsapp || customer.customerNumber || customer.mobile);
  if (!number) return null;
  return {
    number,
    name: customer.name || customer.customerName || customer.fullName || number,
    customerId: customer.id || '',
    source: 'customer'
  };
}

function customerMatchesBulkSegment(customer = {}, segment = 'all') {
  const s = String(segment || 'all').toLowerCase();
  const tags = (Array.isArray(customer.tags) ? customer.tags : []).map(t => String(t || '').toLowerCase());
  const status = String(customer.status || '').toLowerCase();
  const isBlocked = status === 'blocked' || tags.includes('blocked');
  if (s !== 'blocked' && isBlocked) return false;
  if (s === 'all' || s === 'customers') return true;
  if (s === 'leads' || s === 'lead') return status === 'lead';
  if (s === 'active' || s === 'regular') return status === 'active' || tags.includes('regular');
  if (s === 'hot' || s === 'hot-leads' || s === 'hot lead') return tags.includes('hot lead') || tags.includes('hot');
  if (s === 'vip') return tags.includes('vip');
  if (s === 'blocked') return isBlocked;
  return status === s || tags.includes(s);
}

function parseBulkNumbers(value) {
  if (Array.isArray(value)) return value;
  return String(value || '')
    .split(/[\s,;]+/)
    .map(v => v.trim())
    .filter(Boolean);
}

function resolveProductBulkRecipients(body = {}) {
  const direct = [];
  if (Array.isArray(body.contacts)) {
    for (const c of body.contacts) {
      const number = normalizeNumber(c?.number || c?.phone || c?.whatsapp || c?.customerNumber || c);
      if (number) direct.push({ number, name: c?.name || c?.customerName || number, source: 'manual' });
    }
  }
  for (const raw of parseBulkNumbers(body.numbers || body.numberList || body.to)) {
    const number = normalizeNumber(raw);
    if (number) direct.push({ number, name: number, source: 'manual' });
  }

  const segment = body.segment || 'all';
  const selected = direct.length
    ? direct
    : customers
        .filter(c => customerMatchesBulkSegment(c, segment))
        .map(productRecipientFromCustomer)
        .filter(Boolean);

  const seen = new Set();
  const recipients = [];
  for (const contact of selected) {
    const key = normalizeNumber(contact.number);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    recipients.push({ ...contact, number: key });
  }
  const limit = Math.max(0, Math.min(Number(body.limit || recipients.length) || recipients.length, 1000));
  return limit ? recipients.slice(0, limit) : recipients;
}

function rememberProductBulkConversation(number, text, sentWithImage) {
  if (!waConversations[number]) waConversations[number] = { step: 'main', history: [], paused: false };
  waConversations[number].history = waConversations[number].history || [];
  waConversations[number].history.push({
    role: 'bot',
    msg: (sentWithImage ? '(Bulk product image sent) ' : '(Bulk product sent) ') + text,
    time: new Date().toISOString()
  });
  if (waConversations[number].history.length > 80) {
    waConversations[number].history = waConversations[number].history.slice(-80);
  }
}

function updateProductBulkJob(jobId, patch = {}) {
  const idx = productBulkSends.findIndex(j => j.id === jobId);
  if (idx < 0) return null;
  productBulkSends[idx] = {
    ...productBulkSends[idx],
    ...patch,
    updated: new Date().toISOString()
  };
  saveJSON('bulk_sends.json', productBulkSends);
  io.emit('product_bulk_progress', productBulkSends[idx]);
  return productBulkSends[idx];
}

async function runProductBulkSend(jobId, productSnapshot, recipients, note, delayMs, requireImage) {
  const text = formatProductShareMessage(productSnapshot, note);
  let media = null;
  try {
    updateProductBulkJob(jobId, { status: 'running', message: 'Sending product catalog...' });
    if (productSnapshot.image) {
      media = await createMediaFromSource(productSnapshot.image);
    } else if (requireImage) {
      throw new Error('Product image is missing. Add product picture before bulk send.');
    }

    for (let i = 0; i < recipients.length; i++) {
      const contact = recipients[i];
      try {
        const safety = validateSafetyRecipient(contact, { context: 'product_bulk', productId: productSnapshot.id });
        if (!safety.allowed) throw new Error(`Safety blocked: ${safety.reasons.join(', ')}`);
        if (media) {
          await sendProductPictureAndDetails(contact.number, media, text, productSnapshot, { useRotation: true });
        } else {
          await sendDirect(contact.number, text, { useRotation: true });
        }
        recordSafetySend(contact.number, { type: 'product_bulk', productId: productSnapshot.id });
        rememberProductBulkConversation(contact.number, text, !!media);
        const current = productBulkSends.find(j => j.id === jobId) || {};
        updateProductBulkJob(jobId, {
          sent: Number(current.sent || 0) + 1,
          lastNumber: contact.number,
          progress: Math.round(((i + 1) / recipients.length) * 100)
        });
        if (typeof logs !== 'undefined') {
          logs.push({ id: uuid(), type: 'product_bulk', to: contact.number, status: 'sent', productId: productSnapshot.id, message: text, time: new Date().toISOString() });
        }
      } catch (error) {
        const current = productBulkSends.find(j => j.id === jobId) || {};
        const errors = Array.isArray(current.errors) ? current.errors.slice(-14) : [];
        errors.push({ number: contact.number, error: error.message });
        updateProductBulkJob(jobId, {
          failed: Number(current.failed || 0) + 1,
          lastNumber: contact.number,
          errors,
          progress: Math.round(((i + 1) / recipients.length) * 100)
        });
        if (typeof logs !== 'undefined') {
          logs.push({ id: uuid(), type: 'product_bulk', to: contact.number, status: 'failed', productId: productSnapshot.id, error: error.message, time: new Date().toISOString() });
        }
      }
      await safetyPauseIfNeeded(i + 1);
      if (i < recipients.length - 1) await sleep(delayMs);
    }
    saveConversations();
    if (typeof logs !== 'undefined') saveJSON('logs.json', logs);
    const finalJob = productBulkSends.find(j => j.id === jobId) || {};
    const status = Number(finalJob.failed || 0) ? 'completed_with_errors' : 'completed';
    updateProductBulkJob(jobId, { status, message: 'Bulk product send complete', completed: new Date().toISOString(), progress: 100 });
    const adminNumber = getAdminWhatsAppNumber();
    if (adminNumber) {
      try {
        await sendDirect(adminNumber, `Product bulk send complete\n\nProduct: ${productSnapshot.name}\nSent: ${finalJob.sent || 0}/${recipients.length}\nFailed: ${finalJob.failed || 0}`);
      } catch {}
    }
  } catch (error) {
    updateProductBulkJob(jobId, { status: 'failed', message: error.message, error: error.message, completed: new Date().toISOString() });
  }
}

async function notifyAdminStockAlert(product) {
  const adminNumber = getAdminWhatsAppNumber();
  const message = [
    '*Stock Alert*',
    `${product.name || 'Product'} is now out of stock.`,
    Number(product.price || 0) ? `Price: Rs. ${Number(product.price || 0).toLocaleString()}` : '',
    product.condition ? `Condition: ${product.condition}` : '',
    product.url ? `Link: ${product.url}` : ''
  ].filter(Boolean).join('\n');

  const alert = {
    id: uuid(),
    type: 'stock',
    title: 'Product out of stock',
    productId: product.id,
    productName: product.name,
    message,
    time: new Date().toISOString()
  };
  try {
    if (typeof alerts !== 'undefined') {
      alerts.unshift(alert);
      alerts = alerts.slice(0, 200);
      saveJSON('alerts.json', alerts);
    }
    io.emit('alert', alert);
  } catch {}

  if (!adminNumber || !waClients.get('default')?.isReady) return false;
  if (product.image) {
    try {
      const media = await createMediaFromSource(product.image);
      await sendDirectMedia(adminNumber, media, message);
      return true;
    } catch {}
  }
  await sendDirect(adminNumber, message);
  return true;
}

