app.post('/api/products/:id/send', async (req, res) => {
  try {
    const p = laptopProducts.find(x => x.id === req.params.id);
    if (!p) return res.status(404).json({ error: 'Product not found' });
    const number = normalizeNumber(req.body?.number || req.body?.phone || req.body?.to);
    if (!number) return res.status(400).json({ error: 'Customer WhatsApp number is required' });
    const inst = waClients.get('default');
    if (!inst?.isReady) throw new Error('WhatsApp not connected');
    const text = formatProductShareMessage(p, req.body?.message || req.body?.note || '');
    const requireImage = req.body?.requireImage !== false;
    let sentWithImage = false;

    if (p.image) {
      const media = await createMediaFromSource(p.image);
      await sendProductPictureAndDetails(number, media, text, p);
      sentWithImage = true;
    } else if (requireImage) {
      throw new Error('Product image is missing. Add product picture before sending.');
    } else {
      await sendDirect(number, text);
    }

    if (!waConversations[number]) waConversations[number] = { step: 'main', history: [], paused: false };
    waConversations[number].history = waConversations[number].history || [];
    waConversations[number].history.push({
      role: 'bot',
      msg: (sentWithImage ? '(Product image sent) ' : '(Product sent) ') + text,
      time: new Date().toISOString()
    });
    saveConversations();
    queueWebhookEvent('message_sent', { number, message: text, productId: p.id, sentWithImage, source: 'product_catalog' });
    res.json({ success: true, number, productId: p.id, sentWithImage, image: p.image || null, message: text });
  } catch (e) {
    const status = /not connected|required|missing|invalid|not found|not an image/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});
app.post('/api/products/:id/bulk-send', async (req, res) => {
  try {
    const p = laptopProducts.find(x => x.id === req.params.id);
    if (!p) return res.status(404).json({ error: 'Product not found' });
    const inst = waClients.get('default');
    if (!inst?.isReady) throw new Error('WhatsApp not connected');

    const requireImage = req.body?.requireImage !== false;
    if (requireImage && !p.image) throw new Error('Product image is missing. Add product picture before bulk send.');

    const recipients = resolveProductBulkRecipients(req.body || {});
    if (!recipients.length) return res.status(400).json({ error: 'No recipients found. Add customers or paste WhatsApp numbers.' });
    const safetyCheck = filterSafetyRecipients(recipients, { context: 'product_bulk_queue', productId: p.id });
    if (!safetyCheck.valid.length) {
      return res.status(400).json({
        error: 'All recipients were blocked by Safety Center',
        blocked: safetyCheck.blocked.map(x => ({ number: x.number, reasons: x.safety?.reasons || [] }))
      });
    }

    const delayMs = Math.max(250, Math.min(safetyDelayMs(Number(req.body?.delayMs || req.body?.delay || 900) || 900), 30000));
    const job = {
      id: uuid(),
      type: 'product_bulk',
      productId: p.id,
      productName: p.name || 'Product',
      segment: req.body?.segment || (req.body?.numbers ? 'manual' : 'all'),
      total: safetyCheck.valid.length,
      sent: 0,
      failed: safetyCheck.blocked.length,
      safetyBlocked: safetyCheck.blocked.slice(0, 30).map(x => ({ number: x.number, reasons: x.safety?.reasons || [] })),
      progress: 0,
      status: 'queued',
      requireImage,
      delayMs,
      errors: [],
      created: new Date().toISOString(),
      updated: new Date().toISOString()
    };
    productBulkSends.unshift(job);
    productBulkSends = productBulkSends.slice(0, 100);
    saveJSON('bulk_sends.json', productBulkSends);
    setImmediate(() => runProductBulkSend(job.id, { ...p }, safetyCheck.valid, req.body?.message || req.body?.note || '', delayMs, requireImage));
    res.json({ success: true, queued: safetyCheck.valid.length, blocked: safetyCheck.blocked.length, job });
  } catch (e) {
    const status = /not connected|required|missing|invalid|not found|recipients/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});
