app.get('/api/diagnostics/idle-followups', (req, res) => {
  try {
    const now = Date.now();
    const items = Object.entries(waConversations || {})
      .map(([number, conv]) => {
        if (shouldSkipLaptopFollowupNumber(number)) return null;
        const idle = conv?.botData?.idleFollowup;
        if (!idle) return null;
        const dueAtMs = Date.parse(idle.dueAt || '');
        return {
          number,
          bot: idle.bot,
          section: idle.section,
          title: idle.title || '',
          dueAt: idle.dueAt || '',
          sent: !!idle.sent,
          secondsRemaining: Number.isFinite(dueAtMs) ? Math.max(0, Math.ceil((dueAtMs - now) / 1000)) : null
        };
      })
      .filter(Boolean)
      .sort((a, b) => String(a.dueAt).localeCompare(String(b.dueAt)));
    res.json({ ok: true, delayMs: BOT_IDLE_FOLLOWUP_DELAY_MS, pending: items.filter(item => !item.sent), all: items });
  } catch (error) {
    res.status(500).json({ ok: false, error: error.message });
  }
});

function buildCockpitTemplateMessage(type, name = storeDisplayName()) {
  const normalized = String(type || '').toLowerCase();
  const templates = {
    menu: buildMainWelcomeMenu(name),
    'ai-tools': buildAIToolsMenu(),
    laptops: buildLaptopEntryReply(),
    scholarship: scholarshipBot.DEGREE_MENU,
    'real-estate': realEstateBot.getMainMenu({ businessName: 'Real Estate' }),
    'ilm-danish': buildIlmDanishMenu(),
    'ilm-danish-form': buildIlmDanishAdmissionForm(),
    'admission-form': buildIlmDanishAdmissionForm(),
    'daanish-form': buildIlmDanishAdmissionForm(),
    payment: buildPaymentDetailsMessage(),
    plans: buildAIToolsMenu(),
    support: `Assalam o Alaikum! ${storeDisplayName()} mein aap ka khush aamdeed. Batayein kis cheez mein madad chahiye?`
  };
  return templates[normalized] || '';
}

async function buildCockpitAIReply(number, name = 'Customer') {
  const conv = waConversations[number] || { history: [] };
  const last5 = (conv.history || []).slice(-5).map(h => (h.role === 'user' ? 'Customer' : 'Bot') + ': ' + h.msg).join('\n');
  const cust = customers.find(c => c.number === number);
  const catalogSnip = laptopProducts.filter(p => p.stock).slice(0, 5).map(p => p.name + ' Rs.' + (p.price || 0)).join(', ');
  const context = 'Customer: ' + (name || number) +
    (cust ? ', Plan: ' + (cust.plan || 'none') + ', City: ' + (cust.city || 'unknown') : '') +
    '\nRecent chat:\n' + (last5 || 'No history') +
    '\nAvailable products: ' + (catalogSnip || 'none');
  return callAI(
    context + '\nWrite one short, natural WhatsApp reply that helps move the conversation forward.',
    'You are a WhatsApp sales assistant for ' + (settings.business_name || 'Us') + '. Be warm, concise, and practical. Max 2 sentences.'
  );
}

