app.post('/api/cockpit/quick-action', async (req, res) => {
  try {
    const action = String(req.body?.action || '').toLowerCase();
    const chatId = normalizeWAChatId(req.body?.chatId || req.body?.number || '');
    const numberInput = String(req.body?.number || '').trim();
    const number = numberInput.replace(/^whatsapp:/i, '').replace(/^\+/, '').replace(/@c\.us$/i, '') || (chatId.endsWith('@c.us') ? chatId.replace(/@c\.us$/i, '') : chatId);
    const name = req.body?.name ? String(req.body.name) : storeDisplayName();
    let message = '';
    let mediaAssets = [];

    if (['menu', 'ai-tools', 'laptops', 'scholarship', 'real-estate', 'ilm-danish', 'ilm-danish-form', 'admission-form', 'daanish-form', 'payment', 'support', 'plans'].includes(action)) {
      message = buildCockpitTemplateMessage(action, name);
      if (['ilm-danish-form', 'admission-form', 'daanish-form'].includes(action)) {
        mediaAssets = ILM_DANISH_MEDIA.admissionForm || [];
      }
    } else if (action === 'ai-reply') {
      if (!chatId) return res.status(400).json({ error: 'chatId required' });
      if (/@g\.us$/i.test(chatId)) return res.status(400).json({ error: 'AI reply is only available for direct chats' });
      if (conversationControlSnapshot(number || chatId).aiPaused) return res.status(409).json({ error: 'AI replies are stopped for this chat' });
      message = await buildCockpitAIReply(number || chatId.replace(/@c\.us$/i, ''), name);
    } else {
      return res.status(400).json({ error: 'Unknown action' });
    }

    if (!message) return res.status(400).json({ error: 'Template unavailable' });
    const sendTarget = chatId || number;
    if (!sendTarget) return res.status(400).json({ error: 'chatId required' });
    const renderedMessage = renderDynamicTemplate(message, buildCustomerMessageContext(sendTarget, req.body?.variables || req.body || {}));
    await sendDirect(sendTarget, renderedMessage);
    if (mediaAssets.length) await sendMediaAssets(sendTarget, mediaAssets);
    res.json({
      success: true,
      action,
      chatId: sendTarget,
      number: number || '',
      message: renderedMessage,
      mediaAssets: mediaAssets.map(asset => ({ source: asset.source, caption: asset.caption || '' }))
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

