app.post('/api/wa/send-bulk-parallel', async (req, res) => {
  try {
    const message = String(req.body?.message || '').trim();
    const rawRecipients = Array.isArray(req.body?.recipients) ? req.body.recipients : [];
    const concurrency = Math.max(1, Math.min(Number(req.body?.concurrency || 5) || 5, 25));
    const baseDelayMs = Math.max(0, Math.min(Number(req.body?.delayMs || 250) || 250, 10000));
    const accountId = String(req.body?.accountId || '').trim();
    const useRotation = req.body?.useRotation !== false;
    if (!message) return res.status(400).json({ error: 'message is required' });
    if (!rawRecipients.length) return res.status(400).json({ error: 'recipients array is required' });

    const recipients = rawRecipients
      .map(item => {
        if (typeof item === 'string') return { number: normalizeNumber(item), name: '' };
        return {
          number: normalizeNumber(item?.number || item?.phone || item?.whatsapp || ''),
          name: item?.name || ''
        };
      })
      .filter(item => item.number);

    const safetyCheck = filterSafetyRecipients(recipients, { context: 'parallel_bulk_send' });
    const valid = safetyCheck.valid || [];
    const blocked = (safetyCheck.blocked || []).map(x => ({ number: x.number, reasons: x.safety?.reasons || [] }));
    if (!valid.length) {
      return res.status(400).json({ error: 'All recipients were blocked by Safety Center', blocked });
    }

    const sent = [];
    const failed = [];
    let pointer = 0;
    async function worker() {
      while (pointer < valid.length) {
        const currentIndex = pointer++;
        const recipient = valid[currentIndex];
        try {
          const personalized = applyMergeFields(message, {
            name: recipient.name || recipient.number,
            number: recipient.number
          });
          await sendDirect(recipient.number, personalized, { accountId, useRotation });
          recordSafetySend(recipient.number, { type: 'parallel_bulk', index: currentIndex + 1 });
          sent.push({ number: recipient.number });
        } catch (error) {
          failed.push({ number: recipient.number, error: error.message });
        }
        await safetyPauseIfNeeded(currentIndex + 1);
        if (baseDelayMs > 0) await sleep(baseDelayMs);
      }
    }

    await Promise.all(Array.from({ length: Math.min(concurrency, valid.length) }, () => worker()));
    if (typeof logs !== 'undefined') {
      logs.push({
        id: uuid(),
        type: 'parallel_bulk',
        to: 'multiple',
        status: failed.length ? 'completed_with_errors' : 'sent',
        sent: sent.length,
        failed: failed.length,
        time: new Date().toISOString()
      });
      saveJSON('logs.json', logs);
    }
    res.json({ success: true, sent, failed, blocked, concurrency });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.post('/api/wa/send-unknown', async (req, res) => {
  try {
    const body = req.body || {};
    const number = normalizedPhoneWithCountry(body.number || body.phone || body.to || '', body.countryCode || '92');
    const rawText = String(body.text || body.message || '').trim();
    const text = rawText ? renderDynamicTemplate(rawText, buildCustomerMessageContext(number, body.variables || body)) : '';
    const mediaUrl = String(body.mediaUrl || body.image || body.file || '').trim();
    if (!number) return res.status(400).json({ error: 'valid number is required' });
    if (!text && !mediaUrl) return res.status(400).json({ error: 'text or mediaUrl is required' });

    const safety = validateSafetyRecipient({ number, name: body.name || number, optIn: body.optIn === true }, { context: 'direct_unknown' });
    if (!safety.allowed) return res.status(400).json({ error: `Safety blocked: ${safety.reasons.join(', ')}` });

    if (mediaUrl) {
      const media = await createMediaFromSource(mediaUrl);
      await sendDirectMedia(number, media, text);
    } else {
      await sendDirect(number, text);
    }

    recordSafetySend(number, { type: 'direct_unknown' });
    logs.push({
      id: uuid(),
      type: 'direct_unknown',
      to: number,
      status: 'sent',
      message: text || '[Media]',
      time: new Date().toISOString()
    });
    saveJSON('logs.json', logs);
    res.json({ success: true, number, savedToContacts: false, media: !!mediaUrl });
  } catch (e) {
    const status = /not connected|required|invalid|blocked/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

app.post('/api/wa/send-contact', async (req, res) => {
  try {
    const body = req.body || {};
    const targetRaw = String(body.number || body.to || body.phone || '').trim();
    const number = /@(c|g|lid)\.us$/i.test(targetRaw)
      ? targetRaw
      : normalizedPhoneWithCountry(targetRaw, body.countryCode || '92');
    const contactPhone = normalizedPhoneWithCountry(body.contactPhone || body.contact_number || body.sharePhone || '', body.contactCountryCode || '92');
    const contactName = String(body.contactName || body.name || 'Contact').trim();
    if (!number) return res.status(400).json({ error: 'number is required' });
    if (!contactPhone) return res.status(400).json({ error: 'contactPhone is required' });
    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
    const chatId = number.includes('@') ? number : `${number}@c.us`;
    const safeName = contactName.replace(/[;\n\r]/g, ' ').trim() || contactPhone;
    const vcard = [
      'BEGIN:VCARD',
      'VERSION:3.0',
      `FN:${safeName}`,
      `TEL;TYPE=CELL:${contactPhone}`,
      body.company ? `ORG:${String(body.company).replace(/[;\n\r]/g, ' ')}` : '',
      body.email ? `EMAIL:${String(body.email).trim()}` : '',
      'END:VCARD'
    ].filter(Boolean).join('\n');
    const sent = await inst.client.sendMessage(chatId, vcard, { parseVCards: true });
    const note = String(body.note || '').trim();
    if (note) await sendDirect(number, renderDynamicTemplate(note, buildCustomerMessageContext(number, body.variables || body)));
    try {
      messageAnalytics.recordSentMessage({
        to: number,
        content: `[Contact] ${safeName} ${contactPhone}`,
        whatsappId: sent.id?._serialized || null,
        type: 'contact_card'
      });
    } catch {}
    res.json({ success: true, messageId: sent.id?._serialized || null });
  } catch (e) {
    const status = /not connected|required|invalid/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

app.post('/api/wa/send-location', async (req, res) => {
  try {
    const body = req.body || {};
    const targetRaw = String(body.number || body.to || body.phone || '').trim();
    const number = /@(c|g|lid)\.us$/i.test(targetRaw)
      ? targetRaw
      : normalizedPhoneWithCountry(targetRaw, body.countryCode || '92');
    const latitude = Number(body.latitude ?? body.lat);
    const longitude = Number(body.longitude ?? body.lng ?? body.lon);
    if (!number) return res.status(400).json({ error: 'number is required' });
    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) {
      return res.status(400).json({ error: 'valid latitude and longitude are required' });
    }
    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
    const chatId = number.includes('@') ? number : `${number}@c.us`;
    const { Location } = getWWebJS();
    const title = renderDynamicTemplate(body.name || body.title || settings.business_name || 'Location', buildCustomerMessageContext(number, body.variables || body));
    const address = renderDynamicTemplate(body.address || body.description || '', buildCustomerMessageContext(number, body.variables || body));
    let sent;
    if (typeof Location === 'function') {
      sent = await inst.client.sendMessage(chatId, new Location(latitude, longitude, {
        name: title,
        address,
        url: body.url || ''
      }));
    } else {
      const mapsUrl = body.url || `https://maps.google.com/?q=${latitude},${longitude}`;
      sent = await inst.client.sendMessage(chatId, [title, address, mapsUrl].filter(Boolean).join('\n'));
    }
    try {
      messageAnalytics.recordSentMessage({
        to: number,
        content: `[Location] ${title} ${latitude},${longitude}`,
        whatsappId: sent.id?._serialized || null,
        type: 'location'
      });
    } catch {}
    res.json({ success: true, messageId: sent.id?._serialized || null });
  } catch (e) {
    const status = /not connected|required|invalid/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

