function normalizeActionTrigger(input = {}) {
  const priorityMap = { low: 1, normal: 1, medium: 2, high: 3, urgent: 4, critical: 4 };
  const priorityValue = typeof input.priority === 'string'
    ? (priorityMap[input.priority.toLowerCase()] ?? Number(input.priority))
    : Number(input.priority ?? 1);
  return {
    id: input.id || uuid(),
    name: String(input.name || 'Action Trigger').trim(),
    event: String(input.event || 'new_message').trim(),
    conditionField: String(input.conditionField || input.field || 'message').trim(),
    operator: String(input.operator || 'contains').trim(),
    value: String(input.value || '').trim(),
    action: String(input.action || 'handoff').trim(),
    target: String(input.target || '').trim(),
    message: String(input.message || '').trim(),
    priority: Number.isFinite(priorityValue) ? Math.max(0, priorityValue) : 1,
    active: input.active !== false,
    runCount: Number(input.runCount || 0),
    lastRunAt: input.lastRunAt || '',
    createdAt: input.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

function actionTriggerMatches(trigger = {}, payload = {}) {
  if (trigger.active === false) return false;
  const field = String(trigger.conditionField || 'message');
  const actual = field.split('.').reduce((obj, key) => (obj && obj[key] !== undefined ? obj[key] : ''), payload);
  const expected = String(trigger.value || '').toLowerCase();
  const text = String(actual ?? '').toLowerCase();
  switch (String(trigger.operator || 'contains').toLowerCase()) {
    case 'equals': return text === expected;
    case 'starts_with': return text.startsWith(expected);
    case 'ends_with': return text.endsWith(expected);
    case 'gt': return Number(actual) > Number(trigger.value);
    case 'gte': return Number(actual) >= Number(trigger.value);
    case 'lt': return Number(actual) < Number(trigger.value);
    case 'lte': return Number(actual) <= Number(trigger.value);
    case 'exists': return actual !== undefined && actual !== null && String(actual).trim() !== '';
    case 'regex':
      try { return new RegExp(String(trigger.value || ''), 'i').test(String(actual || '')); } catch { return false; }
    case 'contains':
    default:
      return text.includes(expected);
  }
}

function executeActionTrigger(trigger = {}, payload = {}, dryRun = true) {
  const result = {
    triggerId: trigger.id,
    triggerName: trigger.name,
    action: trigger.action,
    dryRun,
    executedAt: new Date().toISOString(),
    outcome: 'preview'
  };
  if (!dryRun) {
    trigger.runCount = Number(trigger.runCount || 0) + 1;
    trigger.lastRunAt = result.executedAt;
    trigger.updatedAt = result.executedAt;
    if (trigger.action === 'handoff') {
      handoffQueue.unshift({
        id: uuid(),
        chatId: String(payload.chatId || payload.number || payload.from || '').trim(),
        assignedTo: trigger.target || 'sales-team',
        priority: trigger.priority >= 3 ? 'urgent' : (trigger.priority >= 2 ? 'high' : 'normal'),
        status: 'open',
        note: trigger.message || `Triggered by ${trigger.name}`,
        createdAt: result.executedAt,
        updatedAt: result.executedAt
      });
      saveHandoffQueue();
      result.outcome = 'handoff_created';
    } else if (trigger.action === 'create_hitl_draft') {
      const draft = createHitlDraft({
        chatId: payload.chatId || payload.customerNumber || payload.number || payload.from,
        customerName: payload.customerName || payload.name,
        message: payload.message || trigger.message || `Triggered by ${trigger.name}`,
        requiresHuman: true
      });
      result.draftId = draft.id;
      result.outcome = 'hitl_draft_created';
    } else if (trigger.action === 'alert') {
      createSystemAlert({
        type: 'trigger',
        title: trigger.name,
        message: trigger.message || `Trigger matched ${trigger.event}`,
        severity: trigger.priority >= 3 ? 'warning' : 'info',
        source: 'action_trigger',
        meta: { triggerId: trigger.id, payload }
      });
      result.outcome = 'alert_created';
    } else {
      result.outcome = 'logged';
    }
    saveActionTriggers();
  }
  return result;
}

function normalizeCommunity(input = {}) {
  const rawGroups = input.groups ?? input.nestedGroups ?? input.groupIds ?? '';
  const groups = Array.isArray(rawGroups)
    ? rawGroups
    : String(rawGroups || '').split(/[,\n]/).map(x => x.trim()).filter(Boolean);
  return {
    id: input.id || uuid(),
    name: String(input.name || 'WhatsApp Community').trim(),
    category: String(input.category || 'operations').trim(),
    announcementGroupId: String(input.announcementGroupId || input.announcementGroup || input.announcement || '').trim(),
    groups: groups.slice(0, 100).map(group => typeof group === 'object' ? group : { id: group, name: group }),
    owner: String(input.owner || '').trim(),
    notes: String(input.notes || '').trim(),
    active: input.active !== false,
    createdAt: input.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

function normalizeTemplateApproval(input = {}) {
  const content = String(input.content || input.message || input.body || '').trim();
  return {
    id: input.id || uuid(),
    templateId: String(input.templateId || '').trim(),
    name: String(input.name || 'WhatsApp Template').trim(),
    category: String(input.category || 'marketing').trim(),
    language: String(input.language || 'ur_PK').trim(),
    content,
    status: String(input.status || 'draft').trim(),
    qualityScore: Math.max(0, Math.min(100, Number(input.qualityScore || estimateTemplateQuality(content)))),
    notes: String(input.notes || '').trim(),
    submittedAt: input.submittedAt || '',
    approvedAt: input.approvedAt || '',
    createdAt: input.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

function estimateTemplateQuality(text = '') {
  const clean = String(text || '').trim();
  let score = 70;
  if (!clean) return 0;
  if (clean.length > 700) score -= 25;
  if (/free|guaranteed|100%|urgent|last chance/gi.test(clean)) score -= 8;
  if (/{{\s*\w+\s*}}/.test(clean)) score += 8;
  if (/stop|unsubscribe|reply/i.test(clean)) score += 8;
  return Math.max(0, Math.min(100, score));
}

function computeSLAStatus() {
  const policy = {
    enabled: slaPolicies?.enabled !== false,
    defaultMinutes: Math.max(1, Number(slaPolicies?.defaultMinutes || 15)),
    urgentMinutes: Math.max(1, Number(slaPolicies?.urgentMinutes || 5)),
    dealerMinutes: Math.max(1, Number(slaPolicies?.dealerMinutes || 30)),
    alertBeforeMinutes: Math.max(0, Number(slaPolicies?.alertBeforeMinutes || 3))
  };
  const now = Date.now();
  const openHandoffs = (handoffQueue || []).filter(item => !['resolved', 'closed', 'done'].includes(String(item.status || '').toLowerCase()));
  const rows = openHandoffs.map(item => {
    const priority = String(item.priority || '').toLowerCase();
    const minutes = priority === 'urgent' ? policy.urgentMinutes : policy.defaultMinutes;
    const startTs = Date.parse(item.createdAt || item.updatedAt || new Date().toISOString());
    const dueTs = startTs + (minutes * 60 * 1000);
    const remainingMinutes = Math.round((dueTs - now) / 60000);
    return {
      id: item.id,
      chatId: item.chatId,
      assignedTo: item.assignedTo || '',
      priority: item.priority || 'normal',
      status: item.status || 'open',
      dueAt: new Date(dueTs).toISOString(),
      remainingMinutes,
      breached: remainingMinutes < 0,
      warning: remainingMinutes >= 0 && remainingMinutes <= policy.alertBeforeMinutes,
      note: item.note || ''
    };
  }).sort((a, b) => a.remainingMinutes - b.remainingMinutes);
  return {
    policy,
    summary: {
      open: rows.length,
      breached: rows.filter(item => item.breached).length,
      warning: rows.filter(item => item.warning).length,
      healthy: rows.filter(item => !item.breached && !item.warning).length
    },
    items: rows
  };
}

function createHitlDraft(input = {}) {
  const message = String(input.message || input.customerMessage || '').trim();
  const intent = analyzeCustomerIntent(message);
  const openEnded = analyzeStructuredIntent(message).openEnded;
  const draft = {
    id: uuid(),
    chatId: String(input.chatId || input.customerNumber || input.number || input.from || '').trim(),
    customerName: String(input.customerName || input.name || '').trim(),
    customerMessage: message,
    intent,
    requiresHuman: input.requiresHuman === true || openEnded || String(intent.intent || '').includes('support'),
    draftReply: String(input.draftReply || '').trim() || buildLocalHitlDraft(message, intent),
    status: 'pending_review',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  hitlDrafts.unshift(draft);
  saveHitlDrafts();
  return draft;
}

function buildLocalHitlDraft(message = '', intent = {}) {
  const topic = intent.intent || intent.type || 'query';
  if (/price|rate|cost/i.test(message)) return 'Assalam o Alaikum! Aap kis AI tool ka plan chahte hain? Main latest available options aur best price share kar deta hoon.';
  if (/support|issue|problem|not working/i.test(message)) return 'Samajh gaya. Please order ID aur issue ka short screenshot/detail bhej dein, main check karwa deta hoon.';
  if (/book|appointment|call/i.test(message)) return 'Sure, aap apna preferred time bhej dein. Main appointment/call slot confirm kar deta hoon.';
  return `Thanks. Main aap ka ${topic} request check kar raha hoon. Please tool/plan aur budget share kar dein.`;
}

