app.post('/api/integrations/:type/test', async (req, res) => {
  try {
    const type = (req.params.type || '').toString().toLowerCase();
    if (type === 'telegram') {
      const telegramChatId = settings.telegram_channel_chat_id || settings.telegram_chat_id || process.env.TELEGRAM_CHANNEL_CHAT_ID || process.env.TELEGRAM_CHAT_ID || '';
      const telegramToken = settings.telegram_token || process.env.TELEGRAM_TOKEN || process.env.TELEGRAM_BOT_TOKEN || '';
      if (!telegramToken || !telegramChatId) {
        return res.status(400).json({ error: 'Telegram token/chat ID missing in Settings' });
      }
      const url = `https://api.telegram.org/bot${telegramToken}/sendMessage`;
      const r = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ chat_id: telegramChatId, text: 'SuperSender Pro test message' })
      });
      const data = await r.json().catch(() => ({}));
      if (!r.ok || data.ok === false) throw new Error(data.description || `Telegram test failed (${r.status})`);
      return res.json({ success: true, type, message: 'Telegram test sent' });
    }

    if (type === 'clickup') {
      if (!settings.clickup_token || !settings.clickup_list_id) {
        return res.status(400).json({ error: 'ClickUp token/list ID missing in Settings' });
      }
      const r = await fetch(`https://api.clickup.com/api/v2/list/${settings.clickup_list_id}`, {
        headers: { Authorization: settings.clickup_token }
      });
      const data = await r.json().catch(() => ({}));
      if (!r.ok) throw new Error(data.err || data.error || `ClickUp test failed (${r.status})`);
      return res.json({ success: true, type, list: data.name || settings.clickup_list_id });
    }

    if (type === 'facebook' || type === 'instagram' || type === 'linkedin') {
      const account = findSocialAccount({ platform: type });
      const configured = !!(account && publicSocialAccount(account).configured);
      if (!configured) return res.status(400).json({ error: `${type} credentials missing in Settings or Social Accounts` });
      return res.json({ success: true, type, message: 'Credentials are saved locally', account: publicSocialAccount(account) });
    }

    res.status(400).json({ error: `Unknown integration type: ${type}` });
  } catch (e) {
    res.status(502).json({ error: e.message });
  }
});

function recordMessengerInboxMessage({ senderId, recipientId, text, source = 'facebook', name = '' }) {
  const row = {
    id: `meta_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    source,
    chatId: senderId,
    recipientId,
    number: senderId,
    name: name || `Messenger ${String(senderId).slice(-6)}`,
    body: text || '',
    timestamp: new Date().toISOString(),
    read: false
  };
  inbox.unshift(row);
  if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
  saveInbox();
  ensureGuestCustomer(senderId, row.name, source);
  try {
    if (settings.reply_speed_tracking_enabled !== false) {
      messageAnalytics.recordInboundMessage({
        from: senderId,
        number: senderId,
        recipientId,
        chatId: senderId,
        content: text || '',
        type: 'text',
        source,
        name: row.name
      });
    }
  } catch {}
  io.emit('incoming_message', row);
  triggerWebhooks('new_message', row);
  return row;
}

async function sendMessengerText(recipientId, message) {
  const token = settings.fb_page_access_token || settings.facebook_page_access_token || process.env.FB_PAGE_ACCESS_TOKEN || '';
  if (!token) throw new Error('Facebook Page Access Token missing in Settings');
  if (!recipientId || !message) throw new Error('recipientId and message are required');
  const r = await fetch(`https://graph.facebook.com/v21.0/me/messages?access_token=${encodeURIComponent(token)}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      recipient: { id: recipientId },
      messaging_type: 'RESPONSE',
      message: { text: String(message).slice(0, 1900) }
    })
  });
  const data = await r.json().catch(() => ({}));
  if (!r.ok || data.error) throw new Error(data.error?.message || `Messenger send failed (${r.status})`);
  return data;
}

