function adminNumberCandidates() {
  return [
    settings.admin_number,
    settings.order_whatsapp,
    settings.owner_whatsapp,
    settings.support_whatsapp,
    process.env.ADMIN_NUMBER,
    process.env.ADMIN_WA_NUMBER,
    '03181781454'
  ].map(toWaMeNumber).filter(Boolean);
}

function isWhatsAppAdminNumber(number = '', options = {}) {
  if (options.fromMe === true) return true;
  const clean = toWaMeNumber(number || '');
  if (!clean) return false;
  return adminNumberCandidates().some(admin => normalizeNumber(admin) === normalizeNumber(clean));
}

function getConfiguredCustomerGroups() {
  const raw = [
    settings.customer_groups,
    settings.customerGroups,
    settings.social_share_groups,
    settings.broadcast_groups,
    process.env.CUSTOMER_GROUPS
  ].filter(Boolean);
  const groups = [];
  for (const item of raw) {
    if (Array.isArray(item)) groups.push(...item);
    else groups.push(...String(item || '').split(/[,\n]/));
  }
  return [...new Set(groups.map(x => String(x || '').trim()).filter(Boolean))];
}

function parseSocialPlatforms(input = '') {
  const value = String(input || '').trim().toLowerCase();
  const defaults = ['facebook', 'instagram', 'linkedin'];
  if (!value || ['all', 'sab', 'allplatforms'].includes(value)) return defaults;
  const parts = value.split(/[,+/|]/).map(normalizeSocialPlatform).filter(Boolean);
  const expanded = [];
  for (const part of parts) {
    if (part === 'all') expanded.push(...defaults);
    else if (SOCIAL_PLATFORMS[part]) expanded.push(part);
  }
  return [...new Set(expanded)];
}

function socialPlatformDisplay(platforms = []) {
  return platforms.map(p => SOCIAL_PLATFORMS[p]?.label || p).join(', ');
}

