function latestBackupZipInfo() {
  const base = path.resolve(__dirname, '..');
  const candidates = [];
  try {
    const managed = backupManager.listBackups();
    for (const row of managed || []) {
      if (!row?.path) continue;
      candidates.push({
        full: row.path,
        name: row.name || path.basename(row.path),
        sizeMb: Math.round(Number(row.size || 0) / 1024 / 1024 * 100) / 100,
        mtime: new Date(row.modified || row.created || Date.now())
      });
    }
  } catch {}
  for (const dir of [__dirname, base]) {
    try {
      for (const file of fs.readdirSync(dir)) {
        if (/supersender-pro-final.*backup.*\.zip$/i.test(file)) {
          const full = path.join(dir, file);
          const stat = fs.statSync(full);
          candidates.push({ full, name: file, sizeMb: Math.round(stat.size / 1024 / 1024 * 100) / 100, mtime: stat.mtime });
        }
      }
    } catch {}
  }
  return candidates.sort((a, b) => b.mtime - a.mtime)[0] || null;
}

function formatBackupSize(bytes = 0) {
  const n = Number(bytes || 0);
  if (!Number.isFinite(n) || n <= 0) return '0 MB';
  if (n >= 1024 * 1024 * 1024) return `${(n / 1024 / 1024 / 1024).toFixed(2)} GB`;
  return `${(n / 1024 / 1024).toFixed(2)} MB`;
}

function backupCreatedReply(result = {}) {
  const filePath = result.backupPath || '';
  let sizeLine = '';
  try {
    if (filePath && fs.existsSync(filePath)) sizeLine = `\nSize: *${formatBackupSize(fs.statSync(filePath).size)}*`;
  } catch {}
  return `💾 *Backup Created*

Name: *${result.backupName || path.basename(filePath) || 'backup'}*
Path: ${filePath || 'data/backups'}
Files: *${result.manifest?.files?.length || 0}*${sizeLine}

Tip: is file ko USB/Drive par copy kar lein.`;
}

function backupListReply(limit = 5) {
  const backups = backupManager.listBackups().slice(0, Math.max(1, Math.min(10, Number(limit) || 5)));
  if (!backups.length) return '💾 No managed data backups found.\nUse *!backup create* to create one now.';
  const lines = backups.map((row, index) => {
    const when = new Date(row.modified || row.created || Date.now()).toLocaleString('en-PK', { timeZone: 'Asia/Karachi' });
    return `${index + 1}. *${row.name || path.basename(row.path || '')}*\n   ${formatBackupSize(row.size)} | ${when}`;
  }).join('\n');
  return `💾 *Managed Backups*\n\n${lines}\n\nUse *!backup create* for a fresh data backup.`;
}

