async function shareScholarshipToWhatsAppGroups(caption = '') {
  const groups = getConfiguredCustomerGroups();
  let sent = 0;
  let failed = 0;
  for (const groupId of groups) {
    try {
      await sendDirect(groupId, caption, { useRotation: true });
      sent += 1;
    } catch (error) {
      failed += 1;
      console.warn(`[ScholarshipPipeline] WhatsApp group share failed for ${groupId}:`, error.message);
    }
    await sleep(2000);
  }
  return { sent, failed, groups };
}

async function publishScholarshipRecord(recordId = 'latest', options = {}) {
  if (!scholarshipPipeline) throw new Error('Scholarship pipeline module not loaded');
  const selected = String(recordId || 'latest').toLowerCase() === 'latest'
    ? scholarshipPipeline.rows()[0]
    : scholarshipPipeline.getRecord(recordId);
  if (!selected) throw new Error('Scholarship record not found');
  const { post, record } = scholarshipPipeline.createWebsitePost(selected.id);
  const caption = scholarshipPipeline.buildCaption(post, record);
  const websiteForward = { success: false, skipped: true };
  if (settings.scholarship_website_webhook_url && webDataBridge && options.skipWebsiteForward !== true) {
    try {
      const forwarded = await webDataBridge.forwardToWebsite({
        targetUrl: settings.scholarship_website_webhook_url,
        payload: { type: 'scholarship_post', record, post, caption },
        allowPrivate: settings.web_bridge_allow_private === true
      });
      Object.assign(websiteForward, forwarded, { skipped: false });
    } catch (error) {
      Object.assign(websiteForward, { skipped: false, error: error.message });
    }
  }
  const social = [];
  if (options.skipSocial !== true) {
    for (const platform of scholarshipPlatformList()) {
      try {
        const result = await publishSocialPayloadToPlatform(platform, {
          message: caption,
          imageUrl: options.imageUrl || '',
          videoUrl: ''
        });
        social.push({ platform, success: true, postId: result.postId || result.externalId || '', link: publicPostLink(platform, result.post) });
      } catch (error) {
        social.push({ platform, success: false, error: error.message });
      }
      await sleep(1500);
    }
  }
  const whatsapp = (settings.scholarship_share_to_whatsapp_groups !== false && options.skipWhatsapp !== true)
    ? await shareScholarshipToWhatsAppGroups(caption)
    : { sent: 0, failed: 0, groups: [], skipped: true };
  const channels = (settings.scholarship_share_to_whatsapp_channels !== false && options.skipChannels !== true && getConfiguredWhatsAppChannels().length)
    ? await shareDataToWhatsAppChannels({ message: caption, delayMs: 2000, useRotation: true })
    : { sent: 0, failed: 0, skipped: true };
  const updated = scholarshipPipeline.updateRecord(record.id, {
    status: 'distributed',
    websiteUrl: post.publicUrl,
    distribution: {
      at: new Date().toISOString(),
      websiteForward,
      social,
      whatsapp,
      channels
    }
  });
  createSystemAlert({
    type: 'scholarship_pipeline',
    title: 'Scholarship post distributed',
    message: `${record.title} | WhatsApp groups: ${whatsapp.sent || 0} | Social: ${social.filter(x => x.success).length}`,
    severity: social.some(x => x.success) || whatsapp.sent ? 'success' : 'warning',
    source: 'scholarship_pipeline',
    meta: { record: updated || record, post, social, whatsapp, channels }
  });
  return { success: true, record: updated || record, post, caption, websiteForward, social, whatsapp, channels };
}

async function captureScholarshipFromWhatsApp(ctx = {}) {
  if (!scholarshipPipeline) return null;
  const record = scholarshipPipeline.ingestMessage(ctx);
  if (record && settings.scholarship_pipeline_auto_publish === true) {
    setImmediate(() => {
      publishScholarshipRecord(record.id, { source: 'auto_capture' })
        .catch(error => console.warn('[ScholarshipPipeline] auto publish failed:', error.message));
    });
  }
  return record;
}

async function runScholarshipSweep(options = {}) {
  if (!scholarshipPipeline) throw new Error('Scholarship pipeline module not loaded');
  const accountId = String(options.accountId || 'default').trim() || 'default';
  const limit = Math.min(200, Math.max(1, Number(options.limit || 50)));
  const inst = waClients.get(accountId);
  if (!inst?.isReady) throw new Error('WhatsApp is not ready');
  const allGroups = await whatsAppAdminGroupRows(accountId);
  const sourceFilters = scholarshipSourceGroupIds().map(x => x.toLowerCase());
  const groups = sourceFilters.length
    ? allGroups.filter(group => sourceFilters.some(f => String(group.id || '').toLowerCase() === f || String(group.name || '').toLowerCase().includes(f)))
    : allGroups;
  let scanned = 0;
  let saved = 0;
  const failures = [];
  for (const group of groups) {
    try {
      const chat = await inst.client.getChatById(group.id);
      const messages = await chat.fetchMessages({ limit });
      for (const msg of messages || []) {
        const body = msg.body || msg.caption || '';
        scanned += 1;
        const contact = typeof msg.getContact === 'function' ? await msg.getContact().catch(() => null) : null;
        const record = scholarshipPipeline.ingestMessage({
          body,
          groupId: group.id,
          groupName: group.name,
          senderName: contact?.pushname || contact?.name || '',
          senderNumber: contact?.number || '',
          messageId: msg.id?._serialized || `${group.id}:${msg.timestamp || ''}:${hashMessageForSweep(body)}`
        });
        if (record) saved += 1;
      }
    } catch (error) {
      failures.push({ groupId: group.id, groupName: group.name, error: error.message });
    }
    await sleep(300);
  }
  return { success: true, accountId, groups: groups.length, scanned, saved, failures, summary: scholarshipPipeline.summary() };
}

function hashMessageForSweep(value = '') {
  return require('crypto').createHash('sha1').update(String(value || '')).digest('hex').slice(0, 12);
}

