async function resolveWhatsAppAdminGroupTarget(input = '', accountId = 'default') {
  const raw = String(input || '').trim();
  if (!raw) return null;
  if (raw.toLowerCase() === 'all') return { all: true, label: 'All Groups' };
  const groups = await whatsAppAdminGroupRows(accountId);
  const asIndex = Number(raw);
  if (Number.isInteger(asIndex) && asIndex > 0 && groups[asIndex - 1]) {
    return { all: false, group: groups[asIndex - 1], groups };
  }
  const found = groups.find(group =>
    String(group.id || '').toLowerCase() === raw.toLowerCase() ||
    String(group.name || '').toLowerCase().includes(raw.toLowerCase())
  );
  if (found) return { all: false, group: found, groups };
  if (raw.endsWith('@g.us') || /^120363/i.test(raw)) return { all: false, group: { id: raw, name: raw }, groups };
  return { all: false, group: null, groups };
}

