app.get('/api/gmail/oauth/callback', async (req, res) => {
  try {
    if (req.query.error) throw new Error(`${req.query.error}: ${req.query.error_description || 'Authorization denied'}`);
    const code = String(req.query.code || '').trim();
    if (!code) throw new Error('OAuth callback missing code.');
    const stateRow = consumeGmailOauthState(String(req.query.state || ''));
    if (!stateRow) throw new Error('Invalid or expired OAuth state. Start connection again from /gmail.');
    const cfg = gmailClientConfig();
    const tokenData = await googleTokenRequest({
      code,
      client_id: cfg.clientId,
      client_secret: cfg.clientSecret,
      redirect_uri: gmailOAuthRedirectUri(req),
      grant_type: 'authorization_code'
    });
    const account = await saveGmailOauthAccount(tokenData, stateRow);
    res.send(gmailOAuthResultHtml({
      ok: true,
      title: 'Gmail connected',
      message: 'Gmail account saved in the local encrypted vault.',
      account: publicGmailAccount(account)
    }));
  } catch (error) {
    console.error('[Gmail OAuth] callback failed:', error.message);
    res.status(500).send(gmailOAuthResultHtml({ ok: false, title: 'Gmail OAuth failed', message: 'Gmail account could not be connected.', error: error.message }));
  }
});

