app.post('/api/gmail/test-all', async (req, res) => {
  try {
    if (!gmailClientReady()) return res.status(400).json({ success: false, error: 'Google OAuth Client ID/Secret missing. Save them on /gmail first.' });
    if (!gmailAccounts.length) return res.status(400).json({ success: false, error: 'No Gmail accounts connected yet.' });
    const results = [];
    for (const account of gmailAccounts) {
      try {
        const tested = await testGmailAccount(account.id);
        results.push({ success: true, account: tested.account });
      } catch (error) {
        account.status = 'error';
        account.lastTestAt = new Date().toISOString();
        account.lastError = error.message;
        results.push({ success: false, account: publicGmailAccount(account), error: error.message });
      }
    }
    saveGmailAccounts();
    res.json({
      success: true,
      tested: results.length,
      ok: results.filter(row => row.success).length,
      failed: results.filter(row => !row.success).length,
      results
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

