app.patch('/api/credential-stock/:id', (req, res) => {
  try {
    const item = (credentialStock || []).find(row => row.id === String(req.params.id || ''));
    if (!item) return res.status(404).json({ success: false, error: 'Credential stock item not found.' });
    const body = req.body || {};
    if (body.status !== undefined) item.status = String(body.status || 'available').trim().toLowerCase();
    if (body.dealerCode !== undefined || body.dealer !== undefined) item.dealerCode = String(body.dealerCode ?? body.dealer ?? '').trim();
    if (body.expiresAt !== undefined) item.expiresAt = String(body.expiresAt || '').trim();
    if (body.credentials || body.details || body.key || body.keyValue || body.email || body.password || body.pass) {
      const credentialsText = normalizeCredentialStockText(body);
      if (!credentialsText) throw new Error('Credentials/details missing.');
      const encrypted = maybeEncryptSensitive(credentialsText);
      if (!encrypted) throw new Error('Credential encryption failed.');
      item.credentialsEncrypted = encrypted;
      item.preview = maskCredentialPreview(credentialsText);
    }
    item.updatedAt = new Date().toISOString();
    saveCredentialStock();
    res.json({ success: true, item: publicCredentialStockItem(item) });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

