app.post('/api/gmail/scan-payments', async (req, res) => {
  try {
    const body = req.body || {};
    const options = {
      query: String(body.query || gmailPaymentScanQuery()).trim(),
      limit: Math.max(1, Math.min(50, Number(body.limit || gmailPaymentScanLimit())))
    };
    if (body.accountId) {
      const account = gmailAccounts.find(row => row.id === String(body.accountId) || row.email === String(body.accountId));
      if (!account) return res.status(404).json({ success: false, error: 'Gmail account not found.' });
      const result = await scanGmailAccountForPayments(account, options);
      gmailScanState.lastPaymentScan = { ...result, accounts: 1, finishedAt: new Date().toISOString() };
      saveGmailScanState();
      return res.json({ success: true, ...result });
    }
    const report = await scanAllGmailAccountsForPayments(options);
    if ((settings.gmail_payment_auto_match_enabled !== false || body.autoMatch === true) && (report.saved > 0 || body.autoMatch === true)) {
      report.matchReport = await autoMatchGmailPaymentsToOrders({ tolerance: 5, minScore: 78 });
    }
    res.status(report.errors?.length && !report.saved && !report.parsed ? 400 : 200).json(report);
  } catch (error) {
    console.error('[Gmail Payment Scanner] API failed:', error.message);
    res.status(502).json({ success: false, error: error.message });
  }
});

