app.post('/api/social/accounts', (req, res) => {
  try {
    const platform = normalizeSocialPlatform(req.body?.platform);
    if (!SOCIAL_PLATFORMS[platform]) return res.status(400).json({ success: false, error: 'Unsupported social platform' });
    const account = {
      id: req.body?.id || uuid(),
      platform,
      name: req.body?.name || SOCIAL_PLATFORMS[platform].label,
      pageId: req.body?.pageId || '',
      igUserId: req.body?.igUserId || '',
      openId: req.body?.openId || '',
      authorUrn: req.body?.authorUrn || '',
      chatId: req.body?.chatId || req.body?.remoteId || '',
      accessToken: req.body?.accessToken || '',
      refreshToken: req.body?.refreshToken || '',
      appId: req.body?.appId || '',
      appSecret: req.body?.appSecret || '',
      clientKey: req.body?.clientKey || '',
      clientId: req.body?.clientId || '',
      clientSecret: req.body?.clientSecret || '',
      publishMode: req.body?.publishMode || '',
      parseMode: req.body?.parseMode || '',
      verifyToken: req.body?.verifyToken || '',
      enabled: req.body?.enabled !== false,
      notes: req.body?.notes || '',
      source: 'manual',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    const existingIndex = socialAccounts.findIndex(item => item.id === account.id);
    if (existingIndex >= 0) socialAccounts[existingIndex] = { ...socialAccounts[existingIndex], ...account, createdAt: socialAccounts[existingIndex].createdAt || account.createdAt };
    else socialAccounts.unshift(account);
    saveSocialAccounts();
    if (req.body?.syncToSettings) {
      if (platform === 'facebook') {
        settings.facebook_page_id = account.pageId || settings.facebook_page_id || '';
        settings.fb_page_access_token = account.accessToken || settings.fb_page_access_token || '';
        settings.facebook_app_id = account.appId || settings.facebook_app_id || '';
        settings.facebook_app_secret = account.appSecret || settings.facebook_app_secret || '';
        settings.fb_verify_token = account.verifyToken || settings.fb_verify_token || '';
      } else if (platform === 'instagram') {
        settings.instagram_ig_user_id = account.igUserId || settings.instagram_ig_user_id || '';
        settings.instagram_page_id = account.pageId || settings.instagram_page_id || '';
        settings.instagram_access_token = account.accessToken || settings.instagram_access_token || '';
      } else if (platform === 'linkedin') {
        settings.linkedin_author_urn = account.authorUrn || settings.linkedin_author_urn || '';
        settings.linkedin_access_token = account.accessToken || settings.linkedin_access_token || '';
        settings.linkedin_client_id = account.clientId || settings.linkedin_client_id || '';
        settings.linkedin_client_secret = account.clientSecret || settings.linkedin_client_secret || '';
      } else if (platform === 'tiktok') {
        settings.tiktok_open_id = account.openId || settings.tiktok_open_id || '';
        settings.tiktok_access_token = account.accessToken || settings.tiktok_access_token || '';
        settings.tiktok_refresh_token = account.refreshToken || settings.tiktok_refresh_token || '';
        settings.tiktok_client_key = account.clientKey || settings.tiktok_client_key || '';
        settings.tiktok_client_secret = account.clientSecret || settings.tiktok_client_secret || '';
        settings.tiktok_publish_mode = account.publishMode || settings.tiktok_publish_mode || 'draft';
      } else if (platform === 'telegram') {
        settings.telegram_token = account.accessToken || settings.telegram_token || '';
        settings.telegram_chat_id = account.chatId || settings.telegram_chat_id || '';
        settings.telegram_channel_chat_id = account.chatId || settings.telegram_channel_chat_id || '';
        settings.telegram_parse_mode = account.parseMode || settings.telegram_parse_mode || '';
      }
      saveJSON('settings.json', settings);
    }
    res.json({ success: true, account: publicSocialAccount(account) });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

