app.post('/webhook/meta', (req, res) => {
  try {
    const body = req.body || {};
    if (body.object !== 'page' && body.object !== 'instagram') return res.sendStatus(404);
    for (const entry of body.entry || []) {
      recordSocialEvent({
        platform: body.object === 'instagram' ? 'instagram' : 'facebook',
        type: 'meta_webhook_entry',
        externalId: entry.id || '',
        raw: entry
      });
      for (const event of entry.messaging || []) {
        const senderId = event.sender?.id;
        const recipientId = event.recipient?.id;
        const text = event.message?.text || event.postback?.title || event.postback?.payload || '';
        if (senderId && text) {
          recordSocialEvent({
            platform: body.object === 'instagram' ? 'instagram' : 'facebook',
            type: 'message',
            externalId: senderId,
            text,
            raw: event
          });
          recordMessengerInboxMessage({ senderId, recipientId, text, source: body.object === 'instagram' ? 'instagram' : 'facebook' });
        }
      }
    }
    res.status(200).send('EVENT_RECEIVED');
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

