function computeRevenueAttribution(days = 30) {
  const since = Date.now() - (Math.max(1, Number(days || 30)) * 24 * 60 * 60 * 1000);
  const clickEvents = (journeyEvents || []).filter(item => {
    const ms = toEpoch(item.createdAt || item.time || 0);
    return ms >= since && /click_to_whatsapp|smart_checkout_link/i.test(String(item.type || ''));
  });
  const orderRows = (orders || []).filter(item => {
    const ms = toEpoch(item.created || item.updated || item.createdAt || 0);
    return ms >= since;
  });
  const campaignMap = new Map();
  let attributedRevenue = 0;
  let unattributedRevenue = 0;
  let attributedOrders = 0;

  for (const order of orderRows) {
    const orderTime = toEpoch(order.created || order.updated || order.createdAt || 0);
    const number = normalizeNumber(order.customerNumber || order.number || '');
    const total = Number(order.total || order.total_price || order.amount || 0);
    const matched = clickEvents
      .filter(item => number && normalizeNumber(item.number || '') === number && toEpoch(item.createdAt || item.time || 0) <= orderTime)
      .sort((a, b) => toEpoch(b.createdAt || b.time || 0) - toEpoch(a.createdAt || a.time || 0))[0];
    if (!matched) {
      unattributedRevenue += total;
      continue;
    }
    attributedOrders++;
    attributedRevenue += total;
    const meta = matched.meta || {};
    const key = String(meta.utmCampaign || meta.sourceTag || meta.label || meta.utmSource || 'direct_whatsapp').trim() || 'direct_whatsapp';
    const existing = campaignMap.get(key) || {
      campaign: key,
      source: meta.utmSource || meta.sourceTag || 'whatsapp',
      clicks: 0,
      startedConversations: 0,
      orders: 0,
      revenue: 0,
      hotLeadSignals: 0
    };
    existing.orders += 1;
    existing.revenue += total;
    existing.lastOrderAt = order.created || order.updated || new Date().toISOString();
    campaignMap.set(key, existing);
  }

  for (const item of clickEvents) {
    const meta = item.meta || {};
    const key = String(meta.utmCampaign || meta.sourceTag || meta.label || meta.utmSource || 'direct_whatsapp').trim() || 'direct_whatsapp';
    const existing = campaignMap.get(key) || {
      campaign: key,
      source: meta.utmSource || meta.sourceTag || 'whatsapp',
      clicks: 0,
      startedConversations: 0,
      orders: 0,
      revenue: 0,
      hotLeadSignals: 0
    };
    existing.clicks += 1;
    if (String(item.type || '').includes('click_to_whatsapp')) existing.startedConversations += 1;
    if (meta.score) existing.hotLeadSignals += Number(meta.score || 0) >= 80 ? 1 : 0;
    campaignMap.set(key, existing);
  }

  const campaigns = [...campaignMap.values()]
    .map(item => ({
      ...item,
      conversionRate: item.clicks ? Number(((item.orders / item.clicks) * 100).toFixed(2)) : 0,
      revenuePerConversation: item.startedConversations ? Number((item.revenue / item.startedConversations).toFixed(2)) : 0
    }))
    .sort((a, b) => b.revenue - a.revenue || b.orders - a.orders);

  return {
    summary: {
      days: Math.max(1, Number(days || 30)),
      totalOrders: orderRows.length,
      attributedOrders,
      unattributedOrders: Math.max(0, orderRows.length - attributedOrders),
      attributedRevenue: Math.round(attributedRevenue),
      unattributedRevenue: Math.round(unattributedRevenue),
      totalRevenue: Math.round(attributedRevenue + unattributedRevenue)
    },
    campaigns
  };
}

