app.post('/api/marketing/messages', async (req, res) => {
  try {
    if (settings.marketing_api_enabled === false) {
      return res.status(403).json({ error: 'Marketing API is disabled in Settings' });
    }
    const body = req.body || {};
    const number = normalizeNumber(body.number || body.phone || '');
    if (!number) return res.status(400).json({ error: 'number is required' });
    const category = String(body.category || (isWithinOpenServiceWindow(number, settings.utility_window_hours || 24) ? 'utility' : 'marketing')).toLowerCase();
    const ttlHours = Math.max(1, Number(body.ttlHours || settings.marketing_default_ttl_hours || 24));
    const weeklyLimit = Math.max(1, Number(settings.marketing_weekly_limit || 2));
    const customer = upsertUnifiedIdentity({
      ...body,
      number,
      channel: 'whatsapp',
      source: body.source || 'marketing_api'
    });
    if (category === 'marketing' && !normalizeOptInStatus(customer)) {
      return res.status(400).json({ error: 'Marketing opt-in required for this contact' });
    }
    const sentThisWeek = countJourneyEvents('marketing_message', number, 7);
    if (category === 'marketing' && sentThisWeek >= weeklyLimit) {
      return res.status(429).json({ error: `Weekly marketing limit reached for this contact (${weeklyLimit})` });
    }
    const baseMessage = String(body.message || '').trim();
    if (!baseMessage) return res.status(400).json({ error: 'message is required' });
    const deepLink = String(body.deepLink || '').trim();
    const finalMessage = deepLink ? `${baseMessage}\n\n${deepLink}` : baseMessage;
    await sendDirect(number, finalMessage, {
      accountId: body.accountId || 'default',
      useRotation: body.useRotation === true
    });
    const logRow = {
      id: uuid(),
      type: 'marketing_api',
      to: number,
      category,
      ttlHours,
      campaign: String(body.campaignName || '').trim(),
      deepLink,
      status: 'sent',
      message: finalMessage,
      time: new Date().toISOString()
    };
    logs.push(logRow);
    saveJSON('logs.json', logs);
    const event = logJourneyEvent(category === 'utility' ? 'utility_message' : 'marketing_message', {
      number,
      customerId: customer.id,
      customerName: customer.name || '',
      channel: 'whatsapp',
      meta: {
        ttlHours,
        campaignName: body.campaignName || '',
        deepLink,
        category,
        source: body.source || 'marketing_api'
      }
    }, getJourneyStageForCustomer(customer));
    res.json({
      success: true,
      message: 'Marketing message queued successfully',
      category,
      ttlHours,
      serviceWindowOpen: isWithinOpenServiceWindow(number, settings.utility_window_hours || 24),
      customer,
      event
    });
  } catch (error) {
    const status = /not connected|required|limit reached|opt-in/i.test(error.message || '') ? 400 : 500;
    res.status(status).json({ error: error.message });
  }
});

