app.post('/api/ai-training/ingest-url', async (req, res) => {
  try {
    const url = String(req.body?.url || '').trim();
    if (!/^https?:\/\//i.test(url)) return res.status(400).json({ error: 'valid url is required' });
    const axios = require('axios');
    const response = await axios.get(url, { timeout: 12000, responseType: 'text' });
    const html = String(response.data || '');
    const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
    const content = extractTrainingContentFromHtml(html);
    const source = normalizeTrainingSource({
      title: req.body?.title || (titleMatch ? titleMatch[1] : url),
      type: 'website',
      url,
      content
    });
    aiTrainingSources.unshift(source);
    saveAITrainingSources();
    res.json({ success: true, source: trainingSourceForOutput(source) });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

