function cleanPlanPayload(body = {}, current = {}) {
  const copy = { ...(body || {}) };
  delete copy.autoForwardToContacts;
  delete copy.broadcastToContacts;
  delete copy.broadcast;
  delete copy.forwardNow;
  const next = { ...current, ...copy };
  next.name = cleanOutgoingText(String(next.name || '').trim()).replace(/\b(waranty|warrnty)\b/ig, 'warranty');
  next.category = cleanOutgoingText(String(next.category || inferBotPlanCategory(next) || 'AI Tools').trim());
  next.emoji = cleanOutgoingText(String(next.emoji || '').trim());
  next.label = cleanOutgoingText(String(next.label || next.duration || '').trim());
  next.price = Number(next.price || 0);
  next.features = Array.isArray(next.features)
    ? next.features.map(item => cleanOutgoingText(String(item || '').trim())).filter(Boolean)
    : cleanOutgoingText(String(next.features || '')).split(/\r?\n/).map(item => item.trim()).filter(Boolean);
  const statusValue = String(next.status || next.availability || '').trim().toLowerCase();
  if (['not_available', 'unavailable', 'out_of_stock', 'sold_out', 'disabled', 'inactive', 'hidden'].includes(statusValue)) {
    next.available = false;
  } else if (['available', 'in_stock', 'active', 'enabled'].includes(statusValue)) {
    next.available = true;
  } else if (copy.available !== undefined || copy.isAvailable !== undefined || copy.inStock !== undefined || copy.enabled !== undefined) {
    next.available = copy.available !== false && copy.isAvailable !== false && copy.inStock !== false && copy.enabled !== false;
  } else {
    next.available = next.available !== false;
  }
  next.status = next.available ? 'available' : 'not_available';
  if (!next.name) throw new Error('Plan name is required');
  if (!Number.isFinite(next.price) || next.price < 0) throw new Error('Valid plan price is required');
  return next;
}

function publicPlanForOutput(plan = {}) {
  const copy = { ...(plan || {}) };
  for (const key of ['name', 'category', 'emoji', 'label', 'duration', 'image']) {
    if (copy[key] !== undefined) copy[key] = cleanOutgoingText(String(copy[key] || ''));
  }
  copy.features = Array.isArray(copy.features)
    ? copy.features.map(item => cleanOutgoingText(String(item || ''))).filter(Boolean)
    : cleanOutgoingText(String(copy.features || '')).split(/\r?\n/).map(item => item.trim()).filter(Boolean);
  copy.available = isPlanAvailableForWhatsApp(plan);
  copy.status = copy.available ? 'available' : 'not_available';
  copy.availabilityLabel = planAvailabilityLabel(plan);
  copy.stockCount = planStockCount(plan);
  return copy;
}

function isAIPlanNotifyIntent(text = '') {
  return /\b(notify|notify me|yes|haan|han|alert|available ho|stock aye|update me|waitlist)\b/i.test(String(text || '').trim());
}

function findPlanByIdLoose(planId = '') {
  const id = String(planId || '').trim();
  if (!id) return null;
  return (plans || []).find(plan => String(plan.id || '') === id) || null;
}

function addAIPlanNotifyRequest(number = '', name = '', plan = {}, source = 'whatsapp') {
  const customerNumber = normalizeNumber(number || '') || String(number || '').trim();
  if (!customerNumber || !plan?.id) return null;
  const existing = (aiPlanNotifyWaitlist || []).find(row =>
    row.active !== false &&
    String(row.planId || '') === String(plan.id || '') &&
    normalizeNumber(row.customerNumber || '') === normalizeNumber(customerNumber)
  );
  if (existing) {
    existing.updatedAt = new Date().toISOString();
    existing.source = source || existing.source || 'whatsapp';
    saveAIPlanNotifyWaitlist();
    return existing;
  }
  const row = {
    id: uuid(),
    planId: plan.id,
    planName: plan.name || 'AI Tools Plan',
    category: inferBotPlanCategory(plan),
    customerNumber,
    customerName: customerFirstName(name, 'Customer'),
    active: true,
    source,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
  aiPlanNotifyWaitlist.unshift(row);
  saveAIPlanNotifyWaitlist();
  return row;
}

function buildAIPlanNotifySavedReply(plan = {}) {
  return `🔔 *Notify Me saved*

Plan: *${plan.name || 'AI Tools Plan'}*
Status: *Not Available*

Jab ye plan available mark hoga, system aap ko WhatsApp par update kar dega.
0️⃣ Back to Main Menu`;
}

async function notifyAIPlanWaitlist(plan = {}, reason = 'available') {
  if (!plan?.id) return { sent: 0, failed: 0, total: 0 };
  const rows = (aiPlanNotifyWaitlist || []).filter(row => row.active !== false && String(row.planId || '') === String(plan.id || ''));
  let sent = 0;
  let failed = 0;
  for (const row of rows.slice(0, 200)) {
    try {
      await sendDirect(row.customerNumber, `✅ *Stock Available*

*${plan.name || row.planName || 'AI Tools Plan'}* ab available hai.
Price: *Rs.${Number(plan.price || 0).toLocaleString()}*

Order ke liye reply karein: *order ${plan.name || ''}*
0️⃣ Back to Main Menu`);
      row.active = false;
      row.notifiedAt = new Date().toISOString();
      row.notifyReason = reason;
      sent += 1;
      await sleep(1200);
    } catch (error) {
      row.lastError = error.message;
      row.updatedAt = new Date().toISOString();
      failed += 1;
    }
  }
  if (rows.length) saveAIPlanNotifyWaitlist();
  return { sent, failed, total: rows.length };
}

async function notifyPlanWaitlistForStockItem(stockItem = {}) {
  const plan = findPlanByIdLoose(stockItem.planId || '') || (stockItem.category ? (plans || []).find(row => inferBotPlanCategory(row) === stockItem.category) : null);
  if (!plan) return { sent: 0, failed: 0, total: 0 };
  return notifyAIPlanWaitlist(plan, 'credential_stock_added');
}

function planStockCount(plan = {}) {
  const direct = Number(plan.stockCount ?? plan.slots ?? plan.quantity ?? plan.qty ?? plan.availableSlots);
  if (Number.isFinite(direct) && direct > 0) return direct;
  const stock = plan.stock && typeof plan.stock === 'object' ? plan.stock : {};
  const total = Object.values(stock).reduce((sum, value) => {
    const n = Number(value || 0);
    return sum + (Number.isFinite(n) && n > 0 ? n : 0);
  }, 0);
  return total || 0;
}

function planFeatureLine(feature = '') {
  const text = String(feature || '').trim();
  if (!text) return '';
  if (/video|editor|creator|editing|capcut/i.test(text)) return `🎬 ${text}`;
  if (/boost|fast|instant|activation/i.test(text)) return `🚀 ${text}`;
  if (/limited|stock|first come/i.test(text)) return `📦 ${text}`;
  if (/shared|access/i.test(text)) return `⚡ ${text}`;
  return `✅ ${text}`;
}

function buildPlanAnnouncementMessage(plan = {}) {
  const name = String(plan.name || 'New Plan').trim();
  const price = Number(plan.price || 0).toLocaleString('en-PK');
  const label = String(plan.label || plan.duration || 'Instant Activation - Shared Access').trim();
  const stock = planStockCount(plan);
  const stockPrefix = stock > 0 ? `${stock}x ` : '';
  const features = (Array.isArray(plan.features) ? plan.features : String(plan.features || '').split(/\r?\n/))
    .map(planFeatureLine)
    .filter(Boolean);
  const featureBlock = features.length
    ? features.slice(0, 5).join('\n')
    : '🎬 Perfect for creators\n🚀 Instant activation\n📦 Limited Stock - First Come First Serve!';

  return [
    'Bot sms ✅',
    `🔴 ${stockPrefix}${name} Add in Bot ✅`,
    '',
    `💰 Price Fixed: ${price} PKR Only`,
    `⚡ ${label}`,
    '',
    featureBlock,
    features.some(line => /limited|stock/i.test(line)) ? '' : '📦 Limited Stock - First Come First Serve!'
  ].filter(line => line !== '').join('\n');
}

function planAnnouncementRecipients() {
  const inboxRows = (Array.isArray(inbox) ? inbox : []).map(row => {
    const raw = row.number || row.customerNumber || row.from || row.chatId || row.id || '';
    const number = normalizeWAContactNumber(raw);
    if (!number || /^120363/.test(number) || /^2026/.test(number)) return null;
    return {
      id: `${number}@c.us`,
      number,
      name: row.name || row.customerName || row.pushName || number,
      lastActive: row.time || row.timestamp || row.createdAt || '',
      source: 'inbox'
    };
  }).filter(Boolean);
  return dedupeWAContacts([...mergedContactRows(true), ...inboxRows]);
}

function publicPlanBroadcastJob(job = {}) {
  return {
    id: job.id,
    planId: job.planId,
    planName: job.planName,
    status: job.status,
    total: job.total || 0,
    sent: job.sent || 0,
    failed: job.failed || 0,
    blocked: job.blocked || 0,
    channelResult: job.channelResult || null,
    createdAt: job.createdAt,
    startedAt: job.startedAt,
    finishedAt: job.finishedAt,
    error: job.error || ''
  };
}

function queuePlanAnnouncementBroadcast(plan = {}, options = {}) {
  const recipients = planAnnouncementRecipients();
  const job = {
    id: uuid(),
    planId: plan.id,
    planName: plan.name,
    message: options.message || buildPlanAnnouncementMessage(plan),
    image: plan.image || '',
    status: recipients.length ? 'queued' : 'empty',
    total: recipients.length,
    sent: 0,
    failed: 0,
    blocked: 0,
    results: [],
    createdAt: new Date().toISOString()
  };
  planBroadcastJobs.push(job);
  savePlanBroadcastJobs();
  if (settings.whatsapp_channel_auto_share_new_plans !== false && getConfiguredWhatsAppChannels().length) {
    setImmediate(async () => {
      try {
        const result = await shareDataToWhatsAppChannels({
          kind: 'custom',
          message: buildChannelPlanAnnouncement(plan),
          mediaUrl: plan.image || '',
          delayMs: 2000,
          useRotation: true
        });
        job.channelResult = result;
        appendWhatsAppChannelLog({
          type: 'whatsapp_channel_plan_announcement',
          status: result.success ? 'sent' : 'partial',
          message: `Plan channel post: ${plan.name || plan.id || 'Plan'}`,
          result
        });
      } catch (error) {
        job.channelResult = { success: false, error: error.message };
        appendWhatsAppChannelLog({
          type: 'whatsapp_channel_plan_announcement',
          status: 'failed',
          message: `Plan channel post failed: ${plan.name || plan.id || 'Plan'}`,
          error: error.message
        });
      } finally {
        savePlanBroadcastJobs();
        io.emit('plan_broadcast:update', publicPlanBroadcastJob(job));
      }
    });
  }
  if (recipients.length) setImmediate(() => processPlanAnnouncementBroadcastJob(job.id));
  return publicPlanBroadcastJob(job);
}

async function processPlanAnnouncementBroadcastJob(jobId) {
  const job = planBroadcastJobs.find(row => row.id === jobId);
  if (!job || job.status === 'running') return;
  job.status = 'running';
  job.startedAt = new Date().toISOString();
  savePlanBroadcastJobs();
  io.emit('plan_broadcast:update', publicPlanBroadcastJob(job));

  let media = null;
  if (job.image) {
    try {
      media = await createMediaFromSource(job.image);
    } catch (error) {
      job.results.push({ type: 'media_fallback', error: error.message });
    }
  }

  const delayMs = safetyDelayMs(Number(settings.plan_auto_forward_delay_ms || process.env.PLAN_AUTO_FORWARD_DELAY_MS || 2500));
  const recipients = planAnnouncementRecipients();

  for (const contact of recipients) {
    const check = validateSafetyRecipient(contact, { context: 'new_plan_announcement' });
    if (!check.allowed) {
      job.blocked += 1;
      job.results.push({ number: check.number || contact.number, status: 'blocked', reasons: check.reasons });
      continue;
    }
    try {
      if (media) await sendDirectMedia(contact.number, media, job.message, { useRotation: true });
      else await sendDirect(contact.number, job.message, { useRotation: true });
      job.sent += 1;
      recordSafetySend(contact.number, { type: 'new_plan_announcement', productId: job.planId });
      if (typeof logs !== 'undefined') {
        logs.push({ id: uuid(), type: 'plan_announcement', to: contact.number, status: 'sent', planId: job.planId, message: job.message, time: new Date().toISOString() });
      }
      job.results.push({ number: contact.number, status: 'sent' });
    } catch (error) {
      job.failed += 1;
      if (typeof logs !== 'undefined') {
        logs.push({ id: uuid(), type: 'plan_announcement', to: contact.number, status: 'failed', planId: job.planId, error: error.message, time: new Date().toISOString() });
      }
      job.results.push({ number: contact.number, status: 'failed', error: error.message });
    }
    savePlanBroadcastJobs();
    if (typeof logs !== 'undefined') saveJSON('logs.json', logs);
    io.emit('plan_broadcast:update', publicPlanBroadcastJob(job));
    await safetyPauseIfNeeded(job.sent + job.failed);
    await sleep(delayMs);
  }

  job.status = job.failed ? 'completed_with_errors' : 'completed';
  job.finishedAt = new Date().toISOString();
  savePlanBroadcastJobs();
  if (typeof logs !== 'undefined') saveJSON('logs.json', logs);
  io.emit('plan_broadcast:update', publicPlanBroadcastJob(job));
}

