function customerInterestText(customer = {}) {
  return [
    customer.name,
    customer.status,
    customer.source,
    customer.plan,
    customer.planName,
    customer.buyerIntent,
    Array.isArray(customer.tags) ? customer.tags.join(' ') : customer.tags,
    customer.lastMessage,
    customer.lastQuery,
    customer.lastInterest,
    customer.lastQuizResult?.topRecommendation,
    JSON.stringify(customer.lastQuizResult?.answers || {})
  ].filter(Boolean).join(' ').toLowerCase();
}

function inferSalesActivationSegment(customer = {}) {
  const text = customerInterestText(customer);
  for (const [id, def] of Object.entries(SALES_ACTIVATION_SEGMENTS)) {
    if ((def.keywords || []).some(keyword => text.includes(keyword))) return id;
  }
  if (/hot|ai tools lead|interested/.test(text)) return 'ai-tools';
  return 'ai-tools';
}

function salesActivationPromoCount(number = '', days = 7) {
  const clean = normalizeSafetyNumber(number);
  const cutoff = Date.now() - Math.max(1, Number(days || 7)) * 24 * 60 * 60 * 1000;
  return (Array.isArray(logs) ? logs : []).filter(row => {
    const rowNumber = normalizeSafetyNumber(row.to || row.number || row.customerNumber || '');
    const ms = Date.parse(row.time || row.sentAt || row.createdAt || 0);
    return clean && rowNumber === clean && ms >= cutoff && /sales_activation|smart_broadcast|plan_announcement|broadcast/i.test(String(row.type || ''));
  }).length;
}

function salesActivationRecipientRows(segmentId = 'all') {
  const rows = [];
  const blocked = [];
  const seen = new Set();
  for (const customer of Array.isArray(customers) ? customers : []) {
    const number = normalizeSafetyNumber(customer.number || customer.phone || customer.whatsapp || customer.customerNumber || '');
    if (!number || seen.has(number)) continue;
    seen.add(number);
    const inferredSegment = inferSalesActivationSegment(customer);
    if (segmentId !== 'all' && inferredSegment !== segmentId) continue;
    const optIn = normalizeOptInStatus(customer);
    const promoCount = salesActivationPromoCount(number, 7);
    const recipient = { ...customer, number, segment: inferredSegment, optIn };
    const safety = validateSafetyRecipient(recipient, { context: 'sales_activation' });
    if (!optIn) {
      blocked.push({ number, name: customer.name || number, segment: inferredSegment, reason: 'No explicit opt-in' });
      continue;
    }
    if (promoCount >= 2) {
      blocked.push({ number, name: customer.name || number, segment: inferredSegment, reason: '2 promotional messages already sent in 7 days' });
      continue;
    }
    if (!safety.allowed) {
      blocked.push({ number, name: customer.name || number, segment: inferredSegment, reason: safety.reasons.join(', ') });
      continue;
    }
    rows.push({ ...recipient, promoCount });
  }
  return { rows, blocked };
}

function renderSalesActivationMessage(segmentId = 'ai-tools', customer = {}) {
  const def = SALES_ACTIVATION_SEGMENTS[segmentId] || SALES_ACTIVATION_SEGMENTS['ai-tools'];
  const ctx = buildCustomerMessageContext(customer, {
    name: customer.name || 'friend',
    segment: def.label,
    date: new Date().toLocaleDateString('en-PK')
  });
  const rendered = renderDynamicTemplate(def.message, ctx).replace(/\{\{name\}\}/g, customer.name || 'friend');
  return appendUnsubscribeFooter(rendered, { unsubscribeFooterText: settings.unsubscribe_footer });
}

function buildSalesActivationPreview(input = {}) {
  const requestedSegment = String(input.segment || 'all').toLowerCase();
  const segmentIds = requestedSegment === 'all'
    ? Object.keys(SALES_ACTIVATION_SEGMENTS)
    : [requestedSegment].filter(id => SALES_ACTIVATION_SEGMENTS[id]);
  const segments = segmentIds.map(segmentId => {
    const def = SALES_ACTIVATION_SEGMENTS[segmentId];
    const { rows, blocked } = salesActivationRecipientRows(segmentId);
    const sampleCustomer = { name: 'friend', number: '' };
    return {
      id: segmentId,
      label: def.label,
      emoji: def.emoji,
      message: renderSalesActivationMessage(segmentId, sampleCustomer),
      eligible: rows.length,
      blocked: blocked.length,
      targets: rows.slice(0, 25).map(row => ({
        name: row.name || row.number,
        number: maskPhoneValue(row.number),
        promoCount: row.promoCount,
        buyerIntent: row.buyerIntent || ''
      })),
      blockedExamples: blocked.slice(0, 10).map(row => ({ ...row, number: maskPhoneValue(row.number) }))
    };
  });
  return {
    success: true,
    generatedAt: new Date().toISOString(),
    policy: 'Opt-in only. Max 2 promotional messages per customer per 7 days. Draft requires admin approval before sending.',
    segments,
    totalEligible: segments.reduce((sum, row) => sum + row.eligible, 0),
    totalBlocked: segments.reduce((sum, row) => sum + row.blocked, 0),
    recentCampaigns: (Array.isArray(salesActivationCampaigns) ? salesActivationCampaigns : []).slice(0, 20)
  };
}

function formatSalesActivationPreviewReply(preview = {}) {
  const rows = (preview.segments || []).map(segment =>
    `${segment.emoji || '•'} *${segment.label}*\nEligible: *${segment.eligible}* | Blocked: *${segment.blocked}*`
  ).join('\n\n');
  const base = String(settings.gmail_public_base_url || settings.social_public_base_url || `http://localhost:${PORT}`).replace(/\/+$/g, '');
  return [
    '📣 *Sales Activation Preview*',
    '',
    preview.policy || 'Opt-in only. Admin approval required.',
    '',
    rows || 'No segments found.',
    '',
    `Open dashboard: ${base}/sales-activation`,
    '',
    'Create draft:',
    '*!salesdraft ai-tools*',
    '*!salesdraft laptops*',
    '*!salesdraft scholarships*'
  ].join('\n');
}

function createSalesActivationDraft(input = {}) {
  const segmentId = String(input.segment || 'ai-tools').toLowerCase();
  if (!SALES_ACTIVATION_SEGMENTS[segmentId]) throw new Error('Unknown sales activation segment.');
  const { rows, blocked } = salesActivationRecipientRows(segmentId);
  if (!rows.length) throw new Error('No opted-in eligible contacts for this segment.');
  const def = SALES_ACTIVATION_SEGMENTS[segmentId];
  const campaign = {
    id: uuid(),
    segment: segmentId,
    label: def.label,
    status: 'drafted',
    targetCount: rows.length,
    blockedCount: blocked.length,
    createdAt: new Date().toISOString(),
    conversions: []
  };
  const message = String(input.message || renderSalesActivationMessage(segmentId, rows[0] || {})).trim();
  const draft = createMcpActionDraft({
    type: 'broadcast',
    title: `Sales activation - ${def.label}`,
    payload: {
      message,
      targets: rows.map(row => row.number),
      delayMs: Number(input.delayMs || 3500),
      options: {
        useRotation: true,
        campaignId: campaign.id,
        source: 'sales_activation',
        segment: segmentId
      }
    }
  }, 'sales_activation');
  campaign.draftId = draft.id;
  campaign.message = message;
  salesActivationCampaigns.unshift(campaign);
  saveSalesActivationCampaigns();
  return { success: true, campaign, draft, blockedExamples: blocked.slice(0, 10).map(row => ({ ...row, number: maskPhoneValue(row.number) })) };
}

function logSalesActivationConversion(input = {}) {
  const campaignId = String(input.campaignId || input.id || '').trim();
  const campaign = salesActivationCampaigns.find(row => row.id === campaignId || row.draftId === campaignId);
  if (!campaign) throw new Error('Sales activation campaign not found.');
  const conversion = {
    id: uuid(),
    customerNumber: normalizeSafetyNumber(input.customerNumber || input.number || ''),
    orderId: String(input.orderId || '').trim(),
    amount: Number(input.amount || 0),
    note: String(input.note || '').slice(0, 500),
    createdAt: new Date().toISOString()
  };
  campaign.conversions = Array.isArray(campaign.conversions) ? campaign.conversions : [];
  campaign.conversions.unshift(conversion);
  campaign.updatedAt = new Date().toISOString();
  saveSalesActivationCampaigns();
  return { success: true, campaign, conversion };
}

