function normalizePaymentBody(body = {}, current = {}) {
  const rawAmount = body.amount ?? current.amount;
  const amount = Number(rawAmount);
  if (!Number.isFinite(amount) || amount <= 0) throw new Error('amount must be greater than 0');

  const allowedStatuses = new Set(['pending', 'approved', 'failed', 'refunded']);
  const status = String(body.status || current.status || 'pending').toLowerCase();
  if (!allowedStatuses.has(status)) throw new Error('invalid payment status');

  const rawDate = body.date || current.date || current.created || new Date().toISOString();
  const dateObj = new Date(rawDate);
  const date = Number.isNaN(dateObj.getTime()) ? new Date().toISOString() : dateObj.toISOString();
  const customerId = (body.customerId ?? current.customerId ?? '').toString().trim();
  let number = (body.customerNumber ?? body.number ?? current.number ?? current.customerNumber ?? '').toString().replace(/\D/g, '');
  let customerName = (body.customerName ?? current.customerName ?? '').toString().trim();
  const linkedCustomer = customers.find(c => (customerId && c.id === customerId) || (number && c.number === number));
  if (linkedCustomer) {
    number = number || linkedCustomer.number || '';
    customerName = customerName || linkedCustomer.name || '';
  }
  if (!number && !customerName) throw new Error('customer name or WhatsApp number is required');

  return {
    customerId: customerId || linkedCustomer?.id || '',
    customerName: customerName || number,
    number,
    customerNumber: number,
    plan: (body.plan ?? current.plan ?? '').toString().trim() || 'Manual Payment',
    amount,
    method: (body.method ?? current.method ?? 'Manual').toString().trim() || 'Manual',
    status,
    date,
    reference: (body.reference ?? current.reference ?? '').toString().trim(),
    notes: (body.notes ?? current.notes ?? '').toString().trim()
  };
}

function applyApprovedPaymentToCustomer(payment) {
  if (!payment || payment.status !== 'approved') return;
  const cust = customers.find(c =>
    (payment.customerId && c.id === payment.customerId) ||
    (payment.number && c.number === payment.number)
  );
  if (!cust) return;
  cust.status = 'active';
  if (payment.plan) {
    cust.plan = payment.plan;
    cust.planName = payment.plan;
  }
  cust.lastPaymentAt = payment.date || new Date().toISOString();
  cust.lastPaymentAmount = payment.amount;
  saveJSON('customers.json', customers);
}

