let webhooks = loadJSON('webhooks.json', []);
let webhookLogs = loadJSON('webhook_logs.json', []);

const WEBHOOK_EVENTS = [
  'all',
  'new_message',
  'new_lead',
  'message_sent',
  'payment_created',
  'payment_approved',
  'order_created',
  'order_updated',
  'order_status_changed',
  'product_updated',
  'campaign_complete',
  'group_price_captured',
  'hot_signal'
];

function normalizeWebhookEvents(events = []) {
  if (typeof events === 'string') {
    events = events.split(/,|\s+/).map(x => x.trim()).filter(Boolean);
  }
  if (!Array.isArray(events) || !events.length) events = ['all'];
  const clean = events.map(e => e.toString().trim()).filter(Boolean);
  return [...new Set(clean.length ? clean : ['all'])];
}

function normalizeWebhook(body = {}, existing = {}) {
  const url = (body.url || existing.url || '').toString().trim();
  return {
    ...existing,
    id: existing.id || uuid(),
    name: (body.name || existing.name || 'Automation Webhook').toString().trim(),
    url,
    events: normalizeWebhookEvents(body.events ?? existing.events ?? ['all']),
    active: boolFromBody(body.active, existing.active !== undefined ? existing.active : true),
    secret: (body.secret ?? existing.secret ?? '').toString(),
    headers: body.headers && typeof body.headers === 'object' ? body.headers : (existing.headers || {}),
    retries: Math.min(5, Math.max(0, Number(body.retries ?? existing.retries ?? 1))),
    timeoutMs: Math.min(30000, Math.max(1000, Number(body.timeoutMs ?? existing.timeoutMs ?? 8000))),
    created: existing.created || new Date().toISOString(),
    updated: new Date().toISOString()
  };
}

function normalizeTrainingSource(input = {}, existing = {}) {
  const content = String(input.content || existing.content || '').trim();
  const encrypted = maybeEncryptSensitive(content);
  return {
    ...existing,
    id: String(input.id || existing.id || uuid()),
    title: String(input.title || existing.title || 'Knowledge Source').trim(),
    type: String(input.type || existing.type || 'faq').trim().toLowerCase(),
    url: String(input.url || existing.url || '').trim(),
    content: encrypted ? '' : content,
    contentEncrypted: encrypted || existing.contentEncrypted || '',
    tags: Array.isArray(input.tags) ? input.tags : String(input.tags || existing.tags || '').split(',').map(x => x.trim()).filter(Boolean),
    active: input.active !== false && existing.active !== false,
    chunks: content.split(/\n\s*\n|\r\n\r\n/).map(x => x.trim()).filter(Boolean).slice(0, 100),
    createdAt: existing.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

function searchTrainingKnowledge(query = '', sourceIds = []) {
  const q = String(query || '').toLowerCase().trim();
  const terms = q.split(/\s+/).filter(Boolean);
  const allowed = Array.isArray(sourceIds) && sourceIds.length ? new Set(sourceIds.map(String)) : null;
  const results = [];
  for (const source of (aiTrainingSources || []).filter(item => item.active !== false)) {
    if (allowed && !allowed.has(String(source.id))) continue;
    for (const chunk of (source.chunks || [])) {
      const lower = chunk.toLowerCase();
      let score = 0;
      terms.forEach(term => {
        if (lower.includes(term)) score += 1;
      });
      if (!terms.length && chunk) score = 1;
      if (score > 0) results.push({ sourceId: source.id, title: source.title, type: source.type, score, chunk });
    }
  }
  return results.sort((a, b) => b.score - a.score).slice(0, 5);
}

function buildTrainingAnswer(query = '', matches = []) {
  if (!matches.length) {
    return `Mujhe abhi exact knowledge base match nahi mila.\n\nQuery: ${query}\n\nWebsite text, FAQ, ya PDF notes add karein aur phir dobara test karein.`;
  }
  const bullets = matches.map((item, index) => `${index + 1}. [${item.type}] ${item.title}\n${item.chunk.slice(0, 320)}`).join('\n\n');
  return `*Knowledge Base Reply*\n\nQuery: ${query}\n\nBest matches:\n${bullets}`;
}

function normalizeAppointment(input = {}, existing = {}) {
  const notes = String(input.notes || existing.notes || '').trim();
  const encryptedNotes = maybeEncryptSensitive(notes);
  return {
    ...existing,
    id: String(input.id || existing.id || uuid()),
    name: String(input.name || existing.name || '').trim(),
    phone: normalizeNumber(input.phone || existing.phone || ''),
    service: String(input.service || existing.service || 'consultation').trim(),
    scheduleAt: String(input.scheduleAt || existing.scheduleAt || '').trim(),
    notes: encryptedNotes ? '' : notes,
    notesEncrypted: encryptedNotes || existing.notesEncrypted || '',
    status: String(input.status || existing.status || 'pending').trim(),
    source: String(input.source || existing.source || 'dashboard').trim(),
    createdAt: existing.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

function analyzeStructuredIntent(text = '') {
  const lower = String(text || '').toLowerCase();
  const patterns = [
    { type: 'support', regex: /\b(help|support|issue|problem|refund|complain|ticket)\b/i },
    { type: 'booking', regex: /\b(book|booking|reserve|appointment|schedule|slot|meeting)\b/i },
    { type: 'order_tracking', regex: /\b(order|track|tracking|shipment|delivery|status|invoice)\b/i },
    { type: 'lead_capture', regex: /\b(price|rates|quote|plan|subscription|buy|purchase|demo|trial)\b/i }
  ];
  const matched = patterns.find(item => item.regex.test(lower));
  const openEnded = /\b(who|what|when|where|why|how|explain|anything|tell me about|general|random|chatgpt|perplexity|essay|story)\b/i.test(lower)
    && !matched;
  return {
    type: matched?.type || (openEnded ? 'open_ended' : 'structured_unknown'),
    compliant: !!matched || !openEnded,
    openEnded,
    handoffRecommended: openEnded || !matched
  };
}

function analyzeCustomerIntent(text = '') {
  const base = analyzeStructuredIntent(text);
  const lower = String(text || '').toLowerCase();
  const signals = [];
  if (/\b(budget|cheap|low budget|affordable|under|less than|small budget)\b/i.test(lower)) signals.push('budget_sensitive');
  if (/\b(today|tomorrow|friday|delivery|kab milega|when|urgent|jaldi)\b/i.test(lower)) signals.push('delivery_timeline');
  if (/\b(best|recommend|which one|kon sa|suggest)\b/i.test(lower)) signals.push('recommendation_needed');
  if (/\b(price|rate|kitne|cost|charges)\b/i.test(lower)) signals.push('pricing_request');
  if (/\b(issue|not working|support|refund|claim|replace)\b/i.test(lower)) signals.push('support_request');
  const confidence = base.compliant ? Math.min(0.95, 0.55 + (signals.length * 0.1)) : 0.35;
  return {
    ...base,
    signals,
    confidence: Number(confidence.toFixed(2))
  };
}

function getPythonCommand() {
  return String(process.env.PYTHON_BIN || 'python').trim() || 'python';
}

function normalizeExtractedKnowledge(text = '', maxLength = 50000) {
  return String(text || '')
    .replace(/\u0000/g, ' ')
    .replace(/\r/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim()
    .slice(0, maxLength);
}

function extractHtmlTextFallback(html = '') {
  return normalizeExtractedKnowledge(
    String(html || '')
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/gi, ' ')
      .replace(/&amp;/gi, '&')
      .replace(/&lt;/gi, '<')
      .replace(/&gt;/gi, '>')
      .replace(/\s+/g, ' ')
  );
}

function runPythonExtraction(mode = '', payload = '', useStdin = false) {
  const pythonCode = [
    'import sys',
    'mode = sys.argv[1]',
    'target = sys.argv[2] if len(sys.argv) > 2 else ""',
    'text = ""',
    'if mode == "pdf":',
    '    from pypdf import PdfReader',
    '    reader = PdfReader(target)',
    '    chunks = []',
    '    for page in reader.pages:',
    '        chunks.append(page.extract_text() or "")',
    '    text = "\\n\\n".join(chunks)',
    'elif mode == "docx":',
    '    from docx import Document',
    '    doc = Document(target)',
    '    paras = [p.text.strip() for p in doc.paragraphs if p.text and p.text.strip()]',
    '    text = "\\n".join(paras)',
    'elif mode == "html_file":',
    '    from bs4 import BeautifulSoup',
    '    with open(target, "r", encoding="utf-8", errors="ignore") as fh:',
    '        html = fh.read()',
    '    soup = BeautifulSoup(html, "html.parser")',
    '    for tag in soup(["script", "style", "noscript"]):',
    '        tag.decompose()',
    '    title = soup.title.get_text(" ", strip=True) if soup.title else ""',
    '    body = soup.get_text("\\n", strip=True)',
    '    text = (title + "\\n\\n" + body).strip() if title else body',
    'elif mode == "html_text":',
    '    from bs4 import BeautifulSoup',
    '    html = sys.stdin.read()',
    '    soup = BeautifulSoup(html, "html.parser")',
    '    for tag in soup(["script", "style", "noscript"]):',
    '        tag.decompose()',
    '    title = soup.title.get_text(" ", strip=True) if soup.title else ""',
    '    body = soup.get_text("\\n", strip=True)',
    '    text = (title + "\\n\\n" + body).strip() if title else body',
    'sys.stdout.write(text[:200000])'
  ].join('\n');

  return execFileSync(getPythonCommand(), ['-c', pythonCode, mode, useStdin ? '' : String(payload || '')], {
    encoding: 'utf8',
    stdio: ['pipe', 'pipe', 'pipe'],
    input: useStdin ? String(payload || '') : undefined,
    windowsHide: true
  });
}

function extractTrainingContentFromFile(filePath = '', originalName = '') {
  const ext = path.extname(originalName || filePath || '').toLowerCase();
  if (['.txt', '.md', '.csv', '.json'].includes(ext)) {
    return normalizeExtractedKnowledge(fs.readFileSync(filePath, 'utf8'));
  }
  if (['.html', '.htm'].includes(ext)) {
    try {
      return normalizeExtractedKnowledge(runPythonExtraction('html_file', filePath));
    } catch {
      return extractHtmlTextFallback(fs.readFileSync(filePath, 'utf8'));
    }
  }
  if (ext === '.pdf') {
    try {
      return normalizeExtractedKnowledge(runPythonExtraction('pdf', filePath));
    } catch (error) {
      return normalizeExtractedKnowledge(`Uploaded PDF: ${originalName}\n\nAutomatic parsing failed: ${error.message}\nPlease add a short manual summary for this document.`);
    }
  }
  if (ext === '.docx') {
    try {
      return normalizeExtractedKnowledge(runPythonExtraction('docx', filePath));
    } catch (error) {
      return normalizeExtractedKnowledge(`Uploaded DOCX: ${originalName}\n\nAutomatic parsing failed: ${error.message}\nPlease add a short manual summary for this document.`);
    }
  }
  return normalizeExtractedKnowledge(`Uploaded file: ${originalName}\n\nAutomatic deep parsing is not available for this file type in the current runtime. Please add a short manual summary below this line.`);
}

function extractTrainingContentFromHtml(html = '') {
  try {
    return normalizeExtractedKnowledge(runPythonExtraction('html_text', html, true));
  } catch {
    return extractHtmlTextFallback(html);
  }
}

function sensitiveEncryptionKey() {
  return String(process.env.DATA_ENCRYPTION_KEY || settings?.admin_password || '').trim();
}

function maybeEncryptSensitive(text = '') {
  const value = String(text || '');
  if (!value || settings?.gdpr_mode_enabled === false) return '';
  const secret = sensitiveEncryptionKey();
  if (!secret) return '';
  try {
    const crypto = require('crypto');
    const key = crypto.createHash('sha256').update(secret).digest();
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
    const enc = Buffer.concat([cipher.update(value, 'utf8'), cipher.final()]);
    return `${iv.toString('hex')}:${enc.toString('hex')}`;
  } catch {
    return '';
  }
}

function maybeDecryptSensitive(payload = '', fallback = '') {
  const value = String(payload || '');
  if (!value) return String(fallback || '');
  const secret = sensitiveEncryptionKey();
  if (!secret) return String(fallback || '');
  try {
    const crypto = require('crypto');
    const [ivHex, dataHex] = value.split(':');
    if (!ivHex || !dataHex) return String(fallback || '');
    const key = crypto.createHash('sha256').update(secret).digest();
    const iv = Buffer.from(ivHex, 'hex');
    const encrypted = Buffer.from(dataHex, 'hex');
    const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
    return Buffer.concat([decipher.update(encrypted), decipher.final()]).toString('utf8');
  } catch {
    return String(fallback || '');
  }
}

