function normalizeWAAccountConfig(input = {}, existing = {}) {
  const baseId = String(input.id ?? existing.id ?? '').trim().toLowerCase();
  const normalizedId = (baseId || 'default').replace(/[^a-z0-9_-]+/g, '-').replace(/^-+|-+$/g, '') || 'default';
  return {
    id: normalizedId,
    name: String(input.name ?? existing.name ?? (normalizedId === 'default' ? 'Primary WhatsApp' : normalizedId)).trim() || (normalizedId === 'default' ? 'Primary WhatsApp' : normalizedId),
    phone: normalizeNumber(input.phone ?? existing.phone ?? ''),
    enabled: input.enabled !== undefined ? input.enabled !== false : (existing.enabled !== false),
    notes: String(input.notes ?? existing.notes ?? '').trim(),
    addedAt: existing.addedAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };
}

function ensureDefaultWAAccount() {
  const rows = Array.isArray(waAccounts) ? waAccounts.slice() : [];
  const seen = new Set();
  const normalized = [];
  for (const row of rows) {
    const item = normalizeWAAccountConfig(row, row);
    if (seen.has(item.id)) continue;
    seen.add(item.id);
    normalized.push(item);
  }
  if (!seen.has('default')) {
    normalized.unshift(normalizeWAAccountConfig({ id: 'default', name: 'Primary WhatsApp', enabled: true }, {}));
  }
  waAccounts = normalized;
  saveJSON('wa_accounts.json', waAccounts);
}

function saveWAAccounts() {
  ensureDefaultWAAccount();
}

function saveWARotationState() {
  if (!waRotationState || typeof waRotationState !== 'object') {
    waRotationState = { currentIndex: 0, lastTenantId: 'default', sentCounts: {}, updatedAt: null };
  }
  saveJSON('wa_rotation_state.json', waRotationState);
}

function cleanupInboxPresence() {
  const ttlMs = Math.max(15000, Number(process.env.INBOX_PRESENCE_TTL_MS || 120000));
  const now = Date.now();
  const cleaned = {};
  for (const [chatId, agents] of Object.entries(inboxPresence || {})) {
    const nextAgents = {};
    for (const [agentKey, item] of Object.entries(agents || {})) {
      const updatedAt = new Date(item.updatedAt || 0).getTime();
      if (updatedAt && now - updatedAt <= ttlMs) {
        nextAgents[agentKey] = item;
      }
    }
    if (Object.keys(nextAgents).length) cleaned[chatId] = nextAgents;
  }
  inboxPresence = cleaned;
}

function presenceRowsForChat(chatId = '') {
  cleanupInboxPresence();
  const rows = Object.entries((inboxPresence || {})[chatId] || {}).map(([agentKey, item]) => ({
    chatId,
    agentKey,
    agent: item.agent || agentKey,
    team: item.team || '',
    status: item.status || 'viewing',
    updatedAt: item.updatedAt || null
  }));
  return rows.sort((a, b) => new Date(b.updatedAt || 0).getTime() - new Date(a.updatedAt || 0).getTime());
}

function buildWAAccountSnapshot(accountId = 'default') {
  ensureDefaultWAAccount();
  const config = waAccounts.find(item => item.id === accountId) || normalizeWAAccountConfig({ id: accountId, name: accountId }, {});
  const inst = waClients.get(accountId);
  const cachedQr = waLastQR.tenantId === accountId ? waLastQR.data : null;
  return {
    ...config,
    connected: !!inst?.isReady,
    status: inst?.isReady ? 'ready' : (inst?.status || (accountId === 'default' ? waLastState.status : 'idle')),
    message: inst?.isReady ? 'WhatsApp linked' : (inst?.statusMsg || (accountId === 'default' ? waLastState.message : 'Idle')),
    error: inst?.error || (accountId === 'default' ? waLastState.error : ''),
    hasSession: hasWASession(accountId),
    qr: inst?.isReady ? null : (inst?.qr || cachedQr || null),
    qrGeneratedAt: inst?.qrGeneratedAt || (waLastQR.tenantId === accountId ? waLastQR.generatedAt : 0) || 0,
    pairingCode: inst?.pairingCode || null,
    pairingPhone: inst?.pairingPhone || '',
    info: inst?.info || null,
    sentCount: Number(waRotationState?.sentCounts?.[accountId] || 0)
  };
}

function resolveReadyWAAccountIds() {
  ensureDefaultWAAccount();
  const configuredReady = waAccounts
    .filter(item => item.enabled !== false)
    .map(item => item.id)
    .filter(id => waClients.get(id)?.isReady);
  if (configuredReady.length) return configuredReady;
  return Array.from(waClients.entries())
    .filter(([, inst]) => !!inst?.isReady)
    .map(([id]) => id);
}

function pickOutboundWAAccountId(options = {}) {
  const preferred = String(options.accountId || options.preferredAccountId || '').trim();
  const readyIds = resolveReadyWAAccountIds();
  if (preferred && readyIds.includes(preferred)) return preferred;
  if (!readyIds.length) return preferred || 'default';
  if (options.useRotation !== true || options.disableRotation || settings.account_rotation_enabled === false || readyIds.length === 1) {
    return readyIds.includes('default') ? 'default' : readyIds[0];
  }
  if (settings.account_rotation_strategy === 'primary_first' && readyIds.includes('default')) {
    return 'default';
  }
  const currentIndex = Number(waRotationState?.currentIndex || 0);
  const nextIndex = ((currentIndex % readyIds.length) + readyIds.length) % readyIds.length;
  const picked = readyIds[nextIndex];
  waRotationState.currentIndex = (nextIndex + 1) % readyIds.length;
  waRotationState.lastTenantId = picked;
  waRotationState.updatedAt = new Date().toISOString();
  saveWARotationState();
  return picked;
}

function resolveOutboundWAInstance(options = {}) {
  const accountId = pickOutboundWAAccountId(options);
  const inst = waClients.get(accountId);
  return { accountId, inst };
}

function markWAAccountSend(accountId = 'default') {
  waRotationState.sentCounts = waRotationState.sentCounts || {};
  waRotationState.sentCounts[accountId] = Number(waRotationState.sentCounts[accountId] || 0) + 1;
  waRotationState.lastTenantId = accountId;
  waRotationState.updatedAt = new Date().toISOString();
  saveWARotationState();
}

