function logWebhookDelivery(row = {}) {
  webhookLogs.push({
    id: uuid(),
    time: new Date().toISOString(),
    ...row
  });
  saveWebhookLogs();
}

function webhookMatches(hook, eventName) {
  if (!hook || hook.active === false) return false;
  const events = normalizeWebhookEvents(hook.events);
  return events.includes('all') || events.includes(eventName);
}

async function deliverWebhook(hook, eventName, payload, meta = {}) {
  const axios = require('axios');
  const started = Date.now();
  const body = {
    event: eventName,
    data: payload,
    timestamp: new Date().toISOString(),
    source: 'supersender-pro'
  };
  const headers = {
    'Content-Type': 'application/json',
    'X-SuperSender-Event': eventName,
    'X-SuperSender-Webhook': hook.id,
    ...(hook.headers || {})
  };
  if (hook.secret) {
    try {
      const crypto = require('crypto');
      headers['X-SuperSender-Signature'] = crypto
        .createHmac('sha256', hook.secret)
        .update(JSON.stringify(body))
        .digest('hex');
    } catch {}
  }
  let lastError = null;
  const maxAttempts = Math.max(1, Number(hook.retries || 0) + 1);
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const res = await axios.post(hook.url, body, {
        headers,
        timeout: Number(hook.timeoutMs || 8000),
        validateStatus: () => true
      });
      const ok = res.status >= 200 && res.status < 300;
      const log = {
        webhookId: hook.id,
        webhookName: hook.name,
        url: hook.url,
        event: eventName,
        status: ok ? 'delivered' : 'failed',
        httpStatus: res.status,
        attempts: attempt,
        durationMs: Date.now() - started,
        responsePreview: typeof res.data === 'string' ? res.data.slice(0, 300) : JSON.stringify(res.data || {}).slice(0, 300),
        meta
      };
      logWebhookDelivery(log);
      if (ok) return { success: true, ...log };
      lastError = new Error(`HTTP ${res.status}`);
    } catch (error) {
      lastError = error;
      if (attempt < maxAttempts) await sleep(600 * attempt);
    }
  }
  const log = {
    webhookId: hook.id,
    webhookName: hook.name,
    url: hook.url,
    event: eventName,
    status: 'failed',
    httpStatus: 0,
    attempts: maxAttempts,
    durationMs: Date.now() - started,
    error: lastError?.message || 'Webhook failed',
    meta
  };
  logWebhookDelivery(log);
  return { success: false, ...log };
}

// Function to broadcast events to external apps (Zapier/Make)
async function triggerWebhooks(eventName, payload) {
  const matched = (webhooks || []).filter(hook => webhookMatches(hook, eventName));
  matched.forEach(hook => {
    deliverWebhook(hook, eventName, payload).catch(error => {
      logWebhookDelivery({
        webhookId: hook.id,
        webhookName: hook.name,
        url: hook.url,
        event: eventName,
        status: 'failed',
        error: error.message
      });
    });
  });
  return { matched: matched.length };
}

function queueWebhookEvent(eventName, payload) {
  try {
    setImmediate(() => {
      triggerWebhooks(eventName, payload).catch(error => {
        logWebhookDelivery({
          event: eventName,
          status: 'failed',
          error: error.message,
          meta: { queued: true }
        });
      });
    });
  } catch (error) {
    logWebhookDelivery({
      event: eventName,
      status: 'failed',
      error: error.message,
      meta: { queued: true }
    });
  }
}

// Global outgoing webhooks management APIs
app.get('/api/webhooks', (req, res) => {
  webhooks = (webhooks || []).map(w => normalizeWebhook(w));
  saveWebhooks();
  res.json(webhooks.map(w => ({ ...w, secret: w.secret ? '********' : '' })));
});
app.get('/api/webhooks/events', (req, res) => res.json({ events: WEBHOOK_EVENTS }));
app.get('/api/webhooks/logs', (req, res) => {
  const limit = Math.min(500, Math.max(1, Number(req.query.limit || 100)));
  const event = (req.query.event || '').toString();
  let rows = webhookLogs || [];
  if (event) rows = rows.filter(r => r.event === event);
  res.json(rows.slice(-limit).reverse());
});
app.post('/api/webhooks', (req, res) => {
  const w = normalizeWebhook(req.body || {});
  if (!/^https?:\/\//i.test(w.url)) return res.status(400).json({ error: 'valid webhook URL is required' });
  webhooks.push(w);
  saveWebhooks();
  res.json(w);
});
app.put('/api/webhooks/:id', (req, res) => {
  const idx = webhooks.findIndex(w => w.id === req.params.id);
  if (idx < 0) return res.status(404).json({ error: 'Webhook not found' });
  webhooks[idx] = normalizeWebhook(req.body || {}, webhooks[idx]);
  saveWebhooks();
  res.json({ ...webhooks[idx], secret: webhooks[idx].secret ? '********' : '' });
});
app.delete('/api/webhooks/:id', (req, res) => {
  webhooks = webhooks.filter(w => w.id !== req.params.id);
  saveWebhooks();
  res.json({ success: true });
});
app.post('/api/webhooks/:id/test', async (req, res) => {
  const hook = webhooks.find(w => w.id === req.params.id);
  if (!hook) return res.status(404).json({ error: 'Webhook not found' });
  const result = await deliverWebhook(normalizeWebhook(hook), req.body?.event || 'test', {
    message: 'SuperSender Pro webhook test',
    sample: true
  }, { manualTest: true });
  res.status(result.success ? 200 : 502).json(result);
});
app.post('/api/webhooks/test', async (req, res) => {
  const hook = normalizeWebhook({ ...req.body, active: true, retries: 0 });
  if (!/^https?:\/\//i.test(hook.url)) return res.status(400).json({ error: 'valid webhook URL is required' });
  const result = await deliverWebhook(hook, req.body?.event || 'test', {
    message: 'SuperSender Pro webhook test',
    sample: true
  }, { manualTest: true, unsaved: true });
  res.status(result.success ? 200 : 502).json(result);
});

