app.post('/api/apikeys', (req, res) => {
  const name = (req.body?.name || 'Key').toString().trim();
  const k = { id: uuid(), name, key: makeApiKey(), status: 'active', hits: 0, created: new Date().toISOString(), lastUsed: null };
  apiKeys.unshift(k);
  if (apiKeys.length > 200) apiKeys = apiKeys.slice(0, 200);
  saveApiKeys();
  res.json(k);
});
app.delete('/api/apikeys/:id', (req, res) => {
  const before = apiKeys.length;
  apiKeys = apiKeys.filter(k => k.id !== req.params.id);
  saveApiKeys();
  res.json({ success: true, removed: before - apiKeys.length });
});

function requireApiKey(req, res, next) {
  const key = (req.headers['x-api-key'] || '').toString().trim();
  const found = (apiKeys || []).find(k => k.key === key && k.status === 'active');
  if (!found) return res.status(401).json({ error: 'Invalid API key' });
  found.hits = (found.hits || 0) + 1;
  found.lastUsed = new Date().toISOString();
  saveApiKeys();
  req.apiKey = found;
  next();
}

// Minimal MCP routes
app.post('/mcp/send', requireApiKey, async (req, res) => {
  try {
    const { number, message } = req.body || {};
    if (!number || !message) return res.status(400).json({ error: 'number and message are required' });
    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
    await sendDirect(number, message);
    logs.push({ id: uuid(), type: 'api', to: normalizeNumber(number), status: 'sent', message, time: new Date().toISOString(), apiKeyId: req.apiKey?.id });
    saveJSON('logs.json', logs);
    queueWebhookEvent('message_sent', { number, message, source: 'mcp_api', apiKeyId: req.apiKey?.id });
    res.json({ success: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Generic Incoming Webhook Receiver (from Zapier, Make, Pabbly, Custom Apps)
app.post('/api/webhook/incoming', async (req, res) => {
  try {
    const { action, number, message, data = {} } = req.body || {};
    logWebhookDelivery({
      webhookName: 'Incoming Webhook',
      url: req.originalUrl,
      event: action || 'incoming',
      status: 'received',
      httpStatus: 200,
      payloadPreview: JSON.stringify(req.body || {}).slice(0, 500)
    });
    
    // Action 1: Send WhatsApp Message
    if (action === 'send_message' && number && message) {
      const inst = waClients.get('default');
      if (inst && inst.isReady) {
        await sendDirect(number, message);
        triggerWebhooks('message_sent', { number, message, source: 'incoming_webhook' });
        return res.json({ success: true, result: 'Message sent via Webhook' });
      } else {
        return res.status(500).json({ success: false, error: 'WhatsApp not ready' });
      }
    }
    
    // Action 2: Add Customer/Lead
    if (action === 'create_lead') {
      const normalized = normalizeSafetyNumber(number || data.number || data.phone || '');
      if (!normalized) return res.status(400).json({ success: false, error: 'number is required for create_lead' });
      const existing = customers.find(c => normalizeSafetyNumber(c.number || c.phone) === normalized);
      const c = existing || {
        id: uuid(),
        number: normalized,
        name: data.name || req.body.name || 'Webhook Lead',
        status: 'lead',
        platform: data.source || req.body.source || 'Webhook',
        tags: []
      };
      Object.assign(c, {
        ...data,
        number: normalized,
        name: data.name || req.body.name || c.name,
        updated: new Date().toISOString(),
        created: c.created || new Date().toISOString()
      });
      if (!existing) customers.push(c);
      saveJSON('customers.json', customers);
      triggerWebhooks('new_lead', c);
      return res.json({ success: true, result: 'Lead created', lead: c });
    }

    if (action === 'create_order') {
      const orderData = data.order || data || {};
      const customerNumber = normalizeSafetyNumber(number || orderData.customerNumber || orderData.phone || '');
      const items = Array.isArray(orderData.items) && orderData.items.length
        ? orderData.items
        : [{ name: orderData.productName || orderData.product || 'Webhook Item', qty: Number(orderData.qty || 1), price: Number(orderData.price || orderData.amount || 0) }];
      if (!customerNumber) return res.status(400).json({ success: false, error: 'customerNumber is required for create_order' });
      const total = Number(orderData.total || items.reduce((sum, i) => sum + (Number(i.price || 0) * Number(i.qty || 1)), 0));
      const order = {
        id: uuid(),
        orderNumber: typeof generateOrderNumber === 'function' ? generateOrderNumber() : `ORD-${Date.now()}`,
        customerNumber,
        customerName: orderData.customerName || orderData.name || customerNumber,
        items,
        total,
        notes: orderData.notes || 'Created from incoming webhook',
        deliveryAddress: orderData.deliveryAddress || orderData.address || '',
        status: orderData.status || 'pending',
        source: orderData.source || 'incoming_webhook',
        statusHistory: [{ status: orderData.status || 'pending', time: new Date().toISOString(), note: 'Order created by webhook' }],
        created: new Date().toISOString(),
        updated: new Date().toISOString()
      };
      orders.push(order);
      saveJSON('orders.json', orders);
      io.emit('new_order', order);
      triggerWebhooks('order_created', order);
      return res.json({ success: true, result: 'Order created', order });
    }

    if (action === 'record_payment' || action === 'create_payment') {
      const body = normalizePaymentBody({
        ...(data.payment || data || {}),
        number: number || data.number || data.phone,
        status: data.status || req.body.status || 'pending'
      });
      const payment = { id: uuid(), ...body, created: new Date().toISOString(), updated: new Date().toISOString(), source: 'incoming_webhook' };
      payments.push(payment);
      saveJSON('payments.json', payments);
      applyApprovedPaymentToCustomer(payment);
      triggerWebhooks(payment.status === 'approved' || payment.status === 'paid' ? 'payment_approved' : 'payment_created', payment);
      return res.json({ success: true, result: 'Payment recorded', payment });
    }

    if (action === 'product_upsert' || action === 'upsert_product') {
      const product = data.product || data || {};
      const productId = product.id || product.sku || uuid();
      const idx = laptopProducts.findIndex(p => p.id === productId || (product.sku && p.sku === product.sku));
      const row = {
        ...(idx >= 0 ? laptopProducts[idx] : {}),
        ...product,
        id: productId,
        name: product.name || product.title || 'Webhook Product',
        updated: new Date().toISOString(),
        created: idx >= 0 ? laptopProducts[idx].created : new Date().toISOString()
      };
      if (idx >= 0) laptopProducts[idx] = row;
      else laptopProducts.unshift(row);
      saveJSON('laptop_products.json', laptopProducts);
      triggerWebhooks('product_updated', row);
      return res.json({ success: true, result: idx >= 0 ? 'Product updated' : 'Product created', product: row });
    }
    
    res.status(400).json({ success: false, error: 'Invalid action or missing parameters' });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

