function createSystemAlert(input = {}) {
  try {
    const alert = {
      id: input.id || uuid(),
      type: input.type || 'info',
      title: input.title || 'System Alert',
      message: input.message || '',
      severity: input.severity || input.level || 'info',
      source: input.source || 'system',
      meta: input.meta || {},
      read: input.read === true ? true : false,
      createdAt: input.createdAt || new Date().toISOString()
    };
    alerts.unshift(alert);
    saveAlerts();
    try { io.emit('alert', alert); } catch {}
    return alert;
  } catch (error) {
    console.warn('[Alerts] create skipped:', error.message);
    return null;
  }
}

