// In-memory campaign runners (pause/stop). Persisted campaign state is in campaigns.json.
const campaignRunners = new Map(); // id -> { paused:boolean, stopped:boolean }

function normalizeNumber(n) {
  return (n || '').toString().replace(/\D/g, '');
}

function renderDynamicTemplate(text = '', variables = {}) {
  return renderMergeFields(text, buildCustomerMessageContext(variables.customer || variables.contact || variables.customerId || variables.number || '', variables));
}

function ensureGuestCustomer(number, name = '', source = 'whatsapp') {
  const clean = normalizeNumber(number);
  if (!clean || clean.endsWith('g')) return null;
  let customer = customers.find(c => normalizeNumber(c.number || c.phone || c.whatsapp || '') === clean);
  if (customer) {
    customer.lastSeen = new Date().toISOString();
    if (name && (!customer.name || customer.name === customer.number)) customer.name = name;
    return customer;
  }
  customer = {
    id: uuid(),
    name: name || clean,
    number: clean,
    phone: clean,
    status: 'lead',
    source,
    tags: ['Guest'],
    created: new Date().toISOString(),
    lastSeen: new Date().toISOString(),
    autoSaved: true
  };
  customers.unshift(customer);
  if (customers.length > 5000) customers = customers.slice(0, 5000);
  saveJSON('customers.json', customers);
  io.emit('customer_added', customer);
  return customer;
}

function shouldAttachUnsubscribeFooter(campaign = {}) {
  if (campaign.disableUnsubscribeFooter === true) return false;
  if (campaign.unsubscribeFooter === false) return false;
  return settings.unsubscribe_footer_enabled !== false;
}

function appendUnsubscribeFooter(text = '', campaign = {}) {
  let output = String(text || '').trim();
  if (!output || !shouldAttachUnsubscribeFooter(campaign)) return output;
  const footer = String(
    campaign.unsubscribeFooterText ||
    settings.unsubscribe_footer ||
    'Reply STOP to unsubscribe.'
  ).trim();
  if (!footer) return output;
  const lower = output.toLowerCase();
  if (lower.includes('unsubscribe') || lower.includes('reply stop') || lower.includes('stop to')) return output;
  return `${output}\n\n${footer}`;
}

function parseMultilineOptions(value = '') {
  return String(value || '')
    .split(/\r?\n|\|/g)
    .map(item => item.trim())
    .filter(Boolean);
}

function hashString(value = '') {
  let hash = 0;
  const text = String(value || '');
  for (let i = 0; i < text.length; i++) {
    hash = ((hash << 5) - hash) + text.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash);
}

function pickStableOption(list = [], seed = '') {
  const items = Array.isArray(list) ? list.filter(Boolean) : [];
  if (!items.length) return '';
  return items[hashString(seed || Date.now().toString()) % items.length];
}

function numericLike(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function getLogicContext(input = {}) {
  const tags = Array.isArray(input.tags)
    ? input.tags
    : String(input.tags || '').split(',').map(tag => tag.trim()).filter(Boolean);
  return {
    ...input,
    tags,
    tagsText: tags.join(', '),
    points: numericLike(input.points ?? input.loyaltyPoints ?? input.score) ?? 0,
    leadScore: numericLike(input.leadScore) ?? 0
  };
}

function getRuleFieldValue(ctx = {}, field = '') {
  const key = String(field || '').trim();
  if (!key) return '';
  if (key === 'tags') return Array.isArray(ctx.tags) ? ctx.tags : [];
  return ctx[key];
}

function evaluateRuleMatch(rule = {}, ctx = {}) {
  const actual = getRuleFieldValue(ctx, rule.field);
  const expected = rule.value;
  const op = String(rule.operator || 'equals').trim().toLowerCase();
  const actualNum = numericLike(actual);
  const expectedNum = numericLike(expected);
  switch (op) {
    case 'equals':
    case 'eq':
      return String(actual ?? '').toLowerCase() === String(expected ?? '').toLowerCase();
    case 'not_equals':
    case 'neq':
      return String(actual ?? '').toLowerCase() !== String(expected ?? '').toLowerCase();
    case 'contains':
      if (Array.isArray(actual)) return actual.map(v => String(v).toLowerCase()).includes(String(expected || '').toLowerCase());
      return String(actual ?? '').toLowerCase().includes(String(expected ?? '').toLowerCase());
    case 'not_contains':
      if (Array.isArray(actual)) return !actual.map(v => String(v).toLowerCase()).includes(String(expected || '').toLowerCase());
      return !String(actual ?? '').toLowerCase().includes(String(expected ?? '').toLowerCase());
    case 'gt':
      return actualNum !== null && expectedNum !== null && actualNum > expectedNum;
    case 'gte':
      return actualNum !== null && expectedNum !== null && actualNum >= expectedNum;
    case 'lt':
      return actualNum !== null && expectedNum !== null && actualNum < expectedNum;
    case 'lte':
      return actualNum !== null && expectedNum !== null && actualNum <= expectedNum;
    case 'exists':
      return Array.isArray(actual) ? actual.length > 0 : String(actual ?? '').trim() !== '';
    case 'not_exists':
      return Array.isArray(actual) ? actual.length === 0 : String(actual ?? '').trim() === '';
    default:
      return false;
  }
}

function evaluateCustomLogicRules(context = {}) {
  const ctx = getLogicContext(context);
  const rules = (Array.isArray(customLogicRules) ? customLogicRules : [])
    .filter(rule => rule && rule.active !== false)
    .sort((a, b) => Number(b.priority || 0) - Number(a.priority || 0));
  const results = rules.map(rule => ({
    id: rule.id,
    name: rule.name || 'Rule',
    match: evaluateRuleMatch(rule, ctx),
    field: rule.field,
    operator: rule.operator,
    value: rule.value,
    priority: Number(rule.priority || 0),
    trueMessage: rule.trueMessage || '',
    falseMessage: rule.falseMessage || ''
  }));
  return { context: ctx, results };
}

function applyCustomLogicMessage(baseMessage = '', context = {}, campaign = {}) {
  let output = String(baseMessage || '').trim();
  if (settings.logic_conditions_enabled === false) return { message: output, appliedRule: null };
  const evaluation = evaluateCustomLogicRules(context);
  const firstRule = evaluation.results.find(rule => rule.match && rule.trueMessage) || evaluation.results.find(rule => !rule.match && rule.falseMessage);
  if (!firstRule) return { message: output, appliedRule: null, evaluation };
  const chosenTemplate = firstRule.match ? firstRule.trueMessage : firstRule.falseMessage;
  if (chosenTemplate) {
    output = renderDynamicTemplate(chosenTemplate, {
      ...(context || {}),
      ...(campaign || {})
    });
  }
  return { message: output, appliedRule: firstRule, evaluation };
}

function applyCompliantMessageVariation(text = '', contact = {}, context = {}) {
  let output = String(text || '').trim();
  if (!output || settings.message_variation_enabled === false) return output;
  const openers = parseMultilineOptions(settings.message_variation_openers);
  const closers = parseMultilineOptions(settings.message_variation_closers);
  const seed = `${contact?.number || contact?.phone || contact?.id || 'guest'}:${context?.campaignId || context?.segment || new Date().toISOString().slice(0, 10)}`;
  const opener = pickStableOption(openers, seed + ':open');
  const closer = pickStableOption(closers, seed + ':close');
  const personalizedOpener = opener ? renderDynamicTemplate(opener, buildCustomerMessageContext(contact?.id || contact?.number || contact?.phone || '', contact)) : '';
  const personalizedCloser = closer ? renderDynamicTemplate(closer, buildCustomerMessageContext(contact?.id || contact?.number || contact?.phone || '', contact)) : '';
  if (personalizedOpener && !output.toLowerCase().startsWith(personalizedOpener.toLowerCase())) {
    output = `${personalizedOpener}\n${output}`;
  }
  if (personalizedCloser && !output.toLowerCase().includes(personalizedCloser.toLowerCase())) {
    output = `${output}\n\n${personalizedCloser}`;
  }
  return output;
}

function buildAIAutoReplyStylePrompt() {
  const language = String(settings.ai_reply_language || 'auto').trim();
  const dialect = String(settings.ai_reply_dialect || '').trim();
  const tone = String(settings.ai_reply_tone || 'friendly_sales').trim();
  const custom = String(settings.ai_reply_custom_instructions || '').trim();
  const parts = [
    `Preferred language: ${language}.`,
    dialect ? `Dialect: ${dialect}.` : '',
    `Tone: ${tone}.`,
    'Keep replies context-aware, short, structured, and business-specific.',
    custom
  ].filter(Boolean);
  return parts.join(' ');
}

function pickCampaignMessage(messages, contact, campaign = {}) {
  const list = (Array.isArray(messages) ? messages : []).filter(Boolean);
  if (!list.length) return '';
  const chosen = list[Math.floor(Math.random() * list.length)];
  const rendered = renderDynamicTemplate(chosen, {
    ...(contact || {}),
    name: contact?.name || 'Customer',
    number: contact?.number || contact?.phone || ''
  });
  const logicApplied = applyCustomLogicMessage(rendered, contact || {}, campaign || {});
  const varied = applyCompliantMessageVariation(logicApplied.message, contact || {}, { campaignId: campaign?.id, segment: campaign?.segment || '' });
  return appendUnsubscribeFooter(varied, campaign);
}

async function runCampaign(campaignId) {
  const c = campaigns.find(x => x.id === campaignId);
  if (!c) return;
  const inst = waClients.get('default');
  if (!inst?.isReady) {
    c.status = 'failed';
    c.error = 'WhatsApp not connected';
    saveJSON('campaigns.json', campaigns);
    io.emit('campaign_complete', { id: c.id, status: c.status, error: c.error });
    return;
  }

  const runner = campaignRunners.get(campaignId) || { paused: false, stopped: false };
  campaignRunners.set(campaignId, runner);

  c.total = Array.isArray(c.contacts) ? c.contacts.length : 0;
  c.sent = c.sent || 0;
  c.failed = c.failed || 0;
  c.currentIndex = c.currentIndex || 0;

  let delayMin = Math.max(1, Number(c.delayMin || c.delay_min || 5));
  let delayMax = Math.max(delayMin, Number(c.delayMax || c.delay_max || 10));
  if (safetySettings.enabled !== false && safetySettings.smartDelayEnabled !== false) {
    delayMin = Math.max(delayMin, Number(safetySettings.minDelaySeconds || 0));
    delayMax = Math.max(delayMin, Number(safetySettings.maxDelaySeconds || delayMax));
  }

  // Resolve media file path if present
  let mediaPath = null;
  if (c.mediaUrl && typeof c.mediaUrl === 'string' && c.mediaUrl.startsWith('/uploads/')) {
    // c.mediaUrl is like "/uploads/abc.jpg" -> turn into "<repo>/uploads/abc.jpg"
    mediaPath = path.join(__dirname, c.mediaUrl.replace(/^\/+/, ''));
  }

  while (c.currentIndex < c.total) {
    if (runner.stopped) { c.status = 'stopped'; break; }
    while (runner.paused && !runner.stopped) await sleep(500);
    if (runner.stopped) { c.status = 'stopped'; break; }

    const contact = c.contacts[c.currentIndex];
    const to = normalizeNumber(contact?.number || contact?.phone || contact);
    const msgText = pickCampaignMessage(c.messages || c.messageVariants || [], { ...(contact || {}), name: contact?.name, number: to }, c);

    try {
      if (!to) throw new Error('Invalid number');
      const safety = validateSafetyRecipient({ ...contact, number: to }, { context: 'campaign', campaignId: c.id });
      if (!safety.allowed) throw new Error(`Safety blocked: ${safety.reasons.join(', ')}`);

      if (mediaPath && fs.existsSync(mediaPath)) {
        const media = createMediaFromFilePath(mediaPath);
        await sendDirectMedia(to, media, msgText || '', { useRotation: true });
      } else {
        await sendDirect(to, msgText, { useRotation: true });
      }

      c.sent++;
      recordSafetySend(to, { type: 'campaign', campaignId: c.id });
      logs.push({ id: uuid(), type: 'campaign', to, status: 'sent', message: msgText, time: new Date().toISOString(), campaignId: c.id });
    } catch (e) {
      c.failed++;
      logs.push({ id: uuid(), type: 'campaign', to, status: 'failed', message: msgText, time: new Date().toISOString(), campaignId: c.id, error: e.message });
    }

    c.currentIndex++;
    c.progress = c.total ? Math.round((c.currentIndex / c.total) * 100) : 0;
    c.updated = new Date().toISOString();
    saveJSON('campaigns.json', campaigns);
    saveJSON('logs.json', logs);
    io.emit('campaign_progress', { id: c.id, status: c.status, sent: c.sent, failed: c.failed, total: c.total, progress: c.progress });

    // human-like delay
    const delay = Math.floor((Math.random() * (delayMax - delayMin + 1) + delayMin) * 1000);
    await safetyPauseIfNeeded(c.currentIndex);
    await sleep(delay);
  }

  if (c.status !== 'stopped' && c.currentIndex >= c.total) {
    c.status = 'completed';
    c.progress = 100;
  }
  c.completed = new Date().toISOString();
  saveJSON('campaigns.json', campaigns);
  io.emit('campaign_complete', { id: c.id, status: c.status, sent: c.sent, failed: c.failed, total: c.total });
}

