app.post('/api/inbox/reply', async (req, res) => {
  try {
    const { number, recipientId, message, source = 'whatsapp' } = req.body || {};
    const to = (recipientId || number || '').toString().trim();
    if (!to || !message) return res.status(400).json({ error: 'number and message are required' });
    if (source === 'facebook' || source === 'instagram') {
      const sent = await sendMessengerText(to, message);
      const row = {
        id: sent.message_id || uuid(),
        source,
        chatId: to,
        recipientId: to,
        number: to,
        name: to,
        body: message,
        timestamp: new Date().toISOString(),
        read: true,
        fromMe: true
      };
      inbox.unshift(row);
      if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
      saveInbox();
      return res.json({ success: true, message: row });
    }
    if (source !== 'whatsapp') return res.status(400).json({ error: 'Only WhatsApp, Facebook, and Instagram replies are supported' });
    const sent = await sendDirect(to, message);
    const row = {
      id: sent?.id?._serialized || uuid(),
      source: 'whatsapp',
      chatId: to.includes('@') ? to : `${to}@c.us`,
      number: to.replace(/\D/g, ''),
      name: to,
      body: message,
      timestamp: new Date().toISOString(),
      read: true,
      fromMe: true
    };
    inbox.unshift(row);
    if (inbox.length > 2000) inbox = inbox.slice(0, 2000);
    saveInbox();
    res.json({ success: true, message: row });
  } catch (e) {
    const status = /not connected|required/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});
