function productForCatalog(product = {}) {
  const price = Number(product.price || 0);
  return {
    id: product.id || product.sku || uuid(),
    name: product.name || product.title || 'Product',
    price,
    stock: product.stock !== false,
    condition: product.condition || '',
    image: product.image || product.imageUrl || '',
    url: product.url || product.link || '',
    specs: String(product.specs || product.description || '').replace(/\s+/g, ' ').slice(0, 500)
  };
}

function buildCatalogMessage(catalog = {}) {
  const products = Array.isArray(catalog.products) ? catalog.products : [];
  const title = catalog.title || `${settings.business_name || 'SuperSender Pro'} Catalog`;
  const lines = [
    `ðŸ›ï¸ *${title}*`,
    catalog.description ? String(catalog.description) : '',
    ''
  ].filter(Boolean);
  products.slice(0, 20).forEach((product, index) => {
    const price = Number(product.price || 0);
    lines.push(`${index + 1}. *${product.name || 'Product'}*`);
    if (price) lines.push(`   ðŸ’° Rs. ${price.toLocaleString()}`);
    if (product.condition) lines.push(`   ðŸ·ï¸ ${product.condition}`);
    lines.push(`   ${product.stock === false ? 'âŒ Out of stock' : 'âœ… Available'}`);
    if (product.url) lines.push(`   ðŸ”— ${product.url}`);
  });
  const admin = getAdminWhatsAppNumber();
  if (admin) lines.push('', `ðŸ“ž Order ke liye: https://wa.me/${admin}`);
  return lines.join('\n');
}

