app.post('/api/polls/:id/vote', (req, res) => {
  const poll = polls.find(p => p.id === req.params.id);
  if (!poll) return res.status(404).json({ error: 'Poll not found' });
  const number = normalizedPhoneWithCountry(req.body?.number || req.body?.phone || req.body?.from || req.body?.voter || '', req.body?.countryCode || '92');
  const rawChoices = Array.isArray(req.body?.optionIndexes || req.body?.options)
    ? (req.body.optionIndexes || req.body.options)
    : [req.body?.optionIndex ?? req.body?.option];
  const optionIndexes = [...new Set(rawChoices.map(value => Number(value) - 1).filter(index => index >= 0 && index < (poll.options || []).length))];
  if (!number || !optionIndexes.length) return res.status(400).json({ error: 'valid number and option are required' });
  if (!poll.allowMultipleAnswers && optionIndexes.length > 1) return res.status(400).json({ error: 'This poll allows one answer only' });
  poll.votes = (Array.isArray(poll.votes) ? poll.votes : []).filter(v => normalizedPhoneWithCountry(v.number) !== number);
  optionIndexes.forEach(optionIndex => poll.votes.push({ number, optionIndex, votedAt: new Date().toISOString() }));
  saveJSON('polls.json', polls);
  res.json({ success: true, results: pollResults(poll) });
});
app.post('/api/polls/:id/send', async (req, res) => {
  try {
    const poll = polls.find(p => p.id === req.params.id);
    if (!poll) return res.status(404).json({ error: 'Poll not found' });
    const recipients = filterSafetyRecipients(resolveProductBulkRecipients({ contacts: req.body?.contacts || poll.contacts, numbers: req.body?.numbers, segment: req.body?.segment || 'all', limit: req.body?.limit || 100 }), { context: 'poll' }).valid;
    if (!recipients.length) return res.status(400).json({ error: 'No recipients found' });
    const text = formatPollMessage(poll);
    let sent = 0;
    let failed = 0;
    for (const contact of recipients) {
      try {
        await sendDirect(contact.number, text);
        sent += 1;
        recordSafetySend(contact.number, { type: 'poll', pollId: poll.id });
      } catch {
        failed += 1;
      }
      await sleep(safetyDelayMs(1000));
    }
    logs.push({ id: uuid(), type: 'poll', to: `${recipients.length} recipients`, status: failed ? 'partial' : 'sent', message: poll.question, time: new Date().toISOString(), pollId: poll.id });
    saveJSON('logs.json', logs);
    res.json({ success: true, sent, failed });
  } catch (e) {
    const status = /not connected|required/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

