app.post('/api/update/check', async (req, res) => {
  const manifestUrl = req.body?.manifestUrl || settings.update_manifest_url || process.env.UPDATE_MANIFEST_URL || '';
  const pkg = loadJSON('../package.json', {});
  const check = { id: uuid(), checkedAt: new Date().toISOString(), manifestUrl, currentVersion: pkg.version || '1.0.0' };
  try {
    if (!manifestUrl) {
      check.status = 'not_configured';
      check.message = 'Set update_manifest_url in Settings to enable update checks.';
    } else {
      const axios = require('axios');
      const response = await axios.get(manifestUrl, { timeout: 8000 });
      const manifest = response.data || {};
      check.status = 'ok';
      check.latestVersion = manifest.version || manifest.latestVersion || '';
      check.downloadUrl = manifest.downloadUrl || manifest.url || '';
      check.releaseNotes = manifest.notes || manifest.releaseNotes || '';
      check.updateAvailable = !!check.latestVersion && check.latestVersion !== check.currentVersion;
    }
    updateChecks.unshift(check);
    updateChecks = updateChecks.slice(0, 50);
    saveJSON('update_checks.json', updateChecks);
    res.json({ success: true, ...check });
  } catch (e) {
    check.status = 'failed';
    check.error = e.message;
    updateChecks.unshift(check);
    updateChecks = updateChecks.slice(0, 50);
    saveJSON('update_checks.json', updateChecks);
    res.status(400).json({ success: false, ...check });
  }
});

