function boolFromBody(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  return !['false', '0', 'off', 'no'].includes(value.toString().toLowerCase());
}

function normalizeAutoReplyRule(body = {}, existing = {}) {
  const keyword = (body.keyword || body.match || existing.keyword || existing.match || '').toString().trim();
  const response = (body.response || body.reply || existing.response || existing.reply || '').toString().trim();
  return {
    ...existing,
    id: existing.id || uuid(),
    keyword,
    match: keyword,
    response,
    reply: response,
    active: boolFromBody(body.active, existing.active !== undefined ? existing.active : true),
    created: existing.created || new Date().toISOString(),
    updated: new Date().toISOString()
  };
}

function normalizeSequence(body = {}, existing = {}) {
  let steps = Array.isArray(body.steps) ? body.steps : [];
  if (!steps.length && typeof body.stepsText === 'string') {
    steps = body.stepsText
      .split(/\n\s*---+\s*\n|\n{2,}/)
      .map((message, index) => ({ delay: index === 0 ? 0 : 1, message: message.trim() }))
      .filter(step => step.message);
  }
  if (!steps.length && Array.isArray(existing.steps)) steps = existing.steps;
  steps = steps.map((step, index) => ({
    delay: Number(step.delay ?? step.delayDays ?? (index === 0 ? 0 : 1)),
    message: (step.message || step.text || '').toString().trim()
  })).filter(step => step.message);

  return {
    ...existing,
    id: existing.id || uuid(),
    name: (body.name || existing.name || 'New Sequence').toString().trim(),
    description: (body.description || existing.description || '').toString().trim(),
    steps,
    active: boolFromBody(body.active, existing.active !== undefined ? existing.active : true),
    created: existing.created || new Date().toISOString(),
    updated: new Date().toISOString()
  };
}

function normalizeReminder(body = {}, existing = {}) {
  return {
    ...existing,
    id: existing.id || uuid(),
    name: (body.name || body.customer || existing.name || existing.customer || '').toString().trim(),
    number: normalizeNumber(body.number || existing.number || ''),
    message: (body.message || existing.message || '').toString().trim(),
    time: (body.time || body.dueAt || body.date || existing.time || existing.dueAt || existing.date || '').toString(),
    dueAt: (body.dueAt || body.time || body.date || existing.dueAt || existing.time || existing.date || '').toString(),
    repeat: (body.repeat || existing.repeat || 'none').toString(),
    status: (body.status || existing.status || 'pending').toString(),
    created: existing.created || new Date().toISOString(),
    updated: new Date().toISOString()
  };
}

function updateCollectionItem(collection, id, normalize, saveFile, req, res) {
  const index = collection.findIndex(x => x.id === id);
  if (index === -1) return res.status(404).json({ error: 'Not found' });
  collection[index] = normalize(req.body || {}, collection[index]);
  saveJSON(saveFile, collection);
  res.json(collection[index]);
}

function deleteCollectionItem(collectionRef, id, saveFile, res) {
  const before = collectionRef.value.length;
  collectionRef.value = collectionRef.value.filter(x => x.id !== id);
  if (collectionRef.value.length === before) return res.status(404).json({ error: 'Not found' });
  saveJSON(saveFile, collectionRef.value);
  res.json({ success: true });
}

