function normalizeCrmContact(row = {}, provider = 'manual') {
  const props = row.properties || row;
  const first = props.firstname || props.firstName || '';
  const last = props.lastname || props.lastName || '';
  const name = props.name || props.fullName || [first, last].filter(Boolean).join(' ') || props.company || props.email || props.phone || 'CRM Contact';
  const phone = normalizeNumber(props.phone || props.mobilephone || props.mobile || props.whatsapp || props.number || '');
  return {
    id: props.id || row.id || uuid(),
    name,
    number: phone,
    phone,
    email: props.email || '',
    company: props.company || props.companyName || '',
    source: `crm_${provider}`,
    status: props.status || 'lead',
    tags: Array.from(new Set([...(Array.isArray(props.tags) ? props.tags : []), provider.toUpperCase()])),
    created: props.created || props.createdAt || new Date().toISOString(),
    updated: new Date().toISOString()
  };
}

