app.post('/api/crm-sync/import', (req, res) => {
  const provider = String(req.body?.provider || 'manual').toLowerCase();
  const rows = Array.isArray(req.body?.contacts) ? req.body.contacts : [];
  if (!rows.length) return res.status(400).json({ error: 'contacts array is required' });
  let added = 0, updated = 0;
  for (const row of rows) {
    const c = normalizeCrmContact(row, provider);
    if (!c.number && !c.email) continue;
    const idx = customers.findIndex(existing =>
      (c.number && normalizeNumber(existing.number || existing.phone || '') === c.number) ||
      (c.email && String(existing.email || '').toLowerCase() === String(c.email).toLowerCase())
    );
    if (idx >= 0) {
      customers[idx] = { ...customers[idx], ...c, id: customers[idx].id, updated: new Date().toISOString() };
      updated++;
    } else {
      customers.unshift(c);
      added++;
    }
  }
  crmSyncSettings.lastSyncAt = new Date().toISOString();
  saveCrmSyncSettings();
  saveJSON('customers.json', customers);
  res.json({ success: true, provider, added, updated, totalCustomers: customers.length });
});

