function bulkDeleteCustomers(payload = {}) {
  const ids = new Set([...(payload.ids || []), ...(payload.customerIds || [])].map(v => String(v || '').trim()).filter(Boolean));
  const numbers = new Set([...(payload.numbers || []), ...(payload.phones || [])].map(normalizeNumber).filter(Boolean));
  if (!ids.size && !numbers.size) return { success: false, error: 'ids or numbers required', removed: 0 };
  const before = customers.length;
  const removedRows = [];
  customers = customers.filter(c => {
    const cId = String(c.id || '').trim();
    const cNum = normalizeNumber(c.number || c.phone || c.whatsapp || c.customerNumber || '');
    const remove = (cId && ids.has(cId)) || (cNum && numbers.has(cNum));
    if (remove) removedRows.push({ id: c.id, number: cNum, name: c.name || '' });
    return !remove;
  });
  if (removedRows.length) {
    saveJSON('customers.json', customers);
    io.emit('customers_bulk_deleted', { removed: removedRows.length, rows: removedRows });
  }
  return { success: true, removed: before - customers.length, rows: removedRows };
}

