function leadAnalytics() {
  const allLeads = laptopLeads.length ? laptopLeads : customers.filter(c => (c.status || 'lead') === 'lead');
  const byPlatform = {};
  const byCity = {};
  const byStatus = {};
  const budgetRanges = { '<50k': 0, '50k-100k': 0, '100k-200k': 0, '200k+': 0, unknown: 0 };
  for (const l of allLeads) {
    const platform = l.platform || 'WhatsApp';
    byPlatform[platform] = (byPlatform[platform] || 0) + 1;
    const city = l.city || 'Unknown';
    byCity[city] = (byCity[city] || 0) + 1;
    const status = l.status || 'new';
    byStatus[status] = (byStatus[status] || 0) + 1;
    const b = Number(l.budget || l.maxBudget || 0);
    if (!b) budgetRanges.unknown++;
    else if (b < 50000) budgetRanges['<50k']++;
    else if (b < 100000) budgetRanges['50k-100k']++;
    else if (b < 200000) budgetRanges['100k-200k']++;
    else budgetRanges['200k+']++;
  }
  const converted = allLeads.filter(l => ['converted', 'active'].includes((l.status || '').toLowerCase())).length;
  const totalRevenue = payments.filter(p => p.status === 'approved').reduce((s, p) => s + Number(p.amount || 0), 0);
  return {
    total: allLeads.length,
    converted,
    successRate: allLeads.length ? Math.round((converted / allLeads.length) * 100) : 0,
    totalRevenue,
    byPlatform: Object.entries(byPlatform).sort((a, b) => b[1] - a[1]),
    byCity: Object.entries(byCity).sort((a, b) => b[1] - a[1]),
    byStatus,
    budgetRanges
  };
}

