app.post('/api/automation/followup-cold-leads', async (req, res) => {
  try {
    const hours = Math.max(1, Math.min(720, Number(req.body?.hours || 24)));
    const max = Math.max(1, Math.min(200, Number(req.body?.max || 20)));
    const cutoff = Date.now() - hours * 60 * 60 * 1000;
    const sources = laptopLeads.length ? laptopLeads : customers.filter(c => (c.status || 'lead') === 'lead');
    const isCold = (lead) => {
      const status = (lead.status || 'new').toString().toLowerCase();
      if (['converted', 'lost', 'closed'].includes(status)) return false;
      if (!lead.number) return false;
      if (lead.lastFollowup && new Date(lead.lastFollowup).getTime() > cutoff) return false;
      const last = new Date(lead.lastActive || lead.updated || lead.created || 0).getTime();
      return !Number.isFinite(last) || last === 0 || last <= cutoff;
    };
    const targets = sources.filter(isCold).slice(0, max);
    const connected = !!waClients.get('default')?.isReady;
    let sent = 0;
    let queued = 0;

    for (const lead of targets) {
      const message = `Hi ${lead.name || 'there'}, following up on your laptop requirement${lead.budget ? ` around Rs. ${Number(lead.budget).toLocaleString()}` : ''}. Tell me your budget/use-case and I will share the best available options.`;
      let status = 'draft';
      if (connected) {
        try {
          await sendDirect(lead.number, message);
          status = 'sent';
          sent++;
        } catch {
          queued++;
        }
      } else {
        queued++;
      }
      lead.lastFollowup = new Date().toISOString();
      followups.push({ id: uuid(), number: lead.number, message, status, created: new Date().toISOString(), leadId: lead.id });
    }

    saveJSON('followups.json', followups);
    saveJSON('laptop_leads.json', laptopLeads);
    saveJSON('customers.json', customers);
    res.json({ success: true, processing: targets.length, sent, queued, whatsappConnected: connected });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

