app.post('/api/automation/smart-catalog', (req, res) => {
  try {
    const budget = Number(req.body?.budget || 0);
    const city = (req.body?.city || '').toString().trim();
    const useCase = (req.body?.useCase || '').toString().trim().toLowerCase();
    const scored = laptopProducts
      .filter(p => p.stock !== false)
      .filter(p => !budget || Number(p.price || 0) <= budget)
      .map(p => {
        const hay = [p.name, p.brand, p.specs, p.condition, p.category, p.subcategory, p.description].join(' ').toLowerCase();
        const score = useCase && hay.includes(useCase) ? 2 : 1;
        return { p, score };
      })
      .sort((a, b) => b.score - a.score || Number(a.p.price || 0) - Number(b.p.price || 0))
      .slice(0, 5)
      .map(x => x.p);

    const intro = `Hi! Based on your ${budget ? `Rs. ${budget.toLocaleString()} budget` : 'requirement'}${useCase ? ` for ${useCase}` : ''}${city ? ` in ${city}` : ''}, these are the best options available:`;
    const lines = scored.map((p, i) => `${i + 1}. ${p.name || p.brand || 'Laptop'} - Rs. ${Number(p.price || 0).toLocaleString()}${p.specs ? ` | ${p.specs}` : ''}`);
    const message = scored.length
      ? [intro, ...lines, 'Reply with the number you like and I will share details.'].join('\n')
      : 'No matching in-stock products found right now. Add products or increase the budget, then generate the catalog again.';
    res.json({ success: true, count: scored.length, products: scored, message });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

