// Run follow-up automation now (time-saver button on dashboard)
app.post('/api/followups/run', async (req, res) => {
  try {
    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });

    const limit = Math.max(1, Math.min(200, Number(req.body?.limit || 50)));
    const message = (req.body?.message || '').toString().trim() ||
      `Hi {name}! Quick follow-up so you don't miss this. Reply with what you need and I'll help right away.`;

    const targets = customers
      .filter(c => (c.status || 'lead') === 'lead')
      .filter(c => !(c.tags || []).includes('followed_up'))
      .slice(0, limit);

    res.json({ success: true, queued: targets.length });

    (async () => {
      let sent = 0, failed = 0;
      for (const c of targets) {
        try {
          const txt = renderDynamicTemplate(message, buildCustomerMessageContext(c));
          await sendDirect(c.number, txt);
          sent++;
          followups.push({ id: uuid(), number: c.number, message: txt, created: new Date().toISOString(), status: 'sent' });
          customers = addCustomerTags(customers, c.id, 'followed_up');
        } catch (e) {
          failed++;
          followups.push({ id: uuid(), number: c.number, message, created: new Date().toISOString(), status: 'failed', error: e.message });
        }
        io.emit('followup_progress', { sent, failed, total: targets.length, percent: targets.length ? Math.round((sent + failed) / targets.length * 100) : 0 });
        await sleep(Math.floor(Math.random() * 2000) + 3500);
      }
      saveJSON('followups.json', followups);
      saveJSON('customers.json', customers);
      io.emit('followup_complete', { sent, failed, total: targets.length });
      logs.push({ id: uuid(), type: 'followup', to: 'leads', status: 'sent', message: `Follow-ups sent=${sent}, failed=${failed}`, time: new Date().toISOString() });
      saveJSON('logs.json', logs);
    })();
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

