function ensureWhatsAppChannelTemplates() {
  const defaults = defaultWhatsAppChannelTemplates();
  let changed = false;
  if (!Array.isArray(whatsappChannelTemplates)) {
    whatsappChannelTemplates = [];
    changed = true;
  }
  const byId = new Map(whatsappChannelTemplates.map(item => [String(item.id || '').trim(), item]));
  for (const item of defaults) {
    if (!byId.has(item.id)) {
      whatsappChannelTemplates.push(item);
      changed = true;
    }
  }
  whatsappChannelTemplates = whatsappChannelTemplates.map(item => {
    const next = { ...item };
    const cleanBody = cleanOutgoingText(next.body || '');
    if (cleanBody !== next.body) {
      next.body = cleanBody;
      changed = true;
    }
    return next;
  });
  if (changed) {
    saveJSON('whatsapp_channel_templates.json', whatsappChannelTemplates);
  }
  return whatsappChannelTemplates;
}

