function findCustomerByNormalizedNumber(number = '') {
  const normalized = normalizeNumber(number);
  if (!normalized) return null;
  return customers.find(c => normalizeNumber(c.number || c.phone || c.whatsapp || '') === normalized) || null;
}

function scoreHotLeadClick(row = {}) {
  const recentBonus = Date.parse(row.lastClickedAt || 0) >= Date.now() - (24 * 60 * 60 * 1000) ? 20 : 0;
  const repeatBonus = Math.max(0, (Number(row.clicks || 0) - 1) * 15);
  const campaignBonus = row.campaign ? 10 : 0;
  return Math.min(100, 25 + recentBonus + repeatBonus + campaignBonus);
}

function recordHotLeadClick(link, click, req) {
  if (settings.click_hot_lead_enabled === false) return null;
  const hintedNumber = normalizeNumber(
    req.query.number ||
    req.query.n ||
    req.query.lead ||
    req.query.phone ||
    link.contactNumber ||
    ''
  );
  const hintedName = String(req.query.name || link.contactName || '').trim();
  const threshold = Math.max(1, Number(link.hotThreshold || 2));
  const customer = hintedNumber ? (findCustomerByNormalizedNumber(hintedNumber) || ensureGuestCustomer(hintedNumber, hintedName || link.label, 'link_click')) : null;

  const key = `${link.id}:${hintedNumber || click.code}`;
  let row = (hotClickLeads || []).find(item => item.key === key);
  if (!row) {
    row = {
      id: uuid(),
      key,
      linkId: link.id,
      linkLabel: link.label,
      campaign: link.campaign || '',
      code: click.code,
      customerId: customer?.id || null,
      customerNumber: hintedNumber || '',
      customerName: customer?.name || hintedName || '',
      clicks: 0,
      contacted: false,
      createdAt: new Date().toISOString()
    };
    hotClickLeads.unshift(row);
  }

  row.clicks = Number(row.clicks || 0) + 1;
  row.lastClickedAt = click.clickedAt;
  row.lastIp = click.ip || '';
  row.lastReferrer = click.referrer || '';
  row.score = scoreHotLeadClick(row);
  row.customerId = customer?.id || row.customerId || null;
  row.customerNumber = hintedNumber || row.customerNumber || '';
  row.customerName = customer?.name || hintedName || row.customerName || '';
  saveHotClickLeads();

  if (customer && row.clicks >= threshold) {
    customer.tags = [...new Set([...(customer.tags || []), 'Hot Lead', 'Clicked Link'])];
    customer.lastClickAt = row.lastClickedAt;
    customer.leadScore = Math.max(Number(customer.leadScore || 0), row.score);
    customer.utmSource = click.utmSource || customer.utmSource || link.utmSource || '';
    customer.utmMedium = click.utmMedium || customer.utmMedium || link.utmMedium || '';
    customer.utmCampaign = click.utmCampaign || customer.utmCampaign || link.utmCampaign || link.campaign || '';
    customer.referral = click.referral || customer.referral || link.referral || '';
    saveJSON('customers.json', customers);
    logJourneyEvent('click_to_whatsapp', {
      number: customer.number || customer.phone || '',
      customerId: customer.id,
      customerName: customer.name || '',
      channel: 'whatsapp',
      meta: {
        linkId: link.id,
        label: link.label,
        score: row.score,
        utmSource: click.utmSource || '',
        utmMedium: click.utmMedium || '',
        utmCampaign: click.utmCampaign || '',
        referral: click.referral || ''
      }
    }, 'consideration');
    if (row.clicks === threshold) {
      createSystemAlert({
        type: 'lead',
        title: 'Hot lead clicked tracking link',
        message: `${customer.name || customer.number} clicked ${link.label} and crossed the hot threshold.`,
        severity: 'warning',
        source: 'link_tracking',
        meta: { customerId: customer.id, linkId: link.id, clicks: row.clicks, score: row.score }
      });
    }
  }

  return row;
}

function hotLeadClickSummary() {
  const rows = Array.isArray(hotClickLeads) ? hotClickLeads : [];
  const active = rows.filter(item => !item.contacted);
  return {
    total: rows.length,
    active: active.length,
    topScore: active.reduce((max, item) => Math.max(max, Number(item.score || 0)), 0),
    hottest: active
      .slice()
      .sort((a, b) => Number(b.score || 0) - Number(a.score || 0))
      .slice(0, 20)
  };
}

function audioTranscriptionConfig() {
  const openaiKey = String(settings.openai_api_key || process.env.OPENAI_API_KEY || '').trim();
  if (openaiKey) {
    return {
      provider: 'openai',
      url: 'https://api.openai.com/v1/audio/transcriptions',
      key: openaiKey,
      model: settings.audio_transcription_model || 'whisper-1'
    };
  }

  const groqKey = String(settings.groq_api_key || process.env.GROQ_API_KEY || '').trim();
  if (groqKey) {
    return {
      provider: 'groq',
      url: 'https://api.groq.com/openai/v1/audio/transcriptions',
      key: groqKey,
      model: settings.audio_transcription_model || 'whisper-large-v3-turbo'
    };
  }

  return null;
}

async function transcribeAudioWithAvailableProvider(filePath, mimetype = 'audio/ogg') {
  const cfg = audioTranscriptionConfig();
  if (!cfg) throw new Error('Configure OpenAI or Groq API key for audio transcription');

  const form = new FormData();
  form.append('model', cfg.model);
  form.append('language', 'ur');
  form.append('prompt', 'Transcribe Urdu, Roman Urdu, and English business conversations accurately.');
  form.append('file', new Blob([fs.readFileSync(filePath)], { type: mimetype }), path.basename(filePath));

  const response = await fetch(cfg.url, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${cfg.key}`
    },
    body: form
  });

  const data = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(data.error?.message || `Audio transcription failed (${response.status})`);
  return String(data.text || data.transcript || '').trim();
}

async function buildAudioLeadReply(transcript = '', context = {}) {
  const cleaned = String(transcript || '').trim();
  if (!cleaned) return 'Voice note mil gayi. Agar possible ho to ek line me apni need likh dein, main foran help karta hoon.';

  const sys = `You are a structured WhatsApp sales/support assistant for ${settings.business_name || 'our business'}.
Allowed work only: support, lead capture, booking, product guidance, order tracking, and human handoff.
Never behave like a general open-ended chatbot.
Reply in the user's language, usually Roman Urdu for Pakistan.
Keep it short, helpful, and sales-aware.`;

  const prompt = `Customer voice note transcript:\n${cleaned}\n\nContext:\n- Source: ${context.source || 'whatsapp'}\n- Number: ${context.number || ''}\n- Name: ${context.name || ''}\n\nWrite a concise WhatsApp reply that either answers, qualifies the lead, or routes to human support if needed.`;
  const reply = await callAI(prompt, sys);
  if (isAIUnavailableReply(reply)) {
    return `Voice note samajh aa gayi. Aap ne yeh kaha: "${cleaned.slice(0, 120)}${cleaned.length > 120 ? '...' : ''}"\n\nMain help ke liye ready hoon. Agar aap price, order, support, ya booking batayen to main next step share kar deta hoon.`;
  }
  return reply;
}

