function agentLearningSummary() {
  const rows = Array.isArray(agentLearningLog) ? agentLearningLog : [];
  const summary = {};
  for (const row of rows) {
    const id = row.agentId || 'unknown';
    if (!summary[id]) {
      summary[id] = {
        agentId: id,
        total: 0,
        wins: 0,
        losses: 0,
        interactions: 0,
        avgScore: 0
      };
    }
    summary[id].total += 1;
    summary[id].avgScore += Number(row.score || 0);
    if (row.outcome === 'win' || row.outcome === 'resolved' || row.outcome === 'converted') summary[id].wins += 1;
    if (row.outcome === 'loss' || row.outcome === 'failed') summary[id].losses += 1;
    if (row.outcome === 'interaction') summary[id].interactions += 1;
  }
  return Object.values(summary).map(item => ({
    ...item,
    avgScore: item.total ? Math.round(item.avgScore / item.total) : 0,
    winRate: item.total ? Math.round((item.wins / item.total) * 100) : 0
  })).sort((a, b) => b.winRate - a.winRate || b.avgScore - a.avgScore);
}

