app.post('/api/issues', (req, res) => {
  const title = (req.body?.title || req.body?.subject || '').toString().trim();
  const description = (req.body?.description || req.body?.desc || '').toString().trim();
  if (!title || !description) return res.status(400).json({ error: 'title and description are required' });
  const issue = { id: uuid(), ...req.body, title, description, status: req.body?.status || 'open', created: new Date().toISOString() };
  issues.push(issue); saveJSON('issues.json', issues);
  res.json(issue);
});
app.post('/api/issues/:id/reply', async (req, res) => {
  try {
    const issue = issues.find(i => i.id === req.params.id);
    if (!issue) return res.status(404).json({ error: 'Not found' });
    const message = (req.body?.message || '').toString().trim();
    if (!message) return res.status(400).json({ error: 'message is required' });
    if (!issue.number) return res.status(400).json({ error: 'Issue has no customer number' });

    const inst = waClients.get('default');
    if (!inst?.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });

    await sendDirect(issue.number, message);
    issue.replies = Array.isArray(issue.replies) ? issue.replies : [];
    issue.replies.push({ id: uuid(), message, time: new Date().toISOString() });
    issue.updated = new Date().toISOString();
    saveJSON('issues.json', issues);

    logs.push({ id: uuid(), type: 'support', to: issue.number, status: 'sent', message, time: new Date().toISOString(), issueId: issue.id });
    saveJSON('logs.json', logs);

    res.json({ success: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});
app.post('/api/issues/:id/send-to-clickup', async (req, res) => {
  try {
    const issue = issues.find(i => i.id === req.params.id);
    if (!issue) return res.status(404).json({ error: 'Not found' });
    const token = settings.clickup_token;
    const listId = settings.clickup_list_id;
    if (!token || !listId) return res.status(400).json({ error: 'Configure ClickUp token + list id in Settings first' });

    const axios = require('axios');
    const payload = {
      name: `[Support] ${issue.title || issue.subject || 'Ticket'}`,
      description: `${issue.description || issue.desc || ''}\n\nCustomer: ${issue.name || ''}\nNumber: ${issue.number || ''}\nCreated: ${issue.created || ''}`.trim()
    };
    const r = await axios.post(`https://api.clickup.com/api/v2/list/${listId}/task`, payload, {
      headers: { Authorization: token, 'Content-Type': 'application/json' }
    });
    issue.clickupTaskId = r.data?.id || null;
    issue.updated = new Date().toISOString();
    saveJSON('issues.json', issues);
    res.json({ success: true, taskId: issue.clickupTaskId });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});
