app.post('/api/links', (req, res) => {
  const label = (req.body?.label || '').toString().trim();
  const targetUrl = normalizeTargetUrl(req.body?.targetUrl || req.body?.target || req.body?.url || '');
  const customCode = (req.body?.code || '').toString().trim().toLowerCase().replace(/[^a-z0-9-]/g, '').slice(0, 32);
  if (!label || !targetUrl) return res.status(400).json({ error: 'label and target URL are required' });
  try {
    new URL(targetUrl);
  } catch {
    return res.status(400).json({ error: 'target URL is invalid' });
  }
  const code = customCode || uniqueShortCode(label);
  if (trackedLinks.some(link => link.code === code)) return res.status(409).json({ error: 'short code already exists' });
  const link = {
    id: uuid(),
    label,
    code,
    targetUrl,
    campaign: (req.body?.campaign || '').toString().trim(),
    contactNumber: normalizeNumber(req.body?.contactNumber || ''),
    contactName: (req.body?.contactName || '').toString().trim(),
    sourceTag: (req.body?.sourceTag || '').toString().trim(),
    utmSource: (req.body?.utmSource || '').toString().trim(),
    utmMedium: (req.body?.utmMedium || '').toString().trim(),
    utmCampaign: (req.body?.utmCampaign || '').toString().trim(),
    referral: (req.body?.referral || req.body?.ref || '').toString().trim(),
    hotThreshold: Math.max(1, Number(req.body?.hotThreshold || 2)),
    created: new Date().toISOString(),
    updated: new Date().toISOString()
  };
  trackedLinks.unshift(link);
  saveJSON('links.json', trackedLinks);
  res.json(withShortUrl(req, link));
});

app.post('/api/commerce/smart-link', async (req, res) => {
  try {
    const body = req.body || {};
    const targetUrl = normalizeTargetUrl(body.targetUrl || body.url || body.checkoutUrl || '');
    if (!targetUrl) return res.status(400).json({ error: 'targetUrl is required' });
    const number = normalizeNumber(body.number || body.phone || '');
    const label = String(body.label || body.productName || body.orderNumber || 'Smart Checkout').trim();
    const code = uniqueShortCode(label);
    const link = {
      id: uuid(),
      label,
      code,
      targetUrl,
      campaign: String(body.campaign || 'smart_checkout').trim(),
      contactNumber: number,
      contactName: String(body.name || body.customerName || '').trim(),
      sourceTag: String(body.sourceTag || 'commerce').trim(),
      utmSource: String(body.utmSource || 'whatsapp').trim(),
      utmMedium: String(body.utmMedium || 'chat').trim(),
      utmCampaign: String(body.utmCampaign || body.campaign || 'smart_checkout').trim(),
      referral: String(body.referral || 'checkout').trim(),
      hotThreshold: Math.max(1, Number(body.hotThreshold || 1)),
      created: new Date().toISOString(),
      updated: new Date().toISOString()
    };
    trackedLinks.unshift(link);
    saveJSON('links.json', trackedLinks);
    const responseLink = withShortUrl(req, link);
    let sent = false;
    if (body.sendNow === true && number) {
      const text = [
        `ðŸ›’ *${label}*`,
        '',
        body.amount ? `Amount: Rs. ${Number(body.amount || 0).toLocaleString()}` : '',
        body.orderNumber ? `Order: ${body.orderNumber}` : '',
        'Complete checkout here:',
        responseLink.shortUrl
      ].filter(Boolean).join('\n');
      sent = await sendCommerceMessage(number, text);
    }
    logCommerceEvent('smart_checkout_link', {
      number,
      label,
      targetUrl,
      shortUrl: responseLink.shortUrl,
      campaign: link.campaign,
      sent
    }, 'commerce');
    if (number) {
      const customer = upsertUnifiedIdentity({
        number,
        name: body.name || body.customerName || '',
        source: 'smart_checkout_link',
        channel: 'whatsapp'
      });
      logJourneyEvent('smart_checkout_link', {
        number,
        customerId: customer.id,
        customerName: customer.name || '',
        channel: 'whatsapp',
        meta: {
          label,
          shortUrl: responseLink.shortUrl,
          utmSource: link.utmSource,
          utmCampaign: link.utmCampaign,
          referral: link.referral
        }
      }, 'purchase');
    }
    res.json({ success: true, link: responseLink, sent });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

