app.get('/l/:code', (req, res) => {
  const link = trackedLinks.find(x => x.code === req.params.code);
  if (!link) return res.status(404).send('Link not found');
  const click = {
    id: uuid(),
    linkId: link.id,
    code: link.code,
    ip: req.headers['x-forwarded-for'] || req.socket?.remoteAddress || '',
    userAgent: req.headers['user-agent'] || '',
    referrer: req.headers.referer || req.headers.referrer || '',
    utmSource: String(req.query.utm_source || link.utmSource || '').trim(),
    utmMedium: String(req.query.utm_medium || link.utmMedium || '').trim(),
    utmCampaign: String(req.query.utm_campaign || link.utmCampaign || '').trim(),
    referral: String(req.query.ref || req.query.referral || link.referral || '').trim(),
    clickedAt: new Date().toISOString()
  };
  linkClicks.push(click);
  link.lastClickAt = click.clickedAt;
  const hotLead = recordHotLeadClick(link, click, req);
  if (hotLead) {
    link.lastHotLeadAt = hotLead.lastClickedAt;
    link.lastHotLeadScore = hotLead.score;
  }
  saveJSON('link_clicks.json', linkClicks.slice(-5000));
  linkClicks = linkClicks.slice(-5000);
  saveJSON('links.json', trackedLinks);
  res.redirect(link.targetUrl);
});

app.get('/api/price-intel', (req, res) => {
  const q = (req.query.q || req.query.search || '').toString().trim().toLowerCase();
  const group = (req.query.group || '').toString().trim().toLowerCase();
  const hours = Number(req.query.hours || 0);
  const limit = Math.min(1000, Math.max(1, Number(req.query.limit || 500)));
  const cutoff = hours > 0 ? Date.now() - (hours * 60 * 60 * 1000) : 0;
  let rows = [...(priceIntel || [])];
  if (cutoff) rows = rows.filter(r => Date.parse(r.date || 0) >= cutoff);
  if (group) rows = rows.filter(r => (r.groupName || r.groupId || '').toLowerCase().includes(group));
  if (q) {
    rows = rows.filter(r => [r.product, r.title, r.plan, r.brand, r.category, r.seller, r.groupName, r.rawPost, r.notes]
      .some(v => (v || '').toString().toLowerCase().includes(q)));
  }
  rows.sort((a, b) => Date.parse(b.date || 0) - Date.parse(a.date || 0));
  res.json(rows.slice(0, limit));
});

