app.post('/api/price-intel/:id/caption', async (req, res) => {
  const rec = priceIntel.find(r => r.id === req.params.id);
  if (!rec) return res.status(404).json({ error: 'not found' });
  const platform = (req.body?.platform || 'social media').toString();
  const tone = (req.body?.tone || 'sales').toString();
  try {
    if (hasAnyAIProvider()) {
      const prompt = [
        `Platform: ${platform}`,
        `Tone: ${tone}`,
        `Product: ${rec.title || rec.product}`,
        `Price: ${rec.currency === 'USD' ? '$' : 'Rs.'} ${Number(rec.price || 0).toLocaleString()}`,
        rec.plan ? `Plan: ${rec.plan}` : '',
        rec.duration ? `Duration: ${rec.duration}` : '',
        rec.notes ? `Notes: ${rec.notes}` : '',
        'Write one ready-to-post caption. Keep it short, clean, and non-spammy. Return only caption text.'
      ].filter(Boolean).join('\n');
      rec.socialCaption = await callGroqRaw(prompt, 'You write concise social media sales captions for digital tools, subscriptions, and seller offers.', 350);
    } else {
      rec.socialCaption = buildSocialCaption(rec);
    }
    rec.captionUpdated = new Date().toISOString();
    saveJSON('price_intel.json', priceIntel);
    res.json({ success: true, record: rec });
  } catch (e) {
    rec.socialCaption = buildSocialCaption(rec);
    saveJSON('price_intel.json', priceIntel);
    res.json({ success: true, fallback: true, record: rec });
  }
});

