app.post('/api/price-monitors/run', (req, res) => {
  // Compute simple â€œlowest sellerâ€ per monitored product from recent mentions.
  const hours = Number(req.body?.hours || 24);
  const cutoff = Date.now() - (hours * 60 * 60 * 1000);
  const recent = (priceIntel || []).filter(r => Date.parse(r.date || 0) > cutoff);
  const summary = priceMonitors.filter(m => m.enabled !== false).map(m => {
    const matches = recent.filter(r => (r.product || '').toLowerCase().includes((m.product || '').toLowerCase()));
    const numeric = matches
      .map(r => ({ ...r, priceNum: Number((r.price || '').toString().replace(/[^\d.]/g,'')) }))
      .filter(r => Number.isFinite(r.priceNum) && r.priceNum > 0);
    numeric.sort((a, b) => a.priceNum - b.priceNum);
    return { monitor: m, matches: matches.length, lowest: numeric[0] || null };
  });
  res.json({ success: true, hours, summary });
});

