function computeCPSC(days = 7) {
  const safeDays = Math.max(1, Number(days || 7));
  const rows = Array.isArray(campaigns) ? campaigns : [];
  const recent = rows.filter(item => withinLastDays(item.created || item.updated || item.completed, safeDays));
  const spend = recent.reduce((sum, item) => sum + Number(item.spend || item.cost || item.budgetUsed || 0), 0);
  const startedConversations = Object.keys(waConversations || {}).filter(number => {
    const history = waConversations[number]?.history || [];
    return history.some(msg => msg?.role === 'user' && withinLastDays(msg?.time || msg?.created || msg?.at || new Date().toISOString(), safeDays));
  }).length;
  return {
    days: safeDays,
    spend,
    startedConversations,
    cpsc: startedConversations ? Number((spend / startedConversations).toFixed(2)) : 0
  };
}

function computeLeadLifecycleSummary(days = 7) {
  const safeDays = Math.max(1, Number(days || 7));
  const leadRows = Array.isArray(customers) ? customers : [];
  const newLeads = leadRows.filter(item => withinLastDays(item.created || item.first_order || item.firstContact || item.lastSeen, safeDays));
  const qualified = leadRows.filter(item => Number(item.leadScore || 0) >= 80 || String(item.buyerIntent || '').toUpperCase() === 'HOT');
  const nurture = leadRows.filter(item => Number(item.leadScore || 0) >= 40 && Number(item.leadScore || 0) < 80);
  const lowIntent = leadRows.filter(item => Number(item.leadScore || 0) < 40);
  const booked = (appointments || []).filter(item => withinLastDays(item.createdAt || item.scheduleAt || item.updatedAt, safeDays));
  const converted = (orders || []).filter(item => withinLastDays(item.created || item.order_date || item.updated, safeDays));
  const openHandoffs = (handoffQueue || []).filter(item => String(item.status || 'open') !== 'resolved');
  const response = messageAnalytics.getReplySpeedSummary({ days: safeDays });
  return {
    days: safeDays,
    newLeads: newLeads.length,
    qualified: qualified.length,
    nurture: nurture.length,
    lowIntent: lowIntent.length,
    bookedMeetings: booked.length,
    conversions: converted.length,
    openHandoffs: openHandoffs.length,
    firstReplyUnder3s: Number(response.under3Seconds || 0),
    avgReplySeconds: Number(response.avgReplySeconds || 0),
    cpsc: computeCPSC(safeDays)
  };
}

function scoreLeadIntent(input = {}) {
  const text = String(input.message || input.text || '').trim();
  const analysis = analyzeCustomerIntent(text);
  let score = 20;
  if (analysis.signals.includes('pricing_request')) score += 20;
  if (analysis.signals.includes('budget_sensitive')) score += 15;
  if (analysis.signals.includes('delivery_timeline')) score += 15;
  if (analysis.signals.includes('recommendation_needed')) score += 10;
  if (analysis.type === 'booking') score += 25;
  if (analysis.type === 'lead_capture') score += 20;
  if (String(input.source || '').toLowerCase().includes('utm')) score += 10;
  if (input.referral) score += 5;
  score = Math.max(0, Math.min(100, score));
  return {
    score,
    tier: score >= 80 ? 'high_intent' : score >= 50 ? 'warm' : 'low_intent',
    analysis
  };
}

function detectInboxCollisionRisk() {
  const now = Date.now();
  const risky = Object.entries(inboxPresence || {}).map(([chatId, entries]) => {
    const active = Object.values(entries || {}).filter(item => {
      const updated = Date.parse(item.updatedAt || 0);
      return Number.isFinite(updated) && (now - updated) <= (2 * 60 * 1000);
    });
    return {
      chatId,
      active,
      collision: active.length > 1
    };
  }).filter(item => item.active.length);
  return {
    totalActiveChats: risky.length,
    collisions: risky.filter(item => item.collision).length,
    items: risky.filter(item => item.collision).slice(0, 30)
  };
}

