function withinLastDays(dateValue, days = 7) {
  const ts = Date.parse(dateValue || 0);
  if (!Number.isFinite(ts)) return false;
  return ts >= (Date.now() - (Math.max(1, Number(days || 7)) * 24 * 60 * 60 * 1000));
}

function buildDetailedReport(days = 7) {
  const safeDays = Math.max(1, Number(days || 7));
  const messageReport = messageAnalytics.getAnalytics({ days: safeDays });
  const replyReport = messageAnalytics.getReplySpeedSummary({ days: safeDays });
  const recentLogs = (Array.isArray(logs) ? logs : []).filter(row => withinLastDays(row.time || row.created || row.sentAt, safeDays));
  const recentCampaigns = (Array.isArray(campaigns) ? campaigns : []).filter(row => withinLastDays(row.created || row.updated || row.completed, safeDays));
  const recentOrders = (Array.isArray(orders) ? orders : []).filter(row => withinLastDays(row.created || row.order_date || row.updated, safeDays));
  const safetyRows = (Array.isArray(sendSafetyLog) ? sendSafetyLog : []).filter(row => withinLastDays(row.time || row.createdAt, safeDays));
  const byStatus = recentLogs.reduce((acc, row) => {
    const key = String(row.status || 'unknown');
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  return {
    generatedAt: new Date().toISOString(),
    days: safeDays,
    messaging: {
      totals: messageReport.totals || {},
      rates: messageReport.rates || {},
      replySpeed: {
        avgReplySeconds: replyReport.avgReplySeconds || 0,
        medianReplySeconds: replyReport.medianReplySeconds || 0,
        unresolvedCount: replyReport.unresolvedCount || 0,
        under3Seconds: replyReport.under3Seconds || 0
      },
      byStatus,
      recentFailures: recentLogs.filter(row => row.status === 'failed').slice(-20).reverse(),
      recentLogs: recentLogs.slice(-50).reverse().map(row => ({
        time: row.time || row.created || row.sentAt || '',
        status: row.status || 'unknown',
        number: row.number || row.to || row.chatId || '',
        campaign: row.campaignName || row.campaignId || '',
        detail: row.error || row.note || row.message || ''
      }))
    },
    campaigns: {
      count: recentCampaigns.length,
      completed: recentCampaigns.filter(row => row.status === 'completed').length,
      running: recentCampaigns.filter(row => row.status === 'running').length,
      failed: recentCampaigns.filter(row => row.status === 'failed').length,
      recent: recentCampaigns.slice(-20).reverse().map(row => ({
        name: row.name || row.title || 'Campaign',
        status: row.status || 'draft',
        created: row.created || row.updated || row.completed || '',
        segment: row.segment || row.audience || 'all',
        sent: Number(row.sent || row.totalSent || 0),
        failed: Number(row.failed || row.totalFailed || 0)
      }))
    },
    orders: {
      count: recentOrders.length,
      revenue: recentOrders.reduce((sum, row) => sum + Number(row.total || row.sell_price || 0), 0),
      pending: recentOrders.filter(row => ['pending', 'awaiting_payment', 'awaiting_verification'].includes(String(row.status || '').toLowerCase())).length,
      recent: recentOrders.slice(-20).reverse().map(row => ({
        id: row.id || row.orderId || row.order_id || '',
        customer: row.customerName || row.customer || row.number || '',
        status: row.status || 'unknown',
        total: Number(row.total || row.sell_price || 0),
        created: row.created || row.order_date || row.updated || ''
      }))
    },
    safety: {
      sendsRecorded: safetyRows.length,
      recent: safetyRows.slice(-20).reverse().map(row => ({
        time: row.time || row.createdAt || '',
        type: row.type || row.kind || 'send',
        status: row.status || 'logged',
        detail: row.detail || row.reason || row.message || ''
      }))
    }
  };
}

