app.post('/api/ab-tests/:id/launch', async (req, res) => {
  try {
    const test = abTesting.getAllTests().find(item => item.id === req.params.id);
    if (!test) return res.status(404).json({ error: 'Test not found' });
    if (!Array.isArray(test.variants) || test.variants.length < 2) {
      return res.status(400).json({ error: 'At least two variants are required' });
    }

    const audienceSegment = String(req.body?.segment || test.audience?.segment || 'all').toLowerCase();
    const sampleSize = Math.max(1, Math.min(Number(req.body?.sampleSize || test.sampleSize || 20), customers.length || 1));
    const eligible = shuffleArray((customers || []).filter(customer => customerMatchesBulkSegment(customer, audienceSegment))).slice(0, sampleSize);
    if (!eligible.length) return res.status(400).json({ error: 'No customers match this audience segment' });

    abTesting.startTest(test.id);

    const sent = [];
    const failed = [];
    for (let i = 0; i < eligible.length; i += 1) {
      const customer = eligible[i];
      const variant = test.variants[i % test.variants.length];
      const number = normalizeNumber(customer.number || customer.phone || customer.whatsapp || '');
      if (!number) {
        failed.push({ customerId: customer.id, variantId: variant.id, error: 'No number found' });
        continue;
      }
      try {
        const message = renderDynamicTemplate(variant.content || '', buildCustomerMessageContext(customer.id || number, {
          name: customer.name || number,
          number,
          city: customer.city || '',
          plan: customer.plan || customer.interestedPlan || '',
          product: customer.product || ''
        }));
        await sendDirect(number, message);
        abTesting.recordSend(test.id, variant.id, customer.id || number, { number, audienceSegment });
        sent.push({ customerId: customer.id, number, variantId: variant.id, variantName: variant.name || variant.id });
        await safetyPauseIfNeeded(i + 1);
      } catch (error) {
        failed.push({ customerId: customer.id, number, variantId: variant.id, error: error.message });
      }
    }

    const updated = abTesting.getAllTests().find(item => item.id === test.id);
    res.json({
      success: true,
      test: updated,
      segment: audienceSegment,
      sampleSize: eligible.length,
      sentCount: sent.length,
      failedCount: failed.length,
      sent,
      failed
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

