app.post('/api/wa/send-button', async (req, res) => {
  try {
    const { number, text, buttons, variables = {}, customerId } = req.body;
    const buttonList = Array.isArray(buttons) ? buttons : [];
    if (!number || !text || !buttonList.length) {
      return res.status(400).json({ error: 'number, text, and at least one button are required' });
    }
    const inst = waClients.get('default');
    if (!inst?.isReady) {
      return res.status(500).json({ error: 'WhatsApp not connected' });
    }

    const chatId = number.includes('@') ? number : `${number}@c.us`;
    const context = buildCustomerMessageContext(customerId || number, variables);
    const renderedText = renderDynamicTemplate(text, context);
    const buttonMsg = await inst.client.sendMessage(chatId, renderedText, {
      buttons: buttonList.map(btn => ({
        buttonId: btn.id || uuid(),
        buttonText: { displayText: renderDynamicTemplate(btn.text || btn.title || 'Option', context).slice(0, 120) },
        type: 1 // reply button
      }))
    });

    // Record in analytics
    messageAnalytics.recordSentMessage({
      to: number,
      content: renderedText,
      whatsappId: buttonMsg.id._serialized,
      type: 'button_message',
      buttonCount: buttonList.length
    });

    res.json({ success: true, messageId: buttonMsg.id._serialized });
  } catch (error) {
    console.error('Send button error:', error);
    res.status(500).json({ error: error.message });
  }
});

