app.post('/api/wa/send-vcf', async (req, res) => {
  let filePath = '';
  try {
    if (settings.vcf_sending_enabled === false || settings.contact_sharing_enabled === false) {
      return res.status(400).json({ error: 'VCF / contact card sending is disabled in Settings' });
    }
    const recipient = normalizeNumber(req.body?.number || req.body?.recipient || '');
    if (!recipient) return res.status(400).json({ error: 'recipient number is required' });
    const contactNumber = normalizeSafetyNumber(req.body?.contactNumber || req.body?.phone || req.body?.cardNumber || '');
    if (!contactNumber) return res.status(400).json({ error: 'contactNumber is required' });
    const caption = String(req.body?.caption || '').trim();
    const vcard = buildVCardText({
      firstName: req.body?.firstName,
      lastName: req.body?.lastName,
      fullName: req.body?.fullName || req.body?.name,
      org: req.body?.org || req.body?.company,
      title: req.body?.title,
      email: req.body?.email,
      url: req.body?.url,
      note: req.body?.note,
      contactNumber
    });
    const filename = `contact_${Date.now()}.vcf`;
    filePath = path.join(__dirname, 'uploads', filename);
    fs.writeFileSync(filePath, vcard, 'utf8');
    const media = createMediaFromFilePath(filePath, 'text/vcard', filename);
    await sendDirectMedia(recipient, media, caption || `Contact card: *${sanitizeVCardField(req.body?.fullName || req.body?.name || 'Contact')}*`, {
      accountId: req.body?.accountId,
      useRotation: req.body?.useRotation === true
    });
    res.json({ success: true, vcard, filename });
  } catch (error) {
    res.status(500).json({ error: error.message });
  } finally {
    if (filePath) {
      try { fs.unlink(filePath, () => {}); } catch {}
    }
  }
});

