// Lightweight agent chat backed by the configured AI provider, with a local fallback.
app.post('/api/agents/chat', async (req, res) => {
  try {
    const { agent, agentId, message } = req.body || {};
    if (!message) return res.status(400).json({ error: 'message is required' });
    const selectedAgent = findAIAgent(agentId || agent);
    const agentName = selectedAgent?.name || 'General Agent';
    const snap = businessSnapshot();
    const productContext = snap.inStockProducts.map(p => `${p.name} Rs.${Number(p.price || 0).toLocaleString()} ${p.stock === false ? 'out of stock' : 'in stock'}`).join('\n');
    const sys = `You are ${agentName} inside SuperSender Pro.
Role: ${selectedAgent?.role || 'Business Agent'}
Goal: ${selectedAgent?.goal || 'Help the user run the business dashboard.'}
Instructions: ${selectedAgent?.instructions || 'Reply clearly and briefly.'}

Current business snapshot:
- Customers: ${snap.customers}
- Orders: ${snap.orders}
- Revenue: Rs. ${snap.revenue.toLocaleString()}
- Products: ${snap.products}
Top products:
${productContext || 'No products loaded'}

Give actionable, concise answers (max 6 lines). Reply in the user's language. Include helpful emojis.`;
    let reply = await callAI(message, sys);
    let source = 'ai';
    if (isAIUnavailableReply(reply)) {
      reply = buildLocalAgentReply(selectedAgent, message);
      source = 'local';
    }
    try {
      recordAgentLearning(selectedAgent?.id || 'general-agent', {
        outcome: 'interaction',
        source: 'agent_chat',
        category: selectedAgent?.role || '',
        score: source === 'ai' ? 60 : 35
      });
    } catch {}
    res.json({ success: true, reply, source, agent: selectedAgent });
  } catch (e) {
    const selectedAgent = findAIAgent(req.body?.agentId || req.body?.agent);
    res.json({ success: true, reply: buildLocalAgentReply(selectedAgent, req.body?.message || ''), source: 'local', agent: selectedAgent });
  }
});

