app.post('/api/wa/send-audio', upload.single('file'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: 'Audio file is required' });
    }
    const inst = waClients.get('default');
    if (!inst?.isReady) {
      return res.status(500).json({ error: 'WhatsApp not connected' });
    }

    const { number } = req.body;
    if (!number) return res.status(400).json({ error: 'number is required' });
    const chatId = number.includes('@') ? number : `${number}@c.us`;
    const media = createMediaFromFilePath(req.file.path, req.file.mimetype, req.file.originalname);
    const audioMsg = await inst.client.sendMessage(chatId, media, { 
      sendAudioAsVoice: true 
    });

    try {
      const analyticsRow = messageAnalytics.recordSentMessage({
        to: number,
        content: '[Voice Note]',
        whatsappId: audioMsg.id._serialized,
        type: 'voice'
      });
      if (settings.reply_speed_tracking_enabled !== false) {
        messageAnalytics.recordReplyForConversation(number, analyticsRow?.id || null, { source: 'voice_note' });
      }
    } catch {}

    res.json({ success: true, messageId: audioMsg.id._serialized });
    try { fs.unlink(req.file.path, () => {}); } catch {}
  } catch (error) {
    console.error('Send audio error:', error);
    res.status(500).json({ error: error.message });
  }
});

app.post('/api/ai/audio-reply', upload.single('file'), async (req, res) => {
  try {
    if (settings.audio_ai_reply_enabled === false) {
      return res.status(400).json({ error: 'Audio AI replies are disabled in Settings' });
    }

    let transcript = String(req.body?.transcript || '').trim();
    if (!transcript && req.file?.path) {
      transcript = await transcribeAudioWithAvailableProvider(req.file.path, req.file.mimetype || 'audio/ogg');
    }
    if (!transcript) return res.status(400).json({ error: 'audio file or transcript is required' });

    const number = normalizeNumber(req.body?.number || req.body?.phone || '');
    const name = String(req.body?.name || '').trim();
    const reply = await buildAudioLeadReply(transcript, {
      number,
      name,
      source: req.body?.source || 'whatsapp_audio'
    });

    let sent = false;
    if (number && (req.body?.send === 'true' || req.body?.send === true)) {
      await sendDirect(number, reply);
      sent = true;
    }

    res.json({ success: true, transcript, reply, sent });
  } catch (error) {
    res.status(500).json({ error: error.message });
  } finally {
    if (req.file?.path) {
      try { fs.unlinkSync(req.file.path); } catch {}
    }
  }
});

