// Group @Everyone Announcer
app.post('/api/wa/group-announce', async (req, res) => {
  const inst = waClients.get('default');
  if (!inst?.isReady) return res.status(400).json({ error: 'Not connected' });
  const { groupId, message } = req.body;
  if (!groupId || !message) return res.status(400).json({ error: 'groupId and message required' });
  try {
    const chat = await inst.client.getChatById(groupId);
    if (!chat.isGroup) return res.status(400).json({ error: 'Not a group chat' });
    let text = message + '\n\n';
    const mentions = [];
    for (const participant of chat.participants) {
      const contact = await inst.client.getContactById(participant.id._serialized);
      mentions.push(contact);
      text += '@' + participant.id.user + ' ';
    }
    await chat.sendMessage(text, { mentions });
    res.json({ success: true, totalMentions: mentions.length });
  } catch (err) { res.status(500).json({ error: err.message }); }
});

// PDF Invoice Generator
app.post('/api/invoice/generate', (req, res) => {
  const { name, items, total, number } = req.body;
  if (!name || !items || !total) return res.status(400).json({ error: 'name, items, and total required' });
  const doc = new PDFDocument();
  const filename = 'invoice_' + Date.now() + '.pdf';
  const filepath = path.join('uploads', filename);
  const writeStream = fs.createWriteStream(filepath);
  doc.pipe(writeStream);
  doc.fontSize(20).text((settings.business_name || 'SuperSender Pro') + ' - INVOICE', { align: 'center' });
  doc.moveDown();
  doc.fontSize(12).text('Customer: ' + name);
  doc.text('Number: ' + (number || 'N/A'));
  doc.text('Date: ' + new Date().toLocaleDateString());
  doc.moveDown();
  (Array.isArray(items) ? items : []).forEach(i => doc.text('- ' + i.name + ': Rs.' + i.price));
  doc.moveDown().fontSize(14).text('Total: Rs.' + total, { underline: true });
  doc.end();
  writeStream.on('finish', () => res.json({ success: true, url: '/uploads/' + filename }));
  writeStream.on('error', err => res.status(500).json({ error: err.message }));
});

// Abandoned Cart Recovery (hourly - re-engages laptop leads stuck in chatting for 1+ hour)
cron.schedule('0 * * * *', async () => {
  const now = Date.now();
  const inst = waClients.get('default');
  if (!inst?.isReady) return;
  const abandonedFollowupMs = Number(process.env.ABANDONED_FOLLOWUP_MS || 60 * 60 * 1000);
  const abandoned = laptopLeads.filter(l =>
    l.status === 'chatting' && l.productId && (now - new Date(l.created).getTime() > abandonedFollowupMs)
  );
  for (const lead of abandoned.slice(0, 10)) {
    try {
      const msg = 'Hi ' + lead.name + ', you were looking at the ' + lead.product + '. Are you still interested? Let me know if you need a special discount!';
      await sendDirect(lead.number, msg);
      lead.status = 'followed_up';
    } catch (e) {}
    await sleep(5000);
  }
  if (abandoned.length > 0) saveJSON('laptop_leads.json', laptopLeads);
});


// ==============================================================
// FEATURE: INVOICE GENERATOR (PDF)
// ==============================================================
app.post('/api/invoices/generate', async (req, res) => {
  try {
    const { customerName, customerNumber, items, notes } = req.body;
    if (!customerName || !items || !items.length) return res.status(400).json({ error: 'customerName and items are required' });

    const invoiceId = 'INV-' + Date.now();
    const total = items.reduce((s, i) => s + (i.qty * i.price), 0);

    const doc = new PDFDocument({ size: 'A4', margin: 50 });
    const filename = `invoice_${invoiceId}.pdf`;
    const filePath = path.join(__dirname, 'uploads', filename);
    doc.pipe(fs.createWriteStream(filePath));

    // Header
    doc.fillColor('#25D366').fontSize(28).text(settings.business_name || 'SuperSender Store', { align: 'left' });
    doc.fillColor('#111').fontSize(12).text('Professional Invoice', { align: 'left' });
    doc.moveDown();
    doc.fillColor('#555').fontSize(10)
      .text(`Invoice: ${invoiceId}`, { align: 'right' })
      .text(`Date: ${new Date().toLocaleDateString()}`, { align: 'right' })
      .text(`Customer: ${customerName}`, { align: 'right' });
    if (customerNumber) doc.text(`WhatsApp: ${customerNumber}`, { align: 'right' });

    doc.moveDown().moveTo(50, doc.y).lineTo(545, doc.y).strokeColor('#25D366').stroke();
    doc.moveDown();

    // Items header
    doc.fillColor('#fff').rect(50, doc.y, 495, 20).fill('#25D366');
    doc.fillColor('#fff').text('Item', 55, doc.y - 15, { width: 250 });
    doc.text('Qty', 310, doc.y - 15, { width: 60, align: 'center' });
    doc.text('Unit Price', 370, doc.y - 15, { width: 80, align: 'right' });
    doc.text('Total', 450, doc.y - 15, { width: 90, align: 'right' });
    doc.moveDown();

    // Items rows
    items.forEach((item, i) => {
      const y = doc.y;
      if (i % 2 === 0) doc.rect(50, y - 4, 495, 20).fillColor('#f9f9f9').fill();
      doc.fillColor('#111')
        .text(item.name, 55, y, { width: 250 })
        .text(item.qty, 310, y, { width: 60, align: 'center' })
        .text('Rs. ' + Number(item.price).toLocaleString(), 370, y, { width: 80, align: 'right' })
        .text('Rs. ' + (item.qty * item.price).toLocaleString(), 450, y, { width: 90, align: 'right' });
      doc.moveDown();
    });

    doc.moveDown();
    doc.moveTo(350, doc.y).lineTo(545, doc.y).strokeColor('#25D366').stroke();
    doc.moveDown(0.5).fillColor('#25D366').fontSize(14)
      .text(`Total: Rs. ${total.toLocaleString()}`, { align: 'right' });
    if (notes) {
      doc.moveDown().fillColor('#555').fontSize(10).text('Notes: ' + notes);
    }
    doc.end();

    // Save invoice record
    let invoices = loadJSON('invoices.json', []);
    invoices.push({ id: invoiceId, customerName, customerNumber, items, total, notes, file: filename, date: new Date().toISOString() });
    saveJSON('invoices.json', invoices);

    // Send via WhatsApp if number provided
    if (customerNumber) {
      const inst = waClients.get('default');
      if (inst?.isReady) {
        await new Promise(r => setTimeout(r, 1500));
        const media = createMediaFromFilePath(filePath, 'application/pdf', `${invoiceId}.pdf`);
        await sendDirectMedia(customerNumber, media, `Invoice *${invoiceId}* for Rs. ${total.toLocaleString()}. Thank you.`);
      }
    }

    res.json({ success: true, invoiceId, total, file: `/uploads/${filename}` });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

