// ------------------------------------------------------------------
// FEATURE 2: VISUAL FLOW BUILDER (CRUD + EXECUTION ENGINE)
// ------------------------------------------------------------------
let flows = loadJSON('flows.json', []);
let flowSubmissions = loadJSON('flow_submissions.json', []);

const FLOW_NODE_TYPES = [
  { type: 'message', label: 'Message', description: 'Send a WhatsApp text message with variables.' },
  { type: 'template_message', label: 'Template Message', description: 'Send a saved template from the Template Manager inside the bot flow.' },
  { type: 'input', label: 'Input Capture', description: 'Ask the customer for text, image, PDF, or location and store it.' },
  { type: 'condition', label: 'Condition', description: 'Route by keyword, exact match, starts-with, regex, or variable comparison.' },
  { type: 'request_api', label: 'Request API', description: 'Call any external API and save the response into flow variables.' },
  { type: 'webhook', label: 'Webhook', description: 'Send real-time flow data to n8n, Zapier, Make, or your own system.' },
  { type: 'google_sheet', label: 'Sheet Save', description: 'Save captured form data locally and optionally POST it to a sheet webhook.' },
  { type: 'ai', label: 'AI Reply', description: 'Ask the active AI provider to reply in the customer language.' },
  { type: 'tag', label: 'Tag Customer', description: 'Apply a CRM tag to the current customer.' },
  { type: 'update_contact', label: 'Update Contact', description: 'Update CRM status, source, group, tags, or custom fields from flow data.' },
  { type: 'wait', label: 'Wait', description: 'Pause the flow until the customer sends another message.' }
];

function normalizeFlowNodeType(type = '') {
  const clean = String(type || '').trim().toLowerCase();
  if (['api', 'request', 'request-api'].includes(clean)) return 'request_api';
  if (['template', 'template-message', 'message_template', 'saved_template'].includes(clean)) return 'template_message';
  if (['sheet', 'google-sheet', 'spreadsheet'].includes(clean)) return 'google_sheet';
  if (['capture', 'capture_input', 'form'].includes(clean)) return 'input';
  if (['contact', 'crm', 'update-contact', 'update_customer'].includes(clean)) return 'update_contact';
  return clean || 'message';
}

function flowContextValues(ctx = {}) {
  const vars = ctx.vars || {};
  const customer = findCustomerByIdentifier(ctx.customerId || ctx.number || vars.number || '') || {};
  const customFields = {
    ...normalizeCustomFields(customer.customFields),
    ...normalizeCustomFields(vars.customFields),
    ...normalizeCustomFields(vars.custom_fields)
  };
  return {
    ...vars,
    customer,
    contact: customer,
    customFields,
    name: ctx.name || vars.name || 'Customer',
    number: ctx.number || vars.number || '',
    message: ctx.message || '',
    business: settings.business_name || settings.store_name || process.env.STORE_NAME || 'SuperSender Pro',
    owner: settings.owner_whatsapp || settings.admin_phone || settings.support_whatsapp || '',
    easypaisa: settings.easypaisa_number || settings.easypaisa || '',
    jazzcash: settings.jazzcash_number || settings.jazzcash || '',
    nayapay: settings.nayapay_number || settings.nayapay_iban || '',
    askari: settings.askari_bank_account || settings.askari_account || '',
    bank: settings.bank_iban || settings.bank_account || settings.bank_account_name || ''
  };
}

function renderFlowText(value, ctx = {}) {
  return renderDynamicTemplate(String(value ?? ''), flowContextValues(ctx));
}

function renderFlowValue(value, ctx = {}) {
  if (Array.isArray(value)) return value.map(item => renderFlowValue(item, ctx));
  if (value && typeof value === 'object') {
    return Object.fromEntries(Object.entries(value).map(([k, v]) => [k, renderFlowValue(v, ctx)]));
  }
  if (typeof value === 'string') return renderFlowText(value, ctx);
  return value;
}

function renderFlowTemplateMessage(node = {}, ctx = {}) {
  const templateId = renderFlowText(node.templateId || node.template_id || node.template || '', ctx).trim();
  const inlineFallback = node.content || node.message || node.text || node.fallback || '';
  const variableOverrides = renderFlowValue(parseFlowJSON(node.variables || node.vars || node.mergeFields, {}), ctx) || {};
  if (templateId) {
    try {
      return templateManager.renderTemplate(
        templateId,
        buildCustomerMessageContext(ctx.number || variableOverrides.number || '', {
          ...flowContextValues(ctx),
          ...variableOverrides
        })
      );
    } catch (error) {
      if (!inlineFallback) throw error;
      console.warn('[Flow] Template node fallback used:', error.message);
    }
  }
  return renderFlowText(inlineFallback, ctx);
}

function updateContactFromFlow(number, node = {}, ctx = {}) {
  const clean = normalizeNumber(number);
  let customer = ensureGuestCustomer(clean, ctx.name, 'flow');
  if (!customer) return null;
  const fieldMap = renderFlowValue(parseFlowJSON(node.fields || node.updates, {}), ctx) || {};
  const flowCustomFields = {
    ...normalizeCustomFields(fieldMap.customFields),
    ...normalizeCustomFields(fieldMap.custom_fields),
    ...normalizeCustomFields(fieldMap.fields),
    ...normalizeCustomFields(fieldMap.mergeFields)
  };
  delete fieldMap.customFields;
  delete fieldMap.custom_fields;
  delete fieldMap.fields;
  delete fieldMap.mergeFields;
  const tags = [
    ...(Array.isArray(node.tags) ? node.tags : String(node.tags || node.tag || '').split(',')),
    ...(Array.isArray(fieldMap.tags) ? fieldMap.tags : String(fieldMap.tags || '').split(','))
  ].map(tag => renderFlowText(tag, ctx).trim()).filter(Boolean);
  delete fieldMap.tags;
  Object.entries(fieldMap).forEach(([key, value]) => {
    if (!key) return;
    customer[key] = value;
  });
  if (Object.keys(flowCustomFields).length) {
    customer.customFields = {
      ...normalizeCustomFields(customer.customFields),
      ...flowCustomFields
    };
  }
  ['status', 'source', 'group', 'plan', 'city', 'intent'].forEach(key => {
    if (node[key] !== undefined && node[key] !== '') customer[key] = renderFlowText(node[key], ctx);
  });
  if (tags.length) customer.tags = [...new Set([...(customer.tags || []), ...tags])];
  customer.updatedAt = new Date().toISOString();
  saveJSON('customers.json', customers);
  io.emit('customer_updated', customer);
  return customer;
}

function parseFlowJSON(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'object') return value;
  try { return JSON.parse(String(value)); } catch { return fallback; }
}

function flowValueByPath(ctx = {}, pathText = '') {
  const values = flowContextValues(ctx);
  const pathParts = String(pathText || '').replace(/^\$\./, '').split('.').filter(Boolean);
  let cur = values;
  for (const part of pathParts) {
    if (cur && Object.prototype.hasOwnProperty.call(cur, part)) cur = cur[part];
    else return '';
  }
  return cur;
}

function evaluateFlowCondition(rule = {}, ctx = {}) {
  const matchType = String(rule.matchType || rule.operator || 'contains').toLowerCase();
  const leftRaw = rule.field ? flowValueByPath(ctx, rule.field) : ctx.message;
  const rightRaw = rule.value ?? rule.keyword ?? '';
  const left = String(leftRaw ?? '').toLowerCase();
  const right = String(rightRaw ?? '').toLowerCase();
  if (!right && !['exists', 'notempty'].includes(matchType)) return false;
  if (matchType === 'exact' || matchType === 'equals') return left === right;
  if (matchType === 'startswith' || matchType === 'starts_with') return left.startsWith(right);
  if (matchType === 'endswith' || matchType === 'ends_with') return left.endsWith(right);
  if (matchType === 'regex') {
    try { return new RegExp(String(rightRaw), 'i').test(String(leftRaw ?? '')); } catch { return false; }
  }
  if (matchType === 'not_equals') return left !== right;
  if (matchType === 'gt') return Number(leftRaw) > Number(rightRaw);
  if (matchType === 'lt') return Number(leftRaw) < Number(rightRaw);
  if (matchType === 'exists' || matchType === 'notempty') return String(leftRaw ?? '').trim().length > 0;
  return left.includes(right);
}

async function executeFlowRequestNode(node, ctx, options = {}) {
  const url = renderFlowText(node.url || node.endpoint || '', ctx).trim();
  if (!url) throw new Error('API node URL is required');
  const method = String(node.method || 'POST').toUpperCase();
  const headers = renderFlowValue(parseFlowJSON(node.headers, {}), ctx) || {};
  const bodySource = node.body ?? node.payload ?? '';
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), Number(node.timeoutMs || 8000));
  if (timer.unref) timer.unref();
  try {
    const fetchOptions = { method, headers: { ...headers }, signal: controller.signal };
    if (!['GET', 'HEAD'].includes(method) && bodySource !== '') {
      const parsedBody = parseFlowJSON(bodySource, null);
      if (parsedBody !== null && typeof parsedBody === 'object') {
        fetchOptions.body = JSON.stringify(renderFlowValue(parsedBody, ctx));
        if (!fetchOptions.headers['Content-Type'] && !fetchOptions.headers['content-type']) {
          fetchOptions.headers['Content-Type'] = 'application/json';
        }
      } else {
        fetchOptions.body = renderFlowText(bodySource, ctx);
      }
    }
    if (options.dryRun) {
      return { ok: true, status: 0, dryRun: true, url, method, body: fetchOptions.body || null };
    }
    const response = await fetch(url, fetchOptions);
    const text = await response.text();
    let data = text;
    try { data = JSON.parse(text); } catch {}
    const result = { ok: response.ok, status: response.status, data, text: String(text || '').slice(0, 1500) };
    const saveAs = node.saveAs || node.variable || 'api';
    ctx.vars[saveAs] = data;
    return result;
  } finally {
    clearTimeout(timer);
  }
}

async function executeFlowWebhookNode(node, ctx, options = {}) {
  const eventName = node.event || 'new_lead';
  const payload = renderFlowValue(parseFlowJSON(node.body || node.payload, {
    flowId: ctx.flow?.id,
    flowName: ctx.flow?.name,
    number: ctx.number,
    name: ctx.name,
    message: ctx.message,
    variables: ctx.vars
  }), ctx);
  const url = renderFlowText(node.url || node.webhookUrl || '', ctx).trim();
  if (!url) {
    if (!options.dryRun) queueWebhookEvent(eventName, payload);
    return { queuedInternalWebhook: true, event: eventName, payload };
  }
  return executeFlowRequestNode({ ...node, type: 'request_api', method: node.method || 'POST', url, body: payload }, ctx, options);
}

function buildFlowSubmission(flow, node, ctx) {
  const fields = renderFlowValue(parseFlowJSON(node.fields || node.mapping, ctx.vars || {}), ctx);
  return {
    id: uuid(),
    flowId: flow.id,
    flowName: flow.name,
    nodeId: node.id,
    nodeLabel: node.label || node.type,
    number: ctx.number,
    name: ctx.name || ctx.number,
    message: ctx.message,
    fields,
    variables: ctx.vars || {},
    createdAt: new Date().toISOString()
  };
}

async function executeFlowSheetNode(flow, node, ctx, options = {}) {
  const record = buildFlowSubmission(flow, node, ctx);
  if (!options.dryRun) {
    flowSubmissions.push(record);
    flowSubmissions = flowSubmissions.slice(-1000);
    saveJSON('flow_submissions.json', flowSubmissions);
    if (node.webhookUrl || node.url) {
      try {
        await executeFlowRequestNode({
          type: 'request_api',
          method: 'POST',
          url: node.webhookUrl || node.url,
          body: record
        }, ctx);
      } catch (error) {
        console.warn('[Flow] Sheet webhook skipped:', error.message);
      }
    }
  }
  return record;
}

function saveFlowPause(number, flow, node, ctx, captureField = '') {
  const conv = waConversations[number] || {};
  conv.flowId = flow.id;
  conv.flowNodeId = node.next || null;
  conv.flowVars = ctx.vars || {};
  if (captureField) conv.flowCaptureField = captureField;
  waConversations[number] = conv;
  saveConversations();
}

