async function executeFlow(flow, number, message, name) {
  const nodes = flow.nodes || [];
  let currentNodeId = flow.startNodeId || (nodes[0] && nodes[0].id);
  const visited = new Set();
  const conv = waConversations[number] || {};
  const ctx = {
    flow,
    number,
    name: name || number,
    message: String(message || ''),
    vars: { ...(conv.flowVars || {}) }
  };
  while (currentNodeId && !visited.has(currentNodeId)) {
    visited.add(currentNodeId);
    const node = nodes.find(n => n.id === currentNodeId);
    if (!node) break;
    const type = normalizeFlowNodeType(node.type);
    if (type === 'message') {
      const text = renderFlowText(node.content || node.text || node.message || '', ctx);
      if (text.trim()) await sendDirect(number, text);
      await sleep(900);
      currentNodeId = node.next || null;
    } else if (type === 'template_message') {
      const text = renderFlowTemplateMessage(node, ctx);
      if (String(text || '').trim()) await sendDirect(number, text);
      await sleep(900);
      currentNodeId = node.next || null;
    } else if (type === 'input') {
      const prompt = renderFlowText(node.prompt || node.content || node.message || 'Please share the required detail.', ctx);
      if (prompt.trim()) await sendDirect(number, prompt);
      const captureField = String(node.field || node.saveAs || node.variable || node.label || 'input').trim();
      saveFlowPause(number, flow, node, ctx, captureField);
      break;
    } else if (type === 'condition') {
      const matched = (node.conditions || []).find(rule => evaluateFlowCondition(rule, ctx));
      currentNodeId = matched ? matched.next : (node.defaultNext || node.next || null);
    } else if (type === 'request_api') {
      try {
        const result = await executeFlowRequestNode(node, ctx);
        if (node.replyWithResponse) {
          await sendDirect(number, renderFlowText(node.responseTemplate || '{api}', { ...ctx, vars: { ...ctx.vars, api: JSON.stringify(result.data || result.text || '') } }));
        }
      } catch (error) {
        if (node.errorMessage) await sendDirect(number, renderFlowText(node.errorMessage, ctx));
        console.warn('[Flow] API node failed:', error.message);
      }
      currentNodeId = node.next || null;
    } else if (type === 'webhook') {
      try { await executeFlowWebhookNode(node, ctx); } catch (error) { console.warn('[Flow] Webhook node failed:', error.message); }
      currentNodeId = node.next || null;
    } else if (type === 'google_sheet') {
      await executeFlowSheetNode(flow, node, ctx);
      currentNodeId = node.next || null;
    } else if (type === 'ai') {
      const sp = node.systemPrompt || ('You are a helpful assistant for ' + (settings.business_name || 'Us') + '.');
      const reply = await callAI(ctx.message, sp);
      await sendDirect(number, reply);
      currentNodeId = node.next || null;
    } else if (type === 'tag') {
      const cust = customers.find(c => c.number === number || c.number === normalizeNumber(number));
      if (cust && node.tag) { cust.tags = [...new Set([...(cust.tags || []), renderFlowText(node.tag, ctx)])]; saveJSON('customers.json', customers); }
      currentNodeId = node.next || null;
    } else if (type === 'update_contact') {
      updateContactFromFlow(number, node, ctx);
      currentNodeId = node.next || null;
    } else if (type === 'wait') {
      saveFlowPause(number, flow, node, ctx);
      break;
    } else {
      currentNodeId = node.next || null;
    }
  }
  return true;
}

async function checkFlows(number, message, name) {
  const cleanMessage = String(message || '').trim();
  if (settings.laptop_bot_enabled && (isMenuCommand(cleanMessage) || cleanMessage === '0')) {
    return false;
  }

  const conv = waConversations[number] || {};
  if (conv.flowCaptureField) {
    conv.flowVars = { ...(conv.flowVars || {}), [conv.flowCaptureField]: cleanMessage };
    delete conv.flowCaptureField;
    waConversations[number] = conv;
    saveConversations();
  }
  if (conv.flowId && conv.flowNodeId) {
    const flow = flows.find(f => f.id === conv.flowId && f.active);
    if (flow) {
      const nodeId = conv.flowNodeId;
      delete conv.flowId; delete conv.flowNodeId;
      waConversations[number] = conv;
      await executeFlow({ ...flow, startNodeId: nodeId }, number, message, name);
      return true;
    }
  }
  const lower = cleanMessage.toLowerCase();
  for (const flow of flows.filter(f => f.active)) {
    if ((flow.triggers || []).some(t => lower.includes(t.toLowerCase()))) {
      await executeFlow(flow, number, message, name);
      return true;
    }
  }
  return false;
}

