app.post('/api/broadcast/smart', async (req, res) => {
  const { message, segment, aiPersonalize } = req.body;
  const inst = waClients.get('default');
  if (!inst || !inst.isReady) return res.status(400).json({ error: 'WhatsApp not connected' });
  let targets = [...customers];
  if (segment === 'active') targets = customers.filter(c => c.status === 'active');
  else if (segment === 'leads') targets = customers.filter(c => c.status === 'lead');
  else if (segment === 'expired') targets = customers.filter(c => c.status === 'expired');
  else if (segment === 'hot') targets = customers.filter(c => c.buyerIntent === 'HOT' || (c.leadScore || 0) >= 80);
  res.json({ success: true, queued: targets.length });
  (async () => {
    let sent = 0, failed = 0;
    for (const cust of targets) {
      try {
        const safety = validateSafetyRecipient(cust, { context: 'smart_broadcast' });
        if (!safety.allowed) throw new Error(`Safety blocked: ${safety.reasons.join(', ')}`);
        let finalMsg = renderDynamicTemplate(message, buildCustomerMessageContext(cust));
        if (aiPersonalize && hasAnyAIProvider()) {
          finalMsg = await callAI(
            'Original: "' + message + '"\nCustomer: name=' + cust.name + ', city=' + (cust.city || 'unknown') +
            ', plan=' + (cust.plan || 'none') + ', tags=' + (cust.tags || []).join(',') +
            '.\nPersonalize this WhatsApp message for them. Return ONLY the message text.',
            'You are a WhatsApp marketing expert for ' + (settings.business_name || 'Us') + '. Max 150 words, casual friendly tone. ' + buildAIAutoReplyStylePrompt()
          );
        }
        finalMsg = applyCustomLogicMessage(finalMsg, cust || {}, { segment, context: 'smart_broadcast' }).message;
        finalMsg = applyCompliantMessageVariation(finalMsg, cust || {}, { segment, context: 'smart_broadcast' });
        finalMsg = appendUnsubscribeFooter(finalMsg, { unsubscribeFooterText: settings.unsubscribe_footer });
        await sendDirect(cust.number, finalMsg);
        recordSafetySend(cust.number, { type: 'smart_broadcast' });
        sent++;
        io.emit('broadcast_progress', { sent, failed, total: targets.length, percent: Math.round(sent / targets.length * 100) });
        await safetyPauseIfNeeded(sent + failed);
        await sleep(safetyDelayMs(Math.floor(Math.random() * 3000) + 4000));
      } catch(e) {
        failed++;
        io.emit('broadcast_progress', { sent, failed, total: targets.length, percent: Math.round(sent / targets.length * 100) });
      }
    }
    io.emit('broadcast_complete', { sent, failed, total: targets.length });
    logs.push({ id: uuid(), type: 'smart_broadcast', segment, aiPersonalize: !!aiPersonalize, sent, failed, total: targets.length, time: new Date().toISOString() });
    saveJSON('logs.json', logs);
  })();
});

