app.get('/api/customers/:id/timeline', (req, res) => {
  const cust = customers.find(c => c.id === req.params.id);
  if (!cust) return res.status(404).json({ error: 'Not found' });
  const allPayments = loadJSON('payments.json', []).filter(p => p.number === cust.number);
  const myFollowups = followups.filter(f => f.number === cust.number);
  const myLogs = logs.filter(l => l.to === cust.number || l.number === cust.number).slice(-15);
  const conv = waConversations[cust.number];
  const messages = conv ? (conv.history || []).slice(-25) : [];
  const timeline = [];
  allPayments.forEach(p => timeline.push({ type: 'payment', icon: 'money', label: 'Payment Rs.' + p.amount + ' â€” ' + (p.status || 'pending'), time: p.created || p.date, data: p }));
  myFollowups.forEach(f => timeline.push({ type: 'followup', icon: 'phone', label: 'Follow-up: ' + (f.note || f.message || 'Scheduled'), time: f.created || f.scheduledAt, data: f }));
  myLogs.forEach(l => timeline.push({ type: 'log', icon: 'send', label: 'Sent: ' + ((l.message || '').substring(0, 60) || 'Campaign msg'), time: l.time, data: l }));
  messages.forEach(m => timeline.push({ type: 'chat', icon: m.role === 'user' ? 'user' : 'bot', label: (m.role === 'user' ? 'Customer: ' : 'Bot: ') + (m.msg || '').substring(0, 80), time: m.time, data: m }));
  timeline.sort((a, b) => new Date(b.time || 0) - new Date(a.time || 0));
  res.json({ customer: maskCustomerForRole(cust, req), timeline: timeline.slice(0, 60) });
});

