function normalizeWAChatId(id = '') {
  return id.toString().trim().replace(/^whatsapp:/i, '').replace(/\s+/g, '');
}

function normalizeWAMessageId(id = '') {
  if (!id) return '';
  if (typeof id === 'object') return normalizeWAMessageId(id._serialized || id.id || id.key?.id || '');
  return id.toString().trim();
}

function waMessageId(msg = {}) {
  return normalizeWAMessageId(msg.id || msg.messageId || msg.whatsappId || msg.key?.id || msg._data?.id || '');
}

function waChatKeyCandidates(rawId = '') {
  const raw = normalizeWAChatId(rawId);
  const keys = new Set();
  if (raw) keys.add(raw);
  if (raw) keys.add(raw.toLowerCase());
  const digits = raw.replace(/@(c|g|lid)\.us$/i, '').replace(/\D/g, '');
  if (digits) {
    keys.add(digits);
    keys.add(`${digits}@c.us`);
    keys.add(`${digits}@lid`);
    if (raw.includes('@g.us')) keys.add(`${digits}@g.us`);
  }
  return Array.from(keys).filter(Boolean);
}

function conversationControlSnapshot(rawId = '') {
  const candidates = waChatKeyCandidates(rawId);
  let conv = null;
  let key = candidates.find(k => waConversations[k]);
  if (key) conv = waConversations[key];
  if (!conv) {
    const digits = normalizeNumber(rawId);
    key = digits || normalizeWAChatId(rawId);
    conv = { step: 'main', history: [], paused: false, botPaused: false, aiPaused: false, humanHandoff: false };
  }
  return {
    key,
    paused: !!conv.paused,
    botPaused: !!conv.botPaused,
    aiPaused: !!conv.aiPaused,
    humanHandoff: !!conv.humanHandoff,
    updatedAt: conv.controlUpdatedAt || null
  };
}

function updateConversationControl(rawId = '', updates = {}) {
  const candidates = waChatKeyCandidates(rawId);
  const digits = normalizeNumber(rawId);
  if (digits) candidates.push(digits);
  const unique = [...new Set(candidates.filter(Boolean))];
  const primary = unique[0] || digits || normalizeWAChatId(rawId);
  if (primary && !unique.includes(primary)) unique.push(primary);
  const patch = {};
  ['paused', 'botPaused', 'aiPaused', 'humanHandoff'].forEach(key => {
    if (updates[key] !== undefined) patch[key] = !!updates[key];
  });
  if (updates.botPaused !== undefined) patch.paused = !!updates.botPaused;
  if (updates.paused !== undefined) patch.botPaused = !!updates.paused;
  patch.controlUpdatedAt = new Date().toISOString();

  for (const key of unique) {
    const current = waConversations[key] || { step: 'main', history: [], paused: false };
    waConversations[key] = { ...current, ...patch };
  }
  saveConversations();
  return conversationControlSnapshot(primary);
}

function deletedWAIdsForChat(chatId = '') {
  const ids = new Set();
  for (const key of waChatKeyCandidates(chatId)) {
    const list = deletedWAMessages?.[key];
    if (Array.isArray(list)) list.forEach(id => ids.add(normalizeWAMessageId(id)));
  }
  return ids;
}

function rememberDeletedWAMessage(chatId, messageId) {
  const id = normalizeWAMessageId(messageId);
  if (!chatId || !id) return 0;
  let added = 0;
  for (const key of waChatKeyCandidates(chatId)) {
    const set = new Set(Array.isArray(deletedWAMessages[key]) ? deletedWAMessages[key].map(normalizeWAMessageId) : []);
    if (!set.has(id)) {
      set.add(id);
      added++;
    }
    deletedWAMessages[key] = Array.from(set).filter(Boolean).slice(-500);
  }
  return added;
}

function removeLiveMessageById(inst, chatId, messageId) {
  if (!inst?.liveMessages || !messageId) return 0;
  let removed = 0;
  for (const key of waChatKeyCandidates(chatId)) {
    const list = inst.liveMessages.get(key);
    if (!Array.isArray(list)) continue;
    const next = list.filter(m => waMessageId(m) !== messageId);
    removed += list.length - next.length;
    inst.liveMessages.set(key, next);
  }
  return removed;
}

function waChatIds(chat = {}) {
  const id = chat.id || {};
  const serialized = id._serialized || (typeof id === 'string' ? id : '');
  const user = id.user || '';
  const ids = [serialized, user, chat.name, chat.formattedTitle].filter(Boolean).map(normalizeWAChatId);
  if (user) {
    ids.push(`${user}@c.us`, `${user}@lid`, `${user}@g.us`);
  }
  return new Set(ids);
}

async function getWAChatByAnyId(inst, rawId) {
  const wanted = normalizeWAChatId(rawId);
  if (!wanted) throw new Error('chat id required');
  try {
    return await inst.client.getChatById(wanted);
  } catch (directError) {
    const chats = await inst.client.getChats();
    const chat = (chats || []).find(c => waChatIds(c).has(wanted));
    if (chat) return chat;
    throw directError;
  }
}

// Get chat messages for cockpit
app.get('/api/wa/chat/:id', async (req, res) => {
  const inst = waClients.get('default');
  if (!inst || !inst.isReady) return res.status(400).json({ error: 'Not connected' });
  try {
    const chat = await getWAChatByAnyId(inst, req.params.id);
    let msgs = [];
    try {
      msgs = typeof chat.fetchMessages === 'function' ? await chat.fetchMessages({ limit: 50 }) : [];
    } catch (fetchError) {
      const last = chat.lastMessage;
      const lastBody = last?.body || last?._data?.body || last?.caption || '';
      msgs = lastBody ? [last] : [];
    }
    const hiddenIds = deletedWAIdsForChat(req.params.id);
    if (hiddenIds.size) {
      msgs = (msgs || []).filter(m => !hiddenIds.has(waMessageId(m)));
    }
    res.json(msgs.map(m => {
      const authorId = m.author || null;
      const authorNumber = authorId ? String(authorId).split('@')[0].replace(/\D/g, '') : '';
      return {
        id: waMessageId(m),
        body: m.body || m._data?.body || m.caption || '',
        fromMe: !!m.fromMe,
        timestamp: m.timestamp || m._data?.t || chat.timestamp || 0,
        type: m.type,
        from: m.from,
        to: m.to,
        author: authorId,
        authorNumber,
        authorName: m.senderName || m._data?.notifyName || m._data?.authorName || null,
        isGroup: !!chat.isGroup
      };
    }));
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// Hide a WhatsApp message from the SuperSender dashboard history.
// This does not delete the original message from WhatsApp for everyone.
app.delete('/api/wa/chat-message', async (req, res) => {
  try {
    const chatId = normalizeWAChatId(req.body?.chatId || req.query?.chatId || '');
    const messageId = normalizeWAMessageId(req.body?.messageId || req.query?.messageId || '');
    if (!chatId || !messageId) return res.status(400).json({ error: 'chatId and messageId are required' });

    const inst = waClients.get('default');
    const added = rememberDeletedWAMessage(chatId, messageId);
    const liveRemoved = removeLiveMessageById(inst, chatId, messageId);

    let inboxRemoved = 0;
    if (Array.isArray(inbox) && inbox.length) {
      const before = inbox.length;
      inbox = inbox.filter(item => {
        const itemChat = normalizeWAChatId(item.chatId || item.from || item.number || '');
        const sameChat = !itemChat || waChatKeyCandidates(chatId).includes(itemChat) || waChatKeyCandidates(itemChat).includes(chatId);
        const itemMessageId = normalizeWAMessageId(item.messageId || item.id || item.whatsappId || '');
        return !(sameChat && itemMessageId && itemMessageId === messageId);
      });
      inboxRemoved = before - inbox.length;
      if (inboxRemoved) saveInbox();
    }

    saveDeletedWAMessages();
    res.json({ success: true, hidden: true, removed: liveRemoved + inboxRemoved, remembered: added });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

