app.post('/api/logic-rules', (req, res) => {
  try {
    const body = req.body || {};
    const rule = {
      id: body.id || uuid(),
      name: String(body.name || 'Logic Rule').trim(),
      field: String(body.field || '').trim(),
      operator: String(body.operator || 'equals').trim(),
      value: body.value ?? '',
      trueMessage: String(body.trueMessage || '').trim(),
      falseMessage: String(body.falseMessage || '').trim(),
      priority: Number(body.priority || 0),
      active: body.active !== false,
      createdAt: body.createdAt || new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };
    if (!rule.field) return res.status(400).json({ error: 'field required' });
    const idx = (customLogicRules || []).findIndex(item => item.id === rule.id);
    if (idx >= 0) customLogicRules[idx] = { ...customLogicRules[idx], ...rule };
    else customLogicRules.unshift(rule);
    saveCustomLogicRules();
    res.json({ success: true, rule });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

