app.post('/api/logic-rules/evaluate', (req, res) => {
  try {
    const context = req.body?.context && typeof req.body.context === 'object' ? req.body.context : (req.body || {});
    const baseMessage = String(req.body?.message || '').trim();
    const inlineRule = req.body?.rule && typeof req.body.rule === 'object'
      ? {
          id: req.body.rule.id || 'inline-rule',
          name: String(req.body.rule.name || 'Inline Rule').trim(),
          field: String(req.body.rule.field || '').trim(),
          operator: String(req.body.rule.operator || 'equals').trim(),
          value: req.body.rule.value ?? '',
          trueMessage: String(req.body.rule.trueMessage || '').trim(),
          falseMessage: String(req.body.rule.falseMessage || '').trim(),
          priority: Number(req.body.rule.priority || 0),
          active: req.body.rule.active !== false
        }
      : null;
    const evaluation = inlineRule
      ? (inlineRule.active === false
          ? { matched: false, rule: inlineRule, reason: 'inactive' }
          : { matched: evaluateRuleMatch(inlineRule, context), rule: inlineRule })
      : evaluateCustomLogicRules(context);
    const applied = inlineRule
      ? (baseMessage
          ? {
              message: evaluation.matched
                ? (inlineRule.trueMessage || baseMessage)
                : (inlineRule.falseMessage || baseMessage),
              appliedRule: inlineRule
            }
          : null)
      : (baseMessage ? applyCustomLogicMessage(baseMessage, context) : null);
    res.json({
      success: true,
      evaluation,
      appliedMessage: applied?.message || '',
      appliedRule: applied?.appliedRule || null
    });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

