function buildAIToolQuizRecommendations(input = {}) {
  const catalog = [
    { slug: 'chatgpt_plus', name: 'ChatGPT Plus', strengths: ['general', 'content', 'research', 'speed', 'support'], basePrice: 1199 },
    { slug: 'claude_pro', name: 'Claude Pro', strengths: ['writing', 'research', 'long_context', 'analysis'], basePrice: 1699 },
    { slug: 'gemini_advanced', name: 'Gemini Advanced', strengths: ['google', 'workspace', 'productivity', 'multimodal'], basePrice: 1599 },
    { slug: 'cursor_pro', name: 'Cursor Pro', strengths: ['coding', 'developer', 'productivity'], basePrice: 1999 },
    { slug: 'midjourney', name: 'Midjourney', strengths: ['image', 'creative', 'design'], basePrice: 1499 },
    { slug: 'kimi', name: 'Kimi', strengths: ['budget', 'research', 'long_context'], basePrice: 899 }
  ];
  const answers = {
    useCase: String(input.useCase || input.goal || '').toLowerCase(),
    budget: Number(input.budget || 0),
    teamSize: Number(input.teamSize || input.team || 1),
    needsImages: input.needsImages === true || /image|design|creative/.test(String(input.useCase || '').toLowerCase()),
    needsCoding: input.needsCoding === true || /code|coding|developer|cursor/.test(String(input.useCase || '').toLowerCase()),
    needsResearch: input.needsResearch === true || /research|study|analysis|compare/.test(String(input.useCase || '').toLowerCase()),
    wantsGoogle: input.wantsGoogle === true || /google|workspace|gmail|docs/.test(String(input.stack || input.useCase || '').toLowerCase()),
    wantsBudget: input.wantsBudget === true || (Number(input.budget || 0) > 0 && Number(input.budget || 0) <= 1200)
  };

  const scored = catalog.map(tool => {
    let score = 35;
    if (answers.needsCoding && tool.strengths.includes('coding')) score += 40;
    if (answers.needsImages && tool.strengths.includes('image')) score += 45;
    if (answers.needsResearch && (tool.strengths.includes('research') || tool.strengths.includes('analysis'))) score += 30;
    if (answers.wantsGoogle && tool.strengths.includes('google')) score += 35;
    if (answers.wantsBudget && (tool.strengths.includes('budget') || tool.basePrice <= 1200)) score += 25;
    if (answers.teamSize > 1 && tool.slug === 'chatgpt_plus') score += 10;
    if (/content|marketing|sales|general/.test(answers.useCase) && tool.slug === 'chatgpt_plus') score += 25;
    if (/writing|documents|proposal/.test(answers.useCase) && tool.slug === 'claude_pro') score += 30;
    if (/design|branding|creative/.test(answers.useCase) && tool.slug === 'midjourney') score += 30;
    return {
      ...tool,
      score,
      fitReason:
        tool.slug === 'cursor_pro' && answers.needsCoding ? 'Best fit for coding-heavy workflow.' :
        tool.slug === 'midjourney' && answers.needsImages ? 'Best fit for visual creatives and image generation.' :
        tool.slug === 'claude_pro' && answers.needsResearch ? 'Strong for long-form analysis and research.' :
        tool.slug === 'gemini_advanced' && answers.wantsGoogle ? 'Best fit if Google Workspace is central.' :
        tool.slug === 'kimi' && answers.wantsBudget ? 'Good low-budget option for research-focused users.' :
        'Balanced option for daily AI work.'
    };
  }).sort((a, b) => b.score - a.score);

  const top = scored.slice(0, 3);
  const summary = top[0]
    ? `Recommended: ${top[0].name}. ${top[0].fitReason}`
    : 'No recommendation available.';
  return { answers, recommendations: top, summary };
}

app.post('/api/ai-tools/recommendation-quiz', (req, res) => {
  try {
    const body = req.body || {};
    const result = buildAIToolQuizRecommendations(body);
    const number = normalizeNumber(body.number || body.phone || '');
    if (number || body.email) {
      const customer = upsertUnifiedIdentity({
        ...body,
        number,
        email: normalizeIdentityEmail(body.email || ''),
        channel: 'whatsapp'
      });
      customer.lastQuizResult = {
        answers: result.answers,
        topRecommendation: result.recommendations[0]?.name || '',
        updatedAt: new Date().toISOString()
      };
      saveJSON('customers.json', customers);
      logJourneyEvent('ai_tool_quiz', {
        number: customer.number || '',
        customerId: customer.id,
        customerName: customer.name || '',
        channel: 'whatsapp',
        meta: {
          answers: result.answers,
          topRecommendation: result.recommendations[0]?.slug || '',
          email: customer.email || ''
        }
      }, getJourneyStageForCustomer(customer));
    }
    res.json({ success: true, ...result });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});


