let orders = loadJSON('orders.json', []);

// ------------------------------------------------------------------
// PROJECT PROMPT AGENT
// ------------------------------------------------------------------
let projectPromptAgentRuns = loadJSON('project_prompt_agent_runs.json', []);
let projectPromptAgentQueue = loadJSON('project_prompt_agent_queue.json', []);
if (!Array.isArray(projectPromptAgentRuns)) projectPromptAgentRuns = [];
if (!Array.isArray(projectPromptAgentQueue)) projectPromptAgentQueue = [];

function saveProjectPromptAgentRuns() {
  projectPromptAgentRuns = (Array.isArray(projectPromptAgentRuns) ? projectPromptAgentRuns : [])
    .sort((a, b) => Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, 300);
  saveJSON('project_prompt_agent_runs.json', projectPromptAgentRuns);
}

function saveProjectPromptAgentQueue() {
  projectPromptAgentQueue = (Array.isArray(projectPromptAgentQueue) ? projectPromptAgentQueue : [])
    .sort((a, b) => Number(b.priority || 0) - Number(a.priority || 0) || Date.parse(b.createdAt || 0) - Date.parse(a.createdAt || 0))
    .slice(0, 500);
  saveJSON('project_prompt_agent_queue.json', projectPromptAgentQueue);
}

function projectAgentArray(value) {
  return Array.isArray(value) ? value : [];
}

function projectAgentDateKey(value = new Date()) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleDateString('en-CA', { timeZone: 'Asia/Karachi' });
}

function projectAgentFingerprint(input = {}) {
  return crypto.createHash('sha1')
    .update([input.category || '', input.title || '', String(input.prompt || '').slice(0, 500)].join('|'))
    .digest('hex');
}

function projectAgentOpenTasks() {
  return projectAgentArray(projectPromptAgentQueue).filter(task => !['done', 'dismissed', 'archived'].includes(String(task.status || 'open').toLowerCase()));
}

function collectProjectPromptSignals() {
  const today = projectAgentDateKey(new Date());
  const orderRows = projectAgentArray(orders);
  const paymentRows = projectAgentArray(payments);
  const productRows = projectAgentArray(laptopProducts);
  const planRows = projectAgentArray(plans);
  const customerRows = projectAgentArray(customers);
  const relayRows = projectAgentArray(channelRelayInbox);
  const taskRows = projectAgentArray(fulfillmentTasks);
  const stockRows = projectAgentArray(credentialStock);
  const socialRows = projectAgentArray(socialAccounts);
  const channelPostRows = projectAgentArray(whatsappChannelPosts);
  const todayOrders = orderRows.filter(row => projectAgentDateKey(row.created || row.orderDate || row.updated) === today);
  const todayPayments = paymentRows.filter(row => projectAgentDateKey(row.date || row.created || row.updated) === today);
  const approvedPayments = paymentRows.filter(row => /approved|paid|verified/i.test(String(row.status || row.paymentStatus || '')));
  const pendingRelays = relayRows.filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase()));
  const manualRelays = relayRows.filter(row => ['manual_required', 'failed'].includes(String(row.status || '').toLowerCase()));
  const pendingFulfillment = taskRows.filter(row => !['delivered', 'cancelled', 'archived'].includes(String(row.status || 'pending').toLowerCase()));
  const availableCredentialStock = stockRows.filter(row => String(row.status || 'available').toLowerCase() === 'available');
  const unavailablePlans = planRows.filter(row => row.available === false || row.stock === false || /not available|out/i.test(String(row.status || '')));
  const outOfStockProducts = productRows.filter(row => row.stock === false || /out/i.test(String(row.status || '')));
  const recentErrors = projectAgentArray(logs).filter(row => {
    const text = [row.status, row.type, row.error, row.message].join(' ');
    return /fail|error|crash|timeout/i.test(text) && (Date.now() - (Date.parse(row.time || row.createdAt || row.created || 0) || 0) < 3 * 24 * 60 * 60 * 1000);
  }).slice(0, 20);

  return {
    generatedAt: new Date().toISOString(),
    whatsappConnected: !!waClients.get('default')?.isReady,
    whatsappStatus: waClients.get('default')?.status || (waClients.get('default')?.isReady ? 'ready' : 'not_ready'),
    customers: customerRows.length,
    hotCustomers: customerRows.filter(row => projectAgentArray(row.tags).some(tag => /hot|vip/i.test(String(tag))) || row.isVip || row.vip).length,
    plans: planRows.length,
    unavailablePlans: unavailablePlans.length,
    products: productRows.length,
    outOfStockProducts: outOfStockProducts.length,
    orders: orderRows.length,
    todayOrders: todayOrders.length,
    pendingOrders: orderRows.filter(row => /pending/i.test(String(row.status || row.paymentStatus || ''))).length,
    payments: paymentRows.length,
    todayPayments: todayPayments.length,
    approvedRevenue: approvedPayments.reduce((sum, row) => sum + Number(row.amount || row.total || 0), 0),
    fulfillmentPending: pendingFulfillment.length,
    credentialStockAvailable: availableCredentialStock.length,
    gmailAccounts: projectAgentArray(gmailAccounts).length,
    gmailPaymentEvents: projectAgentArray(gmailPaymentEvents).length,
    socialAccounts: socialRows.length,
    socialPlatforms: [...new Set(socialRows.map(row => row.platform).filter(Boolean))],
    socialAutoPosts: projectAgentArray(socialAutoPosts).length,
    files: projectAgentArray(fileLibrary).length,
    fileSections: FILE_LIBRARY_SECTIONS.length,
    channelTargets: getConfiguredWhatsAppChannels().length,
    channelSources: getConfiguredWhatsAppChannelSources().length,
    channelDiscoveries: projectAgentArray(whatsappChannelDiscoveries).length,
    channelPosts: channelPostRows.length,
    channelRelayPending: pendingRelays.length,
    channelRelayManual: manualRelays.length,
    channelCopyEnabled: settings.whatsapp_channel_copy_enabled === true,
    channelAutoPublish: settings.whatsapp_channel_relay_auto_publish === true,
    stockSourcingRequests: projectAgentArray(stockSourcingRequests).length,
    recentErrors
  };
}

function projectPromptTemplate(category, title, priority, reason, prompt, extra = {}) {
  return {
    category,
    title,
    priority,
    reason,
    prompt: cleanOutgoingText(prompt),
    commandHint: extra.commandHint || '',
    tags: extra.tags || [],
    effort: extra.effort || 'medium'
  };
}

