  processing:  (o) => `ðŸ”§ *Order Processing*\n\nHi ${o.customerName}! Your order *#${o.orderNumber}* is being prepared.\nâ³ Expected dispatch: within 24 hours.`,
  shipped:     (o) => `ðŸšš *Order Shipped!*\n\nGreat news ${o.customerName}! Your order *#${o.orderNumber}* is on the way!\nðŸ“ Tracking: ${o.trackingNumber || 'Will be shared soon'}\nðŸ“¦ Estimated delivery: ${o.deliveryEta || '2-3 days'}`,
  delivered:   (o) => `ðŸŽ‰ *Order Delivered!*\n\nHi ${o.customerName}! Your order *#${o.orderNumber}* has been delivered.\n\nWe hope you love it! Please share your feedback. â­\nReply REVIEW to leave a review.`,
  cancelled:   (o) => `âŒ *Order Cancelled*\n\nHi ${o.customerName}, your order *#${o.orderNumber}* has been cancelled.\n${o.cancelReason ? 'Reason: ' + o.cancelReason : ''}\n\nContact us if you have questions.`,
