const saveCustomLogicRules = () => saveJSON('custom_logic_rules.json', customLogicRules);

function saveCommerceSettings() {
  saveJSON('commerce_settings.json', commerceSettings);
}

function saveCommerceEvents() {
  commerceEvents = (commerceEvents || []).slice(-500);
  saveJSON('commerce_events.json', commerceEvents);
}

function saveCommerceConnections() {
  commerceConnections = (commerceConnections || []).slice(0, 300);
  saveJSON('commerce_connections.json', commerceConnections);
}

function logCommerceEvent(type, payload = {}, source = '') {
  commerceEvents.push({
    id: uuid(),
    type,
    source,
    payload,
    createdAt: new Date().toISOString()
  });
  saveCommerceEvents();
}

