app.post('/api/commerce/delay-notify', async (req, res) => {
  try {
    const order = findOrderByAnyIdentifier(req.body?.orderId || req.body?.orderNumber || '');
    const number = normalizeNumber(req.body?.phone || req.body?.number || order?.customerNumber || '');
    if (!number) return res.status(400).json({ success: false, error: 'order or phone is required' });
    const message = buildCommerceDelayMessage(order || {}, req.body || {});
    const sent = await sendCommerceMessage(number, message);
    if (order) {
      order.delayNotices = Array.isArray(order.delayNotices) ? order.delayNotices : [];
      order.delayNotices.push({
        reason: String(req.body?.reason || '').trim(),
        etaHours: Number(req.body?.etaHours || req.body?.delayHours || 0),
        trackUrl: String(req.body?.trackUrl || '').trim(),
        addressUrl: String(req.body?.addressUrl || '').trim(),
        sentAt: new Date().toISOString()
      });
      order.statusHistory = Array.isArray(order.statusHistory) ? order.statusHistory : [];
      order.statusHistory.push({
        status: 'delayed',
        time: new Date().toISOString(),
        note: String(req.body?.reason || 'Delay notification sent').trim()
      });
      order.updated = new Date().toISOString();
      saveJSON('orders.json', orders);
    }
    logCommerceEvent('delay_notification', {
      orderNumber: order?.orderNumber || req.body?.orderNumber || '',
      phone: number,
      reason: req.body?.reason || '',
      etaHours: Number(req.body?.etaHours || req.body?.delayHours || 0),
      sent
    }, 'commerce');
    logJourneyEvent('delay_notification', {
      number,
      customerId: order?.customerId || null,
      customerName: order?.customerName || req.body?.customerName || '',
      channel: 'whatsapp',
      meta: {
        orderNumber: order?.orderNumber || req.body?.orderNumber || '',
        reason: req.body?.reason || '',
        etaHours: Number(req.body?.etaHours || req.body?.delayHours || 0)
      }
    }, 'retention');
    res.json({ success: true, sent, message, order: order || null });
  } catch (error) {
    res.status(400).json({ success: false, error: error.message });
  }
});

