// CREATE order
app.post('/api/orders', async (req, res) => {
  const { customerId, customerNumber, customerName, items, notes, deliveryAddress } = req.body;
  if (!customerNumber || !items || !items.length) return res.status(400).json({ error: 'customerNumber and items required' });
  const total = items.reduce((sum, i) => sum + ((i.price || 0) * (i.qty || 1)), 0);
  const order = {
    id: uuid(),
    orderNumber: generateOrderNumber(),
    customerId, customerNumber, customerName: customerName || customerNumber,
    items, total, notes, deliveryAddress,
    status: 'pending',
    statusHistory: [{ status: 'pending', time: new Date().toISOString(), note: 'Order created' }],
    trackingNumber: null, deliveryEta: null, cancelReason: null,
    created: new Date().toISOString(),
    updated: new Date().toISOString()
  };
  orders.push(order);
  saveJSON('orders.json', orders);
  // Update customer stats
  const cust = customers.find(c => c.id === customerId || c.number === customerNumber);
  if (cust) {
    cust.totalOrders = (cust.totalOrders || 0) + 1;
    cust.totalSpent = (cust.totalSpent || 0) + total;
    cust.lastOrderDate = new Date().toISOString();
    cust.status = 'active';
    saveJSON('customers.json', customers);
  }
  io.emit('new_order', order);
  queueWebhookEvent('order_created', order);
  if (typeof sendOrderConfirmation === 'function') {
    setImmediate(() => {
      sendOrderConfirmation({
        ...order,
        orderId: order.orderNumber || order.id,
        customerPhone: order.customerNumber,
        customerName: order.customerName,
        productName: Array.isArray(order.items) ? order.items.map(i => i.productName || i.name || i.title || i.product || 'Item').join(', ') : '',
        amount: order.total
      }).catch(error => console.error('[Automation] order confirmation failed:', error.message));
    });
  }
  res.json(order);
});

