// UPDATE order STATUS + auto WhatsApp notification
app.put('/api/orders/:id/status', async (req, res) => {
  const { status, note, trackingNumber, deliveryEta, cancelReason } = req.body;
  if (!ORDER_STATUSES.includes(status)) return res.status(400).json({ error: 'Invalid status' });
  const o = orders.find(o => o.id === req.params.id);
  if (!o) return res.status(404).json({ error: 'Not found' });
  const prevStatus = o.status;
  o.status = status;
  o.updated = new Date().toISOString();
  if (trackingNumber) o.trackingNumber = trackingNumber;
  if (deliveryEta) o.deliveryEta = deliveryEta;
  if (cancelReason) o.cancelReason = cancelReason;
  o.statusHistory = o.statusHistory || [];
  o.statusHistory.push({ status, time: new Date().toISOString(), note: note || '' });
  saveJSON('orders.json', orders);
  // Send WhatsApp notification
  let notifSent = false;
  if (ORDER_MESSAGES[status] && o.customerNumber) {
    try {
      const msg = ORDER_MESSAGES[status](o);
      await sendDirect(o.customerNumber, msg);
      notifSent = true;
    } catch(e) { console.error('Order notification failed:', e.message); }
  }
  io.emit('order_status_changed', { id: o.id, orderNumber: o.orderNumber, prevStatus, status });
  queueWebhookEvent('order_status_changed', { order: o, id: o.id, orderNumber: o.orderNumber, prevStatus, status });
  res.json({ order: o, notifSent });
});

