function reportDateKey(input = new Date()) {
  const date = input instanceof Date ? input : new Date(input);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleDateString('en-CA', { timeZone: 'Asia/Karachi' });
}

function buildDailySalesReport() {
  const todayKey = reportDateKey(new Date());
  const todayOrders = orders.filter(o => reportDateKey(o.created || o.updated) === todayKey);
  const todayPayments = payments.filter(p => reportDateKey(p.date || p.created) === todayKey);
  const approvedPayments = todayPayments.filter(p => String(p.status || '').toLowerCase() === 'approved');
  const revenue = approvedPayments.reduce((sum, p) => sum + Number(p.amount || 0), 0);
  const delivered = todayOrders.filter(o => o.status === 'delivered').length;
  const pending = orders.filter(o => o.status === 'pending').length;
  const confirmed = orders.filter(o => o.status === 'confirmed').length;
  const outOfStock = laptopProducts.filter(p => p.stock === false).length;
  const hotLeads = customers.filter(c => {
    const tags = Array.isArray(c.tags) ? c.tags.map(t => String(t).toLowerCase()) : [];
    return tags.includes('hot lead') || tags.includes('hot');
  }).length;

  return [
    `*Daily Sales Report - ${todayKey}*`,
    '',
    `Orders today: ${todayOrders.length}`,
    `Delivered today: ${delivered}`,
    `Pending orders: ${pending}`,
    `Confirmed orders: ${confirmed}`,
    `Payments today: ${todayPayments.length}`,
    `Approved revenue: Rs. ${revenue.toLocaleString()}`,
    `Hot leads: ${hotLeads}`,
    `Out of stock products: ${outOfStock}`,
    '',
    'Reply with the customer number in SuperSender to follow up.'
  ].join('\n');
}

async function sendDailySalesReportToAdmin() {
  const adminNumber = getAdminWhatsAppNumber();
  if (!adminNumber) throw new Error('Owner/support WhatsApp number is missing in Settings.');
  if (!waClients.get('default')?.isReady) throw new Error('WhatsApp not connected');
  const report = buildDailySalesReport();
  await sendDirect(adminNumber, report);
  logs.push({ id: uuid(), type: 'daily_sales_report', to: adminNumber, status: 'sent', message: report, time: new Date().toISOString() });
  saveJSON('logs.json', logs);
  return report;
}

app.post('/api/reports/daily-sales/send', async (req, res) => {
  try {
    const report = await sendDailySalesReportToAdmin();
    res.json({ success: true, report });
  } catch (e) {
    const status = /missing|not connected/i.test(e.message || '') ? 400 : 500;
    res.status(status).json({ error: e.message });
  }
});

