let whatsAppChannelCopyPollBusy = false;
async function runWhatsAppChannelCopyPollTick() {
  if (whatsAppChannelCopyPollBusy) return { skipped: true, reason: 'copy poll already running' };
  if (settings.whatsapp_channel_copy_enabled !== true || settings.whatsapp_channel_relay_auto_publish !== true) {
    return { skipped: true, reason: 'channel copy autopublish disabled' };
  }
  if (!waClients.get('default')?.isReady) return { skipped: true, reason: 'main WhatsApp not ready' };
  if (!waClients.get(baileysChannelPublisherId())?.isReady) return { skipped: true, reason: 'channel publisher not ready' };
  if (!getConfiguredWhatsAppChannels().length || !getConfiguredWhatsAppChannelSources().length) {
    return { skipped: true, reason: 'source/target channels missing' };
  }
  whatsAppChannelCopyPollBusy = true;
  try {
    let discovery = null;
    if (settings.whatsapp_channel_auto_source_all_followed === true) {
      discovery = await discoverWhatsAppChannels({ accountId: 'default', save: true, autoConfigure: false })
        .catch(error => ({ success: false, error: error.message }));
    }
    const sweep = await runWhatsAppChannelCopySweep({
      accountId: 'default',
      limit: Math.max(1, Number(settings.whatsapp_channel_copy_poll_limit || 3)),
      autoPublish: true
    });
    const retries = await processPendingWhatsAppChannelRelays(Math.max(1, Number(settings.whatsapp_channel_copy_retry_limit || 3)));
    logs.push({
      id: uuid(),
      type: 'whatsapp_channel_copy_poll',
      status: sweep?.failures?.length ? 'partial' : 'complete',
      discovery,
      sweep,
      retries,
      time: new Date().toISOString()
    });
    saveJSON('logs.json', logs);
    return { success: true, sweep, retries };
  } catch (error) {
    logs.push({ id: uuid(), type: 'whatsapp_channel_copy_poll', status: 'failed', error: error.message, time: new Date().toISOString() });
    saveJSON('logs.json', logs);
    console.error('WhatsApp channel copy poll failed:', error.message);
    return { success: false, error: error.message };
  } finally {
    whatsAppChannelCopyPollBusy = false;
  }
}
setInterval(runWhatsAppChannelCopyPollTick, Math.max(20, Number(settings.whatsapp_channel_copy_poll_seconds || 30)) * 1000);
setTimeout(runWhatsAppChannelCopyPollTick, 25000);

let whatsAppChannelAutomationPackBusy = false;
async function runWhatsAppChannelAutomationPackTick(force = false) {
  if (whatsAppChannelAutomationPackBusy) return { skipped: true, reason: 'automation pack already running' };
  whatsAppChannelAutomationPackBusy = true;
  const results = [];
  try {
    const now = Date.now();
    let pendingCount = (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
      .filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())).length;
    if (settings.whatsapp_channel_queue_cleaner_enabled !== false || force) {
      const clean = runChannelQueueCleaner({ force });
      if (clean.success && (clean.stats?.totalRejected || force)) results.push({ type: 'queue_cleaner', ...clean });
      pendingCount = (Array.isArray(channelRelayInbox) ? channelRelayInbox : [])
        .filter(row => ['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())).length;
    }
    const lastSourceDoctor = Date.parse(channelAutomationState.lastSourceDoctorAt || 0) || 0;
    if ((settings.whatsapp_channel_source_doctor_enabled !== false || force) && (force || !lastSourceDoctor || now - lastSourceDoctor > 60 * 60 * 1000)) {
      const doctor = runChannelSourceDoctor({ autoPause: settings.whatsapp_channel_auto_pause_dead_sources === true });
      channelAutomationState.lastSourceDoctorAt = new Date().toISOString();
      if (doctor.success && (force || (doctor.summary?.dead || 0) || (doctor.summary?.silent || 0))) {
        results.push({ type: 'source_doctor', summary: doctor.summary });
      }
    }
    if (pendingCount <= Number(settings.whatsapp_channel_low_queue_threshold || 2)) {
      createChannelAutomationAlert('low_queue', `Channel relay queue low: ${pendingCount}`, { pendingCount });
      const lastGapFill = Date.parse(channelAutomationState.lastGapFillAt || 0) || 0;
      const gapFillDue = !lastGapFill || Date.now() - lastGapFill > 6 * 60 * 60 * 1000;
      if (pendingCount === 0 && gapFillDue && settings.whatsapp_channel_daily_digest_enabled !== false && getConfiguredWhatsAppChannels().length) {
        const gap = await runChannelGapFiller({ publishNow: false, prefix: '🔥 Popular update from our archive:' });
        if (gap.success && !gap.skipped) {
          channelAutomationState.lastGapFillAt = new Date().toISOString();
          results.push({ type: 'gap_filler', ...gap });
        }
      }
    }
    const stuckMinutes = Number(settings.whatsapp_channel_queue_stuck_minutes || 60);
    const stuckRows = (Array.isArray(channelRelayInbox) ? channelRelayInbox : []).filter(row => {
      if (!['draft', 'pending', 'manual_required', 'failed'].includes(String(row.status || '').toLowerCase())) return false;
      const age = now - Date.parse(row.updatedAt || row.createdAt || 0);
      return age > stuckMinutes * 60 * 1000;
    });
    if (stuckRows.length) createChannelAutomationAlert('queue_stuck', `${stuckRows.length} channel relay items stuck`, { count: stuckRows.length, stuckMinutes });

    for (const job of (Array.isArray(channelAutomationJobs) ? channelAutomationJobs : [])) {
      if (job.enabled === false) continue;
      const last = Date.parse(job.lastRunAt || channelAutomationState.lastJobRun?.[job.id] || 0);
      const due = force || !last || (now - last) >= Math.max(1, Number(job.intervalMinutes || 60)) * 60 * 1000;
      if (!due) continue;
      const result = await runChannelAutomationJob(job, { force, publishNow: true });
      const idx = channelAutomationJobs.findIndex(row => row.id === job.id);
      if (idx >= 0) channelAutomationJobs[idx] = result.job;
      results.push(result);
    }

    if (settings.whatsapp_channel_drip_enabled !== false) {
      const drip = await runChannelDripQueue(false);
      if (drip.success) results.push({ type: 'drip_queue', ...drip });
    }

    const hourMinute = new Date().toLocaleTimeString('en-GB', { timeZone: 'Asia/Karachi', hour: '2-digit', minute: '2-digit', hour12: false });
    const dayKey = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Karachi' });
    if ((force || hourMinute === '09:00') && settings.whatsapp_channel_prayer_times_enabled !== false && channelAutomationState.lastPrayerPostDate !== dayKey) {
      const result = await runChannelAutomationJob({ id: 'builtin-prayer-times', name: 'Prayer Times Pakistan', kind: 'prayer_times', intervalMinutes: 1440 }, { force: true, publishNow: true });
      channelAutomationState.lastPrayerPostDate = dayKey;
      results.push(result);
    }
    if ((force || hourMinute === '10:00') && settings.whatsapp_channel_currency_rate_enabled !== false && channelAutomationState.lastCurrencyPostDate !== dayKey) {
      const result = await runChannelAutomationJob({ id: 'builtin-currency-rate', name: 'PKR Currency Rate', kind: 'currency_rate', intervalMinutes: 1440 }, { force: true, publishNow: true });
      channelAutomationState.lastCurrencyPostDate = dayKey;
      results.push(result);
    }
    if ((force || hourMinute === '22:00') && settings.whatsapp_channel_daily_digest_enabled !== false && channelAutomationState.lastDigestDate !== dayKey) {
      const result = await runChannelAutomationJob({ id: 'builtin-daily-digest', name: 'Daily Channel Digest', kind: 'daily_digest', intervalMinutes: 1440 }, { force: true, publishNow: true });
      channelAutomationState.lastDigestDate = dayKey;
      results.push(result);
    }

    const cutoff = now - Number(settings.whatsapp_channel_old_data_archive_days || 30) * 24 * 60 * 60 * 1000;
    const beforeMedia = channelMediaPipeline.length;
    channelMediaPipeline = (Array.isArray(channelMediaPipeline) ? channelMediaPipeline : []).filter(row => Date.parse(row.createdAt || 0) >= cutoff);
    if (beforeMedia !== channelMediaPipeline.length) saveChannelMediaPipeline();
    saveChannelAutomationJobs();
    saveChannelAutomationState();
    return { success: true, results };
  } catch (error) {
    createChannelAutomationAlert('automation_pack_failed', error.message);
    return { success: false, error: error.message, results };
  } finally {
    whatsAppChannelAutomationPackBusy = false;
  }
}
